/// Per-alias generic info: the type-parameter TypeIds in
/// declaration order plus the body TypeId those parameters
/// substitute into. Owned by the checker; the slice lives in the
/// checker's diag/scratch arena.
pub const GenericAliasInfo = struct {
    params: []TypeId,
    body: TypeId,
    /// HIR node for the alias body. Used when the body contains a
    /// mapped type whose constraint can't materialize until the
    /// outer parameters are substituted (homomorphic case:
    /// `type Partial<T> = { [K in keyof T]?: T[K] }`). Falls back
    /// to `body` lookup when the HIR node has been re-evaluated.
    body_node: hir_mod.NodeId = hir_mod.none_node_id,
};

const ActiveGenericAlias = struct {
    name: hir_mod.StringId,
    first_arg: TypeId,
};

/// Subset of compiler-options flags the checker consults. Defaults
/// match `tsc`'s no-flag baseline (everything off). The driver
/// populates this from a parsed `tsconfig` before `checkSourceFile`.
pub const FnPredicate = struct {
    /// 0xFFFF for `this is T`; otherwise the parameter index.
    param_index: u16,
    /// The asserted type (TypeId).
    target_type: TypeId,
    /// Original target type node for explicit predicates. Kept so
    /// forward references such as `this is LaterClass` can be
    /// resolved when the guard is used, after later declarations have
    /// populated the checker type tables.
    target_node: NodeId = hir_mod.none_node_id,
    /// True for `asserts arg is T` — narrows in fall-through, not
    /// just then-branch.
    is_asserts: bool,
};

/// Composite key for member-access narrowing. `obj_name` is the
/// interned identifier name on the LHS of the access; `prop_name`
/// is the property name. Hashed via `AutoHashMap`'s default
/// derivation.
pub const MemberKey = struct {
    obj_name: hir_mod.StringId,
    prop_name: hir_mod.StringId,
};

/// Predicate metadata attached to a specific object member. Unlike
/// `signature_predicates`, this key distinguishes same-shaped methods
/// such as `isLeader(): this is LeadGuard` and
/// `isFollower(): this is FollowerGuard` on the same receiver.
pub const TypeMemberKey = struct {
    receiver_type: TypeId,
    member_name: hir_mod.StringId,
};

pub const SignatureParamKey = struct {
    signature: TypeId,
    param_index: u16,
};

const ParamPredicateEntry = struct {
    param_index: u16,
    pred: FnPredicate,
};

pub const VarDeclKey = struct {
    scope: hir_mod.NodeId,
    name: hir_mod.StringId,
    virtual_section_start: usize,
};

const GeneratorTypeInfo = struct {
    yield_type: TypeId,
    return_type: TypeId,
    next_type: TypeId,
};

const IndexSignatureDuplicateState = struct {
    first_string: NodeId = hir_mod.none_node_id,
    first_number: NodeId = hir_mod.none_node_id,
    first_symbol: NodeId = hir_mod.none_node_id,
    reported_string: bool = false,
    reported_number: bool = false,
    reported_symbol: bool = false,
};

const ClassMethodSeen = struct {
    first_node: NodeId,
    first_static: bool,
    first_visibility: u2,
    bodyless_count: u32 = 0,
    implementation_count: u32 = 0,
};

const IndexKind = enum { string, number, symbol };

const DeclarationEntry = struct {
    node: NodeId,
    is_function: bool = false,
    is_type_alias: bool = false,
    is_var: bool = false,
    has_body: bool = false,
    is_exported: bool = false,
    is_ambient: bool = false,
};

const DeclarationKey = struct {
    name: hir_mod.StringId,
    virtual_section_start: usize,
};

const ExportAssignmentSection = struct {
    export_assignment: NodeId = hir_mod.none_node_id,
    has_other_export: bool = false,
};

pub const StrictFlags = struct {
    /// `noImplicitAny` (also implied by `strict`). When true, a
    /// parameter / variable that ends up typed as `any` because it
    /// has no annotation and no inferable initializer raises TS7006
    /// / TS7005.
    no_implicit_any: bool = false,
    /// `noUnusedParameters`. Emits TS6133 for parameters whose name
    /// isn't referenced inside the function body. Names beginning
    /// with `_` are excluded by convention (matches tsc).
    no_unused_parameters: bool = false,
    /// `noUnusedLocals`. Emits TS6133 for `let` / `const` / `var`
    /// declarations whose name isn't referenced after the
    /// declaration. Names beginning with `_` are excluded.
    no_unused_locals: bool = false,
    /// `strictFunctionTypes` (also implied by `strict`). When true,
    /// function-type parameters are checked contravariantly (the
    /// sound rule). When false, parameters are bivariant (legacy
    /// flexibility — matches `tsc`'s pre-3.0 default and current
    /// behavior on method declarations).
    strict_function_types: bool = false,
    /// `strictNullChecks` (also implied by `strict`). When false,
    /// `null` and `undefined` flow to every type except `never`.
    strict_null_checks: bool = false,
    /// `strictPropertyInitialization` (also implied by `strict`).
    /// Emits TS2564 for typed instance fields that have no initializer
    /// and are not definitely assigned by a constructor analysis pass.
    strict_property_initialization: bool = false,
    /// `noUncheckedIndexedAccess`. When true, indexed access through
    /// an array or index signature widens the result with `undefined`
    /// — `arr[i]` types as `T | undefined` rather than `T`. Tuple
    /// positional access (`tup[0]` against `[A, B]`) keeps the precise
    /// element type since the arity is statically known.
    no_unchecked_indexed_access: bool = false,
    /// `isolatedModules`. Each file must be transpilable in
    /// isolation (no cross-file type info). Forbids constructs that
    /// rely on type-only / cross-module elision: `export const enum`,
    /// type-only re-exports without an explicit `type` modifier,
    /// references to ambient `const enum`s, etc. v0 emits TS1205
    /// for the exported-const-enum case.
    isolated_modules: bool = false,
    /// `resolveJsonModule`. When true, `import data from "./x.json"`
    /// resolves and the default import takes the parsed JSON's shape
    /// (typed as `any` in v0). When false, a `.json` import emits
    /// TS2307 — matches tsc's behavior of refusing the resolution.
    resolve_json_module: bool = false,
    /// `exactOptionalPropertyTypes`. When true, `a?: T` means the
    /// property is absent OR has type `T` — explicitly assigning
    /// `undefined` is rejected (TS2375). When false (legacy), `a?: T`
    /// is treated as `T | undefined` and `{ a: undefined }` is
    /// permitted.
    exact_optional_property_types: bool = false,
    /// `noPropertyAccessFromIndexSignature`. When true, `obj.foo`
    /// is forbidden if `foo` only resolves via an index signature
    /// (i.e. there's no declared property `foo`). The element-access
    /// form `obj["foo"]` must be used instead — surfacing that the
    /// key may or may not exist on the type. Emits TS4111.
    no_property_access_from_index_signature: bool = false,
    /// `noImplicitOverride`. When true, class members that override
    /// base-class members must carry the `override` modifier.
    no_implicit_override: bool = false,
    /// `useUnknownInCatchVariables` (also implied by `strict`). When
    /// true, unannotated `catch (e)` bindings are typed as `unknown`
    /// rather than `any`.
    use_unknown_in_catch_variables: bool = false,
};

pub const Checker = struct {
    gpa: std.mem.Allocator,
    hir: *Hir,
    interner: *interner.Interner,
    string_interner: *string_interner.Interner,
    engine: *relation.Engine,
    lowerer: lower.Lowerer,
    /// Optional bound module — when set, identifier expressions
    /// resolve their type via the symbol table.
    module: ?*const binder_mod.Module,
    /// Stack of name → narrowed-type maps. Each `if`/`while`/etc.
    /// pushes a scope; identifier resolution consults the top of
    /// the stack first before falling back to the static type.
    narrow_scopes: std.ArrayListUnmanaged(std.AutoHashMapUnmanaged(hir_mod.StringId, TypeId)),
    /// Lowest narrow-scope index visible to lookup. Used for closure
    /// boundaries such as class method bodies, where `this`/local
    /// flow scopes should be visible but outer flow narrows must not
    /// leak in.
    narrow_lookup_floor: usize,
    declared_identifier_lookup: bool,
    report_unresolved_in_namespace_scope: bool,
    /// Parallel stack of member-access narrows keyed by
    /// `(obj_name, prop_name)`. Populated by `applyTypeGuard` when
    /// a guard's LHS is a member-access on an identifier root (e.g.
    /// `obj.x !== null`); consulted by `member_access` typing so
    /// the then-branch sees the narrowed property type.
    /// Pushed/popped in lockstep with `narrow_scopes`.
    member_narrow_scopes: std.ArrayListUnmanaged(std.AutoHashMapUnmanaged(MemberKey, TypeId)),
    /// Class-name → instance type. Populated by `checkClassDecl`
    /// when a class is declared; consulted by `instanceof` narrowing
    /// and `new` expression typing — both of which require the name
    /// to refer to a constructable runtime entity (not an interface
    /// or a type alias).
    class_instance_types: std.AutoHashMapUnmanaged(hir_mod.StringId, TypeId),
    /// Class declarations currently being materialized for forward
    /// type-reference resolution. This is only a recursion guard for
    /// shallow type-shape construction; the normal top-level pass still
    /// fully checks class bodies and diagnostics later.
    checked_class_decls: std.AutoHashMapUnmanaged(NodeId, void),
    /// Class-name → constructor signature TypeId. Populated when a
    /// class declares an explicit `constructor(...)`; consulted by
    /// `new_expr` typing to check argument count / types. Classes
    /// without an explicit constructor produce no entry — `new Foo()`
    /// then accepts any args (matches TS's implicit no-arg default).
    class_constructor_sigs: std.AutoHashMapUnmanaged(hir_mod.StringId, TypeId),
    /// Class-name → static-side object type. Populated from `static`
    /// methods/properties; consulted for `super.x` inside static
    /// methods of derived classes.
    class_static_types: std.AutoHashMapUnmanaged(hir_mod.StringId, TypeId),
    /// Class declaration/expression node → static-side object type.
    /// Anonymous class expressions have no class name but still need
    /// to flow as constructor values when returned or assigned.
    class_static_type_by_node: std.AutoHashMapUnmanaged(NodeId, TypeId),
    /// Instance TypeId → declaring class name (StringId). Inverse
    /// of `class_instance_types`. The member-access path uses it
    /// to map the receiver type back to a class for privacy checks.
    class_name_by_instance: std.AutoHashMapUnmanaged(TypeId, hir_mod.StringId),
    /// Static-side TypeId → declaring class name (StringId). Mirrors
    /// `class_name_by_instance` for checks like `Base.privateStatic`
    /// where the receiver is the constructor object.
    class_name_by_static: std.AutoHashMapUnmanaged(TypeId, hir_mod.StringId),
    /// Class-name → set of member names declared `private`.
    /// Populated by `checkClassDecl`; consulted on `member_access`
    /// to flag TS2341 when the access site is outside the
    /// declaring class body.
    class_private_members: std.AutoHashMapUnmanaged(
        hir_mod.StringId,
        std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ),
    /// Class-name → set of member names declared `protected`.
    /// Populated by `checkClassDecl`; consulted on `member_access`
    /// to flag TS2445 when the access site is outside the
    /// declaring class and its subclass chain.
    class_protected_members: std.AutoHashMapUnmanaged(
        hir_mod.StringId,
        std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ),
    /// Subclass-name → parent-class name. Records the immediate
    /// `extends` target so the protected-access check can walk the
    /// inheritance chain. Set when `class B extends A { ... }` is
    /// declared and `A` is itself a known class identifier.
    class_parent: std.AutoHashMapUnmanaged(hir_mod.StringId, hir_mod.StringId),
    /// Set of class names whose declaration carried the `abstract`
    /// modifier. Populated by `checkClassDecl`; consulted on
    /// `new_expr` typing to emit TS2511 ("Cannot create an instance
    /// of an abstract class.") when the construction target resolves
    /// to an abstract class.
    abstract_classes: std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    /// Class-name → set of member names declared as abstract members
    /// inside that class body. v0 approximates "abstract member" as
    /// "method without a body inside an abstract class" — the parser
    /// discards the per-member `abstract` modifier so a missing body
    /// is the only signal we have. Populated by `checkClassDecl`;
    /// consulted on each non-abstract subclass to emit TS2515 for
    /// inherited abstract members the child fails to implement.
    class_abstract_members: std.AutoHashMapUnmanaged(
        hir_mod.StringId,
        std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ),
    /// Class-name → names declared as instance data properties.
    /// Used for TS2611 when a subclass replaces a property with an
    /// accessor.
    class_property_members: std.AutoHashMapUnmanaged(
        hir_mod.StringId,
        std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ),
    /// Class-name → names declared as instance accessors. Used for
    /// TS2610 when a subclass replaces an accessor with a property.
    class_accessor_members: std.AutoHashMapUnmanaged(
        hir_mod.StringId,
        std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ),
    /// Generic name → TypeId table for type-annotation resolution.
    /// A superset of `class_instance_types` that also covers
    /// `interface I { ... }` and `type Alias = T`. Consulted by
    /// `lowererLowerWithTypeParams` so `b: Box`, `b: SomeInterface`,
    /// or `b: SomeAlias` all resolve at the annotation site.
    type_names: std.AutoHashMapUnmanaged(hir_mod.StringId, TypeId),
    /// Generic alias name → (params, body) mapping. Populated by
    /// `checkTypeAliasDecl` when an alias declares type parameters.
    /// Consulted by `lowererLowerWithTypeParams` to instantiate
    /// `Box<number>`-style references against the aliased body.
    generic_aliases: std.AutoHashMapUnmanaged(hir_mod.StringId, GenericAliasInfo),
    /// Generic alias instantiations currently being materialized.
    /// Recursive mapped aliases such as
    /// `type Circular<T> = { [K in keyof T]: Circular<T> }` must defer
    /// when the same alias is re-entered with the same type argument,
    /// but recursive transforms like `DeepReadonly<T[P]>` are allowed
    /// to keep evaluating when the nested argument is a different
    /// structural type.
    active_generic_aliases: std.ArrayListUnmanaged(ActiveGenericAlias),
    /// Value names whose declared annotation is currently being lowered.
    /// `typeof` queries can legally participate in recursive value
    /// shapes; this guard keeps mutual annotations from re-entering
    /// `typeOfIdentifier` until the stack overflows.
    resolving_value_types: std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    /// Generic function name → owned `[]TypeId` of TypeParameter ids
    /// (in declaration order). Populated by `checkFnSignatureOnly`.
    /// Consulted by call-expression typing when explicit type args
    /// are present so they substitute the parameter types directly
    /// rather than going through argument-driven inference.
    generic_fns: std.AutoHashMapUnmanaged(hir_mod.StringId, []TypeId),
    /// Signature TypeId → owned `[]TypeId` for generic function-type
    /// annotations such as `<T>(x: T) => T` stored in variables or
    /// object members. Function declarations use `generic_fns`; this
    /// side table gives explicit type-argument calls on function
    /// values the same substitution path.
    generic_signature_params: std.AutoHashMapUnmanaged(TypeId, []TypeId),
    /// Signature TypeId → explicit `this` parameter type. The `this`
    /// parameter is not a call argument, but method calls on union
    /// receivers must still prove the receiver satisfies it.
    signature_this_params: std.AutoHashMapUnmanaged(TypeId, TypeId),
    /// Function name → type-predicate info. Populated when the
    /// function's return type is `arg is T` or `asserts arg is T`.
    /// Consulted by `applyTypeGuard` at call sites so the caller's
    /// `arg` identifier narrows in the then-branch (or fall-through
    /// for assertion functions).
    fn_predicates: std.AutoHashMapUnmanaged(hir_mod.StringId, FnPredicate),
    /// Signature TypeId → type-predicate info. This carries
    /// predicate metadata for methods and function-type members where
    /// the call site sees a signature value rather than a bare
    /// function declaration name, e.g. `obj.isFoo(): this is Foo`.
    signature_predicates: std.AutoHashMapUnmanaged(TypeId, FnPredicate),
    /// `(receiver TypeId, member name)` → type-predicate info. This
    /// preserves method predicates whose lowered signatures are
    /// otherwise identical (`() => boolean`) but narrow to different
    /// targets.
    member_predicates: std.AutoHashMapUnmanaged(TypeMemberKey, FnPredicate),
    /// `(enclosing signature, parameter index)` → predicate metadata
    /// for callback-typed parameters. This avoids collisions between
    /// same-shaped predicate callbacks belonging to different generic
    /// functions.
    signature_param_predicates: std.AutoHashMapUnmanaged(SignatureParamKey, FnPredicate),
    /// Variable name → guard expression alias. Records `let cond =
    /// <guard-expr>` so that `if (cond)` narrows the same way as
    /// `if (<guard-expr>)`. Aliased-conditional narrowing per TS
    /// PR #46266. Cleared when `cond` is reassigned.
    cond_aliases: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    /// Function name → list of overload signature TypeIds in
    /// declaration order. Populated when multiple `function f(...)`
    /// declarations share a name (overloads + implementation). The
    /// implementation signature lands last and is used to type the
    /// body; call sites resolve against the prior overload signatures.
    overloads: std.AutoHashMapUnmanaged(hir_mod.StringId, std.ArrayListUnmanaged(TypeId)),
    /// Function names whose overload list includes a concrete
    /// implementation declaration. Ambient overload sets have no
    /// implementation, so every signature remains visible at call
    /// sites.
    overload_has_implementation: std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    /// Auto-inferred variance for type-parameter TypeIds whose
    /// declaration site had no explicit `in` / `out` modifier.
    /// Populated by `checkFnSignatureOnly` and `checkTypeAliasDecl`
    /// after the body is lowered. Since the interner keys variance
    /// into the TypeId, we can't mutate the interned payload — this
    /// side table lets variance-sensitive callers consult the
    /// inferred direction. Unmarked type parameters default to
    /// `.bivariant`.
    inferred_variance: std.AutoHashMapUnmanaged(TypeId, types.Variance),
    /// Set of signature TypeIds whose final parameter was declared as
    /// a rest parameter (`...rest: T[]`). The interner keys signatures
    /// only by their flat parameter type list, so the rest-ness lives
    /// in this side table. Consulted by `checkArgsAgainstSignature` to
    /// allow variadic call sites: 0+ trailing args, each typed
    /// against the array element type of the last param. Populated by
    /// `checkFnSignatureOnly` when any HIR parameter has
    /// `flags.is_rest = true`; carried forward by
    /// `refineSignatureReturn` when the return type is later inferred.
    rest_signatures: std.AutoHashMapUnmanaged(TypeId, void),
    /// Signature TypeId → minimum required runtime arguments. The
    /// flat signature key only stores parameter types, so this side
    /// table preserves declaration-site optional/default metadata and
    /// the TS rule that a trailing `void` parameter may be omitted.
    signature_min_args: std.AutoHashMapUnmanaged(TypeId, usize),
    /// `(enum_name, member_name) → numeric value` for enum members
    /// whose value the checker resolved (either from an explicit
    /// numeric initializer or auto-incremented from the prior
    /// member). String-valued members are not recorded — their value
    /// type is the string literal itself. Populated by
    /// `checkEnumDecl`; consulted by member-access typing on enum
    /// receivers and (in a follow-up) by `const enum` inlining.
    enum_member_values: std.AutoHashMapUnmanaged(MemberKey, f64),
    /// Enum declarations marked `const`, keyed by enum name. This
    /// lets member-access typing prefer literal values even in
    /// checker-only tests that do not attach a binder module.
    const_enums: std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    /// Numeric enum declarations, keyed by enum name. Type
    /// annotations using the enum name lower to a nominal enum type
    /// instead of plain `number`.
    numeric_enums: std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    /// Per-HIR-block `var` declarations already seen. Used for the
    /// TS2403 same-name/same-type rule without conflating unrelated
    /// block/function scopes.
    var_decl_types: std.AutoHashMapUnmanaged(VarDeclKey, TypeId),
    /// Whether the recorded `var_decl_types` entry came from an
    /// explicit type annotation. TS distinguishes `var a: any` from an
    /// unannotated `var a = ...` for subsequent declaration checks.
    var_decl_explicit: std.AutoHashMapUnmanaged(VarDeclKey, bool),
    /// Synthetic marker object TypeId from `ThisType<T>` to the
    /// contextual `this` type T. The marker object is structurally
    /// optional/empty for assignment, while this side table preserves
    /// the contextual-this payload.
    this_type_markers: std.AutoHashMapUnmanaged(TypeId, TypeId),
    /// Object TypeIds whose index signature is readonly. Index
    /// signatures are stored as value-type slots on object payloads,
    /// so this side table preserves mutability for assignment checks.
    readonly_index_types: std.AutoHashMapUnmanaged(TypeId, void),
    /// Synthesized `Generator<Yield, Return, Next>` object TypeId →
    /// the three iteration slots. The structural object type still
    /// handles normal property/index access; this side table preserves
    /// the semantic slots needed by `yield`, `return`, and `yield*`.
    generator_type_info: std.AutoHashMapUnmanaged(TypeId, GeneratorTypeInfo),
    current_generator_info: ?GeneratorTypeInfo = null,
    /// Reentrancy guard while synthesizing the global `Symbol` value.
    /// `interface SymbolConstructor` augmentations may mention `Symbol`
    /// in their member types; those nested lookups should see the base
    /// lib shape instead of recursively expanding the same augmentation.
    symbol_global_building: bool = false,
    /// Strictness flags driving optional diagnostics.
    strict_flags: StrictFlags = .{},
    /// Hard-coded `lib.d.ts` substitute — `String.prototype`,
    /// `Array<T>.prototype`, `Object` global. Populated lazily on
    /// first member-access against the corresponding receiver.
    lib_cache: lib.LibCache = .{},
    diagnostics: std.ArrayListUnmanaged(Diagnostic),
    diag_arena: std.heap.ArenaAllocator,
    /// Source bytes used for directive scanning (`// @ts-ignore` /
    /// `// @ts-expect-error`). Optional — when null, no directive
    /// post-processing runs and the diagnostics list is left as-is.
    source: ?[]const u8 = null,
    /// 0-based source lines on which a `// @ts-ignore` directive
    /// suppresses diagnostics. Populated by `scanDirectives` before
    /// statement checking; consulted in `applyDirectives` after.
    ts_ignore_lines: std.AutoHashMapUnmanaged(u32, void) = .empty,
    /// 0-based source lines on which a `// @ts-expect-error`
    /// directive suppresses diagnostics. Populated by
    /// `scanDirectives`; lines that fail to suppress at least one
    /// diagnostic become a TS2578 in `applyDirectives`.
    ts_expect_error_lines: std.AutoHashMapUnmanaged(u32, void) = .empty,
    /// True when a `// @ts-nocheck` directive appears anywhere in the
    /// source. Populated by `scanDirectives`; consulted by
    /// `applyDirectives` to drop all diagnostics for this file.
    nocheck_file: bool = false,

    pub fn init(
        gpa: std.mem.Allocator,
        hir: *Hir,
        ti: *interner.Interner,
        si: *string_interner.Interner,
        engine: *relation.Engine,
    ) Checker {
        // Wire the relation engine's string-interner so structural
        // assignability can use property-name bytes (numeric-key
        // fallback for tuple-vs-array, etc.).
        engine.setStringInterner(si);
        return .{
            .gpa = gpa,
            .hir = hir,
            .interner = ti,
            .string_interner = si,
            .engine = engine,
            .lowerer = lower.Lowerer.init(gpa, hir, ti, si),
            .module = null,
            .narrow_scopes = .empty,
            .narrow_lookup_floor = 0,
            .declared_identifier_lookup = false,
            .report_unresolved_in_namespace_scope = false,
            .member_narrow_scopes = .empty,
            .class_instance_types = .empty,
            .checked_class_decls = .empty,
            .class_constructor_sigs = .empty,
            .class_static_types = .empty,
            .class_static_type_by_node = .empty,
            .class_name_by_instance = .empty,
            .class_name_by_static = .empty,
            .class_private_members = .empty,
            .class_protected_members = .empty,
            .class_parent = .empty,
            .abstract_classes = .empty,
            .class_abstract_members = .empty,
            .class_property_members = .empty,
            .class_accessor_members = .empty,
            .type_names = .empty,
            .generic_aliases = .empty,
            .active_generic_aliases = .empty,
            .resolving_value_types = .empty,
            .generic_fns = .empty,
            .generic_signature_params = .empty,
            .signature_this_params = .empty,
            .fn_predicates = .empty,
            .signature_predicates = .empty,
            .member_predicates = .empty,
            .signature_param_predicates = .empty,
            .cond_aliases = .empty,
            .overloads = .empty,
            .overload_has_implementation = .empty,
            .inferred_variance = .empty,
            .rest_signatures = .empty,
            .signature_min_args = .empty,
            .enum_member_values = .empty,
            .const_enums = .empty,
            .numeric_enums = .empty,
            .var_decl_types = .empty,
            .var_decl_explicit = .empty,
            .this_type_markers = .empty,
            .readonly_index_types = .empty,
            .generator_type_info = .empty,
            .current_generator_info = null,
            .symbol_global_building = false,
            .diagnostics = .empty,
            .diag_arena = std.heap.ArenaAllocator.init(gpa),
        };
    }

    /// Attach a bound module so identifier expressions get real
    /// types from the symbol table instead of falling through to
    /// `Primitive.any`.
    pub fn setModule(self: *Checker, module: *const binder_mod.Module) void {
        self.module = module;
    }

    pub fn setStrictFlags(self: *Checker, flags: StrictFlags) void {
        self.strict_flags = flags;
        self.engine.setStrictFunctionTypes(flags.strict_function_types);
        self.engine.setStrictNullChecks(flags.strict_null_checks);
    }

    /// Attach the original source bytes so `checkSourceFile` can
    /// honor `// @ts-ignore` and `// @ts-expect-error` directives.
    /// The slice must outlive the checker; we don't copy it.
    pub fn setSource(self: *Checker, source: []const u8) void {
        self.source = source;
    }

    pub fn deinit(self: *Checker) void {
        for (self.narrow_scopes.items) |*scope| {
            var s = scope.*;
            s.deinit(self.gpa);
        }
        self.narrow_scopes.deinit(self.gpa);
        for (self.member_narrow_scopes.items) |*scope| {
            var s = scope.*;
            s.deinit(self.gpa);
        }
        self.member_narrow_scopes.deinit(self.gpa);
        self.class_instance_types.deinit(self.gpa);
        self.checked_class_decls.deinit(self.gpa);
        self.class_constructor_sigs.deinit(self.gpa);
        self.class_static_types.deinit(self.gpa);
        self.class_static_type_by_node.deinit(self.gpa);
        self.class_name_by_instance.deinit(self.gpa);
        self.class_name_by_static.deinit(self.gpa);
        var pm_it = self.class_private_members.valueIterator();
        while (pm_it.next()) |set| set.deinit(self.gpa);
        self.class_private_members.deinit(self.gpa);
        var pr_it = self.class_protected_members.valueIterator();
        while (pr_it.next()) |set| set.deinit(self.gpa);
        self.class_protected_members.deinit(self.gpa);
        self.class_parent.deinit(self.gpa);
        self.abstract_classes.deinit(self.gpa);
        var am_it = self.class_abstract_members.valueIterator();
        while (am_it.next()) |set| set.deinit(self.gpa);
        self.class_abstract_members.deinit(self.gpa);
        var cpm_it = self.class_property_members.valueIterator();
        while (cpm_it.next()) |set| set.deinit(self.gpa);
        self.class_property_members.deinit(self.gpa);
        var cam_it = self.class_accessor_members.valueIterator();
        while (cam_it.next()) |set| set.deinit(self.gpa);
        self.class_accessor_members.deinit(self.gpa);
        self.type_names.deinit(self.gpa);
        var ga_it = self.generic_aliases.valueIterator();
        while (ga_it.next()) |info| self.gpa.free(info.params);
        self.generic_aliases.deinit(self.gpa);
        self.active_generic_aliases.deinit(self.gpa);
        self.resolving_value_types.deinit(self.gpa);
        var gf_it = self.generic_fns.valueIterator();
        while (gf_it.next()) |params| self.gpa.free(params.*);
        self.generic_fns.deinit(self.gpa);
        var gsig_it = self.generic_signature_params.valueIterator();
        while (gsig_it.next()) |params| self.gpa.free(params.*);
        self.generic_signature_params.deinit(self.gpa);
        self.signature_this_params.deinit(self.gpa);
        self.fn_predicates.deinit(self.gpa);
        self.signature_predicates.deinit(self.gpa);
        self.member_predicates.deinit(self.gpa);
        self.signature_param_predicates.deinit(self.gpa);
        self.cond_aliases.deinit(self.gpa);
        var ov_it = self.overloads.valueIterator();
        while (ov_it.next()) |list| list.deinit(self.gpa);
        self.overloads.deinit(self.gpa);
        self.overload_has_implementation.deinit(self.gpa);
        self.inferred_variance.deinit(self.gpa);
        self.rest_signatures.deinit(self.gpa);
        self.signature_min_args.deinit(self.gpa);
        self.enum_member_values.deinit(self.gpa);
        self.const_enums.deinit(self.gpa);
        self.numeric_enums.deinit(self.gpa);
        self.var_decl_types.deinit(self.gpa);
        self.var_decl_explicit.deinit(self.gpa);
        self.this_type_markers.deinit(self.gpa);
        self.readonly_index_types.deinit(self.gpa);
        self.generator_type_info.deinit(self.gpa);
        self.lib_cache.deinit(self.gpa);
        self.diagnostics.deinit(self.gpa);
        self.ts_ignore_lines.deinit(self.gpa);
        self.ts_expect_error_lines.deinit(self.gpa);
        self.diag_arena.deinit();
    }

    /// Look up the auto-inferred variance for a type-parameter
    /// TypeId. Falls back to the variance baked into the interner
    /// when no inference has run for this id (e.g. an explicit
    /// `in` / `out` modifier was present), and to `.bivariant`
    /// for non-type-parameter inputs.
    pub fn typeParameterVariance(self: *const Checker, tp_id: TypeId) types.Variance {
        if (self.inferred_variance.get(tp_id)) |v| return v;
        return self.interner.typeParameterVariance(tp_id);
    }

    /// Check a complete source file. The HIR root must be a
    /// block_stmt of top-level statements.
    pub fn checkSourceFile(self: *Checker, root: NodeId) CheckError!void {
        if (self.source) |src| try self.scanDirectives(src);
        try self.checkRemovedCompilerOptionDirectives(root);
        const stmts = hir_mod.blockStmts(self.hir, root);
        try self.checkNamespaceFunctionMergeOrder(stmts);
        try self.checkDeclarationSpaceDiagnostics(stmts);
        if (!self.sourceHasModuleDirective("umd")) {
            try self.checkMultipleDefaultExports(stmts);
        }
        try self.checkDefaultExportMerges(stmts);
        try self.checkImportLocalConflicts(stmts);
        try self.checkExportStarDiagnostics(stmts);
        try self.checkExportAssignmentExclusivity(stmts);
        // Pre-register top-level type aliases so recursive and mutually
        // recursive references (`type Tree<T> = { children: Tree<T>[] }`,
        // `type A = { b: B }; type B = { a: A }`) resolve to a stub body
        // when the alias body is being lowered. The stub is overwritten
        // with the real body by `checkTypeAliasDecl` below.
        for (stmts) |s| {
            if (self.hir.kindOf(s) == .type_alias_decl) {
                try self.preRegisterTypeAlias(s);
            } else if (self.hir.kindOf(s) == .export_decl) {
                const ex = hir_mod.exportOf(self.hir, s);
                if (ex.decl != hir_mod.none_node_id and self.hir.kindOf(ex.decl) == .type_alias_decl) {
                    try self.preRegisterTypeAlias(ex.decl);
                }
            }
        }
        for (stmts) |s| try self.checkStatement(s);
        try self.checkTopLevelDecoratorDiagnostics(stmts);
        try self.checkUsedBeforeAssignment(stmts);
        try self.checkClassUsedBeforeDeclaration(stmts);
        if (self.source != null) try self.applyDirectives(root);
    }

    fn checkRemovedCompilerOptionDirectives(self: *Checker, root: NodeId) CheckError!void {
        if (!self.sourceDirectiveValueMentions("importsNotUsedAsValues", "error")) return;
        try self.report(root, TsCodes.option_removed, "Option 'importsNotUsedAsValues' has been removed. Please remove it from your configuration.");
    }

    /// Pre-register a type alias's name + type-parameter shape with a
    /// placeholder `unknown` body so other aliases (and the alias's own
    /// body) can resolve references during the main pass. The real body
    /// is filled in by `checkTypeAliasDecl`.
    fn preRegisterTypeAlias(self: *Checker, node: NodeId) CheckError!void {
        const ta = hir_mod.typeAliasOf(self.hir, node);
        if (ta.name == hir_mod.none_node_id) return;
        if (self.hir.kindOf(ta.name) != .identifier) return;
        const id = hir_mod.identifierOf(self.hir, ta.name);
        const type_params = self.hir.childSlice(ta.type_params_start, ta.type_params_len);
        if (type_params.len == 0) {
            // Non-generic alias — `type_names` lookup is enough; record
            // a stub so forward references to plain `Alias` resolve.
            if (!self.type_names.contains(id.name)) {
                try self.type_names.put(self.gpa, id.name, types.Primitive.unknown);
            }
            return;
        }
        if (self.generic_aliases.contains(id.name)) return;
        var param_ids: std.ArrayListUnmanaged(TypeId) = .empty;
        errdefer param_ids.deinit(self.gpa);
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tpp = hir_mod.typeParameterOf(self.hir, tp);
            // Use minimal constraint/default during pre-registration —
            // the real entry from `checkTypeAliasDecl` overwrites this.
            const tp_id = self.interner.internFreshTypeParameterWithFlags(
                tpp.name,
                types.Primitive.unknown,
                types.Primitive.none,
                types.Variance.fromHirBits(tpp.variance),
                tpp.is_const,
            ) catch return error.OutOfMemory;
            try param_ids.append(self.gpa, tp_id);
        }
        const owned_params = param_ids.toOwnedSlice(self.gpa) catch return error.OutOfMemory;
        try self.generic_aliases.put(self.gpa, id.name, .{
            .params = owned_params,
            .body = types.Primitive.unknown,
            .body_node = ta.aliased,
        });
        try self.type_names.put(self.gpa, id.name, types.Primitive.unknown);
    }

    /// Scan the source for `// @ts-ignore` and `// @ts-expect-error`
    /// directives. A directive on line `N` suppresses diagnostics on
    /// the first non-blank, non-directive line strictly after `N`.
    /// Block-comment forms (`/* @ts-ignore */`) are out of scope for
    /// this v0 implementation.
    fn scanDirectives(self: *Checker, src: []const u8) CheckError!void {
        self.ts_ignore_lines.clearRetainingCapacity();
        self.ts_expect_error_lines.clearRetainingCapacity();
        self.nocheck_file = false;

        var line: u32 = 0;
        var i: usize = 0;
        var pending_ignore: bool = false;
        var pending_expect: bool = false;

        while (true) {
            const line_start = i;
            var line_end = line_start;
            while (line_end < src.len and src[line_end] != '\n') : (line_end += 1) {}
            const line_text = src[line_start..line_end];

            // Trim leading whitespace for directive detection.
            var t: usize = 0;
            while (t < line_text.len and (line_text[t] == ' ' or line_text[t] == '\t')) : (t += 1) {}
            const trimmed = line_text[t..];

            const is_blank = trimmed.len == 0;
            const is_ignore_directive = matchDirective(trimmed, "@ts-ignore");
            const is_expect_directive = matchDirective(trimmed, "@ts-expect-error");
            const is_nocheck_directive = matchDirective(trimmed, "@ts-nocheck");
            const is_directive = is_ignore_directive or is_expect_directive or is_nocheck_directive;

            if (is_ignore_directive) pending_ignore = true;
            if (is_expect_directive) pending_expect = true;
            if (is_nocheck_directive) self.nocheck_file = true;

            if (!is_blank and !is_directive) {
                if (pending_ignore) {
                    try self.ts_ignore_lines.put(self.gpa, line, {});
                    pending_ignore = false;
                }
                if (pending_expect) {
                    try self.ts_expect_error_lines.put(self.gpa, line, {});
                    pending_expect = false;
                }
            }

            if (line_end >= src.len) break;
            i = line_end + 1;
            line += 1;
        }
    }

    /// Filter out diagnostics whose line is suppressed by an
    /// `@ts-ignore` or `@ts-expect-error` directive. For
    /// `@ts-expect-error` lines that didn't suppress at least one
    /// diagnostic, emit TS2578 ("Unused @ts-expect-error directive").
    fn applyDirectives(self: *Checker, root: NodeId) CheckError!void {
        // `// @ts-nocheck` disables all diagnostics for the file —
        // including any TS2578 we'd otherwise emit for unused
        // `@ts-expect-error` directives.
        if (self.nocheck_file) {
            self.diagnostics.clearRetainingCapacity();
            return;
        }
        if (self.ts_ignore_lines.count() == 0 and self.ts_expect_error_lines.count() == 0) return;
        const src = self.source orelse return;

        var used_expect: std.AutoHashMapUnmanaged(u32, void) = .empty;
        defer used_expect.deinit(self.gpa);

        var i: usize = 0;
        var keep_count: usize = 0;
        while (i < self.diagnostics.items.len) : (i += 1) {
            const d = self.diagnostics.items[i];
            const span = self.hir.spanOf(d.node);
            const dline = byteOffsetToLine(src, span.start);
            const ignored = self.ts_ignore_lines.contains(dline);
            const expected = self.ts_expect_error_lines.contains(dline);
            if (ignored or expected) {
                if (expected) try used_expect.put(self.gpa, dline, {});
                continue;
            }
            self.diagnostics.items[keep_count] = d;
            keep_count += 1;
        }
        self.diagnostics.shrinkRetainingCapacity(keep_count);

        // Emit TS2578 for unused @ts-expect-error directives.
        var it = self.ts_expect_error_lines.keyIterator();
        while (it.next()) |line_ptr| {
            if (used_expect.contains(line_ptr.*)) continue;
            try self.diagnostics.append(self.gpa, .{
                .node = root,
                .code = TsCodes.unused_ts_expect_error,
                .code_prefix = .TS,
                .message = "Unused '@ts-expect-error' directive.",
            });
        }
    }

    fn checkStatement(self: *Checker, node: NodeId) CheckError!void {
        try self.checkStaticBlockReservedAwaitBinding(node);
        switch (self.hir.kindOf(node)) {
            .var_decl, .let_decl, .const_decl => try self.checkVarDecl(node),
            .fn_decl, .fn_expr, .arrow_fn => try self.checkFnDeclWithFlowBoundary(node),
            .class_decl => try self.checkClassDecl(node),
            .interface_decl => try self.checkInterfaceDecl(node),
            .enum_decl => try self.checkEnumDecl(node),
            .type_alias_decl => try self.checkTypeAliasDecl(node),
            .import_decl => try self.checkImportDecl(node),
            .export_decl => {
                // `export <decl>` — the inner decl needs the same
                // typing pass as a top-level decl. Named-only forms
                // (`export { x }`) and re-exports (`export … from
                // "m"`) have no inner decl and are handled later by
                // cross-file resolution.
                const ex = hir_mod.exportOf(self.hir, node);
                if (self.string_interner.get(ex.module).len != 0 and self.nodeSourceContainsImportAttributes(node)) {
                    try self.report(node, TsCodes.type_not_assignable, "Import attributes are not valid on this export declaration.");
                }
                try self.checkNamedExportLocals(node, ex);
                try self.checkDefaultExportIdentifierUseBeforeDeclaration(node, ex);
                if (ex.decl != hir_mod.none_node_id) {
                    // isolatedModules: `export const enum E { ... }`
                    // can't be transpiled in isolation because
                    // consumers need the inlined member values. Emit
                    // TS1205 to match `tsc --isolatedModules`.
                    if (self.strict_flags.isolated_modules and
                        self.hir.kindOf(ex.decl) == .enum_decl)
                    {
                        const ep = hir_mod.enumOf(self.hir, ex.decl);
                        if (ep.is_const) {
                            try self.report(
                                node,
                                TsCodes.isolated_modules_reexport,
                                "Re-exporting a type when 'isolatedModules' is enabled requires using 'export type'.",
                            );
                        }
                    }
                    try self.checkStatement(ex.decl);
                }
            },
            .return_stmt => {
                const r = hir_mod.returnOf(self.hir, node);
                const ret_t: TypeId = if (r.value != hir_mod.none_node_id)
                    try self.checkExpression(r.value)
                else
                    types.Primitive.void_t;
                if (self.current_generator_info) |gen| {
                    if (!(self.engine.isAssignableTo(ret_t, gen.return_type) catch true)) {
                        try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to generator return type.");
                    }
                } else if (self.returnStatementViolatesGenericRestTuple(node, ret_t)) {
                    try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to function return type.");
                }
            },
            .throw_stmt => {
                const t = hir_mod.throwOf(self.hir, node);
                if (t.value != hir_mod.none_node_id) {
                    _ = try self.checkExpression(t.value);
                }
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                _ = try self.checkExpression(i.cond);
                if (self.isElseIfStatement(node)) try self.reportStaticTruthiness(i.cond);
                try self.pushNarrowScope();
                try self.applyTypeGuard(i.cond, true);
                try self.checkStatement(i.then_branch);
                self.popNarrowScope();
                if (i.else_branch != hir_mod.none_node_id) {
                    try self.pushNarrowScope();
                    try self.applyTypeGuard(i.cond, false);
                    try self.checkStatement(i.else_branch);
                    self.popNarrowScope();
                } else if (self.statementDefinitelyExits(i.then_branch)) {
                    try self.applyTypeGuard(i.cond, false);
                } else {
                    try self.applyNullishGuardAssignmentFlow(i.cond, i.then_branch);
                }
            },
            .while_stmt => {
                const w = hir_mod.whileOf(self.hir, node);
                _ = try self.checkExpression(w.cond);
                try self.checkStatement(w.body);
            },
            .do_while_stmt => {
                const d = hir_mod.doWhileOf(self.hir, node);
                try self.checkStatement(d.body);
                _ = try self.checkExpression(d.cond);
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                if (fr.init != hir_mod.none_node_id) {
                    switch (self.hir.kindOf(fr.init)) {
                        .var_decl, .let_decl, .const_decl => try self.checkVarDecl(fr.init),
                        else => _ = try self.checkExpression(fr.init),
                    }
                }
                if (fr.cond != hir_mod.none_node_id) {
                    _ = try self.checkExpression(fr.cond);
                }
                try self.pushNarrowScope();
                defer self.popNarrowScope();
                if (fr.cond != hir_mod.none_node_id) try self.applyTypeGuard(fr.cond, true);
                try self.checkStatement(fr.body);
                if (fr.update != hir_mod.none_node_id) {
                    _ = try self.checkExpression(fr.update);
                }
            },
            .for_in_stmt => {
                // `for (let k in obj)` — `k` types to `string`
                // regardless of `obj`'s shape (matches tsc).
                const fr = hir_mod.forInOf(self.hir, node);
                const src_t = try self.checkExpression(fr.source);
                if (self.typeContainsSymbol(src_t)) {
                    try self.report(fr.source, TsCodes.for_in_right_type, "The right-hand side of a 'for...in' statement must be of type 'any', an object type or a type parameter, but here has type 'symbol'.");
                }
                if (fr.target != hir_mod.none_node_id and self.hir.kindOf(fr.target) == .identifier) {
                    const target_id = hir_mod.identifierOf(self.hir, fr.target);
                    var has_prior_binding = self.localValueDeclExistsBefore(node, target_id.name);
                    if (!has_prior_binding) {
                        if (self.module) |module| has_prior_binding = module.root.lookup(target_id.name) != null;
                    }
                    if (has_prior_binding) {
                        const target_t = try self.checkExpression(fr.target);
                        if (self.typeContainsSymbol(target_t)) {
                            try self.report(fr.target, TsCodes.for_in_left_type, "The left-hand side of a 'for...in' statement must be of type 'string' or 'any'.");
                        }
                    }
                }
                try self.bindForLoopTarget(fr.target, types.Primitive.string_t);
                try self.checkStatement(fr.body);
            },
            .for_of_stmt => {
                // `for (let x of arr)` — `x` types to `arr`'s
                // element type. We discover that via the array
                // shape's number-key indexer (which is how
                // `internArrayType` exposes it). For unknown
                // sources we fall through to `any`.
                const fr = hir_mod.forInOf(self.hir, node);
                if (fr.is_await and self.sourceTargetDisallowsTopLevelAwait() and !self.nodeIsInsideFunctionLike(node)) {
                    try self.report(node, TsCodes.for_await_target_module, "'for await' loops are only allowed within async functions and at the top levels of modules when the target supports async iteration.");
                }
                const src_t = try self.checkExpression(fr.source);
                try self.checkForOfTarget(fr.target);
                try self.checkForOfVarSelfReferenceDiagnostics(node, fr.target, fr.source);
                if (!self.isIterableLikeType(src_t)) {
                    try self.report(fr.source, TsCodes.yield_star_not_iterable, "Type must have a '[Symbol.iterator]()' method that returns an iterator.");
                } else {
                    try self.checkForOfIteratorShape(fr.source, src_t);
                }
                const elem_t = try self.iterableElementType(src_t);
                switch (self.hir.kindOf(fr.target)) {
                    .var_decl, .let_decl, .const_decl => {
                        const v = hir_mod.varDeclOf(self.hir, fr.target);
                        if (v.type_annotation != hir_mod.none_node_id) {
                            const declared_t = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
                                self.lowerValueTypeAnnotation(hir_mod.identifierOf(self.hir, v.name).name, v.type_annotation) catch types.Primitive.any
                            else
                                self.lowererLowerWithTypeParams(v.type_annotation) catch types.Primitive.any;
                            if (!(self.engine.isAssignableTo(elem_t, declared_t) catch true)) {
                                try self.report(fr.target, TsCodes.type_not_assignable, "Type is not assignable to declared type.");
                            }
                        }
                        if ((self.hir.kindOf(fr.target) == .let_decl or self.hir.kindOf(fr.target) == .const_decl) and
                            v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
                        {
                            const name = hir_mod.identifierOf(self.hir, v.name).name;
                            if (self.nodeContainsIdentifier(fr.source, name)) {
                                try self.report(fr.source, TsCodes.block_scoped_used_before_decl, "Block-scoped variable used before its declaration.");
                            }
                            if (self.bodyHasVarDeclarationNamed(fr.body, name)) {
                                try self.report(fr.body, TsCodes.for_of_var_conflict, "Cannot initialize outer scoped variable in the same scope as block scoped declaration.");
                            }
                        }
                    },
                    .identifier => {
                        const target_t = try self.checkExpression(fr.target);
                        if (target_t == types.Primitive.undefined_t and
                            self.identifierIsUntypedUninitializedVar(fr.target))
                        {
                            // Existing untyped `var` targets are writable
                            // even though their current flow type is
                            // `undefined`.
                        } else if (!(self.engine.isAssignableTo(elem_t, target_t) catch true)) {
                            try self.report(fr.target, TsCodes.type_not_assignable, "Type is not assignable to target type.");
                        }
                    },
                    .array_literal => try self.checkArrayDestructuringAssignment(fr.target, elem_t, hir_mod.none_node_id, 0),
                    .object_literal => try self.checkObjectDestructuringAssignment(fr.target, elem_t, hir_mod.none_node_id),
                    else => {},
                }
                try self.bindForLoopTarget(fr.target, elem_t);
                try self.pushNarrowScope();
                defer self.popNarrowScope();
                try self.recordLoopTargetBindings(fr.target, elem_t);
                try self.checkStatement(fr.body);
            },
            .block_stmt => {
                const stmts = hir_mod.blockStmts(self.hir, node);
                try self.pushNarrowScope();
                defer self.popNarrowScope();
                try self.checkDeclarationSpaceDiagnostics(stmts);
                for (stmts) |s| {
                    try self.checkStatement(s);
                    // Assertion-function call as a statement: narrow
                    // the asserted variable for subsequent statements
                    // in the same block. `assert(x)` where `assert`
                    // has return type `asserts x is string` narrows
                    // `x` to `string` from this point forward.
                    try self.applyAssertionFlow(s);
                    // Logical-assignment narrowing: `x ??= "default"`
                    // makes `x` non-nullish for subsequent statements.
                    try self.applyLogicalAssignmentFlow(s);
                }
            },
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                if (ts.block != hir_mod.none_node_id) try self.checkStatement(ts.block);
                if (ts.catch_param != hir_mod.none_node_id) {
                    const ck = self.hir.kindOf(ts.catch_param);
                    if (ck == .identifier) {
                        self.hir.setType(
                            ts.catch_param,
                            if (self.strict_flags.use_unknown_in_catch_variables) types.Primitive.unknown else types.Primitive.any,
                        );
                    } else if (ck == .object_pattern or ck == .array_pattern) {
                        self.hir.setType(ts.catch_param, types.Primitive.any);
                    }
                }
                if (ts.catch_block != hir_mod.none_node_id) try self.checkStatement(ts.catch_block);
                if (ts.finally_block != hir_mod.none_node_id) try self.checkStatement(ts.finally_block);
                try self.checkUnusedCatchParam(node);
            },
            .namespace_decl, .module_decl => try self.checkNamespaceTypeStatements(node),
            .switch_stmt => try self.checkSwitchStatement(node),
            // Expressions used as statements.
            else => {
                if (hir_mod.NodeKind.isExpression(self.hir.kindOf(node))) {
                    _ = try self.checkExpression(node);
                }
            },
        }
    }

    fn checkStaticBlockReservedAwaitBinding(self: *Checker, node: NodeId) CheckError!void {
        if (!self.nodeIsInClassStaticBlockBeforeFunction(node)) return;
        const await_id = self.string_interner.intern("await") catch return error.OutOfMemory;
        switch (self.hir.kindOf(node)) {
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                if (self.bindingPatternDeclaresName(v.name, await_id)) {
                    try self.report(node, TsCodes.reserved_word_cannot_be_used_here, "Identifier expected. 'await' is a reserved word that cannot be used here.");
                }
            },
            .fn_decl => {
                const f = hir_mod.fnDeclOf(self.hir, node);
                if (f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier and
                    hir_mod.identifierOf(self.hir, f.name).name == await_id)
                {
                    try self.report(f.name, TsCodes.reserved_word_cannot_be_used_here, "Identifier expected. 'await' is a reserved word that cannot be used here.");
                }
            },
            .class_decl => {
                const c = hir_mod.classOf(self.hir, node);
                if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier and
                    hir_mod.identifierOf(self.hir, c.name).name == await_id)
                {
                    try self.report(c.name, TsCodes.reserved_word_cannot_be_used_here, "Identifier expected. 'await' is a reserved word that cannot be used here.");
                }
            },
            else => {},
        }
    }

    fn bindingPatternDeclaresName(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .identifier => return hir_mod.identifierOf(self.hir, node).name == name,
            .object_pattern, .array_pattern => {
                const p = hir_mod.patternOf(self.hir, node);
                for (self.hir.childSlice(p.elements_start, p.elements_len)) |elem| {
                    if (self.hir.kindOf(elem) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, elem);
                    if (self.bindingPatternDeclaresName(pp.name, name)) return true;
                }
                return false;
            },
            else => return false,
        }
    }

    fn nodeIsInClassStaticBlockBeforeFunction(self: *Checker, node: NodeId) bool {
        var cur = node;
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (cur != node and (k == .fn_decl or k == .fn_expr or k == .arrow_fn)) return false;
            if (k != .block_stmt) continue;
            const parent = self.hir.parentOf(cur);
            if (parent == hir_mod.none_node_id) continue;
            const pk = self.hir.kindOf(parent);
            if (pk != .class_decl and pk != .class_expr) continue;
            for (hir_mod.classMembers(self.hir, parent)) |member| {
                if (member == cur) return true;
            }
        }
        return false;
    }

    fn checkNamespaceTypeStatements(self: *Checker, node: NodeId) CheckError!void {
        try self.checkUntypedModuleAugmentation(node);
        try self.checkGlobalAugmentationDiagnostics(node);
        try self.checkDeclarationSpaceDiagnostics(hir_mod.namespaceBody(self.hir, node));
        for (hir_mod.namespaceBody(self.hir, node)) |s| {
            switch (self.hir.kindOf(s)) {
                .fn_decl => try self.checkFnSignatureOnlyNoBody(s),
                .export_decl => {
                    const ex = hir_mod.exportOf(self.hir, s);
                    if (ex.decl != hir_mod.none_node_id and self.hir.kindOf(ex.decl) == .fn_decl) {
                        try self.checkFnSignatureOnlyNoBody(ex.decl);
                    }
                },
                else => {},
            }
        }
        for (hir_mod.namespaceBody(self.hir, node)) |s| {
            switch (self.hir.kindOf(s)) {
                .fn_decl => try self.checkNamespaceFnBodyAfterSignature(s),
                .class_decl,
                .interface_decl,
                .enum_decl,
                .type_alias_decl,
                => try self.checkStatement(s),
                .var_decl,
                .let_decl,
                .const_decl,
                => try self.checkNamespaceValueDecl(s),
                .export_decl => {
                    const ex = hir_mod.exportOf(self.hir, s);
                    if (ex.decl == hir_mod.none_node_id) continue;
                    const decl_kind = self.hir.kindOf(ex.decl);
                    if (self.isExportAssignmentDecl(s)) {
                        if (decl_kind == .identifier) {
                            const id = hir_mod.identifierOf(self.hir, ex.decl);
                            if (!self.isBuiltinName(id.name) and !self.namespaceBodyDeclaresValueName(hir_mod.namespaceBody(self.hir, node), id.name)) {
                                try self.reportCannotFindNamePlain(ex.decl, id.name);
                            } else {
                                _ = try self.checkExpression(ex.decl);
                            }
                            continue;
                        }
                        const old_report = self.report_unresolved_in_namespace_scope;
                        self.report_unresolved_in_namespace_scope = true;
                        defer self.report_unresolved_in_namespace_scope = old_report;
                        _ = try self.checkExpression(ex.decl);
                        continue;
                    }
                    switch (decl_kind) {
                        .class_decl,
                        .interface_decl,
                        .enum_decl,
                        .type_alias_decl,
                        => try self.checkStatement(ex.decl),
                        .fn_decl => try self.checkNamespaceFnBodyAfterSignature(ex.decl),
                        .var_decl,
                        .let_decl,
                        .const_decl,
                        => try self.checkNamespaceValueDecl(ex.decl),
                        else => {},
                    }
                },
                else => switch (self.hir.kindOf(s)) {
                    .call_expr, .new_expr => _ = try self.checkExpression(s),
                    .assignment => _ = try self.checkExpression(s),
                    .binary_op => {
                        const b = hir_mod.binopOf(self.hir, s);
                        if (b.op == .comma) _ = try self.checkExpression(s);
                    },
                    else => {},
                },
            }
        }
    }

    fn checkGlobalAugmentationDiagnostics(self: *Checker, node: NodeId) CheckError!void {
        if (!self.namespaceNameIs(node, "global")) return;
        if (!self.rootHasTopLevelExternalModuleMarker(node)) {
            const ns = hir_mod.namespaceOf(self.hir, node);
            try self.report(ns.name, TsCodes.global_augmentation_not_external, "Augmentations for the global scope can only be directly nested in external modules or ambient module declarations.");
        }
        const global_this_id = self.string_interner.intern("globalThis") catch return error.OutOfMemory;
        for (hir_mod.namespaceBody(self.hir, node)) |s| {
            if (self.hir.kindOf(s) != .export_decl) continue;
            for (hir_mod.exportNamed(self.hir, s)) |spec_node| {
                if (self.hir.kindOf(spec_node) != .import_specifier) continue;
                const spec = hir_mod.importSpecifierOf(self.hir, spec_node);
                if (spec.imported != global_this_id) continue;
                try self.report(spec_node, TsCodes.export_non_local_declaration, "Cannot export 'globalThis'. Only local declarations can be exported from a module.");
            }
        }
    }

    fn namespaceBodyDeclaresValueName(self: *Checker, stmts: []const NodeId, name: hir_mod.StringId) bool {
        for (stmts) |raw| {
            const stmt = self.unwrapExportDecl(raw);
            const k = self.hir.kindOf(stmt);
            if (k == .interface_decl or k == .type_alias_decl) continue;
            if (k == .import_decl and self.importDeclBindsLocal(stmt, name)) return true;
            if (self.declarationName(stmt)) |decl_name| {
                if (decl_name == name) return true;
            }
        }
        return false;
    }

    fn namespaceNameIs(self: *Checker, node: NodeId, name: []const u8) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) return false;
        const ns = hir_mod.namespaceOf(self.hir, node);
        if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, ns.name);
        return std.mem.eql(u8, self.string_interner.get(id.name), name);
    }

    fn rootHasTopLevelExternalModuleMarker(self: *Checker, node: NodeId) bool {
        const root = self.rootBlockFor(node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        if (self.sourceContainsImportMeta()) return true;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (stmt == node) continue;
            switch (self.hir.kindOf(stmt)) {
                .import_decl => return true,
                .export_decl => return true,
                else => {},
            }
        }
        return false;
    }

    fn sourceContainsImportMeta(self: *Checker) bool {
        const src = self.source orelse return false;
        return std.mem.indexOf(u8, src, "import.meta") != null;
    }

    fn checkUntypedModuleAugmentation(self: *Checker, node: NodeId) CheckError!void {
        if (!self.sourceHasVirtualFilenameSections()) return;
        if (self.hir.kindOf(node) != .namespace_decl) return;
        if (self.virtualSectionIsDeclarationFile(node)) return;
        const ns = hir_mod.namespaceOf(self.hir, node);
        if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) return;
        const module_name_id = hir_mod.identifierOf(self.hir, ns.name).name;
        const module_name = self.string_interner.get(module_name_id);
        if (module_name.len == 0 or std.mem.indexOfScalar(u8, module_name, '.') != null) return;
        const resolution = try self.resolveVirtualBareModule(module_name);
        if (resolution != .implementation) return;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Invalid module name in augmentation. Module '{s}' resolves to an untyped module, which cannot be augmented.",
            .{module_name},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = ns.name,
            .code = TsCodes.invalid_module_name_augmentation,
            .message = msg,
        });
    }

    fn checkNamespaceFunctionMergeOrder(self: *Checker, stmts: []const NodeId) CheckError!void {
        for (stmts, 0..) |raw, i| {
            const node = self.unwrapExportDecl(raw);
            if (node == hir_mod.none_node_id) continue;
            if (self.hir.kindOf(node) == .namespace_decl) {
                if (self.namespaceIsAmbient(node)) continue;
                const ns_name = self.declarationName(node) orelse continue;
                for (stmts[i + 1 ..]) |later_raw| {
                    const later = self.unwrapExportDecl(later_raw);
                    const later_name = self.declarationName(later) orelse continue;
                    const later_kind = self.hir.kindOf(later);
                    if ((later_kind == .fn_decl or later_kind == .fn_expr or later_kind == .class_decl or later_kind == .class_expr) and
                        later_name == ns_name)
                    {
                        try self.report(node, TsCodes.namespace_before_merged_function, "A namespace declaration cannot be located prior to a class or function with which it is merged.");
                        break;
                    }
                }
                try self.checkNamespaceFunctionMergeOrder(hir_mod.namespaceBody(self.hir, node));
            }
        }
    }

    fn checkDeclarationSpaceDiagnostics(self: *Checker, stmts: []const NodeId) CheckError!void {
        var seen: std.AutoHashMapUnmanaged(DeclarationKey, DeclarationEntry) = .empty;
        defer seen.deinit(self.gpa);
        var seen_interfaces: std.AutoHashMapUnmanaged(DeclarationKey, NodeId) = .empty;
        defer seen_interfaces.deinit(self.gpa);

        var previous_overload_name: ?hir_mod.StringId = null;
        var previous_overload_section: usize = 0;
        for (stmts) |raw| {
            const exported = self.hir.kindOf(raw) == .export_decl;
            const node = self.unwrapExportDecl(raw);
            if (node == hir_mod.none_node_id) continue;
            const virtual_section = self.virtualSectionStartForNode(node);

            const kind = self.hir.kindOf(node);
            const name = self.declarationName(node) orelse {
                previous_overload_name = null;
                previous_overload_section = 0;
                continue;
            };
            if (kind == .interface_decl) {
                if (self.interfaceHeritageReachesName(node, name, stmts, 0)) {
                    try self.report(node, TsCodes.interface_incorrectly_extends, "An interface cannot recursively extend itself.");
                }
                const key: DeclarationKey = .{ .name = name, .virtual_section_start = virtual_section };
                const gop = try seen_interfaces.getOrPut(self.gpa, key);
                if (gop.found_existing) {
                    try self.checkInterfaceMergeDiagnostics(gop.value_ptr.*, node, name);
                } else {
                    gop.value_ptr.* = node;
                }
                previous_overload_name = null;
                previous_overload_section = 0;
                continue;
            }
            const is_fn = kind == .fn_decl or kind == .fn_expr;
            const is_type_alias = kind == .type_alias_decl;
            const is_var = kind == .var_decl;
            if (!is_fn and !is_var and !is_type_alias) {
                previous_overload_name = null;
                previous_overload_section = 0;
                continue;
            }

            const has_body = if (is_fn) hir_mod.fnDeclOf(self.hir, node).body != hir_mod.none_node_id else false;
            const is_ambient = if (is_fn)
                !has_body and (self.declarationSourceHasLeadingDeclare(node) or self.virtualSectionIsDeclarationFile(node))
            else if (is_var)
                hir_mod.varDeclOf(self.hir, node).is_ambient
            else
                false;

            if (is_fn and has_body) {
                if (previous_overload_name) |expected| {
                    if (previous_overload_section == virtual_section and expected != name) {
                        const expected_name = self.string_interner.get(expected);
                        const msg = try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Function implementation name must be '{s}'.",
                            .{expected_name},
                        );
                        try self.diagnostics.append(self.gpa, .{
                            .node = node,
                            .code = TsCodes.function_implementation_name_mismatch,
                            .message = msg,
                        });
                    }
                }
            }
            if (is_fn and !has_body and !is_ambient) {
                previous_overload_name = name;
                previous_overload_section = virtual_section;
            } else {
                previous_overload_name = null;
                previous_overload_section = 0;
            }

            const key: DeclarationKey = .{ .name = name, .virtual_section_start = virtual_section };
            const gop = try seen.getOrPut(self.gpa, key);
            if (!gop.found_existing) {
                gop.value_ptr.* = .{
                    .node = node,
                    .is_function = is_fn,
                    .is_type_alias = is_type_alias,
                    .is_var = is_var,
                    .has_body = has_body,
                    .is_exported = exported,
                    .is_ambient = is_ambient,
                };
                continue;
            }

            if (gop.value_ptr.is_type_alias or is_type_alias) {
                if (gop.value_ptr.is_type_alias and is_type_alias and gop.value_ptr.is_exported != exported) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Individual declarations in merged declaration '{s}' must be all exported or all local.",
                        .{self.string_interner.get(name)},
                    );
                    try self.report(
                        gop.value_ptr.node,
                        TsCodes.declarations_must_all_be_exported_or_local,
                        msg,
                    );
                    try self.report(
                        node,
                        TsCodes.declarations_must_all_be_exported_or_local,
                        msg,
                    );
                }
                continue;
            }

            if ((gop.value_ptr.is_function and is_var) or (gop.value_ptr.is_var and is_fn)) {
                try self.reportDuplicateIdentifier(gop.value_ptr.node, name);
                try self.reportDuplicateIdentifier(node, name);
            }
            if (gop.value_ptr.is_function and is_fn) {
                if (gop.value_ptr.is_exported != exported) {
                    try self.report(node, TsCodes.overloads_must_all_be_exported_or_not, "Overload signatures must all be exported or non-exported.");
                }
                if (gop.value_ptr.is_ambient != is_ambient) {
                    try self.report(node, TsCodes.overloads_must_all_be_ambient_or_not, "Overload signatures must all be ambient or non-ambient.");
                }
            }
        }
    }

    fn interfaceHeritageReachesName(
        self: *Checker,
        node: NodeId,
        target_name: hir_mod.StringId,
        stmts: []const NodeId,
        depth: u8,
    ) bool {
        if (depth > 16 or node == hir_mod.none_node_id or self.hir.kindOf(node) != .interface_decl) return false;
        for (hir_mod.interfaceExtends(self.hir, node)) |ext_node| {
            const ext_name = self.unqualifiedTypeRefName(ext_node) orelse continue;
            if (ext_name == target_name) return true;
            for (stmts) |raw| {
                const candidate = self.unwrapExportDecl(raw);
                if (candidate == hir_mod.none_node_id or self.hir.kindOf(candidate) != .interface_decl) continue;
                const candidate_name = self.declarationName(candidate) orelse continue;
                if (candidate_name != ext_name) continue;
                if (self.interfaceHeritageReachesName(candidate, target_name, stmts, depth + 1)) return true;
            }
        }
        return false;
    }

    fn unqualifiedTypeRefName(self: *Checker, node: NodeId) ?hir_mod.StringId {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .type_ref) return null;
        const r = hir_mod.typeRefOf(self.hir, node);
        if (r.qualifier_len != 0) return null;
        return r.name;
    }

    fn checkInterfaceMergeDiagnostics(
        self: *Checker,
        first: NodeId,
        current: NodeId,
        name: hir_mod.StringId,
    ) CheckError!void {
        if (!try self.interfaceTypeParametersMerge(first, current)) {
            try self.reportDuplicateIdentifier(current, name);
            return;
        }
        if (!try self.interfaceMembersMerge(first, current)) {
            try self.reportDuplicateIdentifier(current, name);
        }
    }

    fn interfaceTypeParametersMerge(self: *Checker, first: NodeId, current: NodeId) CheckError!bool {
        const a = hir_mod.interfaceOf(self.hir, first);
        const b = hir_mod.interfaceOf(self.hir, current);
        const a_params = self.hir.childSlice(a.type_params_start, a.type_params_len);
        const b_params = self.hir.childSlice(b.type_params_start, b.type_params_len);
        if (a_params.len != b_params.len) return false;
        for (a_params, b_params) |a_tp_node, b_tp_node| {
            if (self.hir.kindOf(a_tp_node) != .type_parameter or self.hir.kindOf(b_tp_node) != .type_parameter) continue;
            const a_tp = hir_mod.typeParameterOf(self.hir, a_tp_node);
            const b_tp = hir_mod.typeParameterOf(self.hir, b_tp_node);
            if (a_tp.name != b_tp.name) return false;
            if (a_tp.constraint != hir_mod.none_node_id and b_tp.constraint != hir_mod.none_node_id and
                !self.nodeSourceTextEqual(a_tp.constraint, b_tp.constraint)) return false;
        }
        return true;
    }

    fn interfaceMembersMerge(self: *Checker, first: NodeId, current: NodeId) CheckError!bool {
        const a_members = hir_mod.interfaceMembers(self.hir, first);
        const b_members = hir_mod.interfaceMembers(self.hir, current);
        for (a_members) |a_member| {
            for (b_members) |b_member| {
                if (self.interfaceMembersConflict(a_member, b_member)) return false;
            }
        }
        return true;
    }

    fn interfaceMembersConflict(self: *Checker, a_member: NodeId, b_member: NodeId) bool {
        const a_kind = self.hir.kindOf(a_member);
        const b_kind = self.hir.kindOf(b_member);
        if (a_kind == .index_signature and b_kind == .index_signature) {
            const a = hir_mod.indexSignatureOf(self.hir, a_member);
            const b = hir_mod.indexSignatureOf(self.hir, b_member);
            if (!self.nodeSourceTextEqual(a.key_type, b.key_type)) return true;
            if (!self.nodeSourceTextEqual(a.value_type, b.value_type)) return true;
            return false;
        }
        if (a_kind != .interface_member or b_kind != .interface_member) return false;
        const a = hir_mod.interfaceMemberOf(self.hir, a_member);
        const b = hir_mod.interfaceMemberOf(self.hir, b_member);
        if (a.name == 0 or b.name == 0 or a.name != b.name) return false;
        if (a.is_method and b.is_method and self.syntheticSignatureMemberName(a.name)) return false;
        if (a.is_optional != b.is_optional) return true;
        if (a.is_method != b.is_method) return true;
        return !self.nodeSourceTextEqual(a.type_node, b.type_node);
    }

    fn syntheticSignatureMemberName(self: *Checker, name: hir_mod.StringId) bool {
        const raw = self.string_interner.get(name);
        return std.mem.eql(u8, raw, "__call") or std.mem.eql(u8, raw, "__construct");
    }

    fn nodeSourceTextEqual(self: *Checker, a: NodeId, b: NodeId) bool {
        if (a == b) return true;
        if (a == hir_mod.none_node_id or b == hir_mod.none_node_id) return a == b;
        const src = self.source orelse return self.hir.kindOf(a) == self.hir.kindOf(b);
        const a_span = self.hir.spanOf(a);
        const b_span = self.hir.spanOf(b);
        if (a_span.end > src.len or b_span.end > src.len or a_span.start > a_span.end or b_span.start > b_span.end) {
            return self.hir.kindOf(a) == self.hir.kindOf(b);
        }
        return std.mem.eql(u8, src[a_span.start..a_span.end], src[b_span.start..b_span.end]);
    }

    fn virtualSectionStartForNode(self: *Checker, node: NodeId) usize {
        const src = self.source orelse return 0;
        if (!self.sourceHasVirtualFilenameSections()) return 0;
        const span = self.hir.spanOf(node);
        const limit = @min(span.start, src.len);
        var last: usize = 0;
        var line_start: usize = 0;
        while (line_start <= limit and line_start < src.len) {
            const line_end = std.mem.indexOfScalarPos(u8, src, line_start, '\n') orelse src.len;
            const line = src[line_start..line_end];
            if (std.mem.indexOf(u8, line, "@filename:") != null or
                std.mem.indexOf(u8, line, "@Filename:") != null)
            {
                last = line_start;
            }
            if (line_end >= limit or line_end == src.len) break;
            line_start = line_end + 1;
        }
        return last;
    }

    fn virtualSectionFilenameForNode(self: *Checker, node: NodeId) ?[]const u8 {
        const src = self.source orelse return null;
        const section = self.virtualSectionStartForNode(node);
        if (section >= src.len) return null;
        const line_end = std.mem.indexOfScalarPos(u8, src, section, '\n') orelse src.len;
        const line = src[section..line_end];
        const marker = std.mem.indexOf(u8, line, "@filename:") orelse
            (std.mem.indexOf(u8, line, "@Filename:") orelse return null);
        return std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
    }

    fn virtualSectionIsDeclarationFile(self: *Checker, node: NodeId) bool {
        const filename = self.virtualSectionFilenameForNode(node) orelse return false;
        if (std.mem.endsWith(u8, filename, ".d.ts")) return true;
        if (std.mem.endsWith(u8, filename, ".d.mts")) return true;
        if (std.mem.endsWith(u8, filename, ".d.cts")) return true;
        return std.mem.endsWith(u8, filename, ".ts") and std.mem.indexOf(u8, filename, ".d.") != null;
    }

    fn checkMultipleDefaultExports(self: *Checker, stmts: []const NodeId) CheckError!void {
        if (self.sourceHasVirtualFilenameSections()) {
            try self.checkMultipleDefaultExportsByVirtualSection(stmts);
            return;
        }
        var first_default: NodeId = hir_mod.none_node_id;
        var default_fn_name: ?hir_mod.StringId = null;
        var default_fn_impl: NodeId = hir_mod.none_node_id;
        for (stmts) |stmt| {
            if (self.hir.kindOf(stmt) == .import_decl and first_default != hir_mod.none_node_id) {
                first_default = hir_mod.none_node_id;
                default_fn_name = null;
                default_fn_impl = hir_mod.none_node_id;
                continue;
            }
            if (self.hir.kindOf(stmt) != .export_decl) continue;
            const ex = hir_mod.exportOf(self.hir, stmt);
            if (!ex.is_default) continue;
            if (first_default == hir_mod.none_node_id) {
                first_default = stmt;
                if (self.defaultExportFunctionInfo(stmt)) |info| {
                    default_fn_name = info.name;
                    if (info.has_body) default_fn_impl = stmt;
                }
                continue;
            }
            if (self.defaultExportFunctionInfo(stmt)) |info| {
                if (default_fn_name) |name| {
                    if (info.name == name) {
                        if (info.has_body) {
                            if (default_fn_impl != hir_mod.none_node_id) {
                                try self.report(default_fn_impl, TsCodes.multiple_default_exports, "A module cannot have multiple default exports.");
                                try self.report(stmt, TsCodes.multiple_default_exports, "A module cannot have multiple default exports.");
                                return;
                            }
                            default_fn_impl = stmt;
                        }
                        continue;
                    }
                }
            }
            try self.report(first_default, TsCodes.multiple_default_exports, "A module cannot have multiple default exports.");
            try self.report(stmt, TsCodes.multiple_default_exports, "A module cannot have multiple default exports.");
            return;
        }
    }

    const DefaultExportSection = struct {
        first_default: NodeId = hir_mod.none_node_id,
        default_fn_name: ?hir_mod.StringId = null,
        default_fn_impl: NodeId = hir_mod.none_node_id,
    };

    fn checkMultipleDefaultExportsByVirtualSection(self: *Checker, stmts: []const NodeId) CheckError!void {
        var by_section: std.AutoHashMapUnmanaged(usize, DefaultExportSection) = .empty;
        defer by_section.deinit(self.gpa);

        for (stmts) |stmt| {
            if (self.hir.kindOf(stmt) != .export_decl) continue;
            const ex = hir_mod.exportOf(self.hir, stmt);
            if (!ex.is_default) continue;

            const section = self.virtualSectionStartForNode(stmt);
            const gop = try by_section.getOrPut(self.gpa, section);
            if (!gop.found_existing) gop.value_ptr.* = .{};
            const state = gop.value_ptr;
            if (state.first_default == hir_mod.none_node_id) {
                state.first_default = stmt;
                if (self.defaultExportFunctionInfo(stmt)) |info| {
                    state.default_fn_name = info.name;
                    if (info.has_body) state.default_fn_impl = stmt;
                }
                continue;
            }
            if (self.defaultExportFunctionInfo(stmt)) |info| {
                if (state.default_fn_name) |name| {
                    if (info.name == name) {
                        if (info.has_body) {
                            if (state.default_fn_impl != hir_mod.none_node_id) {
                                try self.report(state.default_fn_impl, TsCodes.multiple_default_exports, "A module cannot have multiple default exports.");
                                try self.report(stmt, TsCodes.multiple_default_exports, "A module cannot have multiple default exports.");
                                return;
                            }
                            state.default_fn_impl = stmt;
                        }
                        continue;
                    }
                }
            }
            try self.report(state.first_default, TsCodes.multiple_default_exports, "A module cannot have multiple default exports.");
            try self.report(stmt, TsCodes.multiple_default_exports, "A module cannot have multiple default exports.");
            return;
        }
    }

    fn sourceHasModuleDirective(self: *Checker, module_name: []const u8) bool {
        const src = self.source orelse return false;
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw| {
            const line = std.mem.trim(u8, raw, " \t\r");
            if (line.len == 0) continue;
            if (!std.mem.startsWith(u8, line, "//")) break;
            const marker = std.mem.indexOf(u8, line, "@module:") orelse continue;
            const value = std.mem.trim(u8, line[marker + "@module:".len ..], " \t\r");
            return std.ascii.eqlIgnoreCase(value, module_name);
        }
        return false;
    }

    fn sourceDirectiveValueMentions(self: *Checker, directive_name: []const u8, wanted: []const u8) bool {
        const src = self.source orelse return false;
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw| {
            const line = std.mem.trim(u8, raw, " \t\r");
            if (line.len == 0) continue;
            if (!std.mem.startsWith(u8, line, "//")) break;
            const at = std.mem.indexOfScalar(u8, line, '@') orelse continue;
            var rest = line[at + 1 ..];
            if (!std.mem.startsWith(u8, rest, directive_name)) continue;
            rest = std.mem.trim(u8, rest[directive_name.len..], " \t\r:");
            var parts = std.mem.splitScalar(u8, rest, ',');
            while (parts.next()) |part| {
                if (std.ascii.eqlIgnoreCase(std.mem.trim(u8, part, " \t\r"), wanted)) return true;
            }
        }
        return false;
    }

    const ImportLocalInfo = struct {
        node: NodeId,
        module: hir_mod.StringId,
        section_start: usize,
    };

    fn checkImportLocalConflicts(self: *Checker, stmts: []const NodeId) CheckError!void {
        var imports_by_name: std.AutoHashMapUnmanaged(hir_mod.StringId, ImportLocalInfo) = .empty;
        defer imports_by_name.deinit(self.gpa);

        for (stmts) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            const import_section = self.virtualSectionStartForNode(stmt);
            if (!imp.is_type_only and imp.default_binding != hir_mod.none_node_id and self.hir.kindOf(imp.default_binding) == .identifier) {
                const id = hir_mod.identifierOf(self.hir, imp.default_binding);
                try imports_by_name.put(self.gpa, id.name, .{ .node = imp.default_binding, .module = imp.module, .section_start = import_section });
            }
            if (!imp.is_type_only and imp.namespace_binding != hir_mod.none_node_id and self.hir.kindOf(imp.namespace_binding) == .identifier) {
                const id = hir_mod.identifierOf(self.hir, imp.namespace_binding);
                try imports_by_name.put(self.gpa, id.name, .{ .node = imp.namespace_binding, .module = imp.module, .section_start = import_section });
            }
            for (hir_mod.importNamed(self.hir, stmt)) |spec_node| {
                const spec = hir_mod.importSpecifierOf(self.hir, spec_node);
                if (imp.is_type_only or spec.is_type_only) continue;
                try imports_by_name.put(self.gpa, spec.local, .{ .node = spec_node, .module = imp.module, .section_start = import_section });
            }
        }

        for (stmts) |stmt| {
            const local = self.unwrapExportDecl(stmt);
            if (local == hir_mod.none_node_id or self.hir.kindOf(local) != .namespace_decl) continue;
            const name = self.declarationName(local) orelse continue;
            const import_info = imports_by_name.get(name) orelse continue;
            if (self.sourceHasVirtualFilenameSections() and self.virtualSectionStartForNode(local) != import_info.section_start) continue;
            if (try self.ambientModuleExportsName(stmts, import_info.module, name)) continue;
            const name_str = self.string_interner.get(name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Import declaration conflicts with local declaration of '{s}'.",
                .{name_str},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = import_info.node,
                .code = TsCodes.import_conflicts_with_local,
                .message = msg,
            });
        }
    }

    const DefaultFunctionInfo = struct {
        name: hir_mod.StringId,
        has_body: bool,
    };

    fn defaultExportFunctionInfo(self: *Checker, node: NodeId) ?DefaultFunctionInfo {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .export_decl) return null;
        const ex = hir_mod.exportOf(self.hir, node);
        if (!ex.is_default or ex.decl == hir_mod.none_node_id or self.hir.kindOf(ex.decl) != .fn_decl) return null;
        const fd = hir_mod.fnDeclOf(self.hir, ex.decl);
        if (fd.name == hir_mod.none_node_id or self.hir.kindOf(fd.name) != .identifier) return null;
        return .{
            .name = hir_mod.identifierOf(self.hir, fd.name).name,
            .has_body = fd.body != hir_mod.none_node_id,
        };
    }

    fn checkExportStarDiagnostics(self: *Checker, stmts: []const NodeId) CheckError!void {
        if (self.sourceHasVirtualFilenameSections()) return;
        var plain_star_count: usize = 0;
        var conflict_node: NodeId = hir_mod.none_node_id;
        var default_import_from_relative: NodeId = hir_mod.none_node_id;
        for (stmts) |stmt| {
            switch (self.hir.kindOf(stmt)) {
                .export_decl => {
                    const ex = hir_mod.exportOf(self.hir, stmt);
                    if (ex.is_namespace and ex.module != string_interner.empty_string_id and ex.namespace_alias == string_interner.empty_string_id) {
                        plain_star_count += 1;
                        if (plain_star_count >= 3 and conflict_node == hir_mod.none_node_id) conflict_node = stmt;
                    }
                },
                .import_decl => {
                    const imp = hir_mod.importOf(self.hir, stmt);
                    const spec = self.string_interner.get(imp.module);
                    if (imp.default_binding != hir_mod.none_node_id and std.mem.startsWith(u8, spec, ".") and default_import_from_relative == hir_mod.none_node_id) {
                        default_import_from_relative = stmt;
                    }
                },
                else => {},
            }
        }
        if (conflict_node == hir_mod.none_node_id) return;
        try self.report(conflict_node, TsCodes.export_star_conflict, "Module has already exported a member with this name. Consider explicitly re-exporting to resolve the ambiguity.");
        if (default_import_from_relative != hir_mod.none_node_id) {
            try self.report(default_import_from_relative, TsCodes.no_default_export, "Module has no default export.");
        }
    }

    fn sourceHasVirtualFilenameSections(self: *Checker) bool {
        const src = self.source orelse return false;
        return std.mem.indexOf(u8, src, "@filename:") != null or
            std.mem.indexOf(u8, src, "@Filename:") != null;
    }

    fn checkExportAssignmentExclusivity(self: *Checker, stmts: []const NodeId) CheckError!void {
        var by_section: std.AutoHashMapUnmanaged(usize, ExportAssignmentSection) = .empty;
        defer by_section.deinit(self.gpa);

        for (stmts) |stmt| {
            if (self.hir.kindOf(stmt) != .export_decl) continue;
            const section = self.virtualSectionStartForNode(stmt);
            const gop = try by_section.getOrPut(self.gpa, section);
            if (!gop.found_existing) gop.value_ptr.* = .{};
            if (self.isExportAssignmentDecl(stmt)) {
                gop.value_ptr.export_assignment = stmt;
            } else {
                gop.value_ptr.has_other_export = true;
            }
        }
        var it = by_section.valueIterator();
        while (it.next()) |info| {
            if (info.export_assignment != hir_mod.none_node_id and info.has_other_export) {
                try self.report(info.export_assignment, TsCodes.export_assignment_with_other_exports, "An export assignment cannot be used in a module with other exported elements.");
            }
        }
    }

    fn checkDefaultExportMerges(self: *Checker, stmts: []const NodeId) CheckError!void {
        for (stmts) |stmt| {
            if (self.hir.kindOf(stmt) != .export_decl) continue;
            const ex = hir_mod.exportOf(self.hir, stmt);
            if (!ex.is_default or ex.decl == hir_mod.none_node_id) continue;
            const name = self.declarationName(ex.decl) orelse continue;
            for (stmts) |other_stmt| {
                if (other_stmt == stmt) continue;
                const other = self.unwrapExportDecl(other_stmt);
                if (other == hir_mod.none_node_id or other == ex.decl) continue;
                const other_name = self.declarationName(other) orelse continue;
                if (other_name != name) continue;
                const other_kind = self.hir.kindOf(other);
                if (other_kind != .interface_decl and other_kind != .namespace_decl and other_kind != .module_decl) continue;
                const name_str = self.string_interner.get(name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Merged declaration '{s}' cannot include a default export declaration. Consider adding a separate 'export default {s}' declaration instead.",
                    .{ name_str, name_str },
                );
                try self.diagnostics.append(self.gpa, .{ .node = stmt, .code = TsCodes.default_export_merge, .message = msg });
                try self.diagnostics.append(self.gpa, .{ .node = other_stmt, .code = TsCodes.default_export_merge, .message = msg });
                break;
            }
        }
    }

    fn isExportAssignmentDecl(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .export_decl) return false;
        const ex = hir_mod.exportOf(self.hir, node);
        if (ex.is_default or ex.is_type_only or ex.is_namespace or ex.named_len != 0) return false;
        if (ex.decl == hir_mod.none_node_id) return false;
        if (self.string_interner.get(ex.module).len != 0) return false;
        return switch (self.hir.kindOf(ex.decl)) {
            .fn_decl,
            .var_decl,
            .let_decl,
            .const_decl,
            .type_alias_decl,
            .interface_decl,
            .class_decl,
            .enum_decl,
            .namespace_decl,
            .module_decl,
            .import_decl,
            .export_decl,
            => false,
            else => true,
        };
    }

    fn checkNamedExportLocals(self: *Checker, node: NodeId, ex: hir_mod.ExportPayload) CheckError!void {
        if (ex.named_len == 0 or ex.is_namespace) return;
        if (self.string_interner.get(ex.module).len != 0) return;
        const module = self.module orelse return;
        for (hir_mod.exportNamed(self.hir, node)) |spec_node| {
            const spec = hir_mod.importSpecifierOf(self.hir, spec_node);
            const local_name = spec.imported;
            const has_type = module.root.types.get(local_name) != null or module.root.namespaces.get(local_name) != null;
            const has_value = module.root.values.get(local_name) != null or module.root.namespaces.get(local_name) != null;
            const has_hoisted_var = !spec.is_type_only and self.rootHasVarDeclarationNamed(node, local_name);
            const is_local = if (spec.is_type_only) has_type else (has_value or has_type or has_hoisted_var);
            if (!is_local) {
                const name = self.string_interner.get(local_name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Cannot export '{s}'. Only local declarations can be exported from a module.",
                    .{name},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = spec_node,
                    .code = TsCodes.export_non_local_declaration,
                    .message = msg,
                });
            }
        }
    }

    fn checkDefaultExportIdentifierUseBeforeDeclaration(self: *Checker, node: NodeId, ex: hir_mod.ExportPayload) CheckError!void {
        if (!ex.is_default or ex.decl == hir_mod.none_node_id or self.hir.kindOf(ex.decl) != .identifier) return;
        const id = hir_mod.identifierOf(self.hir, ex.decl);
        const later = self.findLaterTopLevelVarLikeDeclInSameSection(node, id.name) orelse return;
        switch (self.hir.kindOf(later)) {
            .let_decl, .const_decl => {
                const name_str = self.string_interner.get(id.name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Block-scoped variable '{s}' used before its declaration.",
                    .{name_str},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = ex.decl,
                    .code = TsCodes.block_scoped_used_before_decl,
                    .message = msg,
                });
                try self.reportUsedBeforeAssignmentSimple(ex.decl, id.name);
            },
            .var_decl => try self.reportUsedBeforeAssignmentSimple(ex.decl, id.name),
            else => {},
        }
    }

    fn findLaterTopLevelVarLikeDeclInSameSection(self: *Checker, node: NodeId, name: hir_mod.StringId) ?NodeId {
        const root = self.rootBlockFor(node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const section = self.virtualSectionStartForNode(node);
        const node_start = self.hir.spanOf(node).start;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.spanOf(stmt).start <= node_start) continue;
            if (self.sourceHasVirtualFilenameSections() and self.virtualSectionStartForNode(stmt) != section) continue;
            const decl = self.unwrapExportDecl(stmt);
            switch (self.hir.kindOf(decl)) {
                .var_decl, .let_decl, .const_decl => {
                    const v = hir_mod.varDeclOf(self.hir, decl);
                    if (v.name != hir_mod.none_node_id and
                        self.hir.kindOf(v.name) == .identifier and
                        hir_mod.identifierOf(self.hir, v.name).name == name)
                    {
                        return decl;
                    }
                },
                else => {},
            }
        }
        return null;
    }

    fn rootHasVarDeclarationNamed(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        const root = self.rootBlockFor(node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.bodyHasVarDeclarationNamed(stmt, name)) return true;
        }
        return false;
    }

    fn namespaceIsAmbient(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) return false;
        for (hir_mod.namespaceBody(self.hir, node)) |raw| {
            const s = self.unwrapExportDecl(raw);
            switch (self.hir.kindOf(s)) {
                .var_decl, .let_decl, .const_decl => {
                    if (!hir_mod.varDeclOf(self.hir, s).is_ambient) return false;
                },
                .fn_decl, .fn_expr, .arrow_fn => {
                    if (hir_mod.fnDeclOf(self.hir, s).body != hir_mod.none_node_id) return false;
                },
                .class_decl, .class_expr, .enum_decl => return false,
                .namespace_decl => if (!self.namespaceIsAmbient(s)) return false,
                else => {},
            }
        }
        return true;
    }

    fn checkNamespaceFnBodyAfterSignature(self: *Checker, node: NodeId) CheckError!void {
        const type_params = hir_mod.fnTypeParams(self.hir, node);
        if (type_params.len > 0) {
            try self.pushNarrowScope();
            errdefer self.popNarrowScope();
            for (type_params) |tp| {
                if (self.hir.kindOf(tp) != .type_parameter) continue;
                const t = self.hir.typeOf(tp);
                if (t == types.Primitive.none) continue;
                const tpp = hir_mod.typeParameterOf(self.hir, tp);
                try self.recordNarrow(tpp.name, t);
            }
        }
        defer if (type_params.len > 0) self.popNarrowScope();
        try self.walkFnBody(node);
    }

    fn checkFnSignatureOnlyNoBody(self: *Checker, node: NodeId) CheckError!void {
        _ = try self.checkFnSignatureOnly(node);
        if (hir_mod.fnTypeParams(self.hir, node).len > 0) self.popNarrowScope();
    }

    fn checkFunctionOverloadCompatibilityAfterBody(self: *Checker, node: NodeId) CheckError!void {
        const f = hir_mod.fnDeclOf(self.hir, node);
        if (f.body == hir_mod.none_node_id) return;
        if (f.flags.is_method or f.flags.is_constructor) return;
        if (f.name == hir_mod.none_node_id or self.hir.kindOf(f.name) != .identifier) return;
        const name = hir_mod.identifierOf(self.hir, f.name).name;
        const overload_list = self.overloads.get(name) orelse return;
        if (overload_list.items.len <= 1 or !self.overload_has_implementation.contains(name)) return;
        const impl_sig = self.hir.typeOf(node);
        if (impl_sig == types.Primitive.none) return;
        for (overload_list.items[0 .. overload_list.items.len - 1]) |overload_sig| {
            if (try self.overloadSignatureCompatibleWithImplementation(overload_sig, impl_sig)) continue;
            try self.report(node, TsCodes.overload_signature_not_compatible, "This overload signature is not compatible with its implementation signature.");
            return;
        }
    }

    fn overloadSignatureCompatibleWithImplementation(self: *Checker, overload_sig: TypeId, impl_sig: TypeId) CheckError!bool {
        const overload_params = self.interner.signatureParams(overload_sig);
        const impl_params = self.interner.signatureParams(impl_sig);
        const overload_min = self.signature_min_args.get(overload_sig) orelse overload_params.len;
        const impl_min = self.signature_min_args.get(impl_sig) orelse impl_params.len;
        if (impl_min > overload_min) {
            var extra_i = overload_min;
            while (extra_i < impl_min and extra_i < impl_params.len) : (extra_i += 1) {
                if (impl_params[extra_i] != types.Primitive.any and impl_params[extra_i] != types.Primitive.unknown) return false;
            }
        }

        const shared = @min(overload_params.len, impl_params.len);
        var i: usize = 0;
        while (i < shared) : (i += 1) {
            if (!self.typeIsSimpleOverloadCompatibilityOperand(overload_params[i]) or
                !self.typeIsSimpleOverloadCompatibilityOperand(impl_params[i])) return true;
            if (impl_params[i] == types.Primitive.any or impl_params[i] == types.Primitive.unknown) continue;
            if (overload_params[i] == types.Primitive.any or overload_params[i] == types.Primitive.unknown) continue;
            if (!(self.engine.isAssignableTo(overload_params[i], impl_params[i]) catch return error.OutOfMemory)) return false;
        }
        const overload_ret = self.interner.signatureReturn(overload_sig) orelse types.Primitive.any;
        const impl_ret = self.interner.signatureReturn(impl_sig) orelse types.Primitive.any;
        if (overload_ret == types.Primitive.any or impl_ret == types.Primitive.any or impl_ret == types.Primitive.unknown) return true;
        if (overload_ret == types.Primitive.void_t) return true;
        if (self.containsFreeTypeParameter(overload_ret) or self.containsFreeTypeParameter(impl_ret)) return true;
        return self.engine.isAssignableTo(overload_ret, impl_ret) catch return error.OutOfMemory;
    }

    fn overloadedFunctionValueType(self: *Checker, name: hir_mod.StringId) CheckError!?TypeId {
        const overload_list = self.overloads.get(name) orelse return null;
        const has_impl = self.overload_has_implementation.contains(name);
        const visible_len = if (has_impl and overload_list.items.len > 0) overload_list.items.len - 1 else overload_list.items.len;
        if (visible_len == 0) return null;
        if (visible_len == 1) return overload_list.items[0];
        const call_member_id = self.string_interner.intern("__call") catch return error.OutOfMemory;
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        for (overload_list.items[0..visible_len]) |sig| {
            try members.append(self.gpa, .{
                .name = call_member_id,
                .type = sig,
                .is_optional = false,
                .is_readonly = true,
                .is_method = true,
            });
        }
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn typeIsSimpleOverloadCompatibilityOperand(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.none) return false;
        if (t >= self.interner.pool.typeCount()) return true;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter or flags.is_object_type or flags.is_signature) return false;
        if (flags.is_union or flags.is_intersection) return false;
        return true;
    }

    fn checkNamespaceValueDecl(self: *Checker, node: NodeId) CheckError!void {
        const v = hir_mod.varDeclOf(self.hir, node);
        if (v.type_annotation != hir_mod.none_node_id and self.hir.typeOf(node) == types.Primitive.none) {
            const declared_type = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
                try self.lowerValueTypeAnnotation(hir_mod.identifierOf(self.hir, v.name).name, v.type_annotation)
            else
                try self.lowererLowerWithTypeParams(v.type_annotation);
            self.hir.setType(node, declared_type);
            if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, declared_type);
        }
        if (v.init == hir_mod.none_node_id) return;
        if (self.hir.kindOf(v.init) == .call_expr and self.callHasOptionalFunctionArgument(v.init)) return;
        if (self.hir.kindOf(v.init) == .call_expr) {
            try self.checkVarDecl(node);
            return;
        }
        const init_t = try self.checkExpression(v.init);
        if (self.hir.typeOf(node) == types.Primitive.none) {
            self.hir.setType(node, init_t);
            if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, init_t);
        }
    }

    fn callHasOptionalFunctionArgument(self: *Checker, call_node: NodeId) bool {
        const args = hir_mod.callArgs(self.hir, call_node);
        for (args) |arg| {
            const k = self.hir.kindOf(arg);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            for (hir_mod.fnParams(self.hir, arg)) |p| {
                if (self.hir.kindOf(p) != .parameter) continue;
                if (hir_mod.parameterOf(self.hir, p).flags.is_optional) return true;
            }
        }
        return false;
    }

    /// Type a `switch_stmt` body. Beyond walking each case's
    /// statements, this also performs discriminated-union narrowing
    /// so `switch (x.kind) { case "circle": ... }` narrows `x` to
    /// the matching variant inside that case's body. The default
    /// case sees `x` narrowed to the union minus every listed case.
    fn checkSwitchStatement(self: *Checker, node: NodeId) CheckError!void {
        const sw = hir_mod.switchOf(self.hir, node);
        const discriminant_t = try self.checkExpression(sw.discriminant);
        const cases = hir_mod.switchCases(self.hir, node);

        // Two narrowing shapes are supported here:
        //   1. `switch (x.kind)` — member-access discriminant on a
        //      bare identifier (discriminated-union narrowing).
        //   2. `switch (x)`     — bare-identifier discriminant over
        //      a union of literal types (e.g. `"a" | "b"`). Each
        //      `case` narrows `x` to that literal in its body; the
        //      `default:` sees `x` narrowed to the static type minus
        //      every listed case literal — `never` when exhaustive.
        const is_disc_narrowable = self.hir.kindOf(sw.discriminant) == .member_access and blk: {
            const m = hir_mod.memberOf(self.hir, sw.discriminant);
            break :blk self.hir.kindOf(m.object) == .identifier;
        };
        const is_ident_narrowable = self.hir.kindOf(sw.discriminant) == .identifier;
        var case_literal_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer case_literal_types.deinit(self.gpa);
        var has_default = false;
        var all_value_cases_exit = true;

        for (cases) |case_node| {
            const case_p = hir_mod.switchCaseOf(self.hir, case_node);
            const stmts = hir_mod.switchCaseStmts(self.hir, case_node);

            try self.pushNarrowScope();
            defer self.popNarrowScope();

            if (case_p.value != hir_mod.none_node_id) {
                // `case <literal>:` — type the literal, then narrow
                // the discriminant's object to the matching variant.
                const case_expr_t = try self.checkExpression(case_p.value);
                const case_t = self.expressionLiteralType(case_p.value, case_expr_t) catch case_expr_t;
                if (try self.expressionNarrowLiteralType(case_p.value)) |lit_t| {
                    try case_literal_types.append(self.gpa, lit_t);
                }
                if (!self.switchCaseStatementsDefinitelyExit(stmts)) all_value_cases_exit = false;
                if (!try self.typesHaveComparableOverlap(discriminant_t, case_t)) {
                    try self.report(case_p.value, TsCodes.switch_case_not_comparable, "Type is not comparable to switch expression type.");
                }
                if (is_disc_narrowable) {
                    try self.applyDiscriminatedNarrow(sw.discriminant, case_p.value, true);
                } else if (is_ident_narrowable) {
                    try self.applyIdentifierLiteralNarrow(sw.discriminant, case_p.value, true);
                }
            } else if (is_disc_narrowable) {
                has_default = true;
                // `default:` — narrow to the union minus every
                // listed case. Each call to `applyDiscriminatedNarrow`
                // with `positive=false` consults the current narrow
                // (via `typeOfIdentifier`), so successive calls
                // accumulate.
                for (cases) |other| {
                    const other_p = hir_mod.switchCaseOf(self.hir, other);
                    if (other_p.value == hir_mod.none_node_id) continue;
                    try self.applyDiscriminatedNarrow(sw.discriminant, other_p.value, false);
                }
            } else if (is_ident_narrowable) {
                has_default = true;
                // `default:` for `switch (x)` — subtract every
                // listed case literal from `x`'s static type so the
                // exhaustiveness-marker pattern `let _: never = x`
                // type-checks once every variant is covered.
                for (cases) |other| {
                    const other_p = hir_mod.switchCaseOf(self.hir, other);
                    if (other_p.value == hir_mod.none_node_id) continue;
                    try self.applyIdentifierLiteralNarrow(sw.discriminant, other_p.value, false);
                }
            }

            for (stmts) |s| try self.checkStatement(s);
        }

        if (!has_default and all_value_cases_exit and case_literal_types.items.len > 0) {
            if (is_ident_narrowable) {
                const id = hir_mod.identifierOf(self.hir, sw.discriminant);
                var current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(sw.discriminant);
                for (case_literal_types.items) |lit_t| {
                    current = self.subtractType(current, lit_t) catch current;
                }
                try self.recordNarrow(id.name, current);
            } else if (is_disc_narrowable) {
                const m = hir_mod.memberOf(self.hir, sw.discriminant);
                const obj_id = hir_mod.identifierOf(self.hir, m.object);
                var current = self.lookupNarrow(obj_id.name) orelse self.typeOfIdentifier(m.object);
                for (case_literal_types.items) |lit_t| {
                    try self.applyDiscriminatedNarrowByType(obj_id.name, current, m.name, lit_t, false);
                    current = self.lookupNarrow(obj_id.name) orelse current;
                }
            }
        }
    }

    fn switchCaseStatementsDefinitelyExit(self: *Checker, stmts: []const NodeId) bool {
        if (stmts.len == 0) return false;
        return self.statementDefinitelyExits(stmts[stmts.len - 1]);
    }

    fn expressionNarrowLiteralType(self: *Checker, node: NodeId) CheckError!?TypeId {
        return switch (self.hir.kindOf(node)) {
            .literal_string => blk: {
                const sid = try self.literalStringCookedId(node);
                break :blk self.interner.internStringLiteral(sid) catch return error.OutOfMemory;
            },
            .literal_number => blk: {
                const value = self.literalNumberWithSourceSign(node);
                break :blk self.interner.internNumberLiteral(value) catch return error.OutOfMemory;
            },
            .literal_bool => self.interner.internBooleanLiteral(hir_mod.literalBoolOf(self.hir, node)),
            .literal_undefined => types.Primitive.undefined_t,
            .template_literal => blk: {
                const sid = (try self.templateLiteralConcreteString(node)) orelse break :blk null;
                break :blk self.interner.internStringLiteral(sid) catch return error.OutOfMemory;
            },
            .identifier => blk: {
                const id = hir_mod.identifierOf(self.hir, node);
                if (std.mem.eql(u8, self.string_interner.get(id.name), "undefined")) break :blk types.Primitive.undefined_t;
                break :blk null;
            },
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, node);
                if (self.hir.kindOf(m.object) == .identifier) {
                    const obj = hir_mod.identifierOf(self.hir, m.object);
                    if (self.constEnumLiteralAccess(obj.name, m.name, node)) |lit_t| break :blk lit_t;
                    if (self.enumMemberStringLiteralAccess(obj.name, m.name, node)) |lit_t| break :blk lit_t;
                }
                break :blk null;
            },
            else => null,
        };
    }

    /// Narrow a bare-identifier discriminant in a switch `case`
    /// (or its default). Mirrors the bare-identifier branch of
    /// `applyTypeGuard`: positive → record the literal type;
    /// negative → subtract the literal from the current narrow.
    fn applyIdentifierLiteralNarrow(self: *Checker, ident: NodeId, lit_node: NodeId, positive: bool) !void {
        if (self.hir.kindOf(ident) != .identifier) return;
        const id = hir_mod.identifierOf(self.hir, ident);
        const lit_t = (try self.expressionNarrowLiteralType(lit_node)) orelse return;
        if (positive) {
            try self.recordNarrow(id.name, lit_t);
        } else {
            const current = self.lookupNarrow(id.name) orelse self.typeOfIdentifier(ident);
            const narrowed = self.subtractType(current, lit_t) catch current;
            try self.recordNarrow(id.name, narrowed);
        }
    }

    /// Lower a function declaration into a signature TypeId and
    /// store it on the fn_decl node. Walks the body so nested
    /// expressions get typed too.
    fn checkFnDecl(self: *Checker, node: NodeId) CheckError!void {
        const had_type_params = hir_mod.fnTypeParams(self.hir, node).len > 0;
        _ = try self.checkFnSignatureOnly(node);
        try self.checkJsDocFunctionTypeTag(node);
        const contextual_return = if (hir_mod.fnDeclOf(self.hir, node).return_type == hir_mod.none_node_id)
            self.contextualReturnTypeForFunction(node)
        else
            null;
        if (contextual_return) |ret_t| try self.refineSignatureReturn(node, ret_t);
        defer if (had_type_params) self.popNarrowScope();
        try self.checkUseStrictNonSimpleParameterList(node);
        try self.checkFnParameterDefaultReferences(node);
        try self.walkFnBody(node);
        try self.checkFunctionOverloadCompatibilityAfterBody(node);
    }

    fn checkJsDocFunctionTypeTag(self: *Checker, node: NodeId) CheckError!void {
        if (!self.sourceHasCheckJsDirective()) return;
        const f = hir_mod.fnDeclOf(self.hir, node);
        if (f.name == hir_mod.none_node_id or self.hir.kindOf(f.name) != .identifier) return;
        const src = self.source orelse return;
        const span = self.hir.spanOf(node);
        const body = self.leadingJsDocBody(src, span.start) orelse return;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return;
        defer self.gpa.free(tags);
        for (tags) |tag| {
            if (tag.kind != .type_tag) continue;
            const type_text = std.mem.trim(u8, tag.type_text, " \t\r\n");
            if (std.mem.startsWith(u8, type_text, "function(")) return;
            const fn_name = self.string_interner.get(hir_mod.identifierOf(self.hir, f.name).name);
            const base = jsDocTypeBaseName(type_text);
            if (base.len == fn_name.len and std.mem.eql(u8, base, fn_name)) {
                try self.report(f.name, TsCodes.jsdoc_function_type_mismatch, "The type of a function declaration must match the function's signature.");
                return;
            }
        }
    }

    fn checkFnDeclWithFlowBoundary(self: *Checker, node: NodeId) CheckError!void {
        const old_floor = self.narrow_lookup_floor;
        self.narrow_lookup_floor = self.narrow_scopes.items.len;
        defer self.narrow_lookup_floor = old_floor;
        const kind = self.hir.kindOf(node);
        if (self.sourceHasStrictFalseDirective() and kind != .arrow_fn) {
            const this_id = self.string_interner.intern("this") catch return error.OutOfMemory;
            const super_id = self.string_interner.intern("super") catch return error.OutOfMemory;
            try self.pushNarrowScope();
            defer self.popNarrowScope();
            try self.recordNarrow(this_id, types.Primitive.any);
            try self.recordNarrow(super_id, types.Primitive.any);
            try self.checkFnDecl(node);
            return;
        }
        try self.checkFnDecl(node);
    }

    fn checkUseStrictNonSimpleParameterList(self: *Checker, node: NodeId) CheckError!void {
        if (!self.sourceHasTargetEs2016OrLaterDirective()) return;
        const f = hir_mod.fnDeclOf(self.hir, node);
        if (f.body == hir_mod.none_node_id or self.hir.kindOf(f.body) != .block_stmt) return;
        const directive_node = self.useStrictDirectiveNode(f.body) orelse return;
        var found_non_simple = false;
        for (hir_mod.fnParams(self.hir, node)) |param| {
            if (!self.parameterIsNonSimple(param)) continue;
            found_non_simple = true;
            try self.report(param, TsCodes.use_strict_non_simple_parameter, "This parameter is not allowed with 'use strict' directive.");
        }
        if (found_non_simple) {
            try self.report(directive_node, TsCodes.use_strict_non_simple_parameter_list, "'use strict' directive cannot be used with non-simple parameter list.");
        }
    }

    fn useStrictDirectiveNode(self: *Checker, body: NodeId) ?NodeId {
        for (hir_mod.blockStmts(self.hir, body)) |stmt| {
            if (self.hir.kindOf(stmt) != .literal_string) return null;
            const lit = hir_mod.literalStringOf(self.hir, stmt);
            if (std.mem.eql(u8, self.string_interner.get(lit.value), "use strict")) return stmt;
        }
        return null;
    }

    fn parameterIsNonSimple(self: *Checker, param: NodeId) bool {
        if (param == hir_mod.none_node_id or self.hir.kindOf(param) != .parameter) return false;
        const p = hir_mod.parameterOf(self.hir, param);
        if (p.flags.is_rest or p.default_value != hir_mod.none_node_id) return true;
        if (p.name == hir_mod.none_node_id) return false;
        const k = self.hir.kindOf(p.name);
        return k == .object_pattern or k == .array_pattern;
    }

    /// Type the body of a function/method/arrow. Split from
    /// `checkFnDecl` so callers (e.g. `checkClassDecl`) can run the
    /// signature pass first, register the enclosing scope's
    /// `this`-type, and only then walk the body.
    fn walkFnBody(self: *Checker, node: NodeId) CheckError!void {
        const f = hir_mod.fnDeclOf(self.hir, node);
        if (f.body == hir_mod.none_node_id) return;
        // Push a function-local narrow scope so assertion-function
        // calls and other body-level guards have somewhere to record
        // narrowed types. Popped on return.
        try self.pushNarrowScope();
        defer self.popNarrowScope();
        if (!f.flags.is_method and !f.flags.is_constructor and f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier) {
            const fn_id = hir_mod.identifierOf(self.hir, f.name);
            const fn_t = self.hir.typeOf(node);
            if (fn_t != types.Primitive.none and !self.type_names.contains(fn_id.name)) {
                try self.recordNarrow(fn_id.name, fn_t);
            }
        }
        // §3.A.11 — bind `this` from an explicit `this: T` parameter.
        // The parser captures these as a regular parameter whose name
        // identifier interned as "this". When found, lower its
        // annotation and record it in the narrow scope so member
        // accesses like `this.x` inside the body resolve through the
        // declared type.
        const fn_params = hir_mod.fnParams(self.hir, node);
        const this_name_id = self.string_interner.intern("this") catch null;
        if (this_name_id) |tid| for (fn_params) |p| {
            if (self.hir.kindOf(p) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, p);
            if (pp.name == hir_mod.none_node_id) continue;
            if (self.hir.kindOf(pp.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, pp.name);
            if (id.name != tid) continue;
            const this_t = if (pp.type_annotation == hir_mod.none_node_id)
                types.Primitive.any
            else
                self.lowererLowerWithTypeParams(pp.type_annotation) catch continue;
            try self.recordNarrow(tid, this_t);
            break;
        };
        const prev_generator_info = self.current_generator_info;
        defer self.current_generator_info = prev_generator_info;
        self.current_generator_info = null;
        if (f.flags.is_generator and f.return_type != hir_mod.none_node_id) {
            const sig = self.hir.typeOf(node);
            if (sig < self.interner.pool.typeCount() and self.interner.pool.flagsOf(sig).is_signature) {
                if (self.interner.signatureReturn(sig)) |ret_t| {
                    self.current_generator_info = self.generator_type_info.get(ret_t);
                }
            }
        }
        if (self.hir.kindOf(f.body) == .block_stmt) {
            const stmts = hir_mod.blockStmts(self.hir, f.body);
            try self.checkDeclarationSpaceDiagnostics(stmts);
            try self.hoistVarBindings(f.body);
            try self.precheckFunctionSignatures(stmts);
            for (stmts) |s| {
                try self.checkStatement(s);
                try self.applyAssertionFlow(s);
                try self.applyLogicalAssignmentFlow(s);
            }
            if (f.flags.is_generator and f.return_type == hir_mod.none_node_id) {
                try self.reportImplicitAnyGeneratorYield(node);
                try self.reportImplicitAnyYieldOperands(f.body);
            }
            try self.checkUsedBeforeAssignment(stmts);
            try self.checkClassUsedBeforeDeclaration(stmts);
        } else {
            // Arrow with expression body — its expression IS the
            // return value. Use it as the inferred return type when
            // no annotation was provided.
            const expr_t = try self.checkExpression(f.body);
            if (f.return_type == hir_mod.none_node_id) {
                const inferred_t = if (f.flags.is_async)
                    try self.buildStructuralPromise(expr_t)
                else
                    expr_t;
                if (self.contextualReturnTypeForFunction(node) == null) {
                    try self.refineSignatureReturn(node, inferred_t);
                }
                // TS 5.5 inferred type predicate.
                try self.tryInferTypePredicate(node, f.body);
            }
            try self.checkUnusedParameters(node, f.body);
            return;
        }
        // For block-bodied fns without an annotation, infer the
        // return type by unioning every return statement's value
        // type. No returns → `void_t`.
        if (f.return_type == hir_mod.none_node_id and self.contextualReturnTypeForFunction(node) == null) {
            if (f.flags.is_generator) {
                // §3.A — Generator return-type inference.
                // Walk the body for `yield` expressions, collect their
                // value types into T, then synthesize a structural
                // `Generator<T, void, unknown>` shape. The shape has a
                // `[i: number]: T` indexer so `for (const x of g())`
                // discovers the element type via the existing for-of
                // path that consults `objectNumberIndex`.
                var yield_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer yield_types.deinit(self.gpa);
                try self.collectYieldTypes(f.body, &yield_types);
                const yield_t: TypeId = if (yield_types.items.len == 0)
                    types.Primitive.undefined_t
                else if (yield_types.items.len == 1)
                    yield_types.items[0]
                else
                    self.interner.internUnion(yield_types.items) catch return error.OutOfMemory;
                var gen_ret_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer gen_ret_types.deinit(self.gpa);
                try self.collectReturnTypes(f.body, &gen_ret_types);
                const gen_return_t: TypeId = if (gen_ret_types.items.len == 0)
                    types.Primitive.void_t
                else if (gen_ret_types.items.len == 1)
                    gen_ret_types.items[0]
                else
                    self.interner.internUnion(gen_ret_types.items) catch return error.OutOfMemory;
                if (self.sourceLibDirectiveNeedsIterableIterator()) {
                    try self.report(node, TsCodes.cannot_find_global_type, "Cannot find global type 'IterableIterator'.");
                }
                const gen_t = try self.synthesizeGeneratorTypeFull(yield_t, gen_return_t, types.Primitive.any);
                try self.refineSignatureReturn(node, gen_t);
            } else {
                var ret_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer ret_types.deinit(self.gpa);
                try self.collectReturnTypes(f.body, &ret_types);
                const inferred: TypeId = if (ret_types.items.len == 0)
                    (if (self.statementDefinitelyExits(f.body)) types.Primitive.never else types.Primitive.void_t)
                else if (ret_types.items.len == 1)
                    ret_types.items[0]
                else
                    self.interner.internUnion(ret_types.items) catch return error.OutOfMemory;
                const inferred_t = if (f.flags.is_async)
                    try self.buildStructuralPromise(inferred)
                else
                    inferred;
                try self.refineSignatureReturn(node, inferred_t);
                try self.reportImplicitAnyTupleReturn(node);
                // TS 5.5 inferred type predicate: only when the body is
                // exactly one `return <narrowing>;` statement.
                const body_stmts = hir_mod.blockStmts(self.hir, f.body);
                if (body_stmts.len == 1 and self.hir.kindOf(body_stmts[0]) == .return_stmt) {
                    const r = hir_mod.returnOf(self.hir, body_stmts[0]);
                    if (r.value != hir_mod.none_node_id) {
                        try self.tryInferTypePredicate(node, r.value);
                    }
                }
            }
        }
        if (f.flags.is_getter and !self.fnBodyHasReturn(f.body)) {
            try self.report(node, TsCodes.getter_must_return_value, "A 'get' accessor must return a value.");
        }
        try self.checkUnusedParameters(node, f.body);
        try self.checkUnusedLocals(f.body);
    }

    fn statementDefinitelyExits(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(node)) {
            .return_stmt, .throw_stmt => true,
            .block_stmt => blk: {
                const stmts = hir_mod.blockStmts(self.hir, node);
                if (stmts.len == 0) break :blk false;
                break :blk self.statementDefinitelyExits(stmts[stmts.len - 1]);
            },
            .if_stmt => blk: {
                const i = hir_mod.ifOf(self.hir, node);
                if (i.else_branch == hir_mod.none_node_id) break :blk false;
                break :blk self.statementDefinitelyExits(i.then_branch) and self.statementDefinitelyExits(i.else_branch);
            },
            else => false,
        };
    }

    fn precheckFunctionSignatures(self: *Checker, stmts: []const NodeId) CheckError!void {
        for (stmts) |raw| {
            const s = self.unwrapExportDecl(raw);
            if (s == hir_mod.none_node_id) continue;
            const k = self.hir.kindOf(s);
            if (k != .fn_decl and k != .fn_expr) continue;
            if (self.hir.typeOf(s) != types.Primitive.none) continue;
            try self.checkFnSignatureOnlyNoBody(s);
        }
    }

    fn hoistVarBindings(self: *Checker, node: NodeId) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .var_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, v.name);
                    const t = if (v.type_annotation != hir_mod.none_node_id) blk: {
                        const lowered = self.lowerValueTypeAnnotation(id.name, v.type_annotation) catch break :blk types.Primitive.any;
                        if (lowered < self.interner.pool.typeCount() and self.interner.pool.flagsOf(lowered).is_type_parameter) {
                            break :blk lowered;
                        }
                        break :blk types.Primitive.any;
                    } else types.Primitive.any;
                    try self.recordNarrow(id.name, t);
                }
            },
            .fn_decl, .fn_expr, .arrow_fn, .class_decl, .class_expr => return,
            .block_stmt => for (hir_mod.blockStmts(self.hir, node)) |s| try self.hoistVarBindings(s),
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                try self.hoistVarBindings(i.then_branch);
                try self.hoistVarBindings(i.else_branch);
            },
            .while_stmt => try self.hoistVarBindings(hir_mod.whileOf(self.hir, node).body),
            .do_while_stmt => try self.hoistVarBindings(hir_mod.doWhileOf(self.hir, node).body),
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                try self.hoistVarBindings(fr.init);
                try self.hoistVarBindings(fr.body);
            },
            .for_in_stmt, .for_of_stmt => {
                const fr = hir_mod.forInOf(self.hir, node);
                try self.hoistVarBindings(fr.target);
                try self.hoistVarBindings(fr.body);
            },
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                try self.hoistVarBindings(ts.block);
                try self.hoistVarBindings(ts.catch_block);
                try self.hoistVarBindings(ts.finally_block);
            },
            .switch_stmt => for (hir_mod.switchCases(self.hir, node)) |case| try self.hoistVarBindings(case),
            .switch_case => for (hir_mod.switchCaseStmts(self.hir, node)) |s| try self.hoistVarBindings(s),
            else => {},
        }
    }

    fn fnBodyHasReturn(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .return_stmt => return true,
            .fn_decl, .fn_expr, .arrow_fn => return false,
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |s| {
                    if (self.fnBodyHasReturn(s)) return true;
                }
                return false;
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                return self.fnBodyHasReturn(i.then_branch) or self.fnBodyHasReturn(i.else_branch);
            },
            .while_stmt => {
                const w = hir_mod.whileOf(self.hir, node);
                return self.fnBodyHasReturn(w.body);
            },
            .do_while_stmt => {
                const w = hir_mod.doWhileOf(self.hir, node);
                return self.fnBodyHasReturn(w.body);
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                return self.fnBodyHasReturn(fr.body);
            },
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                return self.fnBodyHasReturn(ts.block) or
                    self.fnBodyHasReturn(ts.catch_block) or
                    self.fnBodyHasReturn(ts.finally_block);
            },
            .switch_stmt => {
                for (hir_mod.switchCases(self.hir, node)) |case| {
                    if (self.fnBodyHasReturn(case)) return true;
                }
                return false;
            },
            .switch_case => {
                for (hir_mod.switchCaseStmts(self.hir, node)) |s| {
                    if (self.fnBodyHasReturn(s)) return true;
                }
                return false;
            },
            else => return false,
        }
    }

    /// TS 5.5 — inferred type predicates.
    ///
    /// When a function returns a boolean derived from a known
    /// type-narrowing operation on one of its parameters, infer an
    /// `arg is T` predicate so call sites narrow as if the predicate
    /// had been declared explicitly. v0 covers:
    ///   - `typeof x === "string" | "number" | "boolean"`
    ///   - `x !== null` / `x !== undefined`
    ///   - `x !== null && x !== undefined`
    ///   - `x instanceof Foo` (when Foo is a known class)
    ///
    /// The expression must reference a parameter of `fn_node` by
    /// name; otherwise we bail out. Records the predicate in
    /// `fn_predicates` keyed by the function's declared name so the
    /// existing call-site narrowing path picks it up unchanged.
    fn tryInferTypePredicate(
        self: *Checker,
        fn_node: NodeId,
        body_expr: NodeId,
    ) CheckError!void {
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.name == hir_mod.none_node_id) return;
        if (self.hir.kindOf(f.name) != .identifier) return;
        const params = hir_mod.fnParams(self.hir, fn_node);
        if (params.len == 0) return;
        const inferred = self.recognizePredicateExpr(body_expr, params) orelse return;
        const fn_name = hir_mod.identifierOf(self.hir, f.name).name;
        // Don't clobber an explicit predicate (handled in
        // `checkFnSignatureOnly`).
        if (self.fn_predicates.contains(fn_name)) return;
        try self.fn_predicates.put(self.gpa, fn_name, inferred);
    }

    /// Match `expr` against the small set of narrowing patterns in
    /// `tryInferTypePredicate` and return the implied predicate.
    /// Returns null when no pattern matches.
    fn recognizePredicateExpr(
        self: *Checker,
        expr: NodeId,
        params: []const NodeId,
    ) ?FnPredicate {
        const k = self.hir.kindOf(expr);
        // `x !== null && x !== undefined` — x is non-nullish.
        if (k == .logical_op) {
            const lp = hir_mod.logicalOf(self.hir, expr);
            if (lp.op == .@"and") {
                const left = self.recognizePredicateExpr(lp.lhs, params) orelse return null;
                const right = self.recognizePredicateExpr(lp.rhs, params) orelse return null;
                if (left.param_index != right.param_index) return null;
                const param_t = self.hir.typeOf(params[left.param_index]);
                const sub1 = self.subtractType(param_t, types.Primitive.null_t) catch param_t;
                const sub2 = self.subtractType(sub1, types.Primitive.undefined_t) catch sub1;
                return .{ .param_index = left.param_index, .target_type = sub2, .is_asserts = false };
            }
        }
        if (k != .binary_op) return null;
        const b = hir_mod.binopOf(self.hir, expr);

        // `x instanceof Foo` — narrow `x` to the class instance type.
        if (b.op == .instanceof and self.hir.kindOf(b.lhs) == .identifier) {
            const idx = self.paramIndexOfIdentifier(b.lhs, params) orelse return null;
            var narrowed: TypeId = types.Primitive.object_t;
            if (self.hir.kindOf(b.rhs) == .identifier) {
                const rhs_id = hir_mod.identifierOf(self.hir, b.rhs);
                if (self.class_instance_types.get(rhs_id.name)) |inst| narrowed = inst;
            }
            return .{ .param_index = idx, .target_type = narrowed, .is_asserts = false };
        }

        if (b.op != .eq_strict and b.op != .neq_strict) return null;

        // `typeof x === "string" | "number" | "boolean"`.
        if (b.op == .eq_strict and
            self.hir.kindOf(b.lhs) == .unary_op and
            self.hir.kindOf(b.rhs) == .literal_string)
        {
            const u = hir_mod.unaryOf(self.hir, b.lhs);
            if (u.op == .typeof and self.hir.kindOf(u.operand) == .identifier) {
                const idx = self.paramIndexOfIdentifier(u.operand, params) orelse return null;
                const lit = hir_mod.literalStringOf(self.hir, b.rhs);
                const lit_str = self.string_interner.get(lit.value);
                const narrowed = typeOfTypeofString(lit_str) orelse return null;
                if (narrowed != types.Primitive.string_t and
                    narrowed != types.Primitive.number_t and
                    narrowed != types.Primitive.boolean_t) return null;
                return .{ .param_index = idx, .target_type = narrowed, .is_asserts = false };
            }
        }

        // `x !== null` / `x !== undefined`.
        if (b.op == .neq_strict and self.hir.kindOf(b.lhs) == .identifier) {
            const idx = self.paramIndexOfIdentifier(b.lhs, params) orelse return null;
            const param_t = self.hir.typeOf(params[idx]);
            if (self.hir.kindOf(b.rhs) == .literal_null) {
                const sub = self.subtractType(param_t, types.Primitive.null_t) catch param_t;
                return .{ .param_index = idx, .target_type = sub, .is_asserts = false };
            }
            if (self.hir.kindOf(b.rhs) == .literal_undefined) {
                const sub = self.subtractType(param_t, types.Primitive.undefined_t) catch param_t;
                return .{ .param_index = idx, .target_type = sub, .is_asserts = false };
            }
            if (self.hir.kindOf(b.rhs) == .identifier) {
                const rhs_id = hir_mod.identifierOf(self.hir, b.rhs);
                const rhs_name = self.string_interner.get(rhs_id.name);
                if (std.mem.eql(u8, rhs_name, "undefined")) {
                    const sub = self.subtractType(param_t, types.Primitive.undefined_t) catch param_t;
                    return .{ .param_index = idx, .target_type = sub, .is_asserts = false };
                }
            }
        }
        return null;
    }

    /// Return the index of the parameter in `params` whose name
    /// matches the `identifier` node `id_node`. Returns null when
    /// `id_node` isn't an identifier or doesn't match any parameter.
    fn paramIndexOfIdentifier(
        self: *Checker,
        id_node: NodeId,
        params: []const NodeId,
    ) ?u16 {
        if (self.hir.kindOf(id_node) != .identifier) return null;
        const id = hir_mod.identifierOf(self.hir, id_node);
        for (params, 0..) |p, i| {
            if (self.hir.kindOf(p) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, p);
            if (pp.name == hir_mod.none_node_id) continue;
            if (self.hir.kindOf(pp.name) != .identifier) continue;
            const pname = hir_mod.identifierOf(self.hir, pp.name);
            if (pname.name == id.name) return @intCast(i);
        }
        return null;
    }

    /// `noUnusedLocals` (TS6133): walk a function body's
    /// statements, find every `let` / `const` / `var` declaration,
    /// and report names not referenced from elsewhere in the body.
    /// Names beginning with `_` are exempt by convention.
    fn checkUnusedLocals(self: *Checker, body: NodeId) CheckError!void {
        if (!self.strict_flags.no_unused_locals) return;
        if (body == hir_mod.none_node_id) return;
        if (self.hir.kindOf(body) != .block_stmt) return;
        var refs: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer refs.deinit(self.gpa);
        try self.collectIdentifierRefs(body, &refs);
        for (hir_mod.blockStmts(self.hir, body)) |s| {
            const k = self.hir.kindOf(s);
            if (k != .var_decl and k != .let_decl and k != .const_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, s);
            if (v.is_ambient) continue;
            if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, v.name);
            const name_str = self.string_interner.get(id.name);
            if (name_str.len > 0 and name_str[0] == '_') continue;
            if (refs.contains(id.name)) continue;
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "'{s}' is declared but its value is never read.",
                .{name_str},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = s,
                .code = TsCodes.declared_but_not_read,
                .message = msg,
            });
        }
    }

    /// TS2454 — "Variable 'X' is used before being assigned."
    ///
    /// Linear-scan, approximate: walks `stmts` in source order
    /// tracking every typed declaration with no initializer. A
    /// subsequent identifier read of a pending `let` emits TS2454;
    /// a pending `var` only emits inside a conditional expression or
    /// array literal, which catches the high-frequency conformance
    /// shapes without treating every hoisted `var` probe as
    /// definitely unassigned.
    /// A plain `name = ...` removes the name from the tracked set.
    /// This intentionally does *not* build a control-flow graph —
    /// branches collapse to a flat scan, so it catches the common
    /// case but misses anything involving control-flow joins.
    fn checkUsedBeforeAssignment(self: *Checker, stmts: []const NodeId) CheckError!void {
        var pending: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
        defer pending.deinit(self.gpa);
        for (stmts) |s| try self.scanForUsedBeforeAssign(s, &pending);
    }

    fn scanForUsedBeforeAssign(
        self: *Checker,
        node: NodeId,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(node);
        switch (k) {
            .let_decl, .var_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                if (!v.is_ambient and
                    !self.declarationSourceHasLeadingDeclare(node) and
                    !self.declarationLineHasDeclare(node) and
                    !self.sourceHasDeclareAnyVar(v.name) and
                    v.init == hir_mod.none_node_id and
                    v.type_annotation != hir_mod.none_node_id and
                    !self.varDeclHasExplicitAnyAnnotation(node) and
                    !self.varDeclTypeIncludesUndefined(node) and
                    !self.isGlobalSymbolConstructorVarDecl(node) and
                    v.name != hir_mod.none_node_id and
                    self.hir.kindOf(v.name) == .identifier)
                {
                    const id = hir_mod.identifierOf(self.hir, v.name);
                    try pending.put(self.gpa, id.name, node);
                }
                if (v.init != hir_mod.none_node_id) {
                    try self.scanExprForUsedBeforeAssign(v.init, pending);
                    try self.scanBindingPatternDefiniteSideEffects(v.name, pending);
                    if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                        const id = hir_mod.identifierOf(self.hir, v.name);
                        _ = pending.remove(id.name);
                    }
                }
            },
            .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                if (v.init != hir_mod.none_node_id) {
                    try self.scanExprForUsedBeforeAssign(v.init, pending);
                    try self.scanBindingPatternDefiniteSideEffects(v.name, pending);
                }
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(a.value, pending);
                if (a.target != hir_mod.none_node_id and
                    self.hir.kindOf(a.target) == .identifier)
                {
                    const id = hir_mod.identifierOf(self.hir, a.target);
                    if (a.op != null) {
                        try self.flagIfPending(a.target, id.name, pending);
                    } else {
                        _ = pending.remove(id.name);
                    }
                } else if (a.target != hir_mod.none_node_id) {
                    if (a.op == null) {
                        try self.scanAssignmentTargetReadParts(a.target, pending);
                        try self.removeAssignedTargetFromPending(a.target, pending);
                    } else {
                        try self.scanExprForUsedBeforeAssign(a.target, pending);
                    }
                }
            },
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |s| {
                    try self.scanForUsedBeforeAssign(s, pending);
                }
            },
            .namespace_decl => {
                for (hir_mod.namespaceBody(self.hir, node)) |s| {
                    try self.scanForUsedBeforeAssign(s, pending);
                }
            },
            .return_stmt => {
                const r = hir_mod.returnOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(r.value, pending);
            },
            .decorator => {
                const d = hir_mod.decoratorOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(d.expression, pending);
            },
            .export_decl => {
                const ex = hir_mod.exportOf(self.hir, node);
                if (ex.decl != hir_mod.none_node_id) try self.scanForUsedBeforeAssign(ex.decl, pending);
            },
            // Branching / nested-fn constructs — the linear scan
            // gives up here. Treat the body as opaque so we don't
            // emit false positives across control-flow boundaries.
            .for_in_stmt, .for_of_stmt => {
                const fr = hir_mod.forInOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(fr.source, pending);
                var body_pending: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
                defer body_pending.deinit(self.gpa);
                try self.clonePendingAssignments(pending, &body_pending);
                self.removeForLoopTargetFromPending(fr.target, &body_pending);
                try self.removeAssignedTargetFromPending(fr.target, &body_pending);
                try self.scanForUsedBeforeAssign(fr.body, &body_pending);
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(i.cond, pending);
                try self.removeDefinitelyAssignedAfterIf(i, pending);
            },
            .while_stmt => {
                const w = hir_mod.whileOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(w.cond, pending);
            },
            .do_while_stmt => {
                const w = hir_mod.doWhileOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(w.cond, pending);
            },
            .switch_stmt => {
                const sw = hir_mod.switchOf(self.hir, node);
                if (self.hir.kindOf(sw.discriminant) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, sw.discriminant);
                    if (pending.contains(id.name) and !self.sourceHasStrictFalseDirective()) {
                        try self.reportUsedBeforeAssignment(sw.discriminant, id.name, pending);
                    }
                } else {
                    try self.scanExprForUsedBeforeAssign(sw.discriminant, pending);
                }
                for (hir_mod.switchCases(self.hir, node)) |case_node| {
                    try self.scanForUsedBeforeAssign(case_node, pending);
                }
            },
            .switch_case => {
                const sc = hir_mod.switchCaseOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(sc.value, pending);
                for (hir_mod.switchCaseStmts(self.hir, node)) |stmt| {
                    try self.scanForUsedBeforeAssign(stmt, pending);
                }
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                if (fr.init != hir_mod.none_node_id) {
                    try self.scanForUsedBeforeAssign(fr.init, pending);
                }
                if (fr.cond != hir_mod.none_node_id) {
                    try self.scanExprForUsedBeforeAssign(fr.cond, pending);
                }
                if (fr.update != hir_mod.none_node_id) {
                    try self.scanExprForUsedBeforeAssign(fr.update, pending);
                }
            },
            .try_stmt,
            .fn_decl,
            .fn_expr,
            .arrow_fn,
            .class_decl,
            => return,
            else => {
                if (hir_mod.NodeKind.isExpression(k)) {
                    try self.scanExprForUsedBeforeAssign(node, pending);
                }
            },
        }
    }

    fn scanExprForUsedBeforeAssign(
        self: *Checker,
        node: NodeId,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(node);
        switch (k) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, node);
                try self.flagIfPending(node, id.name, pending);
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(b.lhs, pending);
                try self.scanExprForUsedBeforeAssign(b.rhs, pending);
            },
            .unary_op => {
                const u = hir_mod.unaryOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(u.operand, pending);
            },
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(l.lhs, pending);
                var rhs_pending: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
                defer rhs_pending.deinit(self.gpa);
                try self.clonePendingAssignments(pending, &rhs_pending);
                try self.scanExprForUsedBeforeAssign(l.rhs, &rhs_pending);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(c.cond, pending);
                try self.scanExprForUsedBeforeAssign(c.then_branch, pending);
                try self.scanExprForUsedBeforeAssign(c.else_branch, pending);
            },
            .array_literal => {
                for (hir_mod.arrayLiteralElements(self.hir, node)) |el| {
                    try self.scanExprForUsedBeforeAssign(el, pending);
                }
            },
            .object_literal => {
                for (hir_mod.objectLiteralProps(self.hir, node)) |p| {
                    if (self.hir.kindOf(p) != .object_property) {
                        try self.scanExprForUsedBeforeAssign(p, pending);
                        continue;
                    }
                    const op = hir_mod.objectPropertyOf(self.hir, p);
                    if (op.is_computed) try self.scanExprForUsedBeforeAssign(op.key, pending);
                    try self.scanExprForUsedBeforeAssign(op.value, pending);
                }
            },
            .spread => {
                const sp = hir_mod.spreadOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(sp.expression, pending);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(c.callee, pending);
                if (self.hir.kindOf(c.callee) == .arrow_fn or self.hir.kindOf(c.callee) == .fn_expr) {
                    const f = hir_mod.fnDeclOf(self.hir, c.callee);
                    try self.scanForUsedBeforeAssign(f.body, pending);
                }
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    try self.scanExprForUsedBeforeAssign(arg, pending);
                }
            },
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(m.object, pending);
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(e.object, pending);
                try self.scanExprForUsedBeforeAssign(e.index, pending);
            },
            .as_expr, .satisfies_expr, .type_assertion => {
                const a = hir_mod.asExpressionOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(a.expr, pending);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(a.value, pending);
                if (a.target != hir_mod.none_node_id and
                    self.hir.kindOf(a.target) == .identifier)
                {
                    const id = hir_mod.identifierOf(self.hir, a.target);
                    if (a.op != null) {
                        try self.flagIfPending(a.target, id.name, pending);
                    } else {
                        _ = pending.remove(id.name);
                    }
                } else if (a.target != hir_mod.none_node_id) {
                    if (a.op == null) {
                        try self.scanAssignmentTargetReadParts(a.target, pending);
                        try self.removeAssignedTargetFromPending(a.target, pending);
                    } else {
                        try self.scanExprForUsedBeforeAssign(a.target, pending);
                    }
                }
            },
            else => {},
        }
    }

    fn removeAssignedTargetFromPending(
        self: *Checker,
        node: NodeId,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, node);
                _ = pending.remove(id.name);
            },
            .array_literal => for (hir_mod.arrayLiteralElements(self.hir, node)) |el| try self.removeAssignedTargetFromPending(el, pending),
            .spread => try self.removeAssignedTargetFromPending(hir_mod.spreadOf(self.hir, node).expression, pending),
            .assignment => try self.removeAssignedTargetFromPending(hir_mod.assignmentOf(self.hir, node).target, pending),
            .object_literal => for (hir_mod.objectLiteralProps(self.hir, node)) |p| try self.removeAssignedTargetFromPending(p, pending),
            .object_property => try self.removeAssignedTargetFromPending(hir_mod.objectPropertyOf(self.hir, node).value, pending),
            .member_access, .element_access => {},
            else => {},
        }
    }

    fn clonePendingAssignments(
        self: *Checker,
        source: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
        dest: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        var it = source.iterator();
        while (it.next()) |entry| {
            try dest.put(self.gpa, entry.key_ptr.*, entry.value_ptr.*);
        }
    }

    fn scanAssignmentTargetReadParts(
        self: *Checker,
        node: NodeId,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(m.object, pending);
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(e.object, pending);
                try self.scanExprForUsedBeforeAssign(e.index, pending);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                try self.scanExprForUsedBeforeAssign(a.value, pending);
                try self.scanAssignmentTargetReadParts(a.target, pending);
            },
            .array_literal => {
                for (hir_mod.arrayLiteralElements(self.hir, node)) |el| {
                    try self.scanAssignmentTargetReadParts(el, pending);
                }
            },
            .object_literal => {
                for (hir_mod.objectLiteralProps(self.hir, node)) |prop| {
                    if (self.hir.kindOf(prop) != .object_property) continue;
                    const op = hir_mod.objectPropertyOf(self.hir, prop);
                    if (op.is_computed) try self.scanExprForUsedBeforeAssign(op.key, pending);
                    try self.scanAssignmentTargetReadParts(op.value, pending);
                }
            },
            else => {},
        }
    }

    fn scanBindingPatternDefiniteSideEffects(
        self: *Checker,
        node: NodeId,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(node);
        if (k != .object_pattern and k != .array_pattern) return;
        for (hir_mod.patternElements(self.hir, node)) |elem| {
            if (self.hir.kindOf(elem) != .parameter) continue;
            const p = hir_mod.parameterOf(self.hir, elem);
            if (p.flags.is_computed_binding_key) {
                try self.scanExprForUsedBeforeAssign(p.default_value, pending);
                continue;
            }
            if (p.default_value != hir_mod.none_node_id) {
                var default_pending: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
                defer default_pending.deinit(self.gpa);
                try self.clonePendingAssignments(pending, &default_pending);
                try self.scanExprForUsedBeforeAssign(p.default_value, &default_pending);
            }
            try self.scanBindingPatternDefiniteSideEffects(p.name, pending);
        }
    }

    fn removeDefinitelyAssignedAfterIf(
        self: *Checker,
        i: hir_mod.IfPayload,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (i.else_branch == hir_mod.none_node_id or pending.count() == 0) return;

        var then_assigned: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer then_assigned.deinit(self.gpa);
        var else_assigned: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer else_assigned.deinit(self.gpa);
        try self.collectSimpleDefiniteAssignments(i.then_branch, &then_assigned);
        try self.collectSimpleDefiniteAssignments(i.else_branch, &else_assigned);

        const then_exits = self.statementDefinitelyExits(i.then_branch);
        const else_exits = self.statementDefinitelyExits(i.else_branch);

        var to_remove: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer to_remove.deinit(self.gpa);
        var it = pending.keyIterator();
        while (it.next()) |name_ptr| {
            const name = name_ptr.*;
            const then_ok = then_exits or then_assigned.contains(name);
            const else_ok = else_exits or else_assigned.contains(name);
            if (then_ok and else_ok) try to_remove.append(self.gpa, name);
        }
        for (to_remove.items) |name| _ = pending.remove(name);
    }

    fn collectSimpleDefiniteAssignments(
        self: *Checker,
        node: NodeId,
        out: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |stmt| {
                    try self.collectSimpleDefiniteAssignments(stmt, out);
                    if (self.hir.kindOf(stmt) == .return_stmt or self.hir.kindOf(stmt) == .throw_stmt) break;
                }
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                if (a.op == null and a.target != hir_mod.none_node_id and self.hir.kindOf(a.target) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, a.target);
                    try out.put(self.gpa, id.name, {});
                }
            },
            .let_decl, .var_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                if (v.init != hir_mod.none_node_id and v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, v.name);
                    try out.put(self.gpa, id.name, {});
                }
            },
            else => {},
        }
    }

    fn switchBodyAssignsIdentifier(self: *Checker, switch_node: NodeId, name: hir_mod.StringId) bool {
        for (hir_mod.switchCases(self.hir, switch_node)) |case_node| {
            for (hir_mod.switchCaseStmts(self.hir, case_node)) |stmt| {
                if (self.nodeAssignsIdentifier(stmt, name)) return true;
            }
        }
        return false;
    }

    fn nodeAssignsIdentifier(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                if (a.op == null and self.hir.kindOf(a.target) == .identifier and hir_mod.identifierOf(self.hir, a.target).name == name) return true;
                return self.nodeAssignsIdentifier(a.value, name) or self.nodeAssignsIdentifier(a.target, name);
            },
            .block_stmt => for (hir_mod.blockStmts(self.hir, node)) |stmt| {
                if (self.nodeAssignsIdentifier(stmt, name)) return true;
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                return self.nodeAssignsIdentifier(i.then_branch, name) or self.nodeAssignsIdentifier(i.else_branch, name);
            },
            .switch_stmt => return self.switchBodyAssignsIdentifier(node, name),
            .switch_case => for (hir_mod.switchCaseStmts(self.hir, node)) |stmt| {
                if (self.nodeAssignsIdentifier(stmt, name)) return true;
            },
            else => {},
        }
        return false;
    }

    fn removeForLoopTargetFromPending(
        self: *Checker,
        target: NodeId,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) void {
        if (target == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(target)) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, target);
                _ = pending.remove(id.name);
            },
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, target);
                self.removeForLoopTargetFromPending(v.name, pending);
            },
            .object_pattern, .array_pattern => {
                const elements = hir_mod.patternElements(self.hir, target);
                for (elements) |element| {
                    if (self.hir.kindOf(element) != .parameter) continue;
                    const p = hir_mod.parameterOf(self.hir, element);
                    self.removeForLoopTargetFromPending(p.name, pending);
                }
            },
            else => {},
        }
    }

    fn flagIfPending(
        self: *Checker,
        ref_node: NodeId,
        name: hir_mod.StringId,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        const decl_node = pending.get(name) orelse return;
        if (self.sourceHasStrictFalseDirective() and
            !self.nodeHasAncestorKind(ref_node, .as_expr) and
            !self.nodeHasAncestorKind(ref_node, .type_assertion))
        {
            return;
        }
        if (self.nodeInsideComputedPropertyKey(ref_node)) {
            if (self.isGlobalSymbolConstructorVarDecl(decl_node)) return;
            if (!self.varDeclTypeContainsSymbol(decl_node)) return;
        }
        if (self.declarationSourceHasLeadingDeclare(decl_node) or self.declarationLineHasDeclare(decl_node)) return;
        if (self.sourceHasDeclareAnyVarName(name)) return;
        if (std.mem.eql(u8, self.string_interner.get(name), "_")) return;
        if (self.hir.kindOf(decl_node) == .var_decl) {
            if (self.sourceHasStrictFalseDirective() and
                self.varDeclHasTypeAnnotation(decl_node) and
                self.nodeInsideFunctionObjectAssertion(ref_node))
            {
                return;
            }
            if (self.nodeHasAncestorKind(decl_node, .namespace_decl) and self.nodeIsInsideControlFlowCondition(ref_node)) return;
            if (self.namespaceVarReadIsFromNestedNamespaceVarInit(decl_node, ref_node)) return;
            if (!self.nodeHasAncestorKind(ref_node, .conditional) and
                !self.nodeHasAncestorKind(ref_node, .array_literal) and
                !self.nodeHasAncestorKind(ref_node, .object_literal) and
                !self.nodeHasAncestorKind(ref_node, .for_of_stmt) and
                !(self.nodeHasAncestorKind(ref_node, .member_access) and self.varDeclHasTypeAnnotation(decl_node)) and
                !(self.nodeHasAncestorKind(ref_node, .element_access) and self.varDeclHasTypeAnnotation(decl_node)) and
                !(self.nodeHasAncestorKind(ref_node, .binary_op) and self.varDeclHasTypeAnnotation(decl_node)) and
                !(self.nodeHasAncestorKind(ref_node, .logical_op) and self.varDeclHasTypeAnnotation(decl_node)) and
                !(self.nodeHasAncestorKind(ref_node, .assignment) and self.varDeclHasTypeAnnotation(decl_node)) and
                !(self.nodeHasAncestorKind(ref_node, .var_decl) and self.varDeclHasTypeAnnotation(decl_node)) and
                !(self.nodeHasAncestorKind(ref_node, .call_expr) and self.varDeclHasTypeAnnotation(decl_node)) and
                !(self.nodeHasAncestorKind(ref_node, .new_expr) and self.varDeclHasTypeAnnotation(decl_node)) and
                !(self.nodeHasAncestorKind(ref_node, .decorator) and self.varDeclHasTypeAnnotation(decl_node)) and
                !self.isCompoundAssignmentTarget(ref_node) and
                !self.isDirectExpressionStatement(ref_node)) return;
        }
        try self.reportUsedBeforeAssignment(ref_node, name, pending);
    }

    fn reportUsedBeforeAssignment(
        self: *Checker,
        ref_node: NodeId,
        name: hir_mod.StringId,
        pending: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        const name_str = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Variable '{s}' is used before being assigned.",
            .{name_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = ref_node,
            .code = TsCodes.used_before_assignment,
            .message = msg,
        });
        // Remove from pending so we only flag the first use; later
        // reads are noisy.
        _ = pending.remove(name);
    }

    fn isCompoundAssignmentTarget(self: *Checker, node: NodeId) bool {
        const parent = self.hir.parentOf(node);
        if (parent == hir_mod.none_node_id or self.hir.kindOf(parent) != .assignment) return false;
        const a = hir_mod.assignmentOf(self.hir, parent);
        return a.target == node and a.op != null;
    }

    fn nodeInsideComputedPropertyKey(self: *Checker, node: NodeId) bool {
        var child = node;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : ({
            child = cur;
            cur = self.hir.parentOf(cur);
        }) {
            if (self.hir.kindOf(cur) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, cur);
            if (op.is_computed and op.key == child) return true;
        }
        return false;
    }

    fn isDirectExpressionStatement(self: *Checker, node: NodeId) bool {
        const parent = self.hir.parentOf(node);
        if (parent == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(parent)) {
            .block_stmt => true,
            else => false,
        };
    }

    fn nodeIsInsideControlFlowCondition(self: *Checker, node: NodeId) bool {
        var child = node;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : ({
            child = cur;
            cur = self.hir.parentOf(cur);
        }) {
            switch (self.hir.kindOf(cur)) {
                .if_stmt => {
                    if (hir_mod.ifOf(self.hir, cur).cond == child) return true;
                },
                .while_stmt => {
                    if (hir_mod.whileOf(self.hir, cur).cond == child) return true;
                },
                .do_while_stmt => {
                    if (hir_mod.doWhileOf(self.hir, cur).cond == child) return true;
                },
                .for_stmt => {
                    if (hir_mod.forStmtOf(self.hir, cur).cond == child) return true;
                },
                else => {},
            }
        }
        return false;
    }

    fn nodeHasAncestorKind(self: *Checker, node: NodeId, kind: hir_mod.NodeKind) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (self.hir.kindOf(cur) == kind) return true;
        }
        return false;
    }

    fn nearestAncestorKind(self: *Checker, node: NodeId, kind: hir_mod.NodeKind) NodeId {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (self.hir.kindOf(cur) == kind) return cur;
        }
        return hir_mod.none_node_id;
    }

    fn namespaceVarReadIsFromNestedNamespaceVarInit(self: *Checker, decl_node: NodeId, ref_node: NodeId) bool {
        const decl_ns = self.nearestAncestorKind(decl_node, .namespace_decl);
        if (decl_ns == hir_mod.none_node_id) return false;
        const ref_ns = self.nearestAncestorKind(ref_node, .namespace_decl);
        if (ref_ns == hir_mod.none_node_id or ref_ns == decl_ns) return false;
        return self.nodeHasAncestorKind(ref_node, .var_decl);
    }

    fn nodeInsideFunctionObjectAssertion(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .as_expr and k != .type_assertion) continue;
            const a = hir_mod.asExpressionOf(self.hir, cur);
            if (a.type_node == hir_mod.none_node_id or self.hir.kindOf(a.type_node) != .type_ref) return false;
            const r = hir_mod.typeRefOf(self.hir, a.type_node);
            return std.mem.eql(u8, self.string_interner.get(r.name), "Function");
        }
        return false;
    }

    fn nodeIsInsideLoop(self: *Checker, node: NodeId) bool {
        return self.nodeHasAncestorKind(node, .while_stmt) or
            self.nodeHasAncestorKind(node, .do_while_stmt) or
            self.nodeHasAncestorKind(node, .for_stmt) or
            self.nodeHasAncestorKind(node, .for_in_stmt) or
            self.nodeHasAncestorKind(node, .for_of_stmt);
    }

    fn nodeIsInsideFunctionLike(self: *Checker, node: NodeId) bool {
        return self.nodeHasAncestorKind(node, .fn_decl) or
            self.nodeHasAncestorKind(node, .fn_expr) or
            self.nodeHasAncestorKind(node, .arrow_fn);
    }

    fn nodeIsBracketedComputedName(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        if (span.start < src.len and src[span.start] == '[') return true;
        var i: usize = @min(span.start, src.len);
        while (i > 0) {
            i -= 1;
            switch (src[i]) {
                ' ', '\t', '\r', '\n' => continue,
                '[' => return true,
                else => return false,
            }
        }
        return false;
    }

    fn memberSourceLooksComputed(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        if (span.start >= src.len) return false;
        const end = @min(src.len, @as(usize, span.start) + 48);
        var i: usize = span.start;
        while (i < end) : (i += 1) {
            switch (src[i]) {
                '[' => return true,
                '(', '{', ';', ',', ':', '=' => return false,
                ' ', '\t', '\r', '\n' => continue,
                else => continue,
            }
        }
        return false;
    }

    fn memberSourceLooksMethod(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        if (span.start >= src.len) return false;
        const end = @min(src.len, @as(usize, span.start) + 96);
        var saw_close_bracket = false;
        var i: usize = span.start;
        while (i < end) : (i += 1) {
            const ch = src[i];
            if (ch == ']') {
                saw_close_bracket = true;
                continue;
            }
            if (!saw_close_bracket) {
                switch (ch) {
                    ' ', '\t', '\r', '\n' => continue,
                    '(' => return true,
                    ':', '=', ',', '{', ';' => return false,
                    else => continue,
                }
            }
            switch (ch) {
                ' ', '\t', '\r', '\n' => continue,
                '(' => return true,
                '=' => return false,
                else => return false,
            }
        }
        return false;
    }

    fn enclosingStaticClassTypeParams(self: *Checker, node: NodeId) ?[]const NodeId {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            const f = hir_mod.fnDeclOf(self.hir, cur);
            if (!f.flags.is_static) return null;
            var parent = self.hir.parentOf(cur);
            while (parent != hir_mod.none_node_id) : (parent = self.hir.parentOf(parent)) {
                const pk = self.hir.kindOf(parent);
                if (pk == .class_decl or pk == .class_expr) {
                    const c = hir_mod.classOf(self.hir, parent);
                    const tps = self.hir.childSlice(c.type_params_start, c.type_params_len);
                    return if (tps.len == 0) null else tps;
                }
                if (pk == .fn_decl or pk == .fn_expr or pk == .arrow_fn) return null;
            }
            return null;
        }
        return null;
    }

    fn varDeclHasTypeAnnotation(self: *Checker, node: NodeId) bool {
        switch (self.hir.kindOf(node)) {
            .var_decl, .let_decl, .const_decl => {},
            else => return false,
        }
        const v = hir_mod.varDeclOf(self.hir, node);
        return v.type_annotation != hir_mod.none_node_id;
    }

    fn varDeclHasExplicitAnyAnnotation(self: *Checker, node: NodeId) bool {
        switch (self.hir.kindOf(node)) {
            .var_decl, .let_decl, .const_decl => {},
            else => return false,
        }
        const v = hir_mod.varDeclOf(self.hir, node);
        if (v.type_annotation == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(v.type_annotation) != .type_ref) return false;
        const r = hir_mod.typeRefOf(self.hir, v.type_annotation);
        return r.qualifier_len == 0 and std.mem.eql(u8, self.string_interner.get(r.name), "any");
    }

    fn varDeclTypeContainsSymbol(self: *Checker, node: NodeId) bool {
        switch (self.hir.kindOf(node)) {
            .var_decl, .let_decl, .const_decl => {},
            else => return false,
        }
        const v = hir_mod.varDeclOf(self.hir, node);
        if (v.type_annotation == hir_mod.none_node_id) return false;
        const existing = self.hir.typeOf(node);
        const t = if (existing != types.Primitive.none)
            existing
        else if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
            self.lowerValueTypeAnnotation(hir_mod.identifierOf(self.hir, v.name).name, v.type_annotation) catch return false
        else
            self.lowererLowerWithTypeParams(v.type_annotation) catch return false;
        return self.typeContainsSymbol(t);
    }

    fn varDeclTypeIncludesUndefined(self: *Checker, node: NodeId) bool {
        switch (self.hir.kindOf(node)) {
            .var_decl, .let_decl, .const_decl => {},
            else => return false,
        }
        const v = hir_mod.varDeclOf(self.hir, node);
        if (v.type_annotation == hir_mod.none_node_id) return false;
        const t = self.hir.typeOf(node);
        if (t != types.Primitive.none) {
            if (t == types.Primitive.any or t == types.Primitive.unknown) return false;
            return self.typeIncludesUndefined(t);
        }
        const lowered = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
            self.lowerValueTypeAnnotation(hir_mod.identifierOf(self.hir, v.name).name, v.type_annotation) catch return false
        else
            self.lowererLowerWithTypeParams(v.type_annotation) catch return false;
        if (lowered == types.Primitive.any or lowered == types.Primitive.unknown) return false;
        return self.typeIncludesUndefined(lowered);
    }

    fn isGlobalSymbolConstructorVarDecl(self: *Checker, node: NodeId) bool {
        if (self.hir.kindOf(node) != .var_decl) return false;
        if (self.nodeHasAncestorKind(node, .namespace_decl)) return false;
        const v = hir_mod.varDeclOf(self.hir, node);
        if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, v.name);
        if (!std.mem.eql(u8, self.string_interner.get(id.name), "Symbol")) return false;
        if (v.type_annotation == hir_mod.none_node_id or self.hir.kindOf(v.type_annotation) != .type_ref) return false;
        const r = hir_mod.typeRefOf(self.hir, v.type_annotation);
        return r.qualifier_len == 0 and std.mem.eql(u8, self.string_interner.get(r.name), "SymbolConstructor");
    }

    fn sourceHasStrictFalseDirective(self: *Checker) bool {
        const src = self.source orelse return false;
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw_line| {
            const line = std.mem.trim(u8, raw_line, " \t\r");
            if (std.mem.indexOf(u8, line, "@strict: false") != null) return true;
            if (std.mem.indexOf(u8, line, "@strict:false") != null) return true;
        }
        return false;
    }

    fn sourceTargetDisallowsTopLevelAwait(self: *Checker) bool {
        return self.sourceDirectiveValueMentions("target", "es3") or
            self.sourceDirectiveValueMentions("target", "es5") or
            self.sourceDirectiveValueMentions("target", "es2015") or
            self.sourceDirectiveValueMentions("target", "es2016");
    }

    fn sourceHasAllowUnreachableTrueDirective(self: *Checker) bool {
        const src = self.source orelse return false;
        return std.mem.indexOf(u8, src, "@allowUnreachableCode: true") != null or
            std.mem.indexOf(u8, src, "@allowUnreachableCode:true") != null;
    }

    fn sourceHasUseDefineForClassFieldsTrueDirective(self: *Checker) bool {
        const src = self.source orelse return false;
        return std.mem.indexOf(u8, src, "@useDefineForClassFields: true") != null or
            std.mem.indexOf(u8, src, "@useDefineForClassFields:true") != null;
    }

    fn sourceHasReactJsxReference(self: *Checker) bool {
        const src = self.source orelse return false;
        return std.mem.indexOf(u8, src, "/.lib/react") != null;
    }

    fn sourceHasTargetEs2016OrLaterDirective(self: *Checker) bool {
        const src = self.source orelse return false;
        const target_pos = std.mem.indexOf(u8, src, "@target") orelse return false;
        const line_end = std.mem.indexOfScalarPos(u8, src, target_pos, '\n') orelse src.len;
        var buf: [128]u8 = undefined;
        const raw_line = std.mem.trim(u8, src[target_pos..line_end], " \t\r");
        const n = @min(raw_line.len, buf.len);
        const line = std.ascii.lowerString(buf[0..n], raw_line[0..n]);
        return std.mem.indexOf(u8, line, "es2016") != null or
            std.mem.indexOf(u8, line, "es2017") != null or
            std.mem.indexOf(u8, line, "es2018") != null or
            std.mem.indexOf(u8, line, "es2019") != null or
            std.mem.indexOf(u8, line, "es202") != null or
            std.mem.indexOf(u8, line, "esnext") != null;
    }

    fn sourceLibDirectiveNeedsIterableIterator(self: *Checker) bool {
        const src = self.source orelse return false;
        const lib_pos = std.mem.indexOf(u8, src, "@lib") orelse return false;
        const line_end = std.mem.indexOfScalarPos(u8, src, lib_pos, '\n') orelse src.len;
        var buf: [256]u8 = undefined;
        const raw_line = std.mem.trim(u8, src[lib_pos..line_end], " \t\r");
        const n = @min(raw_line.len, buf.len);
        const line = std.ascii.lowerString(buf[0..n], raw_line[0..n]);
        if (std.mem.indexOf(u8, line, "es2015.iterable") != null) return false;
        if (std.mem.indexOf(u8, line, "es2015") != null) return false;
        if (std.mem.indexOf(u8, line, "es2016") != null) return false;
        if (std.mem.indexOf(u8, line, "es2017") != null) return false;
        if (std.mem.indexOf(u8, line, "es2018") != null) return false;
        if (std.mem.indexOf(u8, line, "es2019") != null) return false;
        if (std.mem.indexOf(u8, line, "es202") != null) return false;
        if (std.mem.indexOf(u8, line, "esnext") != null) return false;
        return std.mem.indexOf(u8, line, "es5") != null;
    }

    /// `noUnusedParameters` (TS6133): walks the function body and
    /// collects every identifier StringId referenced *outside* a
    /// declaration's name slot, then reports any parameter whose
    /// name doesn't appear. Names starting with `_` are exempt
    /// (matches tsc).
    fn checkUnusedParameters(self: *Checker, fn_node: NodeId, body: NodeId) CheckError!void {
        if (!self.strict_flags.no_unused_parameters) return;
        const params = hir_mod.fnParams(self.hir, fn_node);
        if (params.len == 0) return;
        var refs: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer refs.deinit(self.gpa);
        try self.collectIdentifierRefs(body, &refs);
        for (params) |p| {
            const pp = hir_mod.parameterOf(self.hir, p);
            if (pp.name == hir_mod.none_node_id or self.hir.kindOf(pp.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, pp.name);
            const name_str = self.string_interner.get(id.name);
            if (name_str.len > 0 and name_str[0] == '_') continue;
            if (refs.contains(id.name)) continue;
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "'{s}' is declared but its value is never read.",
                .{name_str},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = p,
                .code = TsCodes.declared_but_not_read,
                .message = msg,
            });
        }
    }

    /// `noUnusedParameters` (TS6133) for `catch (e) { ... }` clauses.
    /// Mirrors `checkUnusedParameters`: emits TS6133 when the catch
    /// binding's name is never read inside the catch block. Names
    /// starting with `_` are exempt by tsc convention.
    fn checkUnusedCatchParam(self: *Checker, try_node: NodeId) CheckError!void {
        if (!self.strict_flags.no_unused_parameters) return;
        const ts = hir_mod.tryOf(self.hir, try_node);
        if (ts.catch_param == hir_mod.none_node_id) return;
        if (self.hir.kindOf(ts.catch_param) != .identifier) return;
        const id = hir_mod.identifierOf(self.hir, ts.catch_param);
        const name_str = self.string_interner.get(id.name);
        if (name_str.len > 0 and name_str[0] == '_') return;
        var refs: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer refs.deinit(self.gpa);
        if (ts.catch_block != hir_mod.none_node_id) {
            try self.collectIdentifierRefs(ts.catch_block, &refs);
        }
        if (refs.contains(id.name)) return;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}' is declared but its value is never read.",
            .{name_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = ts.catch_param,
            .code = TsCodes.declared_but_not_read,
            .message = msg,
        });
    }

    fn checkClassUsedBeforeDeclaration(self: *Checker, stmts: []const NodeId) CheckError!void {
        var class_names: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
        defer class_names.deinit(self.gpa);
        for (stmts) |raw| {
            const s = self.unwrapExportDecl(raw);
            if (s == hir_mod.none_node_id) continue;
            const k = self.hir.kindOf(s);
            if (k != .class_decl and k != .class_expr) continue;
            const c = hir_mod.classOf(self.hir, s);
            if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, c.name);
            try class_names.put(self.gpa, id.name, s);
        }
        if (class_names.count() == 0) return;

        var declared: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer declared.deinit(self.gpa);
        var reported: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer reported.deinit(self.gpa);
        for (stmts) |raw| {
            const s = self.unwrapExportDecl(raw);
            if (s == hir_mod.none_node_id) continue;

            var refs: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
            defer refs.deinit(self.gpa);
            try self.collectIdentifierRefs(s, &refs);
            if (self.classDeclarationName(s)) |own_name| {
                _ = refs.remove(own_name);
            }
            var it = refs.keyIterator();
            while (it.next()) |name_ptr| {
                const name = name_ptr.*;
                if (!class_names.contains(name) or declared.contains(name) or reported.contains(name)) continue;
                if (self.sourceHasCheckJsDirective() and self.virtualSectionIsJsLike(s)) continue;
                const name_str = self.string_interner.get(name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Class '{s}' used before its declaration.",
                    .{name_str},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = s,
                    .code = TsCodes.class_used_before_declaration,
                    .message = msg,
                });
                try reported.put(self.gpa, name, {});
            }

            const k = self.hir.kindOf(s);
            if (k == .var_decl or k == .let_decl or k == .const_decl) {
                const v = hir_mod.varDeclOf(self.hir, s);
                if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) {
                    try declared.put(self.gpa, hir_mod.identifierOf(self.hir, v.name).name, {});
                }
            } else if (k == .fn_decl or k == .fn_expr) {
                const f = hir_mod.fnDeclOf(self.hir, s);
                if (f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier) {
                    try declared.put(self.gpa, hir_mod.identifierOf(self.hir, f.name).name, {});
                }
            } else if (k == .class_decl or k == .class_expr) {
                const c = hir_mod.classOf(self.hir, s);
                if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, c.name);
                    try declared.put(self.gpa, id.name, {});
                }
            }
        }
    }

    fn classDeclarationName(self: *Checker, node: NodeId) ?hir_mod.StringId {
        if (node == hir_mod.none_node_id) return null;
        const k = self.hir.kindOf(node);
        if (k != .class_decl and k != .class_expr) return null;
        const c = hir_mod.classOf(self.hir, node);
        if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) return null;
        return hir_mod.identifierOf(self.hir, c.name).name;
    }

    /// Recursively collect every identifier StringId reachable from
    /// `node` that is *not* the name slot of a declaration. Stops
    /// at nested function boundaries so inner-fn references don't
    /// satisfy outer-fn parameters.
    fn collectIdentifierRefs(
        self: *Checker,
        node: NodeId,
        out: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(node);
        switch (k) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, node);
                if (!self.isDeclNameSlot(node)) try out.put(self.gpa, id.name, {});
            },
            // Nested fns shadow the outer scope — skip them.
            .fn_decl, .fn_expr, .arrow_fn => return,
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |s| try self.collectIdentifierRefs(s, out);
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                try self.collectIdentifierRefs(i.cond, out);
                try self.collectIdentifierRefs(i.then_branch, out);
                try self.collectIdentifierRefs(i.else_branch, out);
            },
            .while_stmt => {
                const w = hir_mod.whileOf(self.hir, node);
                try self.collectIdentifierRefs(w.cond, out);
                try self.collectIdentifierRefs(w.body, out);
            },
            .do_while_stmt => {
                const w = hir_mod.doWhileOf(self.hir, node);
                try self.collectIdentifierRefs(w.cond, out);
                try self.collectIdentifierRefs(w.body, out);
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                try self.collectIdentifierRefs(fr.init, out);
                try self.collectIdentifierRefs(fr.cond, out);
                try self.collectIdentifierRefs(fr.update, out);
                try self.collectIdentifierRefs(fr.body, out);
            },
            .return_stmt => {
                const r = hir_mod.returnOf(self.hir, node);
                try self.collectIdentifierRefs(r.value, out);
            },
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                // Skip `v.name` — it's the declaration site.
                try self.collectIdentifierRefs(v.init, out);
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                try self.collectIdentifierRefs(b.lhs, out);
                try self.collectIdentifierRefs(b.rhs, out);
            },
            .unary_op => {
                const u = hir_mod.unaryOf(self.hir, node);
                try self.collectIdentifierRefs(u.operand, out);
            },
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                try self.collectIdentifierRefs(l.lhs, out);
                try self.collectIdentifierRefs(l.rhs, out);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                try self.collectIdentifierRefs(c.cond, out);
                try self.collectIdentifierRefs(c.then_branch, out);
                try self.collectIdentifierRefs(c.else_branch, out);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                try self.collectIdentifierRefs(a.target, out);
                try self.collectIdentifierRefs(a.value, out);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                try self.collectIdentifierRefs(c.callee, out);
                for (hir_mod.callArgs(self.hir, node)) |arg| try self.collectIdentifierRefs(arg, out);
            },
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                try self.collectIdentifierRefs(m.object, out);
                // `m.name` is a StringId, not a node — no descend.
            },
            .class_decl, .class_expr => {
                const c = hir_mod.classOf(self.hir, node);
                try self.collectIdentifierRefs(c.extends, out);
                for (hir_mod.classMembers(self.hir, node)) |m| try self.collectIdentifierRefs(m, out);
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                try self.collectIdentifierRefs(e.object, out);
                try self.collectIdentifierRefs(e.index, out);
            },
            .as_expr, .satisfies_expr, .type_assertion => {
                const a = hir_mod.asExpressionOf(self.hir, node);
                try self.collectIdentifierRefs(a.expr, out);
            },
            .throw_stmt => {
                const t = hir_mod.throwOf(self.hir, node);
                try self.collectIdentifierRefs(t.value, out);
            },
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                try self.collectIdentifierRefs(ts.block, out);
                try self.collectIdentifierRefs(ts.catch_block, out);
                try self.collectIdentifierRefs(ts.finally_block, out);
            },
            .switch_stmt => {
                const sw = hir_mod.switchOf(self.hir, node);
                try self.collectIdentifierRefs(sw.discriminant, out);
                for (hir_mod.switchCases(self.hir, node)) |case| try self.collectIdentifierRefs(case, out);
            },
            .switch_case => {
                for (hir_mod.switchCaseStmts(self.hir, node)) |s| try self.collectIdentifierRefs(s, out);
            },
            .array_literal => {
                for (hir_mod.arrayLiteralElements(self.hir, node)) |el| try self.collectIdentifierRefs(el, out);
            },
            .spread => {
                const sp = hir_mod.spreadOf(self.hir, node);
                try self.collectIdentifierRefs(sp.expression, out);
            },
            .object_literal => {
                for (hir_mod.objectLiteralProps(self.hir, node)) |p| try self.collectIdentifierRefs(p, out);
            },
            .object_property => {
                const op = hir_mod.objectPropertyOf(self.hir, node);
                try self.collectIdentifierRefs(op.value, out);
                // Computed keys reference identifiers; skip the name slot.
                if (op.is_computed) try self.collectIdentifierRefs(op.key, out);
            },
            else => {},
        }
    }

    const BindingDefaultMode = enum { variable, parameter };
    const BindingSlot = struct {
        name: hir_mod.StringId,
        node: NodeId,
        default_value: NodeId,
    };
    const NameRef = struct {
        name: hir_mod.StringId,
        node: NodeId,
    };

    fn checkFnParameterDefaultReferences(self: *Checker, fn_node: NodeId) CheckError!void {
        var body_vars: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer body_vars.deinit(self.gpa);
        const fn_payload = hir_mod.fnDeclOf(self.hir, fn_node);
        try self.collectVarDeclNames(fn_payload.body, &body_vars);
        for (hir_mod.fnParams(self.hir, fn_node)) |p| {
            if (self.hir.kindOf(p) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, p);
            if (pp.name == hir_mod.none_node_id) continue;
            const nk = self.hir.kindOf(pp.name);
            if (nk == .object_pattern or nk == .array_pattern) {
                try self.checkPatternComputedBindingKeys(pp.name);
                try self.checkBindingPatternDefaultReferences(pp.name, .parameter);
                try self.checkPatternDefaultsAgainstBodyVars(pp.name, &body_vars);
            }
            if (pp.default_value != hir_mod.none_node_id) {
                _ = try self.checkExpression(pp.default_value);
                if (!self.sourceHasUseDefineForClassFieldsTrueDirective()) {
                    try self.checkDefaultExprAgainstBodyVars(pp.default_value, &body_vars);
                }
            }
            if (nk == .array_pattern and pp.default_value != hir_mod.none_node_id) {
                const default_t = try self.checkExpression(pp.default_value);
                if (!self.isIterableLikeType(default_t) and !self.objectLiteralHasSymbolIteratorMethod(pp.default_value)) {
                    try self.report(pp.default_value, TsCodes.yield_star_not_iterable, "Type must have a '[Symbol.iterator]()' method that returns an iterator.");
                }
            }
            if (nk == .object_pattern and pp.type_annotation != hir_mod.none_node_id) {
                const param_t = self.hir.typeOf(p);
                if (param_t != types.Primitive.none) try self.checkObjectBindingPatternAgainstType(pp.name, param_t);
            }
        }
    }

    fn collectVarDeclNames(
        self: *Checker,
        node: NodeId,
        out: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .block_stmt => for (hir_mod.blockStmts(self.hir, node)) |s| try self.collectVarDeclNames(s, out),
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                try self.collectBindingNames(v.name, out);
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                try self.collectVarDeclNames(i.then_branch, out);
                try self.collectVarDeclNames(i.else_branch, out);
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                try self.collectVarDeclNames(fr.init, out);
                try self.collectVarDeclNames(fr.body, out);
            },
            .for_in_stmt, .for_of_stmt => {
                const fr = hir_mod.forInOf(self.hir, node);
                try self.collectVarDeclNames(fr.target, out);
                try self.collectVarDeclNames(fr.body, out);
            },
            .while_stmt => try self.collectVarDeclNames(hir_mod.whileOf(self.hir, node).body, out),
            .do_while_stmt => try self.collectVarDeclNames(hir_mod.doWhileOf(self.hir, node).body, out),
            .switch_stmt => for (hir_mod.switchCases(self.hir, node)) |case| try self.collectVarDeclNames(case, out),
            .switch_case => for (hir_mod.switchCaseStmts(self.hir, node)) |s| try self.collectVarDeclNames(s, out),
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                try self.collectVarDeclNames(ts.block, out);
                try self.collectVarDeclNames(ts.catch_block, out);
                try self.collectVarDeclNames(ts.finally_block, out);
            },
            .fn_decl, .fn_expr, .arrow_fn, .class_decl, .class_expr => return,
            else => {},
        }
    }

    fn collectBindingNames(
        self: *Checker,
        node: NodeId,
        out: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, node);
                try out.put(self.gpa, id.name, {});
            },
            .object_pattern, .array_pattern => {
                var slots: std.ArrayListUnmanaged(BindingSlot) = .empty;
                defer slots.deinit(self.gpa);
                try self.collectBindingSlots(node, &slots);
                for (slots.items) |slot| try out.put(self.gpa, slot.name, {});
            },
            else => {},
        }
    }

    fn checkPatternDefaultsAgainstBodyVars(
        self: *Checker,
        pattern_node: NodeId,
        body_vars: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        var slots: std.ArrayListUnmanaged(BindingSlot) = .empty;
        defer slots.deinit(self.gpa);
        try self.collectBindingSlots(pattern_node, &slots);
        for (slots.items) |slot| {
            if (slot.default_value == hir_mod.none_node_id) continue;
            try self.checkDefaultExprAgainstBodyVars(slot.default_value, body_vars);
        }
    }

    fn checkDefaultExprAgainstBodyVars(
        self: *Checker,
        default_value: NodeId,
        body_vars: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        var refs: std.ArrayListUnmanaged(NameRef) = .empty;
        defer refs.deinit(self.gpa);
        try self.collectIdentifierRefsWithNodes(default_value, &refs);
        for (refs.items) |ref| {
            if (body_vars.contains(ref.name)) {
                try self.reportBindingDefaultReference(ref.node, .parameter, false);
            }
        }
    }

    fn checkBindingPatternDefaultReferences(
        self: *Checker,
        pattern_node: NodeId,
        mode: BindingDefaultMode,
    ) CheckError!void {
        var slots: std.ArrayListUnmanaged(BindingSlot) = .empty;
        defer slots.deinit(self.gpa);
        try self.collectBindingSlots(pattern_node, &slots);
        for (slots.items, 0..) |slot, i| {
            if (slot.default_value == hir_mod.none_node_id) continue;
            var refs: std.ArrayListUnmanaged(NameRef) = .empty;
            defer refs.deinit(self.gpa);
            try self.collectIdentifierRefsWithNodes(slot.default_value, &refs);
            for (refs.items) |ref| {
                var j: usize = i;
                while (j < slots.items.len) : (j += 1) {
                    const later = slots.items[j];
                    if (later.name != ref.name) continue;
                    try self.reportBindingDefaultReference(ref.node, mode, j == i);
                    break;
                }
            }
        }
    }

    fn collectBindingSlots(
        self: *Checker,
        pattern_node: NodeId,
        out: *std.ArrayListUnmanaged(BindingSlot),
    ) CheckError!void {
        const pk = self.hir.kindOf(pattern_node);
        if (pk != .object_pattern and pk != .array_pattern) return;
        for (hir_mod.patternElements(self.hir, pattern_node)) |e| {
            if (self.hir.kindOf(e) != .parameter) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (ep.flags.is_computed_binding_key) continue;
            if (ep.name == hir_mod.none_node_id) continue;
            const nk = self.hir.kindOf(ep.name);
            if (nk == .identifier) {
                const id = hir_mod.identifierOf(self.hir, ep.name);
                try out.append(self.gpa, .{
                    .name = id.name,
                    .node = ep.name,
                    .default_value = ep.default_value,
                });
            } else if (nk == .object_pattern or nk == .array_pattern) {
                try self.collectBindingSlots(ep.name, out);
            }
        }
    }

    fn checkPatternComputedBindingKeys(self: *Checker, pattern_node: NodeId) CheckError!void {
        const pk = self.hir.kindOf(pattern_node);
        if (pk != .object_pattern and pk != .array_pattern) return;
        for (hir_mod.patternElements(self.hir, pattern_node)) |e| {
            if (self.hir.kindOf(e) != .parameter) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (ep.flags.is_computed_binding_key) {
                if (ep.default_value != hir_mod.none_node_id) _ = try self.checkExpression(ep.default_value);
                continue;
            }
            if (ep.name == hir_mod.none_node_id) continue;
            const nk = self.hir.kindOf(ep.name);
            if (nk == .object_pattern or nk == .array_pattern) {
                try self.checkPatternComputedBindingKeys(ep.name);
            }
        }
    }

    fn collectIdentifierRefsWithNodes(
        self: *Checker,
        node: NodeId,
        out: *std.ArrayListUnmanaged(NameRef),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, node);
                try out.append(self.gpa, .{ .name = id.name, .node = node });
            },
            .fn_decl, .fn_expr, .arrow_fn => return,
            .block_stmt => for (hir_mod.blockStmts(self.hir, node)) |s| try self.collectIdentifierRefsWithNodes(s, out),
            .return_stmt => try self.collectIdentifierRefsWithNodes(hir_mod.returnOf(self.hir, node).value, out),
            .throw_stmt => try self.collectIdentifierRefsWithNodes(hir_mod.throwOf(self.hir, node).value, out),
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(v.init, out);
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(b.lhs, out);
                try self.collectIdentifierRefsWithNodes(b.rhs, out);
            },
            .unary_op => try self.collectIdentifierRefsWithNodes(hir_mod.unaryOf(self.hir, node).operand, out),
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(l.lhs, out);
                try self.collectIdentifierRefsWithNodes(l.rhs, out);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(c.cond, out);
                try self.collectIdentifierRefsWithNodes(c.then_branch, out);
                try self.collectIdentifierRefsWithNodes(c.else_branch, out);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(a.target, out);
                try self.collectIdentifierRefsWithNodes(a.value, out);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(c.callee, out);
                for (hir_mod.callArgs(self.hir, node)) |arg| try self.collectIdentifierRefsWithNodes(arg, out);
            },
            .member_access => try self.collectIdentifierRefsWithNodes(hir_mod.memberOf(self.hir, node).object, out),
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(e.object, out);
                try self.collectIdentifierRefsWithNodes(e.index, out);
            },
            .as_expr, .satisfies_expr, .type_assertion, .non_null_expr => {
                const a = hir_mod.asExpressionOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(a.expr, out);
            },
            .array_literal => for (hir_mod.arrayLiteralElements(self.hir, node)) |el| try self.collectIdentifierRefsWithNodes(el, out),
            .spread => try self.collectIdentifierRefsWithNodes(hir_mod.spreadOf(self.hir, node).expression, out),
            .object_literal => for (hir_mod.objectLiteralProps(self.hir, node)) |p| try self.collectIdentifierRefsWithNodes(p, out),
            .object_property => {
                const op = hir_mod.objectPropertyOf(self.hir, node);
                try self.collectIdentifierRefsWithNodes(op.value, out);
                if (op.is_computed) try self.collectIdentifierRefsWithNodes(op.key, out);
            },
            else => {},
        }
    }

    fn reportBindingDefaultReference(
        self: *Checker,
        node: NodeId,
        mode: BindingDefaultMode,
        is_self: bool,
    ) CheckError!void {
        const code: u32 = switch (mode) {
            .variable => TsCodes.block_scoped_used_before_decl,
            .parameter => if (is_self) TsCodes.parameter_cannot_reference_self else TsCodes.parameter_cannot_reference_later,
        };
        const msg: []const u8 = switch (mode) {
            .variable => "Block-scoped variable used before its declaration.",
            .parameter => if (is_self)
                "Parameter cannot reference itself in its initializer."
            else
                "Parameter cannot reference identifier declared after it.",
        };
        try self.report(node, code, msg);
    }

    fn checkObjectBindingPatternAgainstType(self: *Checker, pattern_node: NodeId, container_t: TypeId) CheckError!void {
        if (container_t == types.Primitive.any or container_t == types.Primitive.unknown) return;
        if (container_t >= self.interner.pool.typeCount()) return;
        if (container_t == types.Primitive.object_t) {
            try self.checkObjectBindingPatternAgainstBroadObject(pattern_node);
            return;
        }
        const flags = self.interner.pool.flagsOf(container_t);
        if (flags.is_union) {
            for (self.interner.unionMembers(container_t)) |member| {
                if (member < self.interner.pool.typeCount() and self.interner.pool.flagsOf(member).is_object_type and
                    self.interner.objectMembers(member).len == 0 and
                    self.interner.objectStringIndex(member) == types.Primitive.none and
                    self.interner.objectNumberIndex(member) == types.Primitive.none)
                {
                    return;
                }
            }
            for (self.interner.unionMembers(container_t)) |member| {
                try self.checkObjectBindingPatternAgainstType(pattern_node, member);
            }
            return;
        }
        if (!flags.is_object_type) return;
        const has_dynamic_computed_key = try self.checkObjectBindingComputedKeysAgainstType(pattern_node, container_t);
        for (hir_mod.patternElements(self.hir, pattern_node)) |e| {
            if (self.hir.kindOf(e) != .parameter) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (ep.name == hir_mod.none_node_id) continue;
            if (ep.flags.is_rest) {
                if (has_dynamic_computed_key and self.hir.kindOf(ep.name) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, ep.name);
                    const rest_t = self.interner.internObjectType(&.{}) catch return error.OutOfMemory;
                    try self.checkRepeatedObjectRestVarBinding(pattern_node, ep.name, id.name, rest_t);
                }
                continue;
            }
            const key_name = (try self.objectBindingElementKeyName(e, ep.name)) orelse continue;
            if (self.interner.objectMemberInfo(container_t, key_name)) |member| {
                _ = member;
                if (ep.default_value != hir_mod.none_node_id) {
                    _ = try self.checkExpression(ep.default_value);
                }
                continue;
            }
            if (self.interner.objectStringIndex(container_t) != types.Primitive.none) continue;
            if (self.interner.objectNumberIndex(container_t) != types.Primitive.none and self.isNumericStringId(key_name)) continue;
            if (ep.default_value != hir_mod.none_node_id) continue;
            const name_str = self.string_interner.get(key_name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Property '{s}' does not exist on type.",
                .{name_str},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = ep.name,
                .code = TsCodes.property_does_not_exist,
                .message = msg,
            });
        }
    }

    fn checkObjectBindingComputedKeysAgainstType(self: *Checker, pattern_node: NodeId, container_t: TypeId) CheckError!bool {
        var saw_dynamic = false;
        for (hir_mod.patternElements(self.hir, pattern_node)) |e| {
            if (self.hir.kindOf(e) != .parameter) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (ep.flags.is_computed_binding_key) {
                if (ep.default_value == hir_mod.none_node_id) continue;
                const key_t = try self.checkExpression(ep.default_value);
                if (try self.reportMissingIndexForComputedBindingKey(ep.default_value, container_t, key_t)) {
                    saw_dynamic = true;
                }
                continue;
            }
            if (ep.name == hir_mod.none_node_id) continue;
            const nk = self.hir.kindOf(ep.name);
            if (nk == .object_pattern or nk == .array_pattern) {
                if (try self.checkObjectBindingComputedKeysAgainstType(ep.name, types.Primitive.any)) saw_dynamic = true;
            }
        }
        return saw_dynamic;
    }

    fn reportMissingIndexForComputedBindingKey(self: *Checker, node: NodeId, container_t: TypeId, key_t: TypeId) CheckError!bool {
        if (container_t == types.Primitive.any or container_t == types.Primitive.unknown) return false;
        if (key_t == types.Primitive.any or key_t == types.Primitive.unknown) return false;
        switch (self.hir.kindOf(node)) {
            .literal_string, .literal_number, .literal_bool, .literal_bigint => return false,
            else => {},
        }
        if (container_t >= self.interner.pool.typeCount()) return false;
        const cf = self.interner.pool.flagsOf(container_t);
        if (cf.is_union) {
            var reported = false;
            for (self.interner.unionMembers(container_t)) |member| {
                if (try self.reportMissingIndexForComputedBindingKey(node, member, key_t)) reported = true;
            }
            return reported;
        }
        if (!cf.is_object_type) return false;
        const key_kind = try self.dynamicComputedIndexKind(key_t) orelse return false;
        const has_index = switch (key_kind) {
            .string => self.interner.objectStringIndex(container_t) != types.Primitive.none,
            .number => self.interner.objectNumberIndex(container_t) != types.Primitive.none,
            .symbol => self.interner.objectSymbolIndex(container_t) != types.Primitive.none,
        };
        if (has_index) return true;
        const kind_text = switch (key_kind) {
            .string => "string",
            .number => "number",
            .symbol => "symbol",
        };
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Type has no matching index signature for type '{s}'.",
            .{kind_text},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.no_matching_index_signature,
            .message = msg,
        });
        return true;
    }

    fn dynamicComputedIndexKind(self: *Checker, key_t: TypeId) CheckError!?IndexKind {
        if (key_t == types.Primitive.string_t) return .string;
        if (key_t == types.Primitive.number_t) return .number;
        if (key_t == types.Primitive.symbol_t) return .symbol;
        if (key_t >= self.interner.pool.typeCount()) return null;
        const f = self.interner.pool.flagsOf(key_t);
        if (f.is_literal) return null;
        if (f.is_string) return .string;
        if (f.is_number) return .number;
        if (f.is_symbol) return .symbol;
        if (f.is_union) {
            var result: ?IndexKind = null;
            for (self.interner.unionMembers(key_t)) |member| {
                const member_kind = (try self.dynamicComputedIndexKind(member)) orelse return null;
                if (result) |existing| {
                    if (existing != member_kind) return null;
                } else {
                    result = member_kind;
                }
            }
            return result;
        }
        return null;
    }

    fn checkObjectBindingPatternAgainstBroadObject(self: *Checker, pattern_node: NodeId) CheckError!void {
        for (hir_mod.patternElements(self.hir, pattern_node)) |e| {
            if (self.hir.kindOf(e) != .parameter) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (ep.name == hir_mod.none_node_id or ep.flags.is_rest) continue;
            if (self.hir.kindOf(ep.name) != .identifier) continue;
            if (!self.objectBindingElementUsesImplicitKey(e, ep.name)) continue;
            const id = hir_mod.identifierOf(self.hir, ep.name);
            const name_str = self.string_interner.get(id.name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Property '{s}' does not exist on type.",
                .{name_str},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = ep.name,
                .code = TsCodes.property_does_not_exist,
                .message = msg,
            });
        }
    }

    fn checkArrayBindingPatternAgainstType(self: *Checker, pattern_node: NodeId, container_t: TypeId) CheckError!void {
        if (container_t == types.Primitive.any or container_t == types.Primitive.unknown) return;
        if (container_t >= self.interner.pool.typeCount()) return;
        const elem_t = try self.iterableElementType(container_t);
        const rest_array_t = self.interner.internArrayType(self.string_interner, elem_t) catch return error.OutOfMemory;
        for (hir_mod.patternElements(self.hir, pattern_node)) |e| {
            if (self.hir.kindOf(e) != .parameter) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (!ep.flags.is_rest or ep.name == hir_mod.none_node_id) continue;
            if (self.hir.kindOf(ep.name) == .object_pattern) {
                try self.checkObjectBindingPatternAgainstType(ep.name, rest_array_t);
            }
        }
    }

    fn reportImplicitAnyNullishArrayBinding(self: *Checker, pattern_node: NodeId, init_node: NodeId) CheckError!void {
        if (!self.strict_flags.no_implicit_any) return;
        if (self.hir.kindOf(pattern_node) != .array_pattern or self.hir.kindOf(init_node) != .array_literal) return;
        const values = hir_mod.arrayLiteralElements(self.hir, init_node);
        for (hir_mod.patternElements(self.hir, pattern_node), 0..) |e, i| {
            if (self.hir.kindOf(e) != .parameter) continue;
            if (i >= values.len) break;
            const value = values[i];
            if (value == hir_mod.none_node_id) continue;
            const vk = self.hir.kindOf(value);
            if (vk != .literal_null and vk != .literal_undefined) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (ep.name == hir_mod.none_node_id or self.hir.kindOf(ep.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, ep.name);
            const raw = self.string_interner.get(id.name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Binding element '{s}' implicitly has an 'any' type.",
                .{raw},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = ep.name,
                .code = TsCodes.binding_element_implicitly_any,
                .message = msg,
            });
        }
    }

    fn isNumericStringId(self: *Checker, name: hir_mod.StringId) bool {
        const s = self.string_interner.get(name);
        if (s.len == 0) return false;
        for (s) |c| {
            if (c < '0' or c > '9') return false;
        }
        return true;
    }

    fn objectBindingElementUsesImplicitKey(self: *Checker, elem_node: NodeId, name_node: NodeId) bool {
        const src = self.source orelse return true;
        const elem_span = self.hir.spanOf(elem_node);
        const name_span = self.hir.spanOf(name_node);
        if (name_span.start <= elem_span.start or name_span.start > src.len) return true;
        const prefix = src[elem_span.start..@min(@as(usize, name_span.start), src.len)];
        return std.mem.indexOfScalar(u8, prefix, ':') == null and
            std.mem.indexOfScalar(u8, prefix, '[') == null;
    }

    fn objectBindingElementKeyName(self: *Checker, elem_node: NodeId, name_node: NodeId) CheckError!?hir_mod.StringId {
        if (name_node == hir_mod.none_node_id) return null;
        if (self.hir.kindOf(name_node) == .identifier and self.objectBindingElementUsesImplicitKey(elem_node, name_node)) {
            return hir_mod.identifierOf(self.hir, name_node).name;
        }
        const src = self.source orelse return null;
        const elem_span = self.hir.spanOf(elem_node);
        const name_span = self.hir.spanOf(name_node);
        if (elem_span.start >= src.len or name_span.start > src.len or name_span.start <= elem_span.start) return null;
        const prefix = src[elem_span.start..name_span.start];
        const colon = std.mem.indexOfScalar(u8, prefix, ':') orelse return null;
        var raw = std.mem.trim(u8, prefix[0..colon], " \t\r\n");
        if (raw.len >= 2 and ((raw[0] == '"' and raw[raw.len - 1] == '"') or (raw[0] == '\'' and raw[raw.len - 1] == '\''))) {
            raw = raw[1 .. raw.len - 1];
        }
        if (raw.len == 0) return null;
        return self.string_interner.intern(raw) catch return error.OutOfMemory;
    }

    /// True when `node` is the name slot of its enclosing
    /// declaration (parameter / var / fn / class / interface /
    /// type alias). Used to filter declarations out of the
    /// reference-counting walk.
    fn isDeclNameSlot(self: *Checker, node: NodeId) bool {
        const parent = self.hir.parentOf(node);
        if (parent == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(parent)) {
            .parameter => {
                const p = hir_mod.parameterOf(self.hir, parent);
                return p.name == node;
            },
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, parent);
                return v.name == node;
            },
            .fn_decl, .fn_expr, .arrow_fn => {
                const f = hir_mod.fnDeclOf(self.hir, parent);
                return f.name == node;
            },
            .class_decl, .class_expr => {
                const c = hir_mod.classOf(self.hir, parent);
                return c.name == node;
            },
            .interface_decl => {
                const it = hir_mod.interfaceOf(self.hir, parent);
                return it.name == node;
            },
            .type_alias_decl => {
                const ta = hir_mod.typeAliasOf(self.hir, parent);
                return ta.name == node;
            },
            else => return false,
        }
    }

    /// If `t` is structurally a `Promise<T>` — an object type with a
    /// `then` member whose first parameter is itself a signature
    /// `(value: T) => any` — return `T`. Otherwise return `t`
    /// unchanged. This lets `await p` unwrap to the resolved value
    /// type without first-class generics support.
    fn unwrapPromise(self: *Checker, t: TypeId) TypeId {
        if (!self.interner.pool.flagsOf(t).is_object_type) return t;
        const then_id = self.string_interner.intern("then") catch return t;
        const then_t = self.interner.objectMember(t, then_id) orelse return t;
        if (!self.interner.pool.flagsOf(then_t).is_signature) return t;
        const then_params = self.interner.signatureParams(then_t);
        if (then_params.len == 0) return t;
        const cb_t = then_params[0];
        if (!self.interner.pool.flagsOf(cb_t).is_signature) return t;
        const cb_params = self.interner.signatureParams(cb_t);
        if (cb_params.len == 0) return t;
        return cb_params[0];
    }

    /// `Awaited<T>` (TS 4.5) — recursively unwrap `Promise<U>` until
    /// the operand is no longer a structural Promise. For non-Promise
    /// types this is a no-op and `t` is returned unchanged.
    fn evalAwaited(self: *Checker, t: TypeId) TypeId {
        var cur = t;
        // Cap recursion in case of pathological self-referential
        // Promise shapes; TS itself imposes no fixed depth, but a
        // small bound matches the practical universe of Promise<...>
        // chains and prevents runaway loops on cyclic types.
        var i: usize = 0;
        while (i < 64) : (i += 1) {
            const next = self.unwrapPromise(cur);
            if (next == cur) return cur;
            cur = next;
        }
        return cur;
    }

    /// Build a minimal structural `Promise<T>` object type — `{ then:
    /// (onfulfilled: (value: T) => any, onrejected?: any) => any }` —
    /// used when intercepting `Promise<T>` type-refs so downstream
    /// Awaited / await unwrap machinery can recognize and peel them.
    fn buildStructuralPromise(self: *Checker, value_t: TypeId) CheckError!TypeId {
        const cb_params = [_]TypeId{value_t};
        const cb_sig = self.interner.internSignature(&cb_params, types.Primitive.any, false) catch return error.OutOfMemory;
        var any_or_undefined_members = [_]TypeId{ types.Primitive.any, types.Primitive.undefined_t };
        const optional_any = self.interner.internUnion(&any_or_undefined_members) catch return error.OutOfMemory;
        const then_params = [_]TypeId{ cb_sig, optional_any };
        const then_sig = self.interner.internSignature(&then_params, types.Primitive.any, false) catch return error.OutOfMemory;
        const finally_cb_sig = self.interner.internSignature(&[_]TypeId{}, types.Primitive.any, false) catch return error.OutOfMemory;
        const finally_sig = self.interner.internSignature(&[_]TypeId{finally_cb_sig}, types.Primitive.any, false) catch return error.OutOfMemory;
        const then_id = self.string_interner.intern("then") catch return error.OutOfMemory;
        const finally_id = self.string_interner.intern("finally") catch return error.OutOfMemory;
        const value_id = self.string_interner.intern("__home_promise_value") catch return error.OutOfMemory;
        const members = [_]types.ObjectMember{
            .{
                .name = then_id,
                .type = then_sig,
                .is_optional = false,
                .is_readonly = false,
                .is_method = true,
            },
            .{
                .name = finally_id,
                .type = finally_sig,
                .is_optional = false,
                .is_readonly = false,
                .is_method = true,
            },
            .{
                .name = value_id,
                .type = value_t,
                .is_optional = false,
                .is_readonly = true,
                .is_method = false,
            },
        };
        return self.interner.internObjectType(&members) catch return error.OutOfMemory;
    }

    fn moduleNamespaceTypeForImportBinding(self: *Checker, decl: NodeId) CheckError!?TypeId {
        if (self.hir.kindOf(decl) != .identifier) return null;
        const parent = self.hir.parentOf(decl);
        if (parent == hir_mod.none_node_id or self.hir.kindOf(parent) != .import_decl) return null;
        const imp = hir_mod.importOf(self.hir, parent);
        const spec = self.string_interner.get(imp.module);
        if (imp.namespace_binding != decl and
            !(imp.default_binding == decl and std.mem.startsWith(u8, spec, ".") and self.importDeclIsRequireAssignment(parent))) return null;
        return try self.moduleNamespaceTypeForSpecifier(imp.module, parent);
    }

    fn moduleNamespaceTypeForLocalImport(self: *Checker, name: hir_mod.StringId, anchor: NodeId) CheckError!?TypeId {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            const spec = self.string_interner.get(imp.module);
            const binding = if (imp.namespace_binding != hir_mod.none_node_id)
                imp.namespace_binding
            else if (imp.default_binding != hir_mod.none_node_id and std.mem.startsWith(u8, spec, ".") and self.importDeclIsRequireAssignment(stmt))
                imp.default_binding
            else
                hir_mod.none_node_id;
            if (binding == hir_mod.none_node_id or self.hir.kindOf(binding) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, binding);
            if (id.name != name) continue;
            return try self.moduleNamespaceTypeForSpecifier(imp.module, stmt);
        }
        return null;
    }

    fn moduleNamespaceTypeForSpecifier(self: *Checker, specifier: hir_mod.StringId, anchor: NodeId) CheckError!?TypeId {
        if (!self.sourceHasVirtualFilenameSections()) return null;
        const spec = self.string_interner.get(specifier);
        if (!std.mem.startsWith(u8, spec, ".")) return null;
        const from = self.virtualSectionFilenameForNode(anchor) orelse return null;
        const resolved = try self.resolveVirtualRelativePath(from, spec);
        defer self.gpa.free(resolved);
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        var found_module = false;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            if (!self.virtualSectionMatchesResolvedModule(raw, resolved, spec)) continue;
            found_module = true;
            if (self.hir.kindOf(raw) != .export_decl) continue;
            const ex = hir_mod.exportOf(self.hir, raw);
            if (ex.is_default) {
                const default_name = self.string_interner.intern("default") catch return error.OutOfMemory;
                const default_t = if (ex.decl != hir_mod.none_node_id and self.hir.typeOf(ex.decl) != types.Primitive.none)
                    self.hir.typeOf(ex.decl)
                else
                    types.Primitive.any;
                try members.append(self.gpa, .{
                    .name = default_name,
                    .type = default_t,
                    .is_optional = false,
                    .is_readonly = true,
                    .is_method = false,
                });
                continue;
            }
            if (ex.decl == hir_mod.none_node_id and ex.named_len > 0 and !ex.is_type_only) {
                for (hir_mod.exportNamed(self.hir, raw)) |spec_node| {
                    if (self.hir.kindOf(spec_node) != .import_specifier) continue;
                    const sp = hir_mod.importSpecifierOf(self.hir, spec_node);
                    if (sp.is_type_only) continue;
                    const member_t = (try self.localValueTypeInVirtualSection(raw, sp.imported)) orelse types.Primitive.any;
                    const exported_name = self.exportSpecifierExportedName(spec_node, sp);
                    try members.append(self.gpa, .{
                        .name = exported_name,
                        .type = member_t,
                        .is_optional = false,
                        .is_readonly = true,
                        .is_method = false,
                    });
                }
                continue;
            }
            const decl = self.unwrapExportDecl(raw);
            if (!self.namespaceExportCreatesValue(decl)) continue;
            const name = self.declarationName(decl) orelse continue;
            const member_t = try self.exportedValueTypeForNamespaceMember(decl, name);
            if (member_t == types.Primitive.none) continue;
            try members.append(self.gpa, .{
                .name = name,
                .type = member_t,
                .is_optional = false,
                .is_readonly = true,
                .is_method = false,
            });
        }
        if (!found_module) return null;
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn localValueTypeInVirtualSection(self: *Checker, anchor: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const section = self.virtualSectionStartForNode(anchor);
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.virtualSectionStartForNode(stmt) != section) continue;
            const decl = self.unwrapExportDecl(stmt);
            const decl_name = self.declarationName(decl) orelse continue;
            if (decl_name != name) continue;
            if (!self.namespaceExportCreatesValue(decl)) continue;
            return try self.exportedValueTypeForNamespaceMember(decl, name);
        }
        return null;
    }

    fn exportSpecifierExportedName(self: *Checker, spec_node: NodeId, sp: hir_mod.ImportSpecifierPayload) hir_mod.StringId {
        const src = self.source orelse return sp.local;
        const span = self.hir.spanOf(spec_node);
        if (span.start >= span.end or span.end > src.len) return sp.local;
        const text = src[span.start..span.end];
        var it = std.mem.tokenizeAny(u8, text, " \t\r\n");
        _ = it.next() orelse return sp.local;
        const maybe_as = it.next() orelse return sp.imported;
        if (std.mem.eql(u8, maybe_as, "as")) return sp.local;
        return sp.imported;
    }

    fn exportedValueTypeForNamespaceMember(self: *Checker, decl: NodeId, name: hir_mod.StringId) CheckError!TypeId {
        if (self.hir.kindOf(decl) == .class_decl or self.hir.kindOf(decl) == .class_expr) {
            if (self.class_static_types.get(name)) |static_t| return static_t;
        }
        if (self.hir.kindOf(decl) == .enum_decl) {
            return try self.enumNamespaceValueType(decl, name);
        }
        const t = self.hir.typeOf(decl);
        return if (t != types.Primitive.none) t else types.Primitive.any;
    }

    fn enumNamespaceValueType(self: *Checker, decl: NodeId, enum_name: hir_mod.StringId) CheckError!TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        const enum_t = try self.enumNominalType(enum_name);
        for (hir_mod.enumMembers(self.hir, decl)) |member| {
            if (self.hir.kindOf(member) != .object_property) continue;
            const prop = hir_mod.objectPropertyOf(self.hir, member);
            const member_name: ?hir_mod.StringId = switch (self.hir.kindOf(prop.key)) {
                .identifier => hir_mod.identifierOf(self.hir, prop.key).name,
                .literal_string => hir_mod.literalStringOf(self.hir, prop.key).value,
                else => null,
            };
            if (member_name == null) continue;
            try members.append(self.gpa, .{
                .name = member_name.?,
                .type = enum_t,
                .is_optional = false,
                .is_readonly = true,
                .is_method = false,
            });
        }
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn virtualSectionMatchesSpecifier(self: *Checker, src: []const u8, node: NodeId, spec: []const u8) bool {
        const section = self.virtualSectionStartForNode(node);
        if (section >= src.len) return false;
        const line_end = std.mem.indexOfScalarPos(u8, src, section, '\n') orelse src.len;
        const line = src[section..line_end];
        const marker = std.mem.indexOf(u8, line, "@filename:") orelse
            (std.mem.indexOf(u8, line, "@Filename:") orelse return false);
        const filename = std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
        return self.moduleSpecifierMatchesFilename(spec, filename);
    }

    fn moduleSpecifierMatchesFilename(self: *Checker, spec: []const u8, filename: []const u8) bool {
        _ = self;
        var spec_tail = spec;
        while (std.mem.startsWith(u8, spec_tail, "./")) spec_tail = spec_tail[2..];
        while (std.mem.startsWith(u8, spec_tail, "../")) spec_tail = spec_tail[3..];
        if (std.mem.lastIndexOfScalar(u8, spec_tail, '/')) |idx| spec_tail = spec_tail[idx + 1 ..];
        var file_tail = filename;
        if (std.mem.lastIndexOfScalar(u8, file_tail, '/')) |idx| file_tail = file_tail[idx + 1 ..];
        return std.mem.eql(u8, spec_tail, file_tail) or
            (std.mem.endsWith(u8, file_tail, ".ts") and std.mem.eql(u8, spec_tail, file_tail[0 .. file_tail.len - ".ts".len])) or
            (std.mem.endsWith(u8, file_tail, ".tsx") and std.mem.eql(u8, spec_tail, file_tail[0 .. file_tail.len - ".tsx".len]));
    }

    /// Re-intern the function's signature with `new_ret` as the
    /// return type, then update the node's type. Identifier lookups
    /// against the function's name see the refined signature.
    fn refineSignatureReturn(self: *Checker, fn_node: NodeId, new_ret: TypeId) CheckError!void {
        const sig = self.hir.typeOf(fn_node);
        if (!self.interner.pool.flagsOf(sig).is_signature) return;
        const params = self.interner.signatureParams(sig);
        // Skip if the inferred type is the same as what we already
        // had (avoids re-interning a no-op).
        if (self.interner.signatureReturn(sig)) |old| if (old == new_ret) return;
        const new_sig = self.interner.internSignature(params, new_ret, false) catch return error.OutOfMemory;
        // Carry the rest-parameter marker forward — re-interning with
        // a refined return type produces a fresh TypeId, but the
        // parameter list (incl. rest-ness) is unchanged.
        if (self.rest_signatures.contains(sig)) {
            try self.rest_signatures.put(self.gpa, new_sig, {});
        }
        if (self.signature_min_args.get(sig)) |min_required| {
            try self.signature_min_args.put(self.gpa, new_sig, min_required);
        }
        const recorded_node_params = try self.recordFunctionNodeGenericSignatureParams(new_sig, fn_node);
        if (!recorded_node_params) if (self.generic_signature_params.get(sig)) |type_params| {
            try self.recordGenericSignatureParams(new_sig, type_params);
        };
        if (self.signature_this_params.get(sig)) |this_t| {
            try self.signature_this_params.put(self.gpa, new_sig, this_t);
        }
        self.hir.setType(fn_node, new_sig);
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.name != hir_mod.none_node_id) self.hir.setType(f.name, new_sig);
    }

    fn contextualReturnTypeForFunction(self: *Checker, fn_node: NodeId) ?TypeId {
        const parent = self.hir.parentOf(fn_node);
        if (parent == hir_mod.none_node_id) return null;
        var target_t: TypeId = types.Primitive.none;
        switch (self.hir.kindOf(parent)) {
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, parent);
                if (v.init != fn_node) return null;
                target_t = self.hir.typeOf(parent);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, parent);
                if (a.value != fn_node or a.target == hir_mod.none_node_id) return null;
                target_t = self.hir.typeOf(a.target);
            },
            else => return null,
        }
        if (target_t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(target_t);
        if (flags.is_signature) return self.interner.signatureReturn(target_t);
        if (flags.is_union) {
            var found: TypeId = types.Primitive.none;
            for (self.interner.unionMembers(target_t)) |member| {
                if (member >= self.interner.pool.typeCount()) continue;
                if (!self.interner.pool.flagsOf(member).is_signature) continue;
                const ret = self.interner.signatureReturn(member) orelse continue;
                if (found == types.Primitive.none) {
                    found = ret;
                } else if (found != ret) {
                    return null;
                }
            }
            return if (found == types.Primitive.none) null else found;
        }
        return null;
    }

    fn returnStatementViolatesGenericRestTuple(self: *Checker, return_node: NodeId, ret_t: TypeId) bool {
        const fn_node = self.enclosingFunctionForReturn(return_node) orelse return false;
        if (!self.functionHasGenericRestTupleReturn(fn_node)) return false;
        const fn_t = self.hir.typeOf(fn_node);
        if (fn_t >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(fn_t).is_signature) return false;
        const expected_t = self.interner.signatureReturn(fn_t) orelse return false;
        return ret_t != expected_t;
    }

    fn enclosingFunctionForReturn(self: *Checker, return_node: NodeId) ?NodeId {
        var cur = self.hir.parentOf(return_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) return cur;
        }
        return null;
    }

    fn functionHasGenericRestTupleReturn(self: *Checker, fn_node: NodeId) bool {
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.return_type == hir_mod.none_node_id or self.hir.kindOf(f.return_type) != .tuple_type) return false;
        var saw_generic_rest = false;
        for (hir_mod.tupleTypeElements(self.hir, f.return_type)) |elem| {
            if (self.hir.kindOf(elem) != .rest_type) continue;
            const rt = hir_mod.restTypeOf(self.hir, elem);
            const operand = if (self.hir.kindOf(rt.operand) == .array_type)
                hir_mod.arrayTypeOf(self.hir, rt.operand).element
            else
                rt.operand;
            if (self.typeNodeNamesFunctionTypeParameter(operand, fn_node)) {
                saw_generic_rest = true;
                continue;
            }
            const operand_t = self.hir.typeOf(operand);
            if (operand_t >= self.interner.pool.typeCount()) continue;
            if (self.interner.pool.flagsOf(operand_t).is_type_parameter) saw_generic_rest = true;
        }
        return saw_generic_rest;
    }

    fn typeNodeNamesFunctionTypeParameter(self: *Checker, type_node: NodeId, fn_node: NodeId) bool {
        if (type_node == hir_mod.none_node_id or self.hir.kindOf(type_node) != .type_ref) return false;
        const r = hir_mod.typeRefOf(self.hir, type_node);
        for (hir_mod.fnTypeParams(self.hir, fn_node)) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            if (hir_mod.typeParameterOf(self.hir, tp).name == r.name) return true;
        }
        return false;
    }

    /// Walk a node tree collecting the types of every `return value`
    /// statement reachable from `node`, but stop at any nested
    /// function boundary so inner-fn returns don't leak into the
    /// outer signature.
    fn collectReturnTypes(
        self: *Checker,
        node: NodeId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(node);
        switch (k) {
            .return_stmt => {
                const r = hir_mod.returnOf(self.hir, node);
                if (r.value != hir_mod.none_node_id) {
                    try out.append(self.gpa, self.hir.typeOf(r.value));
                }
            },
            // Don't descend into nested functions — their returns
            // bind to their own signature.
            .fn_decl, .fn_expr, .arrow_fn => return,
            else => {
                // Walk every child of this node. The HIR exposes
                // a generic per-payload accessor pattern; here we
                // just iterate all child nodes via `forEachChild`.
                try self.forEachChildCollect(node, out);
            },
        }
    }

    fn firstReturnExpressionType(self: *Checker, node: NodeId) CheckError!?TypeId {
        if (node == hir_mod.none_node_id) return null;
        switch (self.hir.kindOf(node)) {
            .return_stmt => {
                const r = hir_mod.returnOf(self.hir, node);
                if (r.value == hir_mod.none_node_id) return types.Primitive.void_t;
                return try self.checkExpression(r.value);
            },
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |s| {
                    if (try self.firstReturnExpressionType(s)) |t| return t;
                }
                return null;
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                if (try self.firstReturnExpressionType(i.then_branch)) |t| return t;
                return try self.firstReturnExpressionType(i.else_branch);
            },
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                if (try self.firstReturnExpressionType(ts.block)) |t| return t;
                if (try self.firstReturnExpressionType(ts.catch_block)) |t| return t;
                return try self.firstReturnExpressionType(ts.finally_block);
            },
            .fn_decl, .fn_expr, .arrow_fn => return null,
            else => return null,
        }
    }

    fn firstReturnExpressionTypeWithClassMemberThis(
        self: *Checker,
        node: NodeId,
        is_static: bool,
        instance_members: []const types.ObjectMember,
        static_members: []const types.ObjectMember,
        string_idx: TypeId,
        number_idx: TypeId,
        symbol_idx: TypeId,
        static_string_idx: TypeId,
        static_number_idx: TypeId,
        static_symbol_idx: TypeId,
        parent_instance_t: ?TypeId,
        parent_static_t: ?TypeId,
    ) CheckError!?TypeId {
        const this_id = self.string_interner.intern("this") catch return error.OutOfMemory;
        const super_id = self.string_interner.intern("super") catch return error.OutOfMemory;
        var merged_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer merged_members.deinit(self.gpa);
        const own_members = if (is_static) static_members else instance_members;
        const inherited_t = if (is_static) parent_static_t else parent_instance_t;
        if (inherited_t) |pt| {
            if (pt < self.interner.pool.typeCount() and self.interner.pool.flagsOf(pt).is_object_type) {
                try merged_members.appendSlice(self.gpa, self.interner.objectMembers(pt));
            }
        }
        try merged_members.appendSlice(self.gpa, own_members);
        const this_string_idx = if (is_static) static_string_idx else string_idx;
        const this_number_idx = if (is_static) static_number_idx else number_idx;
        const this_symbol_idx = if (is_static) static_symbol_idx else symbol_idx;
        const this_t = self.interner.internObjectTypeWithIndexAndSymbol(
            merged_members.items,
            this_string_idx,
            this_number_idx,
            this_symbol_idx,
        ) catch return error.OutOfMemory;
        try self.pushNarrowScope();
        defer self.popNarrowScope();
        try self.recordNarrow(this_id, this_t);
        const super_t = if (is_static) parent_static_t else parent_instance_t;
        if (super_t) |st| try self.recordNarrow(super_id, st);
        return try self.firstReturnExpressionType(node);
    }

    fn forEachChildCollect(
        self: *Checker,
        node: NodeId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        const k = self.hir.kindOf(node);
        switch (k) {
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |s| try self.collectReturnTypes(s, out);
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                try self.collectReturnTypes(i.then_branch, out);
                try self.collectReturnTypes(i.else_branch, out);
            },
            .while_stmt => {
                const w = hir_mod.whileOf(self.hir, node);
                try self.collectReturnTypes(w.body, out);
            },
            .do_while_stmt => {
                const w = hir_mod.doWhileOf(self.hir, node);
                try self.collectReturnTypes(w.body, out);
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                try self.collectReturnTypes(fr.body, out);
            },
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                try self.collectReturnTypes(ts.block, out);
                if (ts.catch_block != hir_mod.none_node_id) try self.collectReturnTypes(ts.catch_block, out);
                if (ts.finally_block != hir_mod.none_node_id) try self.collectReturnTypes(ts.finally_block, out);
            },
            .switch_stmt => {
                for (hir_mod.switchCases(self.hir, node)) |case| try self.collectReturnTypes(case, out);
            },
            .switch_case => {
                for (hir_mod.switchCaseStmts(self.hir, node)) |s| try self.collectReturnTypes(s, out);
            },
            else => {},
        }
    }

    /// Walk a node tree collecting the operand types of every
    /// `yield expr` reachable from `node`, but stop at any nested
    /// function boundary so inner-fn yields don't leak into the
    /// outer generator's element type. Used by generator return-type
    /// inference to discover the yield-type T.
    fn collectYieldTypes(
        self: *Checker,
        node: NodeId,
        out: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(node);
        switch (k) {
            .yield_expr => {
                const y = hir_mod.yieldExprOf(self.hir, node);
                if (y.expr != hir_mod.none_node_id) {
                    try out.append(self.gpa, self.hir.typeOf(y.expr));
                } else {
                    try out.append(self.gpa, types.Primitive.undefined_t);
                }
            },
            // Don't descend into nested fns — their `yield`s belong
            // to that inner generator, not us.
            .fn_decl, .fn_expr, .arrow_fn => return,
            .block_stmt => for (hir_mod.blockStmts(self.hir, node)) |s| try self.collectYieldTypes(s, out),
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                try self.collectYieldTypes(i.then_branch, out);
                try self.collectYieldTypes(i.else_branch, out);
            },
            .while_stmt => {
                const w = hir_mod.whileOf(self.hir, node);
                try self.collectYieldTypes(w.body, out);
            },
            .do_while_stmt => {
                const w = hir_mod.doWhileOf(self.hir, node);
                try self.collectYieldTypes(w.body, out);
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                try self.collectYieldTypes(fr.body, out);
            },
            .for_in_stmt, .for_of_stmt => {
                const fr = hir_mod.forInOf(self.hir, node);
                try self.collectYieldTypes(fr.body, out);
            },
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                try self.collectYieldTypes(ts.block, out);
                if (ts.catch_block != hir_mod.none_node_id) try self.collectYieldTypes(ts.catch_block, out);
                if (ts.finally_block != hir_mod.none_node_id) try self.collectYieldTypes(ts.finally_block, out);
            },
            .switch_stmt => {
                for (hir_mod.switchCases(self.hir, node)) |case| try self.collectYieldTypes(case, out);
            },
            .switch_case => {
                for (hir_mod.switchCaseStmts(self.hir, node)) |s| try self.collectYieldTypes(s, out);
            },
            else => {},
        }
    }

    fn reportImplicitAnyYieldOperands(self: *Checker, node: NodeId) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .yield_expr => {
                const y = hir_mod.yieldExprOf(self.hir, node);
                if (y.expr != hir_mod.none_node_id) {
                    if (self.hir.kindOf(y.expr) == .yield_expr) {
                        const inner = hir_mod.yieldExprOf(self.hir, y.expr);
                        if (inner.expr == hir_mod.none_node_id) {
                            try self.report(y.expr, TsCodes.yield_implicit_any, "'yield' expression implicitly results in an 'any' type because its containing generator lacks a return-type annotation.");
                        }
                    }
                    try self.reportImplicitAnyYieldOperands(y.expr);
                }
            },
            .fn_decl, .fn_expr, .arrow_fn => return,
            .block_stmt => for (hir_mod.blockStmts(self.hir, node)) |s| try self.reportImplicitAnyYieldOperands(s),
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(i.cond);
                try self.reportImplicitAnyYieldOperands(i.then_branch);
                try self.reportImplicitAnyYieldOperands(i.else_branch);
            },
            .while_stmt => {
                const w = hir_mod.whileOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(w.cond);
                try self.reportImplicitAnyYieldOperands(w.body);
            },
            .do_while_stmt => {
                const w = hir_mod.doWhileOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(w.cond);
                try self.reportImplicitAnyYieldOperands(w.body);
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(fr.init);
                try self.reportImplicitAnyYieldOperands(fr.cond);
                try self.reportImplicitAnyYieldOperands(fr.update);
                try self.reportImplicitAnyYieldOperands(fr.body);
            },
            .for_in_stmt, .for_of_stmt => {
                const fr = hir_mod.forInOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(fr.target);
                try self.reportImplicitAnyYieldOperands(fr.source);
                try self.reportImplicitAnyYieldOperands(fr.body);
            },
            .return_stmt => try self.reportImplicitAnyYieldOperands(hir_mod.returnOf(self.hir, node).value),
            .var_decl, .let_decl, .const_decl => try self.reportImplicitAnyYieldOperands(hir_mod.varDeclOf(self.hir, node).init),
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(b.lhs);
                try self.reportImplicitAnyYieldOperands(b.rhs);
            },
            .unary_op => try self.reportImplicitAnyYieldOperands(hir_mod.unaryOf(self.hir, node).operand),
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(l.lhs);
                try self.reportImplicitAnyYieldOperands(l.rhs);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(c.cond);
                try self.reportImplicitAnyYieldOperands(c.then_branch);
                try self.reportImplicitAnyYieldOperands(c.else_branch);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(a.target);
                try self.reportImplicitAnyYieldOperands(a.value);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(c.callee);
                for (hir_mod.callArgs(self.hir, node)) |arg| try self.reportImplicitAnyYieldOperands(arg);
            },
            .member_access => try self.reportImplicitAnyYieldOperands(hir_mod.memberOf(self.hir, node).object),
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(e.object);
                try self.reportImplicitAnyYieldOperands(e.index);
            },
            .as_expr, .satisfies_expr, .type_assertion => try self.reportImplicitAnyYieldOperands(hir_mod.asExpressionOf(self.hir, node).expr),
            .throw_stmt => try self.reportImplicitAnyYieldOperands(hir_mod.throwOf(self.hir, node).value),
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(ts.block);
                try self.reportImplicitAnyYieldOperands(ts.catch_block);
                try self.reportImplicitAnyYieldOperands(ts.finally_block);
            },
            .switch_stmt => {
                const sw = hir_mod.switchOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(sw.discriminant);
                for (hir_mod.switchCases(self.hir, node)) |case| try self.reportImplicitAnyYieldOperands(case);
            },
            .switch_case => for (hir_mod.switchCaseStmts(self.hir, node)) |s| try self.reportImplicitAnyYieldOperands(s),
            .array_literal => for (hir_mod.arrayLiteralElements(self.hir, node)) |el| try self.reportImplicitAnyYieldOperands(el),
            .object_literal => for (hir_mod.objectLiteralProps(self.hir, node)) |p| try self.reportImplicitAnyYieldOperands(p),
            .object_property => {
                const op = hir_mod.objectPropertyOf(self.hir, node);
                try self.reportImplicitAnyYieldOperands(op.value);
                if (op.is_computed) try self.reportImplicitAnyYieldOperands(op.key);
            },
            else => {},
        }
    }

    fn reportImplicitAnyGeneratorYield(self: *Checker, fn_node: NodeId) CheckError!void {
        if (!self.strict_flags.no_implicit_any) return;
        if (self.hir.kindOf(fn_node) != .fn_decl and
            self.hir.kindOf(fn_node) != .fn_expr and
            self.hir.kindOf(fn_node) != .arrow_fn)
        {
            return;
        }
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (!f.flags.is_generator or f.return_type != hir_mod.none_node_id) return;
        if (!self.bodyHasImplicitAnyYieldType(f.body)) return;
        if (f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier) {
            const name = self.string_interner.get(hir_mod.identifierOf(self.hir, f.name).name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "'{s}', which lacks return-type annotation, implicitly has an 'any' yield type.",
                .{name},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = f.name,
                .code = TsCodes.generator_implicit_yield_type,
                .message = msg,
            });
        } else {
            try self.report(fn_node, TsCodes.generator_implicit_yield_type_short, "Generator implicitly has yield type 'any'. Consider supplying a return type annotation.");
        }
    }

    fn reportImplicitAnyTupleReturn(self: *Checker, fn_node: NodeId) CheckError!void {
        if (!self.strict_flags.no_implicit_any) return;
        const k = self.hir.kindOf(fn_node);
        if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) return;
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.return_type != hir_mod.none_node_id) return;
        if (self.functionHasContextualReturnType(fn_node)) return;
        if (!self.functionBodyReturnsNullishTupleLiteral(f.body)) return;
        const name_node = if (f.name != hir_mod.none_node_id) f.name else fn_node;
        const raw = if (f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier)
            self.string_interner.get(hir_mod.identifierOf(self.hir, f.name).name)
        else
            "<anonymous>";
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}', which lacks return-type annotation, implicitly has an 'any' return type.",
            .{raw},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = name_node,
            .code = TsCodes.function_return_implicitly_any,
            .message = msg,
        });
    }

    fn functionHasContextualReturnType(self: *Checker, fn_node: NodeId) bool {
        return self.contextualReturnTypeForFunction(fn_node) != null;
    }

    fn functionBodyReturnsNullishTupleLiteral(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .return_stmt => {
                const r = hir_mod.returnOf(self.hir, node);
                return self.expressionIsNullishTupleLiteral(r.value);
            },
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |s| {
                    if (self.functionBodyReturnsNullishTupleLiteral(s)) return true;
                }
                return false;
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                return self.functionBodyReturnsNullishTupleLiteral(i.then_branch) or
                    self.functionBodyReturnsNullishTupleLiteral(i.else_branch);
            },
            .try_stmt => {
                const t = hir_mod.tryOf(self.hir, node);
                return self.functionBodyReturnsNullishTupleLiteral(t.block) or
                    self.functionBodyReturnsNullishTupleLiteral(t.catch_block) or
                    self.functionBodyReturnsNullishTupleLiteral(t.finally_block);
            },
            .fn_decl, .fn_expr, .arrow_fn => return false,
            else => return false,
        }
    }

    fn expressionIsNullishTupleLiteral(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(node) == .assignment) {
            return self.expressionIsNullishTupleLiteral(hir_mod.assignmentOf(self.hir, node).value);
        }
        if (self.hir.kindOf(node) != .array_literal) return false;
        const elements = hir_mod.arrayLiteralElements(self.hir, node);
        if (elements.len == 0) return true;
        for (elements) |el| {
            if (el == hir_mod.none_node_id) continue;
            const k = self.hir.kindOf(el);
            if (k != .literal_null and k != .literal_undefined) return false;
        }
        return true;
    }

    fn bodyHasImplicitAnyYieldType(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .yield_expr => {
                const y = hir_mod.yieldExprOf(self.hir, node);
                if (y.expr == hir_mod.none_node_id) return true;
                const expr_t = self.hir.typeOf(y.expr);
                if (expr_t == types.Primitive.any) return true;
                if (y.type_node != hir_mod.none_node_id and
                    expr_t < self.interner.pool.typeCount() and
                    self.interner.pool.flagsOf(expr_t).is_object_type)
                {
                    const elem_t = self.interner.objectNumberIndex(expr_t);
                    if (elem_t == types.Primitive.any or elem_t == types.Primitive.undefined_t) return true;
                }
                return self.bodyHasImplicitAnyYieldType(y.expr);
            },
            .fn_decl, .fn_expr, .arrow_fn => return false,
            .block_stmt => for (hir_mod.blockStmts(self.hir, node)) |s| {
                if (self.bodyHasImplicitAnyYieldType(s)) return true;
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(i.cond) or
                    self.bodyHasImplicitAnyYieldType(i.then_branch) or
                    self.bodyHasImplicitAnyYieldType(i.else_branch);
            },
            .while_stmt => {
                const w = hir_mod.whileOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(w.cond) or self.bodyHasImplicitAnyYieldType(w.body);
            },
            .do_while_stmt => {
                const w = hir_mod.doWhileOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(w.cond) or self.bodyHasImplicitAnyYieldType(w.body);
            },
            .for_stmt => {
                const fr = hir_mod.forStmtOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(fr.init) or
                    self.bodyHasImplicitAnyYieldType(fr.cond) or
                    self.bodyHasImplicitAnyYieldType(fr.update) or
                    self.bodyHasImplicitAnyYieldType(fr.body);
            },
            .for_in_stmt, .for_of_stmt => {
                const fr = hir_mod.forInOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(fr.target) or
                    self.bodyHasImplicitAnyYieldType(fr.source) or
                    self.bodyHasImplicitAnyYieldType(fr.body);
            },
            .return_stmt => return self.bodyHasImplicitAnyYieldType(hir_mod.returnOf(self.hir, node).value),
            .var_decl, .let_decl, .const_decl => return self.bodyHasImplicitAnyYieldType(hir_mod.varDeclOf(self.hir, node).init),
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(b.lhs) or self.bodyHasImplicitAnyYieldType(b.rhs);
            },
            .unary_op => return self.bodyHasImplicitAnyYieldType(hir_mod.unaryOf(self.hir, node).operand),
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(l.lhs) or self.bodyHasImplicitAnyYieldType(l.rhs);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(c.cond) or
                    self.bodyHasImplicitAnyYieldType(c.then_branch) or
                    self.bodyHasImplicitAnyYieldType(c.else_branch);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(a.target) or self.bodyHasImplicitAnyYieldType(a.value);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                if (self.bodyHasImplicitAnyYieldType(c.callee)) return true;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.bodyHasImplicitAnyYieldType(arg)) return true;
                }
                return false;
            },
            .member_access => return self.bodyHasImplicitAnyYieldType(hir_mod.memberOf(self.hir, node).object),
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(e.object) or self.bodyHasImplicitAnyYieldType(e.index);
            },
            .as_expr, .satisfies_expr, .type_assertion => return self.bodyHasImplicitAnyYieldType(hir_mod.asExpressionOf(self.hir, node).expr),
            .throw_stmt => return self.bodyHasImplicitAnyYieldType(hir_mod.throwOf(self.hir, node).value),
            .try_stmt => {
                const ts = hir_mod.tryOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(ts.block) or
                    self.bodyHasImplicitAnyYieldType(ts.catch_block) or
                    self.bodyHasImplicitAnyYieldType(ts.finally_block);
            },
            .switch_stmt => {
                const sw = hir_mod.switchOf(self.hir, node);
                if (self.bodyHasImplicitAnyYieldType(sw.discriminant)) return true;
                for (hir_mod.switchCases(self.hir, node)) |case| {
                    if (self.bodyHasImplicitAnyYieldType(case)) return true;
                }
                return false;
            },
            .switch_case => for (hir_mod.switchCaseStmts(self.hir, node)) |s| {
                if (self.bodyHasImplicitAnyYieldType(s)) return true;
            },
            .array_literal => for (hir_mod.arrayLiteralElements(self.hir, node)) |el| {
                if (self.bodyHasImplicitAnyYieldType(el)) return true;
            },
            .object_literal => for (hir_mod.objectLiteralProps(self.hir, node)) |p| {
                if (self.bodyHasImplicitAnyYieldType(p)) return true;
            },
            .object_property => {
                const op = hir_mod.objectPropertyOf(self.hir, node);
                return self.bodyHasImplicitAnyYieldType(op.value) or
                    (op.is_computed and self.bodyHasImplicitAnyYieldType(op.key));
            },
            else => return false,
        }
        return false;
    }

    /// Build a v0 `Generator<T, void, unknown>` shape for generator
    /// return-type inference. The synthesized object exposes:
    ///   - `next(): { value: T | undefined, done: boolean }`
    ///   - `return(): { value: T | undefined, done: boolean }`
    ///   - `throw(): { value: T | undefined, done: boolean }`
    ///   - `[i: number]: T` indexer so `for (const x of g())` resolves
    ///     `x` to T through the existing for-of element-type path.
    /// Async generators get the same shape — for v0 we don't yet wrap
    /// the result in a Promise.
    fn synthesizeGeneratorType(self: *Checker, yield_t: TypeId) CheckError!TypeId {
        return self.synthesizeGeneratorTypeFull(yield_t, types.Primitive.void_t, types.Primitive.any);
    }

    fn synthesizeGeneratorTypeFull(
        self: *Checker,
        yield_t: TypeId,
        return_t: TypeId,
        next_t: TypeId,
    ) CheckError!TypeId {
        const value_id = self.string_interner.intern("value") catch return error.OutOfMemory;
        const done_id = self.string_interner.intern("done") catch return error.OutOfMemory;
        const next_id = self.string_interner.intern("next") catch return error.OutOfMemory;
        const return_id = self.string_interner.intern("return") catch return error.OutOfMemory;
        const throw_id = self.string_interner.intern("throw") catch return error.OutOfMemory;

        // IteratorResult<T, TReturn> = { value: T | TReturn | undefined, done: boolean }
        const value_or_undef = self.interner.internUnion(&.{ yield_t, return_t, types.Primitive.undefined_t }) catch yield_t;
        const ir_members = [_]types.ObjectMember{
            .{ .name = value_id, .type = value_or_undef, .is_optional = false, .is_readonly = false, .is_method = false },
            .{ .name = done_id, .type = types.Primitive.boolean_t, .is_optional = false, .is_readonly = false, .is_method = false },
        };
        const iter_result = self.interner.internObjectType(&ir_members) catch return error.OutOfMemory;

        // `next(value?: TNext)` returns IteratorResult<T, TReturn>.
        const next_param = self.unionWithUndefined(next_t) catch next_t;
        const next_params = [_]TypeId{next_param};
        const next_sig = self.interner.internSignature(&next_params, iter_result, false) catch return error.OutOfMemory;
        try self.recordSignatureMinArgs(next_sig, &.{true});
        const empty_params: []const TypeId = &.{};
        const return_sig = self.interner.internSignature(empty_params, iter_result, false) catch return error.OutOfMemory;
        const throw_sig = self.interner.internSignature(empty_params, iter_result, false) catch return error.OutOfMemory;

        const gen_members = [_]types.ObjectMember{
            .{ .name = next_id, .type = next_sig, .is_optional = false, .is_readonly = false, .is_method = true },
            .{ .name = return_id, .type = return_sig, .is_optional = false, .is_readonly = false, .is_method = true },
            .{ .name = throw_id, .type = throw_sig, .is_optional = false, .is_readonly = false, .is_method = true },
        };
        // Number-key indexer = T so for-of binds the loop variable to T.
        const gen_t = self.interner.internObjectTypeWithIndex(
            &gen_members,
            types.Primitive.none,
            yield_t,
        ) catch return error.OutOfMemory;
        try self.generator_type_info.put(self.gpa, gen_t, .{
            .yield_type = yield_t,
            .return_type = return_t,
            .next_type = next_t,
        });
        return gen_t;
    }

    fn generatorReturnAnnotationDefinitelyInvalid(self: *Checker, ret_t: TypeId) bool {
        _ = self;
        return ret_t == types.Primitive.number_t or
            ret_t == types.Primitive.string_t or
            ret_t == types.Primitive.boolean_t or
            ret_t == types.Primitive.bigint_t or
            ret_t == types.Primitive.symbol_t or
            ret_t == types.Primitive.null_t or
            ret_t == types.Primitive.undefined_t or
            ret_t == types.Primitive.never;
    }

    fn generatorReturnAnnotationRequiresMissingGeneratorMembers(self: *Checker, ret_t: TypeId) bool {
        if (ret_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(ret_t).is_object_type) return false;
        for (self.interner.objectMembers(ret_t)) |member| {
            if (member.is_optional) continue;
            const name = self.string_interner.get(member.name);
            if (std.mem.eql(u8, name, "next") or
                std.mem.eql(u8, name, "return") or
                std.mem.eql(u8, name, "throw"))
            {
                continue;
            }
            return true;
        }
        return false;
    }

    fn isIterableLikeType(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.any or t == types.Primitive.unknown) return true;
        if (t == types.Primitive.string_t) return true;
        if (t < self.interner.pool.typeCount()) {
            const primitive_flags = self.interner.pool.flagsOf(t);
            if (primitive_flags.is_string and !primitive_flags.is_object_type) return true;
        }
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.isIterableLikeType(member)) return false;
            }
            return true;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.isIterableLikeType(member)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return false;
        const symbol_iterator = self.string_interner.intern("Symbol.iterator") catch return false;
        if (self.interner.objectNumberIndex(t) != types.Primitive.none) return true;
        if (self.interner.objectMemberInfo(t, symbol_iterator)) |member| {
            if (member.is_optional) return false;
            if (self.typeHasNextMethod(t)) return true;
            const iterator_t = self.iteratorMethodReturnType(member.type) orelse return true;
            if (iterator_t == types.Primitive.any or iterator_t == types.Primitive.unknown) return true;
            return self.typeHasNextMethod(iterator_t);
        }
        return false;
    }

    fn iterableElementType(self: *Checker, t: TypeId) CheckError!TypeId {
        if (t == types.Primitive.any or t == types.Primitive.unknown) return types.Primitive.any;
        if (t == types.Primitive.string_t) return types.Primitive.string_t;
        if (t >= self.interner.pool.typeCount()) return types.Primitive.any;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_string and !flags.is_object_type) return types.Primitive.string_t;
        if (flags.is_union) {
            var elems: std.ArrayListUnmanaged(TypeId) = .empty;
            defer elems.deinit(self.gpa);
            for (self.interner.unionMembers(t)) |member| {
                try elems.append(self.gpa, try self.iterableElementType(member));
            }
            return self.unionOrAny(elems.items);
        }
        if (flags.is_intersection) {
            var elems: std.ArrayListUnmanaged(TypeId) = .empty;
            defer elems.deinit(self.gpa);
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.isIterableLikeType(member)) try elems.append(self.gpa, try self.iterableElementType(member));
            }
            if (elems.items.len == 0) return types.Primitive.any;
            if (elems.items.len == 1) return elems.items[0];
            return self.interner.internIntersection(elems.items) catch return error.OutOfMemory;
        }
        if (!flags.is_object_type) return types.Primitive.any;
        const number_idx = self.interner.objectNumberIndex(t);
        if (number_idx != types.Primitive.none) return number_idx;
        const next_id = self.string_interner.intern("next") catch return error.OutOfMemory;
        if (self.interner.objectMember(t, next_id)) |next_t| {
            if (self.interner.signatureReturn(next_t)) |ret_t| {
                if (ret_t == types.Primitive.any or ret_t == types.Primitive.unknown) return types.Primitive.any;
                const value_id = self.string_interner.intern("value") catch return error.OutOfMemory;
                if (self.interner.objectMember(ret_t, value_id)) |value_t| return value_t;
            }
        }
        const symbol_iterator = self.string_interner.intern("Symbol.iterator") catch return error.OutOfMemory;
        if (self.interner.objectMember(t, symbol_iterator)) |iter_method_t| {
            if (self.iteratorMethodReturnType(iter_method_t)) |iterator_t| {
                return try self.iteratorNextValueType(iterator_t);
            }
        }
        return types.Primitive.any;
    }

    fn checkForOfIteratorShape(self: *Checker, node: NodeId, t: TypeId) CheckError!void {
        if (t == types.Primitive.any or t == types.Primitive.unknown) return;
        if (t == types.Primitive.string_t) return;
        if (t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_string and !flags.is_object_type) return;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| try self.checkForOfIteratorShape(node, member);
            return;
        }
        if (!flags.is_object_type) return;
        if (self.interner.objectNumberIndex(t) != types.Primitive.none) return;
        const symbol_iterator = self.string_interner.intern("Symbol.iterator") catch return error.OutOfMemory;
        const iter_method_t = self.interner.objectMember(t, symbol_iterator) orelse return;
        if (self.typeHasNextMethod(t)) {
            const value_t = try self.iteratorNextValueType(t);
            if (value_t == types.Primitive.none) {
                try self.report(node, TsCodes.iterator_value_missing, "The type returned by the 'next()' method of an iterator must have a 'value' property.");
            }
            try self.checkIteratorReturnMethod(node, t);
            return;
        }
        if (self.iteratorMethodReturnType(iter_method_t)) |iterator_t| {
            if (iterator_t == types.Primitive.any or iterator_t == types.Primitive.unknown) {
                return;
            }
            if (!self.typeHasNextMethod(iterator_t)) {
                try self.report(node, TsCodes.yield_star_not_iterable, "Type must have a '[Symbol.iterator]()' method that returns an iterator.");
                return;
            }
            const value_t = try self.iteratorNextValueType(iterator_t);
            if (value_t == types.Primitive.none) {
                try self.report(node, TsCodes.iterator_value_missing, "The type returned by the 'next()' method of an iterator must have a 'value' property.");
            }
            try self.checkIteratorReturnMethod(node, iterator_t);
            return;
        }
        const next_id = self.string_interner.intern("next") catch return error.OutOfMemory;
        const next_t = self.interner.objectMember(t, next_id) orelse return;
        const ret_t = self.interner.signatureReturn(next_t) orelse return;
        if (ret_t == types.Primitive.any or ret_t == types.Primitive.unknown) return;
        const value_id = self.string_interner.intern("value") catch return error.OutOfMemory;
        if (self.interner.objectMember(ret_t, value_id) == null) {
            try self.report(node, TsCodes.iterator_value_missing, "The type returned by the 'next()' method of an iterator must have a 'value' property.");
        }
        try self.checkIteratorReturnMethod(node, t);
    }

    fn checkIteratorReturnMethod(self: *Checker, node: NodeId, iterator_t: TypeId) CheckError!void {
        if (iterator_t == types.Primitive.any or iterator_t == types.Primitive.unknown) return;
        if (iterator_t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(iterator_t);
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(iterator_t)) |member| {
                try self.checkIteratorReturnMethod(node, member);
            }
            return;
        }
        if (!flags.is_object_type) return;
        const return_id = self.string_interner.intern("return") catch return error.OutOfMemory;
        const return_t = self.interner.objectMember(iterator_t, return_id) orelse return;
        if (return_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(return_t).is_signature) return;
        try self.report(node, TsCodes.iterator_return_must_be_method, "The 'return' property of an iterator must be a method.");
    }

    fn iteratorMethodReturnType(self: *Checker, method_t: TypeId) ?TypeId {
        if (method_t == types.Primitive.any or method_t == types.Primitive.unknown) return method_t;
        if (self.interner.signatureReturn(method_t)) |ret_t| return ret_t;
        return null;
    }

    fn typeHasNextMethod(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.any or t == types.Primitive.unknown) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| if (self.typeHasNextMethod(member)) return true;
            return false;
        }
        if (!flags.is_object_type) return false;
        const next_id = self.string_interner.intern("next") catch return false;
        return self.interner.objectMember(t, next_id) != null;
    }

    fn iteratorNextValueType(self: *Checker, t: TypeId) CheckError!TypeId {
        if (t == types.Primitive.any or t == types.Primitive.unknown) return types.Primitive.any;
        if (t >= self.interner.pool.typeCount()) return types.Primitive.none;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                const value_t = try self.iteratorNextValueType(member);
                if (value_t != types.Primitive.none) return value_t;
            }
            return types.Primitive.none;
        }
        if (!flags.is_object_type) return types.Primitive.none;
        const next_id = self.string_interner.intern("next") catch return error.OutOfMemory;
        const next_t = self.interner.objectMember(t, next_id) orelse return types.Primitive.none;
        if (next_t == types.Primitive.any or next_t == types.Primitive.unknown) return types.Primitive.any;
        const ret_t = self.interner.signatureReturn(next_t) orelse return types.Primitive.none;
        if (ret_t == types.Primitive.any or ret_t == types.Primitive.unknown) return types.Primitive.any;
        const value_id = self.string_interner.intern("value") catch return error.OutOfMemory;
        return self.interner.objectMember(ret_t, value_id) orelse types.Primitive.none;
    }

    fn arrayBindingPatternParameterType(self: *Checker, pattern_node: NodeId) CheckError!TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        const length_id = self.string_interner.intern("length") catch return error.OutOfMemory;
        try members.append(self.gpa, .{
            .name = length_id,
            .type = types.Primitive.number_t,
            .is_optional = false,
            .is_readonly = false,
            .is_method = false,
        });
        var idx: usize = 0;
        for (hir_mod.patternElements(self.hir, pattern_node)) |e| {
            if (self.hir.kindOf(e) != .parameter) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (ep.flags.is_rest) break;
            var nbuf: [12]u8 = undefined;
            const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{idx}) catch return error.OutOfMemory;
            const name = self.string_interner.intern(name_str) catch return error.OutOfMemory;
            try members.append(self.gpa, .{
                .name = name,
                .type = types.Primitive.any,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            });
            idx += 1;
        }
        return self.interner.internObjectTypeWithIndex(members.items, types.Primitive.none, types.Primitive.any) catch return error.OutOfMemory;
    }

    fn arrayBindingPatternHasRest(self: *Checker, pattern_node: NodeId) bool {
        if (pattern_node == hir_mod.none_node_id or self.hir.kindOf(pattern_node) != .array_pattern) return false;
        for (hir_mod.patternElements(self.hir, pattern_node)) |e| {
            if (self.hir.kindOf(e) != .parameter) continue;
            const ep = hir_mod.parameterOf(self.hir, e);
            if (ep.flags.is_rest) return true;
        }
        return false;
    }

    fn objectLiteralHasSymbolIteratorMethod(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .object_literal) return false;
        for (hir_mod.objectLiteralProps(self.hir, node)) |prop| {
            if (self.hir.kindOf(prop) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, prop);
            if (!op.is_method or !op.is_computed) continue;
            if (self.hir.kindOf(op.key) != .member_access) continue;
            const m = hir_mod.memberOf(self.hir, op.key);
            if (self.hir.kindOf(m.object) != .identifier) continue;
            const obj = hir_mod.identifierOf(self.hir, m.object);
            if (!std.mem.eql(u8, self.string_interner.get(obj.name), "Symbol")) continue;
            if (!std.mem.eql(u8, self.string_interner.get(m.name), "iterator")) continue;
            return true;
        }
        return false;
    }

    /// Walk a type's structural body in search of the given type
    /// parameter, accumulating the variance positions in which it
    /// occurs. Returns the combined variance:
    ///   - `.covariant` only — output position (return / property /
    ///     array element / union member).
    ///   - `.contravariant` only — input position (signature param).
    ///   - both → `.invariant`.
    ///   - neither → `.bivariant` (T is unused, or only appears
    ///     under `keyof` where it's treated as a key).
    fn inferVariance(self: *Checker, body_t: TypeId, param_id: TypeId) types.Variance {
        var saw_co = false;
        var saw_ct = false;
        var visited: std.AutoHashMapUnmanaged(TypeId, void) = .empty;
        defer visited.deinit(self.gpa);
        self.scanVariance(body_t, param_id, .covariant, &saw_co, &saw_ct, &visited);
        if (saw_co and saw_ct) return .invariant;
        if (saw_co) return .covariant;
        if (saw_ct) return .contravariant;
        return .bivariant;
    }

    /// Recursive worker for `inferVariance`. `position` tracks the
    /// polarity of the slot being entered: `.covariant` for output
    /// positions, `.contravariant` for input positions, `.invariant`
    /// for read+write slots (the object of an indexed access),
    /// `.bivariant` to suppress recording (under `keyof`).
    fn scanVariance(
        self: *Checker,
        t: TypeId,
        param_id: TypeId,
        position: types.Variance,
        saw_co: *bool,
        saw_ct: *bool,
        visited: *std.AutoHashMapUnmanaged(TypeId, void),
    ) void {
        if (t == param_id) {
            switch (position) {
                .covariant => saw_co.* = true,
                .contravariant => saw_ct.* = true,
                .invariant => {
                    saw_co.* = true;
                    saw_ct.* = true;
                },
                .bivariant => {},
            }
            return;
        }
        if (t < types.Primitive.first_dynamic) return;
        if (t >= self.interner.pool.typeCount()) return;
        if (visited.contains(t)) return;
        visited.put(self.gpa, t, {}) catch return;
        const flags = self.interner.pool.flagsOf(t);
        const payload_idx = self.interner.pool.payloadOf(t);

        if (flags.is_signature) {
            if (payload_idx >= self.interner.pool.signature_payloads.items.len) return;
            for (self.interner.signatureParams(t)) |p| {
                self.scanVariance(p, param_id, flipVariance(position), saw_co, saw_ct, visited);
            }
            if (self.interner.signatureReturn(t)) |r| {
                self.scanVariance(r, param_id, position, saw_co, saw_ct, visited);
            }
            return;
        }
        if (flags.is_object_type) {
            if (payload_idx >= self.interner.pool.object_type_payloads.items.len) return;
            const members = self.interner.objectMembers(t);
            for (members) |m| {
                self.scanVariance(m.type, param_id, position, saw_co, saw_ct, visited);
            }
            const si = self.interner.objectStringIndex(t);
            if (si != types.Primitive.none) self.scanVariance(si, param_id, position, saw_co, saw_ct, visited);
            const ni = self.interner.objectNumberIndex(t);
            if (ni != types.Primitive.none) self.scanVariance(ni, param_id, position, saw_co, saw_ct, visited);
            return;
        }
        if (flags.is_union) {
            if (payload_idx >= self.interner.pool.union_payloads.items.len) return;
            for (self.interner.unionMembers(t)) |m| {
                self.scanVariance(m, param_id, position, saw_co, saw_ct, visited);
            }
            return;
        }
        if (flags.is_intersection) {
            if (payload_idx >= self.interner.pool.intersection_payloads.items.len) return;
            for (self.interner.intersectionMembers(t)) |m| {
                self.scanVariance(m, param_id, position, saw_co, saw_ct, visited);
            }
            return;
        }
        if (flags.is_tuple) {
            if (payload_idx >= self.interner.pool.tuple_payloads.items.len) return;
            const payload = self.interner.pool.tuple_payloads.items[payload_idx];
            const elems = self.interner.pool.tuple_element_pool.items[payload.elements_start .. payload.elements_start + payload.elements_len];
            for (elems) |e| {
                self.scanVariance(e.type, param_id, position, saw_co, saw_ct, visited);
            }
            return;
        }
        if (flags.is_keyof) {
            // `keyof T` — T is consumed as a key; treat as bivariant
            // (suppress recording inside the keyof operand).
            return;
        }
        if (flags.is_indexed_access) {
            if (payload_idx >= self.interner.pool.indexed_access_payloads.items.len) return;
            const payload = self.interner.pool.indexed_access_payloads.items[payload_idx];
            // Object slot is read+write → invariant. Index slot
            // stays at the surrounding polarity.
            self.scanVariance(payload.object, param_id, .invariant, saw_co, saw_ct, visited);
            self.scanVariance(payload.index, param_id, position, saw_co, saw_ct, visited);
            return;
        }
        if (flags.is_conditional) {
            if (payload_idx >= self.interner.pool.conditional_payloads.items.len) return;
            const c = self.interner.conditionalPayload(t);
            self.scanVariance(c.check_type, param_id, position, saw_co, saw_ct, visited);
            self.scanVariance(c.extends_type, param_id, position, saw_co, saw_ct, visited);
            self.scanVariance(c.true_branch, param_id, position, saw_co, saw_ct, visited);
            self.scanVariance(c.false_branch, param_id, position, saw_co, saw_ct, visited);
            return;
        }
        if (flags.is_mapped) {
            if (payload_idx >= self.interner.pool.mapped_payloads.items.len) return;
            const m = self.interner.mappedPayload(t);
            self.scanVariance(m.constraint, param_id, position, saw_co, saw_ct, visited);
            self.scanVariance(m.template, param_id, position, saw_co, saw_ct, visited);
            return;
        }
        if (flags.is_instantiation) {
            if (payload_idx >= self.interner.pool.instantiation_payloads.items.len) return;
            const payload = self.interner.pool.instantiation_payloads.items[payload_idx];
            const args = self.interner.pool.type_arg_pool.items[payload.args_start .. payload.args_start + payload.args_len];
            // Without per-origin variance metadata, treat each
            // type-argument slot at the surrounding polarity. A
            // future fixed-point pass can refine this.
            for (args) |a| {
                self.scanVariance(a, param_id, position, saw_co, saw_ct, visited);
            }
            return;
        }
        // Primitives, literals, and type parameters other than the
        // target — nothing to walk.
    }

    /// Run the signature-only pass of `checkFnDecl` — type
    /// parameters, parameter annotations, return type, intern the
    /// signature — without walking the body. The caller owns the
    /// narrow scope: a type-params scope is pushed here when the
    /// fn declares any, and the caller must pop it after the body
    /// walk so type-param references inside the body still resolve.
    fn checkFnSignatureOnly(self: *Checker, node: NodeId) CheckError!TypeId {
        const f = hir_mod.fnDeclOf(self.hir, node);
        const type_params = hir_mod.fnTypeParams(self.hir, node);
        try self.checkTypeParameterDeclList(type_params);
        try self.checkFunctionSignatureLocalTypeVisibility(node, type_params);
        if (type_params.len > 0) try self.pushNarrowScope();
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tpp = hir_mod.typeParameterOf(self.hir, tp);
            const placeholder = self.interner.internFreshTypeParameterWithFlags(
                tpp.name,
                types.Primitive.unknown,
                types.Primitive.none,
                types.Variance.fromHirBits(tpp.variance),
                tpp.is_const,
            ) catch return error.OutOfMemory;
            self.hir.setType(tp, placeholder);
            try self.recordNarrow(tpp.name, placeholder);
        }
        var captured_tp_ids: std.ArrayListUnmanaged(TypeId) = .empty;
        defer captured_tp_ids.deinit(self.gpa);
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tpp = hir_mod.typeParameterOf(self.hir, tp);
            const constraint: TypeId = if (tpp.constraint != hir_mod.none_node_id)
                try self.lowererLowerWithTypeParams(tpp.constraint)
            else
                types.Primitive.unknown;
            const def: TypeId = if (tpp.default != hir_mod.none_node_id)
                try self.lowererLowerWithTypeParams(tpp.default)
            else
                types.Primitive.none;
            const tp_id = if (tpp.constraint == hir_mod.none_node_id and tpp.default == hir_mod.none_node_id)
                (self.lookupNarrow(tpp.name) orelse self.hir.typeOf(tp))
            else
                self.interner.internFreshTypeParameterWithFlags(
                    tpp.name,
                    constraint,
                    def,
                    types.Variance.fromHirBits(tpp.variance),
                    tpp.is_const,
                ) catch return error.OutOfMemory;
            self.hir.setType(tp, tp_id);
            try self.recordNarrow(tpp.name, tp_id);
            try captured_tp_ids.append(self.gpa, tp_id);
        }

        var param_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer param_types.deinit(self.gpa);
        var param_omittable: std.ArrayListUnmanaged(bool) = .empty;
        defer param_omittable.deinit(self.gpa);
        var param_predicates: std.ArrayListUnmanaged(ParamPredicateEntry) = .empty;
        defer param_predicates.deinit(self.gpa);
        const params = hir_mod.fnParams(self.hir, node);
        var has_rest_param = false;
        var explicit_this_t: TypeId = types.Primitive.none;
        var value_param_index: u16 = 0;
        for (params, 0..) |p, param_index| {
            const pp = hir_mod.parameterOf(self.hir, p);
            const is_this_param = self.isThisParameter(p);
            try self.checkParameterDecoratorDiagnostics(p, node, param_index, is_this_param);
            if (f.body == hir_mod.none_node_id and pp.default_value != hir_mod.none_node_id) {
                try self.report(p, TsCodes.parameter_initializer_implementation_only, "A parameter initializer is only allowed in a function or constructor implementation.");
            }
            if (is_this_param and param_index != 0) {
                try self.report(p, TsCodes.this_parameter_must_be_first, "A 'this' parameter must be the first parameter.");
            }
            if (pp.flags.is_rest and !is_this_param) has_rest_param = true;
            const has_anno = pp.type_annotation != hir_mod.none_node_id;
            var t: TypeId = if (has_anno)
                try self.lowererLowerWithTypeParams(pp.type_annotation)
            else if (pp.default_value != hir_mod.none_node_id and
                pp.name != hir_mod.none_node_id and
                self.hir.kindOf(pp.name) == .array_pattern)
                try self.checkExpression(pp.default_value)
            else if (pp.name != hir_mod.none_node_id and
                self.hir.kindOf(pp.name) == .array_pattern and
                (pp.flags.is_rest or self.arrayBindingPatternHasRest(pp.name) or pp.default_value == hir_mod.none_node_id))
                try self.arrayBindingPatternParameterType(pp.name)
            else
                types.Primitive.any;
            const declared_param_t = t;
            if (has_anno and pp.default_value != hir_mod.none_node_id) {
                const default_t = try self.checkExpression(pp.default_value);
                const literal_ok = try self.literalExpressionAssignableToTarget(pp.default_value, declared_param_t);
                const loose_nullish_ok = !self.strict_flags.strict_null_checks and
                    (default_t == types.Primitive.null_t or default_t == types.Primitive.undefined_t);
                if (!literal_ok and
                    !loose_nullish_ok and
                    (self.parameterDefaultInvalid(default_t, declared_param_t) or
                        !(self.engine.isAssignableTo(default_t, declared_param_t) catch true)))
                {
                    try self.report(p, TsCodes.type_not_assignable, "Parameter initializer is not assignable to parameter type.");
                }
            }
            // `f(x?: T)` and `f(x: T = default)` both widen the
            // parameter type to include `undefined` (matches the
            // call-site behavior where the caller can omit the arg).
            if (pp.flags.is_optional or pp.default_value != hir_mod.none_node_id) {
                t = self.unionWithUndefined(t) catch t;
            }
            self.hir.setType(p, t);
            if (pp.name != hir_mod.none_node_id) self.hir.setType(pp.name, t);
            if (is_this_param) {
                explicit_this_t = t;
                continue;
            }
            try param_types.append(self.gpa, t);
            try param_omittable.append(self.gpa, pp.flags.is_rest or !has_anno or pp.flags.is_optional or pp.default_value != hir_mod.none_node_id or t == types.Primitive.void_t);
            if (self.signature_predicates.get(t)) |param_pred| {
                try param_predicates.append(self.gpa, .{ .param_index = value_param_index, .pred = param_pred });
            }
            value_param_index += 1;
            if (!has_anno and self.strict_flags.no_implicit_any) {
                const param_name: []const u8 = if (pp.name != hir_mod.none_node_id and self.hir.kindOf(pp.name) == .identifier)
                    self.string_interner.get(hir_mod.identifierOf(self.hir, pp.name).name)
                else
                    "<anonymous>";
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Parameter '{s}' implicitly has an 'any' type.",
                    .{param_name},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = p,
                    .code = TsCodes.parameter_implicitly_any,
                    .message = msg,
                });
            }
        }

        // Detect a `arg is T` / `asserts arg is T` return-type
        // before lowering — the predicate's target type is the
        // *return type* for assignability purposes (it always
        // returns boolean), but we record the predicate separately
        // so call sites can narrow the argument.
        const is_predicate = f.return_type != hir_mod.none_node_id and
            self.hir.kindOf(f.return_type) == .type_predicate_type;
        const ret_t: TypeId = if (f.return_type != hir_mod.none_node_id)
            (if (is_predicate) types.Primitive.boolean_t else try self.lowererLowerWithTypeParams(f.return_type))
        else
            types.Primitive.any;
        if (f.flags.is_generator and f.return_type != hir_mod.none_node_id) {
            if (ret_t == types.Primitive.void_t) {
                try self.report(f.return_type, TsCodes.generator_void_return, "A generator cannot have a 'void' type annotation.");
            } else if (self.generatorReturnAnnotationDefinitelyInvalid(ret_t) or
                self.generatorReturnAnnotationRequiresMissingGeneratorMembers(ret_t))
            {
                try self.report(f.return_type, TsCodes.type_not_assignable, "Generator return type is not assignable to the declared return type.");
            }
        }

        const sig = self.interner.internSignature(param_types.items, ret_t, false) catch return error.OutOfMemory;
        try self.recordGenericSignatureParams(sig, captured_tp_ids.items);
        if (explicit_this_t != types.Primitive.none) try self.signature_this_params.put(self.gpa, sig, explicit_this_t);
        try self.recordSignatureMinArgs(sig, param_omittable.items);
        self.hir.setType(node, sig);
        if (f.name != hir_mod.none_node_id) self.hir.setType(f.name, sig);
        // Record rest-parameter signatures so call-site argument
        // checking can expand the trailing rest into a variadic match
        // (the interner keys signatures only by their flat parameter
        // type list, so rest-ness lives in `rest_signatures`).
        if (has_rest_param) {
            try self.rest_signatures.put(self.gpa, sig, {});
        }
        for (param_predicates.items) |entry| {
            try self.signature_param_predicates.put(self.gpa, .{
                .signature = sig,
                .param_index = entry.param_index,
            }, entry.pred);
        }
        // Auto-infer variance for any type parameter that had no
        // explicit `in` / `out` modifier. We walk the signature —
        // an occurrence of T in a param slot is contravariant, in
        // the return slot covariant. The result lives in the
        // `inferred_variance` side table since the interner keys
        // variance into the TypeId.
        if (captured_tp_ids.items.len > 0) {
            var tp_ix: usize = 0;
            for (type_params) |tp_node| {
                if (self.hir.kindOf(tp_node) != .type_parameter) continue;
                const tpp_h = hir_mod.typeParameterOf(self.hir, tp_node);
                if (tp_ix >= captured_tp_ids.items.len) break;
                const tp_id_v = captured_tp_ids.items[tp_ix];
                tp_ix += 1;
                if (tpp_h.variance != 0) continue; // explicit `in`/`out`
                const v = self.inferVariance(sig, tp_id_v);
                try self.inferred_variance.put(self.gpa, tp_id_v, v);
            }
        }
        // Record the function's generic type parameters keyed by name
        // so call sites with explicit type args (`f<T>(args)`) can
        // substitute directly. Drop any prior recording on shadow.
        if (captured_tp_ids.items.len > 0 and f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier) {
            const fn_name = hir_mod.identifierOf(self.hir, f.name).name;
            if (self.generic_fns.fetchRemove(fn_name)) |old| self.gpa.free(old.value);
            const owned = captured_tp_ids.toOwnedSlice(self.gpa) catch return error.OutOfMemory;
            try self.generic_fns.put(self.gpa, fn_name, owned);
        }
        // Overload tracking: when multiple `function f(...)` decls
        // share a name, we treat the body-less ones as overload
        // signatures. The body-bearing one is the implementation
        // (used only for body typing — never picked by call-site
        // resolution). Ambient overload lists have no body, so every
        // signature stays visible.
        if (f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier) {
            const fn_name = hir_mod.identifierOf(self.hir, f.name).name;
            const has_body = f.body != hir_mod.none_node_id;
            const gop = try self.overloads.getOrPut(self.gpa, fn_name);
            if (!gop.found_existing) gop.value_ptr.* = .empty;
            if (!has_body) {
                try gop.value_ptr.*.append(self.gpa, sig);
            } else {
                // Implementation signature: only append if there
                // are existing overloads — a single-decl function
                // doesn't need overload resolution.
                if (gop.value_ptr.*.items.len > 0) {
                    try gop.value_ptr.*.append(self.gpa, sig);
                    try self.overload_has_implementation.put(self.gpa, fn_name, {});
                }
            }
        }
        // Record the predicate so call sites can narrow.
        if (is_predicate and f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier) {
            const pred = hir_mod.typePredicateOf(self.hir, f.return_type);
            const target_t: TypeId = if (pred.target_type != hir_mod.none_node_id)
                (self.lowererLowerWithTypeParams(pred.target_type) catch types.Primitive.unknown)
            else
                types.Primitive.unknown;
            const fn_name = hir_mod.identifierOf(self.hir, f.name).name;
            const fn_pred: FnPredicate = .{
                .param_index = pred.param_index,
                .target_type = target_t,
                .target_node = pred.target_type,
                .is_asserts = pred.is_asserts,
            };
            try self.fn_predicates.put(self.gpa, fn_name, fn_pred);
            try self.signature_predicates.put(self.gpa, sig, fn_pred);
        }
        return sig;
    }

    fn checkFunctionSignatureLocalTypeVisibility(self: *Checker, fn_node: NodeId, type_params: []const NodeId) CheckError!void {
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.body == hir_mod.none_node_id or self.hir.kindOf(f.body) != .block_stmt) return;
        var local_type_names: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
        defer local_type_names.deinit(self.gpa);
        for (hir_mod.blockStmts(self.hir, f.body)) |stmt| {
            const name_node: NodeId = switch (self.hir.kindOf(stmt)) {
                .interface_decl => hir_mod.interfaceOf(self.hir, stmt).name,
                .type_alias_decl => hir_mod.typeAliasOf(self.hir, stmt).name,
                .class_decl, .class_expr => hir_mod.classOf(self.hir, stmt).name,
                else => continue,
            };
            if (name_node == hir_mod.none_node_id or self.hir.kindOf(name_node) != .identifier) continue;
            try local_type_names.put(self.gpa, hir_mod.identifierOf(self.hir, name_node).name, stmt);
        }
        if (local_type_names.count() == 0) return;

        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tpp = hir_mod.typeParameterOf(self.hir, tp);
            if (local_type_names.contains(tpp.name)) {
                try self.report(tp, TsCodes.duplicate_identifier, "Duplicate identifier.");
            }
        }

        const params = hir_mod.fnParams(self.hir, fn_node);
        for (params) |p| {
            if (self.hir.kindOf(p) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, p);
            if (pp.type_annotation != hir_mod.none_node_id) {
                try self.reportTypeRefsToLocalBodyTypes(pp.type_annotation, &local_type_names);
            }
        }
        if (f.return_type != hir_mod.none_node_id) {
            try self.reportTypeRefsToLocalBodyTypes(f.return_type, &local_type_names);
        }
    }

    fn reportTypeRefsToLocalBodyTypes(
        self: *Checker,
        type_node: NodeId,
        local_type_names: *const std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (type_node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(type_node)) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, type_node);
                if (local_type_names.contains(id.name)) {
                    try self.reportCannotFindName(type_node, id.name);
                }
            },
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, type_node);
                if (r.qualifier_len == 0 and local_type_names.contains(r.name)) {
                    try self.reportCannotFindName(type_node, r.name);
                }
                for (hir_mod.typeRefArgs(self.hir, type_node)) |arg| {
                    try self.reportTypeRefsToLocalBodyTypes(arg, local_type_names);
                }
            },
            .union_type => for (hir_mod.unionTypeMembers(self.hir, type_node)) |member| try self.reportTypeRefsToLocalBodyTypes(member, local_type_names),
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, type_node)) |member| try self.reportTypeRefsToLocalBodyTypes(member, local_type_names),
            .array_type => try self.reportTypeRefsToLocalBodyTypes(hir_mod.arrayTypeOf(self.hir, type_node).element, local_type_names),
            .tuple_type => for (hir_mod.tupleTypeElements(self.hir, type_node)) |elem| try self.reportTypeRefsToLocalBodyTypes(elem, local_type_names),
            .rest_type => try self.reportTypeRefsToLocalBodyTypes(hir_mod.restTypeOf(self.hir, type_node).operand, local_type_names),
            .keyof_type => try self.reportTypeRefsToLocalBodyTypes(hir_mod.keyofTypeOf(self.hir, type_node).operand, local_type_names),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, type_node);
                try self.reportTypeRefsToLocalBodyTypes(ia.object, local_type_names);
                try self.reportTypeRefsToLocalBodyTypes(ia.index, local_type_names);
            },
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, type_node);
                try self.reportTypeRefsToLocalBodyTypes(c.check, local_type_names);
                try self.reportTypeRefsToLocalBodyTypes(c.extends, local_type_names);
                try self.reportTypeRefsToLocalBodyTypes(c.true_branch, local_type_names);
                try self.reportTypeRefsToLocalBodyTypes(c.false_branch, local_type_names);
            },
            else => {},
        }
    }

    fn recordGenericSignatureParams(self: *Checker, sig: TypeId, params: []const TypeId) CheckError!void {
        if (params.len == 0) return;
        if (self.generic_signature_params.fetchRemove(sig)) |old| {
            self.gpa.free(old.value);
        }
        const owned = try self.gpa.dupe(TypeId, params);
        errdefer self.gpa.free(owned);
        try self.generic_signature_params.put(self.gpa, sig, owned);
    }

    fn recordFunctionNodeGenericSignatureParams(self: *Checker, sig: TypeId, fn_node: NodeId) CheckError!bool {
        const type_params = hir_mod.fnTypeParams(self.hir, fn_node);
        if (type_params.len == 0) return false;
        var params: std.ArrayListUnmanaged(TypeId) = .empty;
        defer params.deinit(self.gpa);
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tp_t = self.hir.typeOf(tp);
            if (tp_t == types.Primitive.none) continue;
            try params.append(self.gpa, tp_t);
        }
        if (params.items.len == 0) return false;
        try self.recordGenericSignatureParams(sig, params.items);
        return true;
    }

    fn checkTopLevelDecoratorDiagnostics(self: *Checker, stmts: []const NodeId) CheckError!void {
        var i: usize = 0;
        while (i < stmts.len) {
            if (self.hir.kindOf(stmts[i]) != .decorator) {
                i += 1;
                continue;
            }
            const start = i;
            while (i < stmts.len and self.hir.kindOf(stmts[i]) == .decorator) : (i += 1) {}
            if (i >= stmts.len) break;
            const target = self.unwrapExportDecl(stmts[i]);
            if (target == hir_mod.none_node_id or (self.hir.kindOf(target) != .class_decl and self.hir.kindOf(target) != .class_expr)) continue;
            for (stmts[start..i]) |decorator_node| {
                try self.checkClassDecoratorDiagnostic(decorator_node);
            }
        }
    }

    fn checkClassDecoratorDiagnostic(self: *Checker, decorator_node: NodeId) CheckError!void {
        if (self.hir.kindOf(decorator_node) != .decorator) return;
        const d = hir_mod.decoratorOf(self.hir, decorator_node);
        if (d.expression == hir_mod.none_node_id) return;
        try self.reportDecoratorUsedBeforeAssignment(d.expression);
        const dec_t = try self.checkExpression(d.expression);
        try self.checkDecoratorRuntimeArity(
            decorator_node,
            dec_t,
            if (self.sourceUsesLegacyDecorators()) 1 else 2,
            TsCodes.class_decorator_signature_unresolved,
            "class",
        );
    }

    fn reportDecoratorUsedBeforeAssignment(self: *Checker, expr_node: NodeId) CheckError!void {
        if (expr_node == hir_mod.none_node_id or self.hir.kindOf(expr_node) != .identifier) return;
        const id = hir_mod.identifierOf(self.hir, expr_node);
        const use_start = self.hir.spanOf(expr_node).start;
        var root = expr_node;
        while (self.hir.parentOf(root) != hir_mod.none_node_id) root = self.hir.parentOf(root);
        if (self.hir.kindOf(root) != .block_stmt) return;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.spanOf(stmt).start >= use_start) break;
            if (self.hir.kindOf(stmt) != .var_decl and self.hir.kindOf(stmt) != .let_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, stmt);
            if (v.is_ambient) continue;
            if (v.init != hir_mod.none_node_id or v.type_annotation == hir_mod.none_node_id) continue;
            if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, v.name).name == id.name) {
                const name_str = self.string_interner.get(id.name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Variable '{s}' is used before being assigned.",
                    .{name_str},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = expr_node,
                    .code = TsCodes.used_before_assignment,
                    .message = msg,
                });
                return;
            }
        }
    }

    fn checkClassMemberDecoratorDiagnostics(self: *Checker, members: []const NodeId) CheckError!void {
        var accessor_decorators: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
        defer accessor_decorators.deinit(self.gpa);
        var i: usize = 0;
        while (i < members.len) {
            if (self.hir.kindOf(members[i]) != .decorator) {
                i += 1;
                continue;
            }
            const start = i;
            while (i < members.len and self.hir.kindOf(members[i]) == .decorator) : (i += 1) {}
            if (i >= members.len) break;
            const target = members[i];
            for (members[start..i]) |decorator_node| {
                try self.checkClassMemberDecoratorDiagnostic(decorator_node, target);
            }
            if (self.sourceUsesLegacyDecorators()) {
                try self.checkAccessorDecoratorPairDiagnostic(target, members[start], &accessor_decorators);
            }
        }
    }

    fn checkAccessorDecoratorPairDiagnostic(
        self: *Checker,
        target: NodeId,
        decorator_node: NodeId,
        seen: *std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (target == hir_mod.none_node_id) return;
        if (self.hir.kindOf(target) != .fn_decl and self.hir.kindOf(target) != .fn_expr and self.hir.kindOf(target) != .arrow_fn) return;
        const f = hir_mod.fnDeclOf(self.hir, target);
        if (!f.flags.is_getter and !f.flags.is_setter) return;
        const member_name = (try self.classMemberNameFromFunctionName(f.name)) orelse return;
        if (seen.contains(member_name)) {
            try self.report(decorator_node, TsCodes.multiple_accessor_decorators, "Decorators cannot be applied to multiple get/set accessors of the same name.");
            return;
        }
        try seen.put(self.gpa, member_name, decorator_node);
    }

    fn checkClassMemberDecoratorDiagnostic(self: *Checker, decorator_node: NodeId, target: NodeId) CheckError!void {
        if (self.hir.kindOf(decorator_node) != .decorator) return;
        const d = hir_mod.decoratorOf(self.hir, decorator_node);
        if (d.expression == hir_mod.none_node_id) return;
        _ = try self.checkExpression(d.expression);
        const target_kind = self.hir.kindOf(target);
        if (target_kind == .fn_decl or target_kind == .fn_expr or target_kind == .arrow_fn) {
            const fn_p = hir_mod.fnDeclOf(self.hir, target);
            if (fn_p.flags.is_constructor) {
                try self.report(decorator_node, TsCodes.decorators_not_valid_here, "Decorators are not valid here.");
                return;
            }
            if (fn_p.body == hir_mod.none_node_id and !fn_p.flags.is_getter and !fn_p.flags.is_setter) {
                try self.report(decorator_node, TsCodes.decorator_on_method_overload, "A decorator can only decorate a method implementation, not an overload.");
                return;
            }
            if (self.sourceUsesLegacyDecorators() and !fn_p.flags.is_constructor and self.sourceHasNoLibTrueDirective()) {
                try self.reportMissingGlobalTypeOnce(decorator_node, "TypedPropertyDescriptor");
            }
            try self.checkDecoratorRuntimeArity(
                decorator_node,
                self.hir.typeOf(d.expression),
                if (self.sourceUsesLegacyDecorators()) 3 else 2,
                TsCodes.method_decorator_signature_unresolved,
                "method",
            );
            return;
        }
        if (target_kind == .object_property) {
            const op = hir_mod.objectPropertyOf(self.hir, target);
            const op_is_method = op.is_method or
                (op.value != hir_mod.none_node_id and
                    (self.hir.kindOf(op.value) == .fn_decl or self.hir.kindOf(op.value) == .fn_expr or self.hir.kindOf(op.value) == .arrow_fn) and
                    self.memberSourceLooksMethod(target));
            if (op_is_method) {
                try self.checkDecoratorRuntimeArity(
                    decorator_node,
                    self.hir.typeOf(d.expression),
                    if (self.sourceUsesLegacyDecorators()) 3 else 2,
                    TsCodes.method_decorator_signature_unresolved,
                    "method",
                );
            } else if (self.sourceUsesLegacyDecorators() and !self.classMemberSourceHasLeadingKeyword(target, "accessor")) {
                try self.checkPropertyDecoratorCallableShape(decorator_node, d.expression);
            } else if (!self.sourceUsesLegacyDecorators()) {
                try self.checkDecoratorRuntimeArity(
                    decorator_node,
                    self.hir.typeOf(d.expression),
                    2,
                    TsCodes.property_decorator_signature_unresolved,
                    "field",
                );
            }
        }
    }

    fn sourceUsesLegacyDecorators(self: *Checker) bool {
        const src = self.source orelse return false;
        if (std.mem.indexOf(u8, src, "@experimentalDecorators: true") != null) return true;
        if (std.mem.indexOf(u8, src, "@experimentaldecorators: true") != null) return true;
        if (std.mem.indexOf(u8, src, "\"experimentalDecorators\": true") != null) return true;
        if (std.mem.indexOf(u8, src, "\"experimentalDecorators\":true") != null) return true;
        return false;
    }

    fn classMemberSourceHasLeadingKeyword(self: *Checker, node: NodeId, keyword: []const u8) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        if (span.start >= src.len) return false;
        var i: usize = span.start;
        while (i < src.len) : (i += 1) {
            switch (src[i]) {
                ' ', '\t', '\r', '\n' => continue,
                else => break,
            }
        }
        if (std.mem.startsWith(u8, src[i..], keyword)) {
            const end = i + keyword.len;
            if (end >= src.len) return true;
            if (!std.ascii.isAlphanumeric(src[end]) and src[end] != '_' and src[end] != '$') return true;
        }

        i = span.start;
        while (i > 0) {
            const prev = src[i - 1];
            if (prev == ' ' or prev == '\t' or prev == '\r' or prev == '\n') {
                i -= 1;
                continue;
            }
            break;
        }
        const word_end = i;
        while (i > 0) {
            const prev = src[i - 1];
            if (std.ascii.isAlphanumeric(prev) or prev == '_' or prev == '$') {
                i -= 1;
                continue;
            }
            break;
        }
        return std.mem.eql(u8, src[i..word_end], keyword);
    }

    fn sourceHasNoLibTrueDirective(self: *Checker) bool {
        const src = self.source orelse return false;
        const pos = std.mem.indexOf(u8, src, "@noLib") orelse std.mem.indexOf(u8, src, "@nolib") orelse return false;
        const line_end = std.mem.indexOfScalarPos(u8, src, pos, '\n') orelse src.len;
        const line = src[pos..line_end];
        return std.mem.indexOf(u8, line, "true") != null;
    }

    fn reportMissingGlobalTypeOnce(self: *Checker, node: NodeId, name: []const u8) CheckError!void {
        for (self.diagnostics.items) |d| {
            if (d.code == TsCodes.cannot_find_global_type and std.mem.indexOf(u8, d.message, name) != null) return;
        }
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find global type '{s}'.",
            .{name},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.cannot_find_global_type,
            .message = msg,
        });
    }

    fn checkParameterDecoratorDiagnostics(self: *Checker, param_node: NodeId, fn_node: NodeId, param_index: usize, is_this_param: bool) CheckError!void {
        const decorators = hir_mod.parameterDecorators(self.hir, param_node);
        if (decorators.len == 0) return;
        if (is_this_param) {
            for (decorators) |decorator_node| {
                try self.report(decorator_node, TsCodes.decorator_or_modifier_on_this_parameter, "Neither decorators nor modifiers may be applied to 'this' parameters.");
            }
            return;
        }
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        for (decorators) |decorator_node| {
            if (self.hir.kindOf(decorator_node) != .decorator) continue;
            const d = hir_mod.decoratorOf(self.hir, decorator_node);
            if (d.expression == hir_mod.none_node_id) continue;
            const dec_t = try self.checkExpression(d.expression);
            if (f.flags.is_constructor) {
                try self.checkConstructorParameterDecoratorSignature(decorator_node, dec_t, param_index);
            }
        }
    }

    fn checkConstructorParameterDecoratorSignature(self: *Checker, decorator_node: NodeId, dec_t: TypeId, param_index: usize) CheckError!void {
        _ = param_index;
        if (dec_t >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(dec_t).is_signature) return;
        const params = self.interner.signatureParams(dec_t);
        if (params.len < 2) return;
        const property_key_t = params[1];
        if (self.typeIncludesUndefined(property_key_t)) return;
        try self.report(
            decorator_node,
            TsCodes.parameter_decorator_signature_unresolved,
            "Unable to resolve signature of parameter decorator when called as an expression.\n  Argument of type 'undefined' is not assignable to parameter of type 'string | symbol'.",
        );
    }

    fn checkPropertyDecoratorCallableShape(self: *Checker, decorator_node: NodeId, expr: NodeId) CheckError!void {
        const dec_t = self.hir.typeOf(expr);
        if (dec_t >= self.interner.pool.typeCount()) return;
        if (!self.interner.pool.flagsOf(dec_t).is_signature) return;
        const params = self.interner.signatureParams(dec_t);
        const ret_t = self.interner.signatureReturn(dec_t) orelse types.Primitive.void_t;
        if (self.hir.kindOf(expr) == .identifier and params.len == 0 and ret_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(ret_t).is_signature) {
            try self.reportDecoratorFactoryMustBeCalled(decorator_node, expr);
            return;
        }
        try self.checkPropertyDecoratorSignatureArity(decorator_node, dec_t);
    }

    fn reportDecoratorFactoryMustBeCalled(self: *Checker, decorator_node: NodeId, expr: NodeId) CheckError!void {
        const id = hir_mod.identifierOf(self.hir, expr);
        const name = self.string_interner.get(id.name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}' accepts too few arguments to be used as a decorator here. Did you mean to call it first and write '@{s}()'?",
            .{ name, name },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = decorator_node,
            .code = TsCodes.decorator_too_few_arguments,
            .message = msg,
        });
    }

    fn checkPropertyDecoratorSignatureArity(self: *Checker, decorator_node: NodeId, sig: TypeId) CheckError!void {
        try self.checkDecoratorRuntimeArity(
            decorator_node,
            sig,
            2,
            TsCodes.property_decorator_signature_unresolved,
            "property",
        );
    }

    fn checkDecoratorRuntimeArity(
        self: *Checker,
        decorator_node: NodeId,
        sig: TypeId,
        runtime_arg_count: usize,
        code: u32,
        kind: []const u8,
    ) CheckError!void {
        if (sig >= self.interner.pool.typeCount() or !self.interner.pool.flagsOf(sig).is_signature) return;
        const params = self.interner.signatureParams(sig);
        const min_required = self.signatureMinRequiredArgs(sig, params);
        const has_unbounded_rest = self.rest_signatures.contains(sig) and params.len > 0 and self.fixedTupleLength(params[params.len - 1]) == null;
        if (runtime_arg_count > params.len and self.decoratorSignatureAllowsExtraRuntimeArgs(kind, params)) return;
        if (runtime_arg_count >= min_required and (has_unbounded_rest or runtime_arg_count <= params.len)) return;
        const expected_count = if (runtime_arg_count < min_required) min_required else params.len;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Unable to resolve signature of {s} decorator when called as an expression.\n  The runtime will invoke the decorator with {d} arguments, but the decorator expects {d}.",
            .{ kind, runtime_arg_count, expected_count },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = decorator_node,
            .code = code,
            .message = msg,
        });
    }

    fn decoratorSignatureAllowsExtraRuntimeArgs(self: *Checker, kind: []const u8, params: []const TypeId) bool {
        if (!std.mem.eql(u8, kind, "method")) return false;
        if (params.len != 2) return false;
        _ = self;
        return params[0] == types.Primitive.any or params[0] == types.Primitive.unknown;
    }

    /// Lower a class declaration into an instance object type. Each
    /// method becomes an object member typed as a signature; each
    /// declared field becomes an object member typed as the
    /// annotation (or the initializer's type, or `any`).
    /// Constructors are walked for body typing but excluded from the
    /// instance shape — they live on the constructor function, not
    /// on instances.
    fn checkClassDecl(self: *Checker, node: NodeId) CheckError!void {
        const c = hir_mod.classOf(self.hir, node);
        const members = hir_mod.classMembers(self.hir, node);
        try self.checkClassMemberDecoratorDiagnostics(members);
        const class_name_scope = c.name != hir_mod.none_node_id and
            self.hir.kindOf(c.name) == .identifier;
        if (class_name_scope) {
            const cid = hir_mod.identifierOf(self.hir, c.name);
            try self.pushNarrowScope();
            try self.recordNarrow(cid.name, types.Primitive.any);
        }
        defer if (class_name_scope) self.popNarrowScope();
        const type_params = self.hir.childSlice(c.type_params_start, c.type_params_len);
        try self.checkTypeParameterDeclList(type_params);
        if (type_params.len > 0) try self.pushNarrowScope();
        defer if (type_params.len > 0) self.popNarrowScope();

        var class_param_ids: std.ArrayListUnmanaged(TypeId) = .empty;
        var class_param_ids_moved = false;
        defer if (!class_param_ids_moved) class_param_ids.deinit(self.gpa);
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tpp = hir_mod.typeParameterOf(self.hir, tp);
            const constraint: TypeId = if (tpp.constraint != hir_mod.none_node_id)
                try self.lowererLowerWithTypeParams(tpp.constraint)
            else
                types.Primitive.unknown;
            const def: TypeId = if (tpp.default != hir_mod.none_node_id)
                try self.lowererLowerWithTypeParams(tpp.default)
            else
                types.Primitive.none;
            const tp_id = self.interner.internFreshTypeParameterWithFlags(
                tpp.name,
                constraint,
                def,
                types.Variance.fromHirBits(tpp.variance),
                tpp.is_const,
            ) catch return error.OutOfMemory;
            self.hir.setType(tp, tp_id);
            try self.recordNarrow(tpp.name, tp_id);
            try class_param_ids.append(self.gpa, tp_id);
        }

        // Pass 1: build the instance shape from signatures + field
        // annotations only (no method body walks). Methods need the
        // instance type registered in `class_instance_types` BEFORE
        // their bodies are typed so `this` resolves.
        const parent_instance_t: ?TypeId = if (c.extends != hir_mod.none_node_id) blk: {
            if (self.expressionContainsThis(c.extends)) {
                try self.report(c.extends, TsCodes.not_constructor_function_type, "Type 'typeof globalThis' is not a constructor function type.");
            }
            break :blk try self.classExtendsInstanceType(c.extends);
        } else null;
        const parent_static_t: ?TypeId = if (c.extends != hir_mod.none_node_id)
            (self.classExtendsStaticType(c.extends) catch null) orelse types.Primitive.any
        else
            null;
        var instance_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer instance_members.deinit(self.gpa);
        var static_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer static_members.deinit(self.gpa);
        var ctor_sig: TypeId = types.Primitive.none;
        var has_explicit_ctor = false;
        var string_idx: TypeId = types.Primitive.none;
        var number_idx: TypeId = types.Primitive.none;
        var symbol_idx: TypeId = types.Primitive.none;
        var has_readonly_index = false;
        var static_string_idx: TypeId = types.Primitive.none;
        var static_number_idx: TypeId = types.Primitive.none;
        var static_symbol_idx: TypeId = types.Primitive.none;
        var has_static_readonly_index = false;
        var own_index_signatures: IndexSignatureDuplicateState = .{};
        var own_static_index_signatures: IndexSignatureDuplicateState = .{};
        const parent_class_name = if (c.extends != hir_mod.none_node_id) self.classExtendsName(c.extends) else null;
        // Names of class members declared `private`. After the class
        // name is known we move ownership into `class_private_members`
        // and reset this local to `.empty` so the trailing `defer` is
        // a no-op on the success path.
        var private_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer private_names.deinit(self.gpa);
        var protected_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer protected_names.deinit(self.gpa);
        // Names of class members treated as abstract (v0 heuristic:
        // bodyless methods inside an `abstract` class). Moved into
        // `class_abstract_members` once the class name is known.
        var abstract_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer abstract_names.deinit(self.gpa);
        var property_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer property_names.deinit(self.gpa);
        var parameter_property_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer parameter_property_names.deinit(self.gpa);
        var accessor_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer accessor_names.deinit(self.gpa);
        var own_member_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer own_member_names.deinit(self.gpa);
        // Names the child concretely implements (methods with a body
        // or any field). Used to satisfy inherited abstract members.
        var concrete_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer concrete_names.deinit(self.gpa);
        var static_names: std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId) = .empty;
        defer static_names.deinit(self.gpa);
        var method_seen: std.AutoHashMapUnmanaged(hir_mod.StringId, ClassMethodSeen) = .empty;
        defer method_seen.deinit(self.gpa);
        var static_method_seen: std.AutoHashMapUnmanaged(hir_mod.StringId, ClassMethodSeen) = .empty;
        defer static_method_seen.deinit(self.gpa);
        var instance_member_predicates: std.AutoHashMapUnmanaged(hir_mod.StringId, FnPredicate) = .empty;
        defer instance_member_predicates.deinit(self.gpa);
        var static_member_predicates: std.AutoHashMapUnmanaged(hir_mod.StringId, FnPredicate) = .empty;
        defer static_member_predicates.deinit(self.gpa);

        // Pre-scan for accessor pairs: a member name with both a
        // `get` and a `set` accessor is a regular read+write property.
        // A getter alone is `readonly`. Track which names have a
        // setter so we can clear readonly when the getter lands.
        var setter_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer setter_names.deinit(self.gpa);
        var setter_types: std.AutoHashMapUnmanaged(hir_mod.StringId, TypeId) = .empty;
        defer setter_types.deinit(self.gpa);
        for (members) |m| {
            const k = self.hir.kindOf(m);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            const fp = hir_mod.fnDeclOf(self.hir, m);
            if (!fp.flags.is_setter) continue;
            const nid = (try self.classMemberNameFromFunctionName(fp.name)) orelse continue;
            try setter_names.put(self.gpa, nid, {});
            const sig = try self.checkFnSignatureOnly(m);
            if (hir_mod.fnTypeParams(self.hir, m).len > 0) self.popNarrowScope();
            const params = self.interner.signatureParams(sig);
            if (params.len > 0) try setter_types.put(self.gpa, nid, params[0]);
        }

        for (members) |m| {
            try self.checkStaticMemberTypeParameterUse(m, type_params);
            switch (self.hir.kindOf(m)) {
                .index_signature => {
                    const ix = hir_mod.indexSignatureOf(self.hir, m);
                    const value_t = if (ix.value_type != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(ix.value_type)
                    else
                        types.Primitive.any;
                    const key_t = if (ix.key_type != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(ix.key_type)
                    else
                        types.Primitive.string_t;
                    if (ix.is_static) {
                        if (ix.is_readonly) has_static_readonly_index = true;
                        try self.checkDuplicateIndexSignature(m, key_t, &own_static_index_signatures);
                        if (key_t == types.Primitive.string_t) static_string_idx = value_t;
                        if (key_t == types.Primitive.number_t) static_number_idx = value_t;
                        if (key_t == types.Primitive.symbol_t) static_symbol_idx = value_t;
                    } else {
                        if (ix.is_readonly) has_readonly_index = true;
                        try self.checkDuplicateIndexSignature(m, key_t, &own_index_signatures);
                        if (key_t == types.Primitive.string_t) string_idx = value_t;
                        if (key_t == types.Primitive.number_t) number_idx = value_t;
                        if (key_t == types.Primitive.symbol_t) symbol_idx = value_t;
                    }
                },
                .fn_decl, .fn_expr, .arrow_fn => {
                    const sig = try self.checkFnSignatureOnly(m);
                    // Pop the type-params scope `checkFnSignatureOnly`
                    // pushed (we don't walk the body in this pass).
                    if (hir_mod.fnTypeParams(self.hir, m).len > 0) self.popNarrowScope();
                    const fn_p = hir_mod.fnDeclOf(self.hir, m);
                    if (fn_p.flags.is_constructor) {
                        ctor_sig = sig;
                        has_explicit_ctor = true;
                        const ctor_params = hir_mod.fnParams(self.hir, m);
                        for (ctor_params) |param_node| {
                            const pp = hir_mod.parameterOf(self.hir, param_node);
                            if (!pp.flags.is_parameter_property and !pp.flags.is_override) continue;
                            if (pp.name == hir_mod.none_node_id or self.hir.kindOf(pp.name) != .identifier) continue;
                            const pid = hir_mod.identifierOf(self.hir, pp.name);
                            if (pp.flags.is_parameter_property) {
                                const param_t = if (self.hir.typeOf(param_node) != types.Primitive.none)
                                    self.hir.typeOf(param_node)
                                else if (pp.type_annotation != hir_mod.none_node_id)
                                    try self.lowererLowerWithTypeParams(pp.type_annotation)
                                else
                                    types.Primitive.any;
                                try instance_members.append(self.gpa, .{
                                    .name = pid.name,
                                    .type = param_t,
                                    .is_optional = pp.flags.is_optional,
                                    .is_readonly = pp.flags.is_readonly,
                                    .is_method = false,
                                });
                                try concrete_names.put(self.gpa, pid.name, {});
                                try property_names.put(self.gpa, pid.name, {});
                                try parameter_property_names.put(self.gpa, pid.name, {});
                                try own_member_names.put(self.gpa, pid.name, {});
                                if (pp.flags.is_private) try private_names.put(self.gpa, pid.name, {});
                                if (pp.flags.is_protected) try protected_names.put(self.gpa, pid.name, {});
                                try self.checkPropertyOverridesAccessor(param_node, parent_class_name, pid.name);
                            }
                            try self.checkOverrideModifier(param_node, parent_instance_t, pid.name, pp.flags.is_override, true);
                        }
                        try self.collectConstructorThisAssignments(m, parent_instance_t, &instance_members);
                        continue;
                    }
                    const fn_name_is_computed = self.nodeIsBracketedComputedName(fn_p.name) or self.nodeIsBracketedComputedName(m) or self.memberSourceLooksComputed(m);
                    var computed_fn_key_t: TypeId = types.Primitive.none;
                    if (fn_name_is_computed and fn_p.name != hir_mod.none_node_id) {
                        if (self.computedNameReferencesTypeParams(fn_p.name, type_params)) {
                            try self.report(fn_p.name, 2467, "A computed property name cannot reference a type parameter from its containing type.");
                        }
                        if (self.expressionContainsSuper(fn_p.name)) {
                            try self.report(fn_p.name, TsCodes.super_in_computed_property_name, "'super' cannot be referenced in a computed property name.");
                        }
                        computed_fn_key_t = try self.checkExpression(fn_p.name);
                        if (!try self.computedPropertyKeyTypeIsValid(computed_fn_key_t)) {
                            try self.report(fn_p.name, TsCodes.computed_property_name_type, "A computed property name must be of type 'string', 'number', 'symbol', or 'any'.");
                        }
                    }
                    const member_name_opt = if (fn_name_is_computed)
                        try self.classMemberNameFromPropertyKey(fn_p.name, true)
                    else
                        try self.classMemberNameFromFunctionName(fn_p.name);
                    if (member_name_opt == null) {
                        if (fn_name_is_computed and fn_p.flags.is_override) {
                            try self.report(m, TsCodes.override_dynamic_name, "This member cannot have an 'override' modifier because its name is dynamic.");
                        }
                        if (fn_name_is_computed and (fn_p.flags.is_getter or fn_p.flags.is_setter)) {
                            const accessor_t: TypeId = if (fn_p.flags.is_getter) blk: {
                                var getter_t = self.interner.signatureReturn(sig) orelse types.Primitive.any;
                                if (getter_t == types.Primitive.any and fn_p.return_type == hir_mod.none_node_id) {
                                    getter_t = (try self.firstReturnExpressionTypeWithClassMemberThis(
                                        fn_p.body,
                                        fn_p.flags.is_static,
                                        instance_members.items,
                                        static_members.items,
                                        string_idx,
                                        number_idx,
                                        symbol_idx,
                                        static_string_idx,
                                        static_number_idx,
                                        static_symbol_idx,
                                        parent_instance_t,
                                        parent_static_t,
                                    )) orelse getter_t;
                                }
                                break :blk getter_t;
                            } else blk: {
                                const params = self.interner.signatureParams(sig);
                                break :blk if (params.len > 0) params[0] else types.Primitive.any;
                            };
                            try self.checkComputedIndexSignatureCompatibility(fn_p.name, computed_fn_key_t, accessor_t, string_idx, number_idx, symbol_idx);
                        }
                        continue;
                    }
                    const member_name = member_name_opt.?;
                    const method_predicate = self.signature_predicates.get(sig);
                    if (fn_p.flags.is_static) {
                        try static_names.put(self.gpa, member_name, m);
                    }
                    try self.checkOverrideModifier(m, if (fn_p.flags.is_static) parent_static_t else parent_instance_t, member_name, fn_p.flags.is_override, false);
                    if (fn_p.flags.is_private) try private_names.put(self.gpa, member_name, {});
                    if (fn_p.flags.is_protected) try protected_names.put(self.gpa, member_name, {});
                    if (!fn_p.flags.is_static) try own_member_names.put(self.gpa, member_name, {});

                    // Accessor (get/set): the property type is the
                    // getter's return or the setter's first param.
                    // `readonly` is true only if there is no sibling
                    // setter for the same name. The first accessor
                    // for a name appends the member; later sibling
                    // accessors of either kind are folded by skipping.
                    if (fn_p.flags.is_getter or fn_p.flags.is_setter) {
                        if (fn_p.flags.is_abstract and fn_p.body != hir_mod.none_node_id) {
                            try self.report(m, TsCodes.abstract_accessor_implementation, "An abstract accessor cannot have an implementation.");
                        }
                        if (!fn_p.flags.is_static) {
                            try accessor_names.put(self.gpa, member_name, {});
                            try self.checkAccessorOverridesProperty(m, parent_class_name, member_name);
                        }
                        if (!fn_p.flags.is_static) {
                            if (fn_p.flags.is_abstract and fn_p.body == hir_mod.none_node_id) {
                                try abstract_names.put(self.gpa, member_name, {});
                            } else {
                                try concrete_names.put(self.gpa, member_name, {});
                            }
                        }
                        var already: bool = false;
                        const accessor_members = if (fn_p.flags.is_static) static_members.items else instance_members.items;
                        for (accessor_members) |im| {
                            if (im.name == member_name) {
                                already = true;
                                break;
                            }
                        }
                        if (already) {
                            if (fn_p.flags.is_getter and !setter_names.contains(member_name)) {
                                try self.report(m, TsCodes.duplicate_identifier, "Duplicate identifier.");
                            }
                            continue;
                        }
                        const accessor_t: TypeId = blk: {
                            if (fn_p.flags.is_getter) {
                                var getter_t = self.interner.signatureReturn(sig) orelse types.Primitive.any;
                                if (getter_t == types.Primitive.any and fn_p.return_type == hir_mod.none_node_id) {
                                    getter_t = (try self.firstReturnExpressionTypeWithClassMemberThis(
                                        fn_p.body,
                                        fn_p.flags.is_static,
                                        instance_members.items,
                                        static_members.items,
                                        string_idx,
                                        number_idx,
                                        symbol_idx,
                                        static_string_idx,
                                        static_number_idx,
                                        static_symbol_idx,
                                        parent_instance_t,
                                        parent_static_t,
                                    )) orelse getter_t;
                                }
                                if (setter_types.get(member_name)) |setter_t| {
                                    if (!(self.engine.isAssignableTo(getter_t, setter_t) catch true)) {
                                        try self.report(m, TsCodes.type_not_assignable, "Type is not assignable to declared type.");
                                    }
                                    break :blk setter_t;
                                }
                                break :blk getter_t;
                            }
                            const params = self.interner.signatureParams(sig);
                            break :blk if (params.len > 0) params[0] else types.Primitive.any;
                        };
                        const has_setter = setter_names.contains(member_name);
                        const member: types.ObjectMember = .{
                            .name = member_name,
                            .type = accessor_t,
                            .is_optional = false,
                            .is_readonly = !has_setter,
                            .is_method = false,
                        };
                        if (fn_p.flags.is_static) {
                            try static_members.append(self.gpa, member);
                        } else {
                            try instance_members.append(self.gpa, member);
                        }
                        continue;
                    }

                    // v0 abstract-member heuristic: a method without
                    // a body inside an `abstract` class is treated as
                    // abstract. Methods with a body count as concrete
                    // implementations and satisfy any inherited
                    // abstract member of the same name.
                    const seen = if (fn_p.flags.is_static) &static_method_seen else &method_seen;
                    const overload_info_before = seen.get(member_name);
                    try self.checkClassMethodOverloadState(m, member_name, fn_p.flags.is_static, self.methodVisibilityBits(fn_p.flags), fn_p.body != hir_mod.none_node_id, seen);
                    if (!fn_p.flags.is_static) {
                        if ((c.is_abstract or fn_p.flags.is_abstract) and fn_p.body == hir_mod.none_node_id) {
                            try abstract_names.put(self.gpa, member_name, {});
                        } else {
                            try concrete_names.put(self.gpa, member_name, {});
                        }
                    }
                    const is_visible_overload_implementation = fn_p.body != hir_mod.none_node_id and
                        overload_info_before != null and
                        overload_info_before.?.bodyless_count > 0;
                    if (is_visible_overload_implementation) continue;
                    const method_member: types.ObjectMember = .{
                        .name = member_name,
                        .type = sig,
                        .is_optional = false,
                        .is_readonly = false,
                        .is_method = true,
                    };
                    if (fn_p.flags.is_static) {
                        try static_members.append(self.gpa, method_member);
                        if (method_predicate) |pred| try static_member_predicates.put(self.gpa, member_name, pred);
                    } else {
                        try instance_members.append(self.gpa, method_member);
                        if (method_predicate) |pred| try instance_member_predicates.put(self.gpa, member_name, pred);
                    }
                },
                .object_property => {
                    const op = hir_mod.objectPropertyOf(self.hir, m);
                    const op_is_computed = op.is_computed or self.nodeIsBracketedComputedName(op.key) or self.memberSourceLooksComputed(m);
                    const op_is_method = op.is_method or
                        (op.value != hir_mod.none_node_id and
                            (self.hir.kindOf(op.value) == .fn_decl or self.hir.kindOf(op.value) == .fn_expr or self.hir.kindOf(op.value) == .arrow_fn) and
                            self.memberSourceLooksMethod(m));
                    if (op_is_computed) {
                        if (self.computedNameReferencesTypeParams(op.key, type_params)) {
                            try self.report(op.key, 2467, "A computed property name cannot reference a type parameter from its containing type.");
                        }
                        if (self.expressionContainsSuper(op.key)) {
                            try self.report(op.key, TsCodes.super_in_computed_property_name, "'super' cannot be referenced in a computed property name.");
                        }
                        if (!self.sourceHasStrictFalseDirective() and self.expressionContainsThis(op.key) and self.currentThisType() == null) {
                            try self.report(op.key, TsCodes.this_implicitly_any, "'this' implicitly has type 'any' because it does not have a type annotation.");
                        }
                        const key_t = try self.checkExpression(op.key);
                        if (!try self.computedPropertyKeyTypeIsValid(key_t)) {
                            try self.report(m, TsCodes.computed_property_name_type, "A computed property name must be of type 'string', 'number', 'symbol', or 'any'.");
                        } else if (!op_is_method and
                            !self.classMemberSourceHasLeadingKeyword(m, "accessor") and
                            !self.computedClassPropertyKeyIsSimpleLiteralNode(op.key, key_t))
                        {
                            try self.report(m, 1166, "A computed property name in a class property declaration must have a simple literal type or a 'unique symbol' type.");
                        }
                    }
                    const member_name_opt = try self.classMemberNameFromPropertyKey(op.key, op_is_computed);
                    if (member_name_opt == null) {
                        if (op_is_computed and op.is_override) {
                            try self.report(m, TsCodes.override_dynamic_name, "This member cannot have an 'override' modifier because its name is dynamic.");
                        }
                        if (op_is_computed and
                            !op_is_method and
                            !op.is_static and
                            self.strict_flags.strict_property_initialization and
                            op.type_annotation != hir_mod.none_node_id and
                            op.value == hir_mod.none_node_id)
                        {
                            const field_t = try self.lowererLowerWithTypeParams(op.type_annotation);
                            if (!self.typeExplicitlyIncludesUndefined(field_t)) {
                                try self.report(m, TsCodes.property_not_initialized, "Property '[computed]' has no initializer and is not definitely assigned in the constructor.");
                            }
                        }
                        continue;
                    }
                    const member_name = member_name_opt.?;
                    if (op.is_static) {
                        try static_names.put(self.gpa, member_name, m);
                    }
                    try self.checkOverrideModifier(m, if (op.is_static) parent_static_t else parent_instance_t, member_name, op.is_override, false);
                    if (op.visibility == .private) try private_names.put(self.gpa, member_name, {});
                    if (op.visibility == .protected) try protected_names.put(self.gpa, member_name, {});
                    if (!op.is_static) try own_member_names.put(self.gpa, member_name, {});
                    if (op_is_method and op.value != hir_mod.none_node_id) {
                        const method_t = if (self.hir.kindOf(op.value) == .fn_decl or self.hir.kindOf(op.value) == .fn_expr or self.hir.kindOf(op.value) == .arrow_fn) blk: {
                            const sig = try self.checkFnSignatureOnly(op.value);
                            if (hir_mod.fnTypeParams(self.hir, op.value).len > 0) self.popNarrowScope();
                            const fn_v = hir_mod.fnDeclOf(self.hir, op.value);
                            const seen = if (op.is_static) &static_method_seen else &method_seen;
                            const overload_info_before = seen.get(member_name);
                            try self.checkClassMethodOverloadState(m, member_name, op.is_static, self.methodVisibilityBits(fn_v.flags), fn_v.body != hir_mod.none_node_id, seen);
                            if (fn_v.body != hir_mod.none_node_id and
                                overload_info_before != null and
                                overload_info_before.?.bodyless_count > 0)
                            {
                                break :blk types.Primitive.none;
                            }
                            break :blk sig;
                        } else try self.checkExpression(op.value);
                        if (!op.is_static) try concrete_names.put(self.gpa, member_name, {});
                        if (method_t == types.Primitive.none) continue;
                        const method_predicate = self.signature_predicates.get(method_t);
                        const method_member: types.ObjectMember = .{
                            .name = member_name,
                            .type = method_t,
                            .is_optional = false,
                            .is_readonly = false,
                            .is_method = true,
                        };
                        if (op.is_static) {
                            try static_members.append(self.gpa, method_member);
                            if (method_predicate) |pred| try static_member_predicates.put(self.gpa, member_name, pred);
                        } else {
                            try instance_members.append(self.gpa, method_member);
                            if (method_predicate) |pred| try instance_member_predicates.put(self.gpa, member_name, pred);
                        }
                        continue;
                    }
                    // Class fields count as concrete implementations
                    // for the purpose of satisfying inherited abstract
                    // members (v0 has no syntax for abstract fields).
                    const is_abstract_property = self.classMemberSourceHasLeadingKeyword(m, "abstract");
                    const is_auto_accessor = self.classMemberSourceHasLeadingKeyword(m, "accessor");
                    if (!op.is_static) {
                        if (is_auto_accessor) {
                            try accessor_names.put(self.gpa, member_name, {});
                            try self.checkAccessorOverridesProperty(m, parent_class_name, member_name);
                        } else {
                            try property_names.put(self.gpa, member_name, {});
                            try self.checkPropertyOverridesAccessor(m, parent_class_name, member_name);
                        }
                        try self.checkFieldInitializerParameterPropertyOrder(m, op.value, &parameter_property_names);
                        if (is_abstract_property and op.value != hir_mod.none_node_id) {
                            try self.report(m, TsCodes.abstract_property_initializer, "Property cannot have an initializer because it is marked abstract.");
                        }
                        if (is_abstract_property and op.value == hir_mod.none_node_id) {
                            try abstract_names.put(self.gpa, member_name, {});
                        } else {
                            try concrete_names.put(self.gpa, member_name, {});
                        }
                    }
                    const field_t: TypeId = blk: {
                        if (op.type_annotation != hir_mod.none_node_id) {
                            break :blk try self.lowererLowerWithTypeParams(op.type_annotation);
                        }
                        if (op.value != hir_mod.none_node_id) {
                            const value_kind = self.hir.kindOf(op.value);
                            if (value_kind == .fn_expr) {
                                const sig = try self.checkFnSignatureOnly(op.value);
                                if (hir_mod.fnTypeParams(self.hir, op.value).len > 0) self.popNarrowScope();
                                break :blk sig;
                            }
                            const this_id = self.string_interner.intern("this") catch return error.OutOfMemory;
                            const super_id = self.string_interner.intern("super") catch return error.OutOfMemory;
                            const partial_this_t = if (op.is_static)
                                self.interner.internObjectTypeWithIndexAndSymbol(
                                    static_members.items,
                                    static_string_idx,
                                    static_number_idx,
                                    static_symbol_idx,
                                ) catch return error.OutOfMemory
                            else
                                self.interner.internObjectTypeWithIndexAndSymbol(
                                    instance_members.items,
                                    string_idx,
                                    number_idx,
                                    symbol_idx,
                                ) catch return error.OutOfMemory;
                            try self.pushNarrowScope();
                            defer self.popNarrowScope();
                            try self.recordNarrow(this_id, partial_this_t);
                            const field_super_t = if (op.is_static) parent_static_t else parent_instance_t;
                            if (field_super_t) |st| try self.recordNarrow(super_id, st);
                            break :blk try self.checkExpression(op.value);
                        }
                        break :blk types.Primitive.any;
                    };
                    if (self.strict_flags.no_implicit_any and
                        op.type_annotation == hir_mod.none_node_id and
                        op.value == hir_mod.none_node_id)
                    {
                        try self.reportMemberImplicitAny(m, member_name);
                    }
                    if (self.strict_flags.strict_property_initialization and
                        !op.is_static and
                        op.type_annotation != hir_mod.none_node_id and
                        op.value == hir_mod.none_node_id and
                        !self.typeExplicitlyIncludesUndefined(field_t))
                    {
                        const field_name = self.string_interner.get(member_name);
                        const msg = try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Property '{s}' has no initializer and is not definitely assigned in the constructor.",
                            .{field_name},
                        );
                        try self.diagnostics.append(self.gpa, .{
                            .node = m,
                            .code = TsCodes.property_not_initialized,
                            .message = msg,
                        });
                    }
                    const field_member: types.ObjectMember = .{
                        .name = member_name,
                        .type = field_t,
                        .is_optional = false,
                        .is_readonly = self.classMemberSourceHasLeadingKeyword(m, "readonly") or
                            self.leadingJsDocHasReadonly(m),
                        .is_method = false,
                    };
                    if (op.is_static) {
                        try static_members.append(self.gpa, field_member);
                    } else {
                        try instance_members.append(self.gpa, field_member);
                    }
                },
                else => {},
            }
        }
        try self.checkClassMethodMissingImplementations(node, &method_seen);
        try self.checkClassMethodMissingImplementations(node, &static_method_seen);
        try self.reportMissingOverrideForUnknownLocalBase(node, members, parent_instance_t);

        // `extends Parent`: prepend any inherited members the child
        // doesn't override. The child's declared members win on
        // name conflict (TS prototype-chain semantics).
        if (c.extends != hir_mod.none_node_id) {
            if (self.bareTypeNodeIsTypeParam(c.extends, type_params)) {
                try self.report(c.extends, TsCodes.cannot_find_name, "Cannot find name.");
            }
            try self.mergeExtendedMembers(c.extends, &instance_members, string_idx, number_idx, symbol_idx);
            if (try self.classExtendsInstanceType(c.extends)) |parent_t| {
                const parent_string_idx = self.interner.objectStringIndex(parent_t);
                const parent_number_idx = self.interner.objectNumberIndex(parent_t);
                const parent_symbol_idx = self.interner.objectSymbolIndex(parent_t);
                if (string_idx == types.Primitive.none) string_idx = parent_string_idx;
                if (number_idx == types.Primitive.none) number_idx = parent_number_idx;
                if (symbol_idx == types.Primitive.none) symbol_idx = parent_symbol_idx;
                if (self.typeHasReadonlyIndexSignature(parent_t)) has_readonly_index = true;
            }
            if (parent_static_t) |pst| {
                try self.mergeInheritedStaticMembers(pst, &static_members);
                const parent_static_string_idx = self.interner.objectStringIndex(pst);
                const parent_static_number_idx = self.interner.objectNumberIndex(pst);
                const parent_static_symbol_idx = self.interner.objectSymbolIndex(pst);
                if (static_string_idx == types.Primitive.none) static_string_idx = parent_static_string_idx;
                if (static_number_idx == types.Primitive.none) static_number_idx = parent_static_number_idx;
                if (static_symbol_idx == types.Primitive.none) static_symbol_idx = parent_static_symbol_idx;
                if (self.typeHasReadonlyIndexSignature(pst)) has_static_readonly_index = true;
            }
        }
        try self.checkIndexSignatureMemberCompatibility(node, instance_members.items, string_idx, number_idx, symbol_idx);
        try self.checkIndexSignatureMemberCompatibility(node, static_members.items, static_string_idx, static_number_idx, static_symbol_idx);
        const class_static_name_id = self.string_interner.intern("name") catch return error.OutOfMemory;
        if (!objectMemberListContains(static_members.items, class_static_name_id)) {
            try static_members.append(self.gpa, .{
                .name = class_static_name_id,
                .type = types.Primitive.string_t,
                .is_optional = false,
                .is_readonly = true,
                .is_method = false,
            });
        }

        var instance_t = self.interner.internObjectTypeWithIndexAndSymbol(instance_members.items, string_idx, number_idx, symbol_idx) catch return error.OutOfMemory;
        if (has_readonly_index) try self.readonly_index_types.put(self.gpa, instance_t, {});
        var static_ctor_sig = ctor_sig;
        var inherited_ctor_sig: ?TypeId = null;
        if (!has_explicit_ctor) {
            if (parent_static_t) |pst| {
                var parent_construct_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
                defer parent_construct_sigs.deinit(self.gpa);
                try self.collectConstructSignatures(pst, &parent_construct_sigs);
                if (parent_construct_sigs.items.len > 0) inherited_ctor_sig = parent_construct_sigs.items[0];
            }
        }
        {
            const construct_name = self.string_interner.intern("__construct") catch return error.OutOfMemory;
            const empty_params: [0]TypeId = .{};
            const ctor_params: []const TypeId = if (has_explicit_ctor)
                self.interner.signatureParams(ctor_sig)
            else if (inherited_ctor_sig) |parent_sig|
                self.interner.signatureParams(parent_sig)
            else
                empty_params[0..];
            static_ctor_sig = self.interner.internSignature(ctor_params, instance_t, true) catch return error.OutOfMemory;
            try self.recordGenericSignatureParams(static_ctor_sig, class_param_ids.items);
            if (has_explicit_ctor and self.rest_signatures.contains(ctor_sig)) {
                try self.rest_signatures.put(self.gpa, static_ctor_sig, {});
            }
            if (inherited_ctor_sig) |parent_sig| {
                if (self.rest_signatures.contains(parent_sig)) try self.rest_signatures.put(self.gpa, static_ctor_sig, {});
                if (self.signature_min_args.get(parent_sig)) |min_required| {
                    try self.signature_min_args.put(self.gpa, static_ctor_sig, min_required);
                }
            }
            try static_members.append(self.gpa, .{
                .name = construct_name,
                .type = static_ctor_sig,
                .is_optional = false,
                .is_readonly = false,
                .is_method = true,
            });
        }
        var static_t = self.interner.internObjectTypeWithIndexAndSymbol(static_members.items, static_string_idx, static_number_idx, static_symbol_idx) catch return error.OutOfMemory;
        if (has_static_readonly_index) try self.readonly_index_types.put(self.gpa, static_t, {});
        try self.class_static_type_by_node.put(self.gpa, node, static_t);
        try self.recordMemberPredicatesForReceiver(instance_t, &instance_member_predicates);
        try self.recordMemberPredicatesForReceiver(static_t, &static_member_predicates);
        if (parent_instance_t) |pt| try self.copyMemberPredicatesFromReceiver(instance_t, pt);
        self.hir.setType(node, if (self.hir.kindOf(node) == .class_expr) static_t else instance_t);
        const class_name_for_static_order: ?hir_mod.StringId = if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier)
            hir_mod.identifierOf(self.hir, c.name).name
        else
            null;
        try self.checkStaticInitializationOrder(class_name_for_static_order, members);
        if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier) {
            const cid = hir_mod.identifierOf(self.hir, c.name);
            try self.checkMergedNamespaceStaticConflicts(node, cid.name, &static_names);
            try self.class_instance_types.put(self.gpa, cid.name, instance_t);
            try self.class_static_types.put(self.gpa, cid.name, static_t);
            try self.type_names.put(self.gpa, cid.name, instance_t);
            if (class_param_ids.items.len > 0) {
                if (self.generic_aliases.get(cid.name)) |old| {
                    self.gpa.free(old.params);
                }
                const owned_params = class_param_ids.toOwnedSlice(self.gpa) catch return error.OutOfMemory;
                class_param_ids_moved = true;
                try self.generic_aliases.put(self.gpa, cid.name, .{
                    .params = owned_params,
                    .body = instance_t,
                    .body_node = hir_mod.none_node_id,
                });
            }
            try self.class_name_by_instance.put(self.gpa, instance_t, cid.name);
            try self.class_name_by_static.put(self.gpa, static_t, cid.name);
            if (has_explicit_ctor) {
                try self.class_constructor_sigs.put(self.gpa, cid.name, static_ctor_sig);
            }
            const implements = self.hir.childSlice(c.implements_start, c.implements_len);
            for (implements) |impl_node| {
                const target_t = self.lowererLowerWithTypeParams(impl_node) catch types.Primitive.unknown;
                if (self.objectHasNoOverlapWithWeakTarget(instance_t, target_t) or
                    !(self.heritageAssignable(instance_t, target_t) catch true))
                {
                    const child_str = self.string_interner.get(cid.name);
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Class '{s}' incorrectly implements interface.",
                        .{child_str},
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = node,
                        .code = TsCodes.class_incorrectly_implements_interface,
                        .message = msg,
                    });
                }
            }
            // Track abstract classes so `new X()` can emit TS2511.
            if (c.is_abstract) {
                try self.abstract_classes.put(self.gpa, cid.name, {});
            } else {
                _ = self.abstract_classes.remove(cid.name);
            }
            if (parent_class_name) |ext_name| {
                try self.checkPrivateBaseRedeclarations(node, cid.name, ext_name, &private_names, &own_member_names);
            }
            // Register the private-member set under the class name.
            // A prior registration (rare — repeated checks of the
            // same source) gets clobbered; release the old set's
            // memory before overwriting.
            if (self.class_private_members.fetchRemove(cid.name)) |old| {
                var owned = old.value;
                owned.deinit(self.gpa);
            }
            try self.class_private_members.put(self.gpa, cid.name, private_names);
            // Ownership has moved into the map; reset the local so
            // the trailing `defer` is a no-op on the success path.
            private_names = .empty;
            if (self.class_protected_members.fetchRemove(cid.name)) |old| {
                var owned = old.value;
                owned.deinit(self.gpa);
            }
            try self.class_protected_members.put(self.gpa, cid.name, protected_names);
            protected_names = .empty;
            // Register abstract-member set for this class so subclass
            // checks can consult it. Replace any prior entry.
            if (self.class_abstract_members.fetchRemove(cid.name)) |old| {
                var owned = old.value;
                owned.deinit(self.gpa);
            }
            try self.class_abstract_members.put(self.gpa, cid.name, abstract_names);
            abstract_names = .empty;
            if (self.class_property_members.fetchRemove(cid.name)) |old| {
                var owned = old.value;
                owned.deinit(self.gpa);
            }
            try self.class_property_members.put(self.gpa, cid.name, property_names);
            property_names = .empty;
            if (self.class_accessor_members.fetchRemove(cid.name)) |old| {
                var owned = old.value;
                owned.deinit(self.gpa);
            }
            try self.class_accessor_members.put(self.gpa, cid.name, accessor_names);
            accessor_names = .empty;
            if (c.extends != hir_mod.none_node_id) {
                if (self.classExtendsName(c.extends)) |ext_name| {
                    if (self.class_instance_types.contains(ext_name)) {
                        try self.class_parent.put(self.gpa, cid.name, ext_name);
                    }
                    // TS2515: a non-abstract class extending an abstract
                    // parent must implement each inherited abstract
                    // member. v0 walks one level only and emits one
                    // diagnostic per missing member.
                    if (!c.is_abstract) {
                        if (self.class_abstract_members.getPtr(ext_name)) |parent_abs| {
                            var it = parent_abs.keyIterator();
                            while (it.next()) |name_ptr| {
                                const member_name = name_ptr.*;
                                if (concrete_names.contains(member_name)) continue;
                                const member_str = self.string_interner.get(member_name);
                                const child_str = self.string_interner.get(cid.name);
                                const parent_str = self.string_interner.get(ext_name);
                                const msg = try std.fmt.allocPrint(
                                    self.diag_arena.allocator(),
                                    "Non-abstract class '{s}' does not implement inherited abstract member '{s}' from class '{s}'.",
                                    .{ child_str, member_str, parent_str },
                                );
                                try self.diagnostics.append(self.gpa, .{
                                    .node = node,
                                    .code = TsCodes.abstract_member_not_implemented,
                                    .message = msg,
                                });
                            }
                        }
                    }
                }
            }
            // The class name as a value is the constructor — we don't
            // have a dedicated constructor signature TypeId yet, so
            // record the instance type on the name node. `new Foo()`
            // looks up the class by name to get the instance type.
            self.hir.setType(c.name, instance_t);
        }

        // Pass 2: re-run each method through `checkFnDecl` (which
        // re-derives the signature idempotently and walks the body)
        // with `this` bound to the instance type and `super` bound
        // to the parent class's instance type (when this class
        // `extends`). Identifier lookup consults narrow scopes
        // first, so `this.x` and `super.foo()` resolve through the
        // matching object type's member table.
        const this_id = self.string_interner.intern("this") catch return error.OutOfMemory;
        const super_id = self.string_interner.intern("super") catch return error.OutOfMemory;
        const super_t = if (c.extends != hir_mod.none_node_id)
            self.classExtendsInstanceType(c.extends) catch null
        else
            null;
        const static_super_t = if (c.extends != hir_mod.none_node_id)
            (self.classExtendsStaticType(c.extends) catch null) orelse types.Primitive.any
        else
            null;
        const instance_this_t = try self.classThisType(instance_t);
        for (members) |m| switch (self.hir.kindOf(m)) {
            .block_stmt => {
                const old_floor = self.narrow_lookup_floor;
                self.narrow_lookup_floor = self.narrow_scopes.items.len;
                errdefer self.narrow_lookup_floor = old_floor;
                try self.pushNarrowScope();
                errdefer self.popNarrowScope();
                try self.recordNarrow(this_id, static_t);
                if (static_super_t) |st| try self.recordNarrow(super_id, st);
                try self.checkStatement(m);
                self.popNarrowScope();
                self.narrow_lookup_floor = old_floor;
            },
            .fn_decl, .fn_expr, .arrow_fn => {
                const fn_p = hir_mod.fnDeclOf(self.hir, m);
                const old_floor = self.narrow_lookup_floor;
                self.narrow_lookup_floor = self.narrow_scopes.items.len;
                errdefer self.narrow_lookup_floor = old_floor;
                try self.pushNarrowScope();
                errdefer self.popNarrowScope();
                try self.recordNarrow(this_id, if (fn_p.flags.is_static) static_t else instance_this_t);
                const method_super_t = if (fn_p.flags.is_static) static_super_t else super_t;
                if (method_super_t) |st| try self.recordNarrow(super_id, st);
                try self.checkFnDecl(m);
                self.popNarrowScope();
                self.narrow_lookup_floor = old_floor;
            },
            .object_property => {
                const op = hir_mod.objectPropertyOf(self.hir, m);
                if (op.value == hir_mod.none_node_id) continue;
                const value_kind = self.hir.kindOf(op.value);
                if (value_kind != .fn_decl and value_kind != .fn_expr and value_kind != .arrow_fn) continue;
                const old_floor = self.narrow_lookup_floor;
                self.narrow_lookup_floor = self.narrow_scopes.items.len;
                errdefer self.narrow_lookup_floor = old_floor;
                try self.pushNarrowScope();
                errdefer self.popNarrowScope();
                try self.recordNarrow(this_id, if (op.is_static) static_t else instance_this_t);
                const method_super_t = if (op.is_static) static_super_t else super_t;
                if (method_super_t) |st| try self.recordNarrow(super_id, st);
                if (value_kind == .fn_expr and !op.is_method and !self.memberSourceLooksMethod(m)) {
                    try self.checkFnDeclWithFlowBoundary(op.value);
                } else {
                    try self.checkFnDecl(op.value);
                }
                self.popNarrowScope();
                self.narrow_lookup_floor = old_floor;
            },
            else => {},
        };

        var refined_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer refined_members.deinit(self.gpa);
        var changed = false;
        for (instance_members.items) |im| {
            var next = im;
            if (im.is_method) {
                for (members) |m| {
                    const k = self.hir.kindOf(m);
                    if (k == .object_property) {
                        const op = hir_mod.objectPropertyOf(self.hir, m);
                        if (!op.is_method or op.value == hir_mod.none_node_id) continue;
                        const op_member_name = (try self.classMemberNameFromPropertyKey(op.key, op.is_computed)) orelse continue;
                        if (op_member_name != im.name) continue;
                        const refined_t = self.hir.typeOf(op.value);
                        if (refined_t != types.Primitive.none and refined_t != im.type) {
                            next.type = refined_t;
                            changed = true;
                        }
                        break;
                    }
                    if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
                    const fn_p = hir_mod.fnDeclOf(self.hir, m);
                    if (fn_p.body == hir_mod.none_node_id or fn_p.return_type != hir_mod.none_node_id) continue;
                    const fn_member_name = (try self.classMemberNameFromFunctionName(fn_p.name)) orelse continue;
                    if (fn_member_name != im.name) continue;
                    const refined_t = self.hir.typeOf(m);
                    if (refined_t != types.Primitive.none and refined_t != im.type) {
                        next.type = refined_t;
                        changed = true;
                    }
                    break;
                }
            }
            try refined_members.append(self.gpa, next);
        }
        if (changed) {
            try self.checkIndexSignatureMemberCompatibility(node, refined_members.items, string_idx, number_idx, symbol_idx);
            instance_t = self.interner.internObjectTypeWithIndexAndSymbol(refined_members.items, string_idx, number_idx, symbol_idx) catch return error.OutOfMemory;
            const construct_name = self.string_interner.intern("__construct") catch return error.OutOfMemory;
            const empty_params: [0]TypeId = .{};
            const ctor_params: []const TypeId = if (has_explicit_ctor) self.interner.signatureParams(ctor_sig) else empty_params[0..];
            static_ctor_sig = self.interner.internSignature(ctor_params, instance_t, true) catch return error.OutOfMemory;
            try self.recordGenericSignatureParams(static_ctor_sig, class_param_ids.items);
            if (has_explicit_ctor and self.rest_signatures.contains(ctor_sig)) {
                try self.rest_signatures.put(self.gpa, static_ctor_sig, {});
            }
            for (static_members.items) |*member| {
                if (member.name == construct_name) {
                    member.type = static_ctor_sig;
                    break;
                }
            }
            static_t = self.interner.internObjectTypeWithIndexAndSymbol(static_members.items, static_string_idx, static_number_idx, static_symbol_idx) catch return error.OutOfMemory;
            if (has_static_readonly_index) try self.readonly_index_types.put(self.gpa, static_t, {});
            try self.class_static_type_by_node.put(self.gpa, node, static_t);
            try self.recordMemberPredicatesForReceiver(instance_t, &instance_member_predicates);
            if (parent_instance_t) |pt| try self.copyMemberPredicatesFromReceiver(instance_t, pt);
            self.hir.setType(node, if (self.hir.kindOf(node) == .class_expr) static_t else instance_t);
            if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier) {
                const cid = hir_mod.identifierOf(self.hir, c.name);
                try self.class_instance_types.put(self.gpa, cid.name, instance_t);
                try self.class_static_types.put(self.gpa, cid.name, static_t);
                try self.type_names.put(self.gpa, cid.name, instance_t);
                if (self.generic_aliases.getPtr(cid.name)) |info| {
                    info.body = instance_t;
                }
                try self.class_name_by_instance.put(self.gpa, instance_t, cid.name);
                try self.class_name_by_static.put(self.gpa, static_t, cid.name);
                const implements = self.hir.childSlice(c.implements_start, c.implements_len);
                for (implements) |impl_node| {
                    const target_t = self.lowererLowerWithTypeParams(impl_node) catch types.Primitive.unknown;
                    if (self.objectHasNoOverlapWithWeakTarget(instance_t, target_t) or
                        !(self.heritageAssignable(instance_t, target_t) catch true))
                    {
                        const child_str = self.string_interner.get(cid.name);
                        const msg = try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Class '{s}' incorrectly implements interface.",
                            .{child_str},
                        );
                        try self.diagnostics.append(self.gpa, .{
                            .node = node,
                            .code = TsCodes.class_incorrectly_implements_interface,
                            .message = msg,
                        });
                    }
                }
                self.hir.setType(c.name, instance_t);
            }
        }
    }

    fn collectConstructorThisAssignments(
        self: *Checker,
        ctor_node: NodeId,
        parent_instance_t: ?TypeId,
        members: *std.ArrayListUnmanaged(types.ObjectMember),
    ) CheckError!void {
        const f = hir_mod.fnDeclOf(self.hir, ctor_node);
        if (f.body == hir_mod.none_node_id) return;
        try self.collectThisAssignmentsFromNode(f.body, parent_instance_t, members);
    }

    fn collectThisAssignmentsFromNode(
        self: *Checker,
        node: NodeId,
        parent_instance_t: ?TypeId,
        members: *std.ArrayListUnmanaged(types.ObjectMember),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .block_stmt => {
                for (hir_mod.blockStmts(self.hir, node)) |stmt| {
                    try self.collectThisAssignmentsFromNode(stmt, parent_instance_t, members);
                }
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                try self.collectThisAssignmentTarget(a.target, a.value, parent_instance_t, members);
                try self.collectThisAssignmentsFromNode(a.value, parent_instance_t, members);
            },
            .if_stmt => {
                const i = hir_mod.ifOf(self.hir, node);
                try self.collectThisAssignmentsFromNode(i.then_branch, parent_instance_t, members);
                try self.collectThisAssignmentsFromNode(i.else_branch, parent_instance_t, members);
            },
            .while_stmt => try self.collectThisAssignmentsFromNode(hir_mod.whileOf(self.hir, node).body, parent_instance_t, members),
            .do_while_stmt => try self.collectThisAssignmentsFromNode(hir_mod.doWhileOf(self.hir, node).body, parent_instance_t, members),
            else => {},
        }
    }

    fn collectThisAssignmentTarget(
        self: *Checker,
        target: NodeId,
        value: NodeId,
        parent_instance_t: ?TypeId,
        members: *std.ArrayListUnmanaged(types.ObjectMember),
    ) CheckError!void {
        if (target == hir_mod.none_node_id or self.hir.kindOf(target) != .member_access) return;
        const m = hir_mod.memberOf(self.hir, target);
        if (self.hir.kindOf(m.object) != .identifier) return;
        const obj = hir_mod.identifierOf(self.hir, m.object);
        if (!std.mem.eql(u8, self.string_interner.get(obj.name), "this")) return;
        for (members.items) |existing| {
            if (existing.name == m.name) return;
        }
        if (parent_instance_t) |pt| {
            if (self.interner.objectMemberInfo(pt, m.name) != null) return;
        }
        const value_t = if (value != hir_mod.none_node_id)
            (self.checkExpression(value) catch types.Primitive.any)
        else
            types.Primitive.any;
        try members.append(self.gpa, .{
            .name = m.name,
            .type = value_t,
            .is_optional = false,
            .is_readonly = false,
            .is_method = false,
        });
    }

    fn checkMergedNamespaceStaticConflicts(
        self: *Checker,
        class_node: NodeId,
        class_name: hir_mod.StringId,
        static_names: *const std.AutoHashMapUnmanaged(hir_mod.StringId, NodeId),
    ) CheckError!void {
        if (static_names.count() == 0) return;
        const container = self.declarationContainer(class_node);
        const siblings = self.containerStatements(container) orelse return;
        for (siblings) |sibling| {
            const ns_node = self.unwrapExportDecl(sibling);
            if (ns_node == class_node or self.hir.kindOf(ns_node) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, ns_node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, ns.name).name != class_name) continue;
            for (hir_mod.namespaceBody(self.hir, ns_node)) |member| {
                if (self.hir.kindOf(member) != .export_decl) continue;
                const member_node = self.unwrapExportDecl(member);
                if (!self.namespaceExportCreatesValue(member_node)) continue;
                const member_name = self.declarationName(member_node) orelse continue;
                const static_node = static_names.get(member_name) orelse continue;
                try self.reportDuplicateIdentifier(static_node, member_name);
                try self.reportDuplicateIdentifier(member_node, member_name);
            }
        }
    }

    fn namespaceExportCreatesValue(self: *Checker, node: NodeId) bool {
        return switch (self.hir.kindOf(node)) {
            .var_decl,
            .let_decl,
            .const_decl,
            .fn_decl,
            .fn_expr,
            .class_decl,
            .class_expr,
            .enum_decl,
            => true,
            .namespace_decl => self.namespaceHasRuntimeValue(node),
            .interface_decl, .type_alias_decl => false,
            else => false,
        };
    }

    fn mergedNamespaceValueMemberType(
        self: *Checker,
        namespace_name: hir_mod.StringId,
        member_name: hir_mod.StringId,
        anchor: NodeId,
    ) CheckError!?TypeId {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            const ns_node = self.unwrapExportDecl(raw);
            if (self.hir.kindOf(ns_node) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, ns_node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, ns.name).name != namespace_name) continue;
            for (hir_mod.namespaceBody(self.hir, ns_node)) |member_raw| {
                if (self.hir.kindOf(member_raw) != .export_decl) continue;
                const member_node = self.unwrapExportDecl(member_raw);
                const decl_name = self.declarationName(member_node) orelse continue;
                if (decl_name != member_name) continue;
                switch (self.hir.kindOf(member_node)) {
                    .class_decl, .class_expr => {
                        try self.checkClassDecl(member_node);
                        if (self.class_static_types.get(member_name)) |static_t| return static_t;
                        return self.hir.typeOf(member_node);
                    },
                    .fn_decl, .fn_expr => {
                        try self.checkFnDeclWithFlowBoundary(member_node);
                        return self.hir.typeOf(member_node);
                    },
                    .var_decl, .let_decl, .const_decl => {
                        try self.checkNamespaceValueDecl(member_node);
                        return self.hir.typeOf(member_node);
                    },
                    .enum_decl => {
                        try self.checkEnumDecl(member_node);
                        return try self.enumNominalType(member_name);
                    },
                    .namespace_decl => return types.Primitive.any,
                    else => return null,
                }
            }
        }
        return null;
    }

    fn declarationContainer(self: *Checker, node: NodeId) NodeId {
        var cur = node;
        var parent = self.hir.parentOf(cur);
        while (parent != hir_mod.none_node_id and self.hir.kindOf(parent) == .export_decl) {
            cur = parent;
            parent = self.hir.parentOf(cur);
        }
        return parent;
    }

    fn containerStatements(self: *Checker, container: NodeId) ?[]const NodeId {
        if (container == hir_mod.none_node_id) return null;
        return switch (self.hir.kindOf(container)) {
            .block_stmt => hir_mod.blockStmts(self.hir, container),
            .namespace_decl => hir_mod.namespaceBody(self.hir, container),
            else => null,
        };
    }

    fn unwrapExportDecl(self: *Checker, node: NodeId) NodeId {
        if (node != hir_mod.none_node_id and self.hir.kindOf(node) == .export_decl) {
            const ex = hir_mod.exportOf(self.hir, node);
            if (ex.decl != hir_mod.none_node_id) return ex.decl;
        }
        return node;
    }

    fn declarationName(self: *Checker, node: NodeId) ?hir_mod.StringId {
        if (node == hir_mod.none_node_id) return null;
        const name_node: NodeId = switch (self.hir.kindOf(node)) {
            .var_decl, .let_decl, .const_decl => hir_mod.varDeclOf(self.hir, node).name,
            .fn_decl, .fn_expr, .arrow_fn => hir_mod.fnDeclOf(self.hir, node).name,
            .class_decl, .class_expr => hir_mod.classOf(self.hir, node).name,
            .interface_decl => hir_mod.interfaceOf(self.hir, node).name,
            .enum_decl => hir_mod.enumOf(self.hir, node).name,
            .type_alias_decl => hir_mod.typeAliasOf(self.hir, node).name,
            .namespace_decl => hir_mod.namespaceOf(self.hir, node).name,
            else => return null,
        };
        if (name_node == hir_mod.none_node_id or self.hir.kindOf(name_node) != .identifier) return null;
        return hir_mod.identifierOf(self.hir, name_node).name;
    }

    fn reportDuplicateIdentifier(
        self: *Checker,
        node: NodeId,
        name: hir_mod.StringId,
    ) CheckError!void {
        const name_str = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Duplicate identifier '{s}'.",
            .{name_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.duplicate_identifier,
            .message = msg,
        });
    }

    /// TS2341: emit when `obj.name` reaches a member declared
    /// `private` from outside the declaring class body. The check
    /// is purely structural in v0:
    ///
    ///   1. Map `obj_t` back to a class name via
    ///      `class_name_by_instance`. Non-class receivers
    ///      (interfaces, plain object types) bail out.
    ///   2. Look up the class's private-member set. Non-private
    ///      props bail out.
    ///   3. Walk parents of `node` — if no enclosing `class_decl`
    ///      matches the declaring class's name, the access is
    ///      outside the body and we emit TS2341.
    ///
    /// Inheritance is intentionally not chased — `private` in TS
    /// is per-class, so a subclass accessing a parent-class
    /// `private` member is also a TS2341.
    fn checkPrivateMemberAccess(
        self: *Checker,
        node: NodeId,
        obj_t: TypeId,
        prop_name: hir_mod.StringId,
    ) CheckError!void {
        const class_name = self.class_name_by_instance.get(obj_t) orelse
            self.class_name_by_static.get(obj_t) orelse
            return;
        const private_set = self.class_private_members.getPtr(class_name) orelse return;
        if (!private_set.contains(prop_name)) return;
        // Walk parents looking for an enclosing `class_decl` whose
        // name matches `class_name`. Found → access is inside the
        // declaring body; allow it.
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .class_decl and k != .class_expr) continue;
            const c = hir_mod.classOf(self.hir, cur);
            if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) continue;
            const enclosing = hir_mod.identifierOf(self.hir, c.name).name;
            if (enclosing == class_name) return;
        }
        const prop_str = self.string_interner.get(prop_name);
        const class_str = self.string_interner.get(class_name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Property '{s}' is private and only accessible within class '{s}'.",
            .{ prop_str, class_str },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.private_member_access,
            .message = msg,
        });
    }

    /// TS2445: emit when `obj.name` reaches a member declared
    /// `protected` from outside the declaring class and its
    /// subclass chain. Mirrors `checkPrivateMemberAccess` but
    /// allows access from any subclass body — walk the enclosing
    /// `class_decl` chain via `class_parent` to see whether the
    /// receiver's declaring class is reachable through `extends`.
    fn checkProtectedMemberAccess(
        self: *Checker,
        node: NodeId,
        obj_t: TypeId,
        prop_name: hir_mod.StringId,
    ) CheckError!void {
        const class_name = self.class_name_by_instance.get(obj_t) orelse
            self.class_name_by_static.get(obj_t) orelse
            return;
        const protected_set = self.class_protected_members.getPtr(class_name) orelse return;
        if (!protected_set.contains(prop_name)) return;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .class_decl and k != .class_expr) continue;
            const c = hir_mod.classOf(self.hir, cur);
            if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) continue;
            const enclosing = hir_mod.identifierOf(self.hir, c.name).name;
            var probe: ?hir_mod.StringId = enclosing;
            while (probe) |p| {
                if (p == class_name) return;
                probe = self.class_parent.get(p);
            }
        }
        const prop_str = self.string_interner.get(prop_name);
        const class_str = self.string_interner.get(class_name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Property '{s}' is protected and only accessible within class '{s}' and its subclasses.",
            .{ prop_str, class_str },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.protected_member_access,
            .message = msg,
        });
    }

    /// TS2540: emit when an assignment target `obj.x` resolves to a
    /// property declared `readonly`. Object/interface readonly props
    /// are always immutable; class-level readonly fields are
    /// approximated by the constructor exception — `this.x = ...`
    /// inside a constructor body is allowed. Bare `any` receivers and
    /// non-object types are silently skipped (no readonly to enforce).
    fn checkReadonlyAssignment(self: *Checker, target: NodeId) CheckError!void {
        if (self.hir.kindOf(target) != .member_access) return;
        const m = hir_mod.memberOf(self.hir, target);
        var obj_t = self.hir.typeOf(m.object);
        if (obj_t == types.Primitive.none) return;
        if (obj_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(obj_t).is_type_parameter) {
            obj_t = self.typeParameterConstraint(obj_t) orelse obj_t;
        }
        if (!self.interner.pool.flagsOf(obj_t).is_object_type) return;
        const info = self.interner.objectMemberInfo(obj_t, m.name) orelse return;
        if (!info.is_readonly) return;
        // Constructor exception: `this.x = ...` is only allowed in
        // the constructor of the class that declares readonly `x`.
        // Subclass constructors cannot reassign inherited readonly
        // fields unless they redeclare their own parameter property.
        if (self.nodeIsThisReference(m.object) and self.enclosingConstructorDeclaresReadonlyMember(target, m.name)) {
            return;
        }
        const prop_str = self.string_interner.get(m.name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot assign to '{s}' because it is a read-only property.",
            .{prop_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = target,
            .code = TsCodes.readonly_property,
            .message = msg,
        });
    }

    fn nodeIsThisReference(self: *Checker, node: NodeId) bool {
        return switch (self.hir.kindOf(node)) {
            .this_expr => true,
            .identifier => blk: {
                const id = hir_mod.identifierOf(self.hir, node);
                break :blk std.mem.eql(u8, self.string_interner.get(id.name), "this");
            },
            else => false,
        };
    }

    fn enclosingConstructorDeclaresReadonlyMember(
        self: *Checker,
        node: NodeId,
        member_name: hir_mod.StringId,
    ) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .fn_decl and k != .fn_expr and k != .arrow_fn) continue;
            const fp = hir_mod.fnDeclOf(self.hir, cur);
            if (!fp.flags.is_constructor) return false;
            var parent = self.hir.parentOf(cur);
            while (parent != hir_mod.none_node_id) : (parent = self.hir.parentOf(parent)) {
                const pk = self.hir.kindOf(parent);
                if (pk == .class_decl or pk == .class_expr) {
                    return self.classDeclaresReadonlyMember(parent, member_name);
                }
                if (pk == .fn_decl or pk == .fn_expr or pk == .arrow_fn) return false;
            }
            return false;
        }
        return false;
    }

    fn classDeclaresReadonlyMember(self: *Checker, class_node: NodeId, member_name: hir_mod.StringId) bool {
        for (hir_mod.classMembers(self.hir, class_node)) |member| {
            switch (self.hir.kindOf(member)) {
                .object_property => {
                    const op = hir_mod.objectPropertyOf(self.hir, member);
                    const name = (self.classMemberNameFromPropertyKey(op.key, op.is_computed) catch null) orelse continue;
                    if (name == member_name and
                        (self.classMemberSourceHasLeadingKeyword(member, "readonly") or self.leadingJsDocHasReadonly(member))) return true;
                },
                .fn_decl, .fn_expr, .arrow_fn => {
                    const fn_p = hir_mod.fnDeclOf(self.hir, member);
                    if (!fn_p.flags.is_constructor) continue;
                    for (hir_mod.fnParams(self.hir, member)) |param_node| {
                        const pp = hir_mod.parameterOf(self.hir, param_node);
                        if (!pp.flags.is_parameter_property or !pp.flags.is_readonly) continue;
                        if (pp.name == hir_mod.none_node_id or self.hir.kindOf(pp.name) != .identifier) continue;
                        if (hir_mod.identifierOf(self.hir, pp.name).name == member_name) return true;
                    }
                },
                else => {},
            }
        }
        return false;
    }

    fn checkReadonlyIndexAssignment(self: *Checker, target: NodeId) CheckError!void {
        if (self.hir.kindOf(target) != .element_access) return;
        const e = hir_mod.elementOf(self.hir, target);
        var obj_t = self.hir.typeOf(e.object);
        if (obj_t == types.Primitive.none) return;
        if (!self.typeHasReadonlyIndexSignature(obj_t) and self.hir.kindOf(e.object) == .identifier) {
            obj_t = self.typeOfIdentifierDeclared(e.object);
        }
        if (!self.typeHasReadonlyIndexSignature(obj_t)) return;
        try self.diagnostics.append(self.gpa, .{
            .node = target,
            .code = TsCodes.readonly_index_signature,
            .message = "Index signature only permits reading.",
        });
    }

    fn typeHasReadonlyIndexSignature(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        if (self.readonly_index_types.contains(t)) return true;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (self.typeHasReadonlyIndexSignature(member)) return true;
            }
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.typeHasReadonlyIndexSignature(member)) return true;
            }
        }
        return false;
    }

    fn baseClassHasMember(self: *Checker, parent_t: ?TypeId, name: hir_mod.StringId) bool {
        const pt = parent_t orelse return false;
        if (pt >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(pt);
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(pt)) |member| {
                if (self.baseClassHasMember(member, name)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return false;
        return self.interner.objectMember(pt, name) != null;
    }

    fn checkOverrideModifier(
        self: *Checker,
        node: NodeId,
        parent_t: ?TypeId,
        name: hir_mod.StringId,
        has_override: bool,
        is_parameter_property: bool,
    ) CheckError!void {
        const has_base = self.baseClassHasMember(parent_t, name);
        const has_jsdoc_override = !has_override and !is_parameter_property and
            self.sourceHasCheckJsDirective() and self.leadingJsDocHasOverride(node);
        if ((has_override or has_jsdoc_override) and !has_base) {
            try self.report(node, TsCodes.override_not_in_base, "This member cannot have an 'override' modifier because it is not declared in the base class.");
            return;
        }
        if (!has_override and has_base and self.strict_flags.no_implicit_override) {
            const code = if (is_parameter_property) TsCodes.missing_parameter_property_override else TsCodes.missing_override;
            try self.report(node, code, "This member must have an 'override' modifier because it overrides a member in the base class.");
        }
    }

    fn reportMissingOverrideForUnknownLocalBase(
        self: *Checker,
        class_node: NodeId,
        members: []const NodeId,
        parent_t: ?TypeId,
    ) CheckError!void {
        if (parent_t != null or !self.strict_flags.no_implicit_override) return;
        const c = hir_mod.classOf(self.hir, class_node);
        if (c.extends == hir_mod.none_node_id or self.hir.kindOf(c.extends) != .identifier) return;
        const base_name = hir_mod.identifierOf(self.hir, c.extends).name;
        if (!self.localValueDeclExistsBefore(class_node, base_name)) return;
        for (members) |m| switch (self.hir.kindOf(m)) {
            .fn_decl, .fn_expr, .arrow_fn => {
                const fp = hir_mod.fnDeclOf(self.hir, m);
                if (fp.flags.is_constructor or fp.flags.is_override) continue;
                try self.report(m, TsCodes.missing_override, "This member must have an 'override' modifier because it overrides a member in the base class.");
                return;
            },
            .object_property => {
                const op = hir_mod.objectPropertyOf(self.hir, m);
                if (op.is_override) continue;
                try self.report(m, TsCodes.missing_override, "This member must have an 'override' modifier because it overrides a member in the base class.");
                return;
            },
            else => {},
        };
    }

    fn localValueDeclExistsBefore(self: *Checker, node: NodeId, name: hir_mod.StringId) bool {
        var scope = self.hir.parentOf(node);
        if (scope != hir_mod.none_node_id and self.hir.kindOf(scope) == .export_decl) {
            scope = self.hir.parentOf(scope);
        }
        if (scope == hir_mod.none_node_id) return false;
        const stmts: []const NodeId = switch (self.hir.kindOf(scope)) {
            .block_stmt => hir_mod.blockStmts(self.hir, scope),
            .namespace_decl => hir_mod.namespaceBody(self.hir, scope),
            else => return false,
        };
        for (stmts) |s| {
            if (s == node or (self.hir.kindOf(s) == .export_decl and hir_mod.exportOf(self.hir, s).decl == node)) return false;
            const decl = if (self.hir.kindOf(s) == .export_decl) hir_mod.exportOf(self.hir, s).decl else s;
            if (decl == hir_mod.none_node_id) continue;
            switch (self.hir.kindOf(decl)) {
                .var_decl, .let_decl, .const_decl => {
                    const v = hir_mod.varDeclOf(self.hir, decl);
                    if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier and hir_mod.identifierOf(self.hir, v.name).name == name) return true;
                },
                .fn_decl, .fn_expr => {
                    const f = hir_mod.fnDeclOf(self.hir, decl);
                    if (f.name != hir_mod.none_node_id and self.hir.kindOf(f.name) == .identifier and hir_mod.identifierOf(self.hir, f.name).name == name) return true;
                },
                .class_decl, .class_expr => {
                    const c = hir_mod.classOf(self.hir, decl);
                    if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier and hir_mod.identifierOf(self.hir, c.name).name == name) return true;
                },
                else => {},
            }
        }
        return false;
    }

    fn classMemberNameFromPropertyKey(self: *Checker, key: NodeId, is_computed: bool) CheckError!?hir_mod.StringId {
        return switch (self.hir.kindOf(key)) {
            .identifier => blk: {
                const name = hir_mod.identifierOf(self.hir, key).name;
                if (!is_computed) break :blk name;
                const raw = self.string_interner.get(name);
                if (try self.sourceConstSymbolMemberName(raw)) |member_name| break :blk member_name;
                if (!self.sourceHasDirectConstSymbolInit(raw)) break :blk null;
                const synthetic = try std.fmt.allocPrint(self.gpa, "[computed:{s}]", .{raw});
                defer self.gpa.free(synthetic);
                break :blk self.string_interner.intern(synthetic) catch return error.OutOfMemory;
            },
            .literal_string => hir_mod.literalStringOf(self.hir, key).value,
            .member_access => blk: {
                if (!is_computed) break :blk null;
                const m = hir_mod.memberOf(self.hir, key);
                if (self.hir.kindOf(m.object) != .identifier) break :blk null;
                const obj = hir_mod.identifierOf(self.hir, m.object);
                if (!std.mem.eql(u8, self.string_interner.get(obj.name), "Symbol")) break :blk null;
                const prop = self.string_interner.get(m.name);
                const synthetic = try std.fmt.allocPrint(self.gpa, "Symbol.{s}", .{prop});
                defer self.gpa.free(synthetic);
                break :blk self.string_interner.intern(synthetic) catch return error.OutOfMemory;
            },
            else => null,
        };
    }

    fn classMemberNameFromFunctionName(self: *Checker, name_node: NodeId) CheckError!?hir_mod.StringId {
        if (name_node == hir_mod.none_node_id) return null;
        if (self.hir.kindOf(name_node) == .identifier) {
            return hir_mod.identifierOf(self.hir, name_node).name;
        }
        return try self.classMemberNameFromPropertyKey(name_node, true);
    }

    fn checkClassMethodOverloadState(
        self: *Checker,
        node: NodeId,
        name: hir_mod.StringId,
        is_static: bool,
        visibility: u2,
        has_body: bool,
        seen: *std.AutoHashMapUnmanaged(hir_mod.StringId, ClassMethodSeen),
    ) CheckError!void {
        const gop = try seen.getOrPut(self.gpa, name);
        if (!gop.found_existing) {
            gop.value_ptr.* = .{
                .first_node = node,
                .first_static = is_static,
                .first_visibility = visibility,
                .bodyless_count = if (has_body) 0 else 1,
                .implementation_count = if (has_body) 1 else 0,
            };
            return;
        }
        if (gop.value_ptr.first_static != is_static) {
            const code = if (is_static) TsCodes.overload_must_not_be_static else TsCodes.overload_must_be_static;
            try self.report(node, code, "Overload signatures must all be static or non-static.");
        }
        if (gop.value_ptr.first_visibility != visibility) {
            try self.report(node, TsCodes.overloads_must_all_have_same_visibility, "Overload signatures must all be public, private or protected.");
        }
        if (has_body) {
            gop.value_ptr.implementation_count += 1;
            if (gop.value_ptr.implementation_count > 1) {
                try self.report(node, TsCodes.duplicate_function_implementation, "Duplicate function implementation.");
            }
        } else {
            gop.value_ptr.bodyless_count += 1;
        }
    }

    fn methodVisibilityBits(self: *Checker, flags: hir_mod.FnFlags) u2 {
        _ = self;
        if (flags.is_private) return 1;
        if (flags.is_protected) return 2;
        return 0;
    }

    fn checkClassMethodMissingImplementations(
        self: *Checker,
        class_node: NodeId,
        seen: *const std.AutoHashMapUnmanaged(hir_mod.StringId, ClassMethodSeen),
    ) CheckError!void {
        if (self.classHasLeadingDeclare(class_node)) return;
        if (self.virtualSectionIsDeclarationFile(class_node)) return;
        var it = seen.valueIterator();
        while (it.next()) |info| {
            if (info.bodyless_count == 0 or info.implementation_count != 0) continue;
            if (self.classMethodDeclIsOptional(info.first_node)) continue;
            if (self.classMethodDeclIsAbstract(info.first_node)) continue;
            try self.report(info.first_node, TsCodes.implementation_missing, "Function implementation is missing or not immediately following the declaration.");
        }
    }

    fn classMethodDeclIsAbstract(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .fn_decl, .fn_expr, .arrow_fn => return hir_mod.fnDeclOf(self.hir, node).flags.is_abstract,
            .object_property => {
                const op = hir_mod.objectPropertyOf(self.hir, node);
                if (op.value == hir_mod.none_node_id) return false;
                const vk = self.hir.kindOf(op.value);
                if (vk == .fn_decl or vk == .fn_expr or vk == .arrow_fn) {
                    return hir_mod.fnDeclOf(self.hir, op.value).flags.is_abstract;
                }
                return false;
            },
            else => return false,
        }
    }

    fn classMethodDeclIsOptional(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        const src = self.source orelse return false;
        const member_name = self.classMethodDeclName(node) orelse return false;
        const name_text = self.string_interner.get(member_name);
        if (name_text.len == 0) return false;
        if (name_text[name_text.len - 1] == '?') return true;
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, name_text)) |pos| {
            var i = pos + name_text.len;
            while (i < src.len and std.ascii.isWhitespace(src[i])) : (i += 1) {}
            if (i < src.len and src[i] == '?') {
                i += 1;
                while (i < src.len and std.ascii.isWhitespace(src[i])) : (i += 1) {}
                if (i < src.len and src[i] == '(') return true;
            }
            search_start = pos + name_text.len;
        }
        const anchor_span = blk: {
            const kind = self.hir.kindOf(node);
            if (kind == .fn_decl or kind == .fn_expr) {
                const f = hir_mod.fnDeclOf(self.hir, node);
                if (f.name != hir_mod.none_node_id) break :blk self.hir.spanOf(f.name);
            }
            break :blk self.hir.spanOf(node);
        };
        var line_start: usize = @min(anchor_span.start, src.len);
        while (line_start > 0 and src[line_start - 1] != '\n') : (line_start -= 1) {}
        const line_end = std.mem.indexOfScalarPos(u8, src, line_start, '\n') orelse src.len;
        var i: usize = line_start;
        while (i < line_end) : (i += 1) {
            switch (src[i]) {
                '?' => return true,
                '(' => return false,
                else => {},
            }
        }
        return false;
    }

    fn classMethodDeclName(self: *Checker, node: NodeId) ?hir_mod.StringId {
        return switch (self.hir.kindOf(node)) {
            .fn_decl, .fn_expr => blk: {
                const f = hir_mod.fnDeclOf(self.hir, node);
                if (f.name == hir_mod.none_node_id or self.hir.kindOf(f.name) != .identifier) break :blk null;
                break :blk hir_mod.identifierOf(self.hir, f.name).name;
            },
            .object_property => blk: {
                const op = hir_mod.objectPropertyOf(self.hir, node);
                if (op.key == hir_mod.none_node_id or self.hir.kindOf(op.key) != .identifier) break :blk null;
                break :blk hir_mod.identifierOf(self.hir, op.key).name;
            },
            else => null,
        };
    }

    fn classHasLeadingDeclare(self: *Checker, class_node: NodeId) bool {
        return self.declarationSourceHasLeadingDeclare(class_node);
    }

    fn checkDuplicateIndexSignature(
        self: *Checker,
        node: NodeId,
        key_t: TypeId,
        state: *IndexSignatureDuplicateState,
    ) CheckError!void {
        const slot = if (key_t == types.Primitive.string_t)
            &state.first_string
        else if (key_t == types.Primitive.number_t)
            &state.first_number
        else if (key_t == types.Primitive.symbol_t)
            &state.first_symbol
        else
            return;
        const reported = if (key_t == types.Primitive.string_t)
            &state.reported_string
        else if (key_t == types.Primitive.number_t)
            &state.reported_number
        else
            &state.reported_symbol;
        if (slot.* == hir_mod.none_node_id) {
            slot.* = node;
            return;
        }
        const kind = if (key_t == types.Primitive.number_t)
            "number"
        else if (key_t == types.Primitive.symbol_t)
            "symbol"
        else
            "string";
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Duplicate index signature for type '{s}'.",
            .{kind},
        );
        if (!reported.*) {
            try self.diagnostics.append(self.gpa, .{
                .node = slot.*,
                .code = TsCodes.duplicate_index_signature,
                .message = msg,
            });
            reported.* = true;
        }
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.duplicate_index_signature,
            .message = msg,
        });
    }

    fn declarationSourceHasLeadingDeclare(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        if (span.start > src.len) return false;
        const word = "declare";
        var at_start: usize = span.start;
        while (at_start < src.len and std.ascii.isWhitespace(src[at_start])) : (at_start += 1) {}
        if (at_start + word.len <= src.len and
            std.mem.eql(u8, src[at_start .. at_start + word.len], word) and
            (at_start + word.len == src.len or !isJsDocIdentChar(src[at_start + word.len])))
        {
            return true;
        }
        if (span.start == 0) return false;
        var i: usize = span.start;
        while (i > 0 and std.ascii.isWhitespace(src[i - 1])) : (i -= 1) {}
        if (i < word.len) return false;
        return std.mem.eql(u8, src[i - word.len .. i], word);
    }

    fn declarationLineHasDeclare(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        if (span.start > src.len) return false;
        var line_start: usize = span.start;
        while (line_start > 0 and src[line_start - 1] != '\n') : (line_start -= 1) {}
        var i = line_start;
        while (i < src.len and std.ascii.isWhitespace(src[i]) and src[i] != '\n') : (i += 1) {}
        const word = "declare";
        return i + word.len <= src.len and
            std.mem.eql(u8, src[i .. i + word.len], word) and
            (i + word.len == src.len or !isJsDocIdentChar(src[i + word.len]));
    }

    fn sourceHasDeclareAnyVar(self: *Checker, name_node: NodeId) bool {
        if (name_node == hir_mod.none_node_id or self.hir.kindOf(name_node) != .identifier) return false;
        return self.sourceHasDeclareAnyVarName(hir_mod.identifierOf(self.hir, name_node).name);
    }

    fn sourceHasDeclareAnyVarName(self: *Checker, name: hir_mod.StringId) bool {
        const src = self.source orelse return false;
        const raw = self.string_interner.get(name);
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "declare")) |declare_pos| {
            var p = declare_pos + "declare".len;
            if (declare_pos > 0 and isJsDocIdentChar(src[declare_pos - 1])) {
                search_start = p;
                continue;
            }
            if (p < src.len and isJsDocIdentChar(src[p])) {
                search_start = p;
                continue;
            }
            p = skipAsciiWhitespace(src, p);
            if (p + "var".len > src.len or !std.mem.eql(u8, src[p .. p + "var".len], "var")) {
                search_start = p;
                continue;
            }
            p += "var".len;
            if (p < src.len and isJsDocIdentChar(src[p])) {
                search_start = p;
                continue;
            }
            p = skipAsciiWhitespace(src, p);
            if (!identifierAt(src, p, raw)) {
                search_start = p;
                continue;
            }
            p += raw.len;
            p = skipAsciiWhitespace(src, p);
            if (p >= src.len or src[p] != ':') {
                search_start = p;
                continue;
            }
            p = skipAsciiWhitespace(src, p + 1);
            if (identifierAt(src, p, "any")) return true;
            search_start = p;
        }
        return false;
    }

    fn classPrivateStructuralMismatch(self: *Checker, target_t: TypeId, source_t: TypeId) bool {
        const target_name = self.class_name_by_instance.get(target_t);
        const source_name = self.class_name_by_instance.get(source_t);
        if (target_name != null and source_name != null and target_name.? == source_name.?) return false;
        return self.classPrivateMembersOverlapOther(target_t, source_t) or
            self.classPrivateMembersOverlapOther(source_t, target_t);
    }

    fn classPrivateMembersOverlapOther(self: *Checker, class_t: TypeId, other_t: TypeId) bool {
        const class_name = self.class_name_by_instance.get(class_t) orelse return false;
        const private = self.class_private_members.getPtr(class_name) orelse return false;
        var it = private.keyIterator();
        while (it.next()) |name_ptr| {
            if (self.interner.objectMember(other_t, name_ptr.*) != null) return true;
        }
        return false;
    }

    fn isSymbolNamedMember(self: *Checker, name: hir_mod.StringId) bool {
        const raw = self.string_interner.get(name);
        if (std.mem.startsWith(u8, raw, "Symbol.")) return true;
        if (self.computedMemberNameInner(raw)) |inner| {
            return self.sourceHasUniqueSymbolDeclaration(inner) or self.sourceHasDirectConstSymbolInit(inner);
        }
        return false;
    }

    fn computedMemberNameInner(self: *Checker, raw: []const u8) ?[]const u8 {
        _ = self;
        const prefix = "[computed:";
        if (!std.mem.startsWith(u8, raw, prefix) or raw.len <= prefix.len + 1 or raw[raw.len - 1] != ']') return null;
        return raw[prefix.len .. raw.len - 1];
    }

    fn sourceHasUniqueSymbolDeclaration(self: *Checker, name: []const u8) bool {
        const src = self.source orelse return false;
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "const")) |const_pos| {
            search_start = const_pos + "const".len;
            if (const_pos > 0 and isJsDocIdentChar(src[const_pos - 1])) continue;
            if (search_start < src.len and isJsDocIdentChar(src[search_start])) continue;
            const after_const = std.mem.trim(u8, src[search_start..], " \t\r\n");
            if (!std.mem.startsWith(u8, after_const, name)) continue;
            if (after_const.len > name.len and isJsDocIdentChar(after_const[name.len])) continue;
            const line_end = std.mem.indexOfScalar(u8, after_const, '\n') orelse after_const.len;
            const line = after_const[0..line_end];
            const colon = std.mem.indexOfScalar(u8, line, ':') orelse continue;
            const after_colon = std.mem.trim(u8, line[colon + 1 ..], " \t\r");
            if (std.mem.startsWith(u8, after_colon, "unique symbol")) return true;
        }
        return false;
    }

    fn sourceHasSymbolConstructorMember(self: *Checker, name: hir_mod.StringId) bool {
        const src = self.source orelse return false;
        if (std.mem.indexOf(u8, src, "interface SymbolConstructor") == null) return false;
        return std.mem.indexOf(u8, src, self.string_interner.get(name)) != null;
    }

    fn leadingJsDocHasOverride(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        const body = self.leadingJsDocBody(src, span.start) orelse return false;
        return std.mem.indexOf(u8, body, "@override") != null;
    }

    fn leadingJsDocHasReadonly(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        const body = self.leadingJsDocBody(src, span.start) orelse return false;
        return std.mem.indexOf(u8, body, "@readonly") != null;
    }

    fn sourceHasCheckJsDirective(self: *Checker) bool {
        const src = self.source orelse return false;
        if (std.mem.indexOf(u8, src, "@ts-check") != null) return true;
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "@check")) |pos| {
            search_start = pos + "@check".len;
            if (src.len < pos + "@checkJs".len) continue;
            const js = src[pos + "@check".len .. pos + "@checkJs".len];
            if (!std.ascii.eqlIgnoreCase(js, "js")) continue;
            var rest = std.mem.trim(u8, src[pos + "@checkJs".len ..], " \t");
            if (rest.len > 0 and rest[0] == ':') rest = std.mem.trim(u8, rest[1..], " \t");
            return std.mem.startsWith(u8, rest, "true");
        }
        return false;
    }

    fn sourceHasAllowJsDirective(self: *Checker) bool {
        const src = self.source orelse return false;
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "@allow")) |pos| {
            search_start = pos + "@allow".len;
            if (src.len < pos + "@allowJs".len) continue;
            const js = src[pos + "@allow".len .. pos + "@allowJs".len];
            if (!std.ascii.eqlIgnoreCase(js, "js")) continue;
            var rest = std.mem.trim(u8, src[pos + "@allowJs".len ..], " \t");
            if (rest.len > 0 and rest[0] == ':') rest = std.mem.trim(u8, rest[1..], " \t");
            return std.mem.startsWith(u8, rest, "true");
        }
        return false;
    }

    fn sourceHasDirectConstSymbolInit(self: *Checker, name: []const u8) bool {
        const src = self.source orelse return false;
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "const")) |const_pos| {
            search_start = const_pos + "const".len;
            if (const_pos > 0 and isJsDocIdentChar(src[const_pos - 1])) continue;
            if (search_start < src.len and isJsDocIdentChar(src[search_start])) continue;
            const after_const = std.mem.trim(u8, src[search_start..], " \t\r\n");
            if (!std.mem.startsWith(u8, after_const, name)) continue;
            if (after_const.len > name.len and isJsDocIdentChar(after_const[name.len])) continue;
            const after_name = std.mem.trim(u8, after_const[name.len..], " \t\r\n");
            if (std.mem.startsWith(u8, after_name, "= Symbol(")) return true;
        }
        return false;
    }

    fn sourceConstSymbolMemberName(self: *Checker, name: []const u8) CheckError!?hir_mod.StringId {
        const src = self.source orelse return null;
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "const")) |const_pos| {
            search_start = const_pos + "const".len;
            if (const_pos > 0 and isJsDocIdentChar(src[const_pos - 1])) continue;
            if (search_start < src.len and isJsDocIdentChar(src[search_start])) continue;
            const after_const = std.mem.trim(u8, src[search_start..], " \t\r\n");
            if (!std.mem.startsWith(u8, after_const, name)) continue;
            if (after_const.len > name.len and isJsDocIdentChar(after_const[name.len])) continue;
            const line_end = std.mem.indexOfScalar(u8, after_const, '\n') orelse after_const.len;
            const line = after_const[0..line_end];
            const eq_pos = std.mem.indexOfScalar(u8, line, '=') orelse continue;
            const rhs = std.mem.trim(u8, line[eq_pos + 1 ..], " \t\r;");
            if (!std.mem.startsWith(u8, rhs, "Symbol.")) continue;
            var end: usize = "Symbol.".len;
            while (end < rhs.len and isJsDocIdentChar(rhs[end])) : (end += 1) {}
            const synthetic = try std.fmt.allocPrint(self.gpa, "Symbol.{s}", .{rhs["Symbol.".len..end]});
            defer self.gpa.free(synthetic);
            return self.string_interner.intern(synthetic) catch return error.OutOfMemory;
        }
        return null;
    }

    /// Merge a parent class's instance members into the current
    /// child's member list, inheriting anything the child doesn't
    /// already declare. The child wins on name conflict — that's
    /// override semantics. Silent no-op when the parent expression
    /// isn't a known class identifier.
    fn mergeExtendedMembers(
        self: *Checker,
        extends_expr: NodeId,
        child_members: *std.ArrayListUnmanaged(types.ObjectMember),
        child_string_idx: TypeId,
        child_number_idx: TypeId,
        child_symbol_idx: TypeId,
    ) CheckError!void {
        const parent_t = (try self.classExtendsInstanceType(extends_expr)) orelse return;
        const parent_string_idx = self.interner.objectStringIndex(parent_t);
        if (parent_string_idx != types.Primitive.none and child_string_idx != types.Primitive.none) {
            if (!(self.heritageAssignable(child_string_idx, parent_string_idx) catch false)) {
                try self.reportClassExtendsIndexMismatch(extends_expr);
            }
        }
        const parent_symbol_idx = self.interner.objectSymbolIndex(parent_t);
        if (parent_symbol_idx != types.Primitive.none and child_symbol_idx != types.Primitive.none) {
            if (!(self.heritageAssignable(child_symbol_idx, parent_symbol_idx) catch false)) {
                try self.reportClassExtendsIndexMismatch(extends_expr);
            }
        }
        const parent_number_idx = self.interner.objectNumberIndex(parent_t);
        if (parent_number_idx != types.Primitive.none and child_number_idx != types.Primitive.none) {
            if (!(self.heritageAssignable(child_number_idx, parent_number_idx) catch false)) {
                try self.reportClassExtendsIndexMismatch(extends_expr);
            }
        }
        const parent_members = self.interner.objectMembers(parent_t);

        // Collect the child declarations so overrides can be checked
        // before inherited-only entries are prepended.
        var child_by_name: std.AutoHashMapUnmanaged(hir_mod.StringId, types.ObjectMember) = .empty;
        defer child_by_name.deinit(self.gpa);
        for (child_members.items) |m| try child_by_name.put(self.gpa, m.name, m);

        // Prepend inherited-only members so child entries (declared
        // last) win after sort+dedup is performed by the caller.
        var inherited: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer inherited.deinit(self.gpa);
        for (parent_members) |pm| {
            if (child_by_name.get(pm.name)) |cm| {
                if (!(try self.heritageMemberAssignable(cm.type, pm.type))) {
                    const prop_str = self.string_interner.get(pm.name);
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Property '{s}' in type is not assignable to the same property in base type.",
                        .{prop_str},
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = extends_expr,
                        .code = TsCodes.property_not_assignable_to_base,
                        .message = msg,
                    });
                }
                continue;
            }
            try inherited.append(self.gpa, pm);
        }
        if (inherited.items.len == 0) return;
        try child_members.insertSlice(self.gpa, 0, inherited.items);
    }

    fn mergeInheritedStaticMembers(
        self: *Checker,
        parent_static_t: TypeId,
        child_members: *std.ArrayListUnmanaged(types.ObjectMember),
    ) CheckError!void {
        const construct_name = self.string_interner.intern("__construct") catch return error.OutOfMemory;
        var child_by_name: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer child_by_name.deinit(self.gpa);
        for (child_members.items) |m| try child_by_name.put(self.gpa, m.name, {});

        var inherited: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer inherited.deinit(self.gpa);
        for (self.interner.objectMembers(parent_static_t)) |pm| {
            if (pm.name == construct_name) continue;
            if (child_by_name.contains(pm.name)) continue;
            try inherited.append(self.gpa, pm);
        }
        if (inherited.items.len == 0) return;
        try child_members.insertSlice(self.gpa, 0, inherited.items);
    }

    fn checkPropertyOverridesAccessor(
        self: *Checker,
        node: NodeId,
        parent_class_name: ?hir_mod.StringId,
        member_name: hir_mod.StringId,
    ) CheckError!void {
        const parent_name = parent_class_name orelse return;
        const parent_accessors = self.class_accessor_members.getPtr(parent_name) orelse return;
        if (!parent_accessors.contains(member_name)) return;
        try self.report(node, TsCodes.property_overrides_accessor, "Property overrides an accessor in the base class.");
    }

    fn checkAccessorOverridesProperty(
        self: *Checker,
        node: NodeId,
        parent_class_name: ?hir_mod.StringId,
        member_name: hir_mod.StringId,
    ) CheckError!void {
        const parent_name = parent_class_name orelse return;
        const parent_props = self.class_property_members.getPtr(parent_name) orelse return;
        if (!parent_props.contains(member_name)) return;
        if (self.class_abstract_members.getPtr(parent_name)) |parent_abs| {
            if (parent_abs.contains(member_name)) return;
        }
        try self.report(node, TsCodes.accessor_overrides_property, "Accessor overrides a property in the base class.");
    }

    fn checkFieldInitializerParameterPropertyOrder(
        self: *Checker,
        field_node: NodeId,
        init_node: NodeId,
        parameter_properties: *const std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        if (init_node == hir_mod.none_node_id or parameter_properties.count() == 0) return;
        if (!self.sourceHasUseDefineForClassFieldsTrueDirective()) return;
        var it = parameter_properties.keyIterator();
        while (it.next()) |name_ptr| {
            if (!self.expressionContainsThisMember(init_node, name_ptr.*)) continue;
            const name_text = self.string_interner.get(name_ptr.*);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Property '{s}' is used before its initialization.",
                .{name_text},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = field_node,
                .code = TsCodes.property_used_before_initialization,
                .message = msg,
            });
            return;
        }
    }

    fn expressionContainsThisMember(self: *Checker, node: NodeId, member_name: hir_mod.StringId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                if (m.name == member_name and self.nodeIsThisReference(m.object)) return true;
                return self.expressionContainsThisMember(m.object, member_name);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                if (self.expressionContainsThisMember(c.callee, member_name)) return true;
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    if (self.expressionContainsThisMember(arg, member_name)) return true;
                }
                return false;
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                return self.expressionContainsThisMember(b.lhs, member_name) or self.expressionContainsThisMember(b.rhs, member_name);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                return self.expressionContainsThisMember(a.target, member_name) or self.expressionContainsThisMember(a.value, member_name);
            },
            else => return false,
        }
    }

    fn checkStaticInitializationOrder(
        self: *Checker,
        class_name: ?hir_mod.StringId,
        members: []const NodeId,
    ) CheckError!void {
        var declared_static_fields: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer declared_static_fields.deinit(self.gpa);
        for (members) |member| {
            if (self.hir.kindOf(member) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, member);
            if (!op.is_static) continue;
            const name = (try self.classMemberNameFromPropertyKey(op.key, op.is_computed)) orelse continue;
            try declared_static_fields.put(self.gpa, name, {});
        }

        var initialized_static_fields: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer initialized_static_fields.deinit(self.gpa);
        for (members) |member| {
            switch (self.hir.kindOf(member)) {
                .block_stmt => try self.reportStaticFutureFieldReads(member, class_name, &declared_static_fields, &initialized_static_fields),
                .object_property => {
                    const op = hir_mod.objectPropertyOf(self.hir, member);
                    if (!op.is_static) continue;
                    if (op.value != hir_mod.none_node_id) {
                        try self.reportStaticFutureFieldReads(op.value, class_name, &declared_static_fields, &initialized_static_fields);
                    }
                    if ((try self.classMemberNameFromPropertyKey(op.key, op.is_computed))) |name| {
                        try initialized_static_fields.put(self.gpa, name, {});
                    }
                },
                else => {},
            }
        }
    }

    fn reportStaticFutureFieldReads(
        self: *Checker,
        node: NodeId,
        class_name: ?hir_mod.StringId,
        declared_static_fields: *const std.AutoHashMapUnmanaged(hir_mod.StringId, void),
        initialized_static_fields: *const std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                if (declared_static_fields.contains(m.name) and !initialized_static_fields.contains(m.name) and
                    self.staticMemberAccessUsesCurrentClass(m.object, class_name))
                {
                    const name_text = self.string_interner.get(m.name);
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Property '{s}' is used before its initialization.",
                        .{name_text},
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = node,
                        .code = TsCodes.property_used_before_initialization,
                        .message = msg,
                    });
                }
                try self.reportStaticFutureFieldReads(m.object, class_name, declared_static_fields, initialized_static_fields);
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                try self.reportStaticFutureFieldReads(e.object, class_name, declared_static_fields, initialized_static_fields);
                try self.reportStaticFutureFieldReads(e.index, class_name, declared_static_fields, initialized_static_fields);
            },
            .call_expr, .new_expr => {
                const c = hir_mod.callOf(self.hir, node);
                try self.reportStaticFutureFieldReads(c.callee, class_name, declared_static_fields, initialized_static_fields);
                for (hir_mod.callArgs(self.hir, node)) |arg| {
                    try self.reportStaticFutureFieldReads(arg, class_name, declared_static_fields, initialized_static_fields);
                }
            },
            .binary_op => {
                const b = hir_mod.binopOf(self.hir, node);
                try self.reportStaticFutureFieldReads(b.lhs, class_name, declared_static_fields, initialized_static_fields);
                try self.reportStaticFutureFieldReads(b.rhs, class_name, declared_static_fields, initialized_static_fields);
            },
            .logical_op => {
                const l = hir_mod.logicalOf(self.hir, node);
                try self.reportStaticFutureFieldReads(l.lhs, class_name, declared_static_fields, initialized_static_fields);
                try self.reportStaticFutureFieldReads(l.rhs, class_name, declared_static_fields, initialized_static_fields);
            },
            .assignment => {
                const a = hir_mod.assignmentOf(self.hir, node);
                if (a.op == null) {
                    try self.reportStaticAssignmentTargetReads(a.target, class_name, declared_static_fields, initialized_static_fields);
                } else {
                    try self.reportStaticFutureFieldReads(a.target, class_name, declared_static_fields, initialized_static_fields);
                }
                try self.reportStaticFutureFieldReads(a.value, class_name, declared_static_fields, initialized_static_fields);
            },
            .conditional => {
                const c = hir_mod.conditionalOf(self.hir, node);
                try self.reportStaticFutureFieldReads(c.cond, class_name, declared_static_fields, initialized_static_fields);
                try self.reportStaticFutureFieldReads(c.then_branch, class_name, declared_static_fields, initialized_static_fields);
                try self.reportStaticFutureFieldReads(c.else_branch, class_name, declared_static_fields, initialized_static_fields);
            },
            .array_literal => for (hir_mod.arrayLiteralElements(self.hir, node)) |elem| {
                try self.reportStaticFutureFieldReads(elem, class_name, declared_static_fields, initialized_static_fields);
            },
            .object_literal => for (hir_mod.objectLiteralProps(self.hir, node)) |prop| {
                if (self.hir.kindOf(prop) == .object_property) {
                    const op = hir_mod.objectPropertyOf(self.hir, prop);
                    if (op.is_computed) try self.reportStaticFutureFieldReads(op.key, class_name, declared_static_fields, initialized_static_fields);
                    try self.reportStaticFutureFieldReads(op.value, class_name, declared_static_fields, initialized_static_fields);
                } else {
                    try self.reportStaticFutureFieldReads(prop, class_name, declared_static_fields, initialized_static_fields);
                }
            },
            .block_stmt => for (hir_mod.blockStmts(self.hir, node)) |stmt| {
                try self.reportStaticFutureFieldReads(stmt, class_name, declared_static_fields, initialized_static_fields);
            },
            .return_stmt => {
                const r = hir_mod.returnOf(self.hir, node);
                try self.reportStaticFutureFieldReads(r.value, class_name, declared_static_fields, initialized_static_fields);
            },
            .var_decl, .let_decl, .const_decl => {
                const v = hir_mod.varDeclOf(self.hir, node);
                try self.reportStaticFutureFieldReads(v.init, class_name, declared_static_fields, initialized_static_fields);
            },
            .as_expr, .satisfies_expr, .type_assertion, .non_null_expr => {
                const a = hir_mod.asExpressionOf(self.hir, node);
                try self.reportStaticFutureFieldReads(a.expr, class_name, declared_static_fields, initialized_static_fields);
            },
            .await_expr => {
                const a = hir_mod.awaitExprOf(self.hir, node);
                try self.reportStaticFutureFieldReads(a.expr, class_name, declared_static_fields, initialized_static_fields);
            },
            else => {},
        }
    }

    fn reportStaticAssignmentTargetReads(
        self: *Checker,
        node: NodeId,
        class_name: ?hir_mod.StringId,
        declared_static_fields: *const std.AutoHashMapUnmanaged(hir_mod.StringId, void),
        initialized_static_fields: *const std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .member_access => {
                const m = hir_mod.memberOf(self.hir, node);
                try self.reportStaticFutureFieldReads(m.object, class_name, declared_static_fields, initialized_static_fields);
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, node);
                try self.reportStaticFutureFieldReads(e.object, class_name, declared_static_fields, initialized_static_fields);
                try self.reportStaticFutureFieldReads(e.index, class_name, declared_static_fields, initialized_static_fields);
            },
            .array_literal => for (hir_mod.arrayLiteralElements(self.hir, node)) |elem| {
                try self.reportStaticAssignmentTargetReads(elem, class_name, declared_static_fields, initialized_static_fields);
            },
            .object_literal => for (hir_mod.objectLiteralProps(self.hir, node)) |prop| {
                if (self.hir.kindOf(prop) == .object_property) {
                    const op = hir_mod.objectPropertyOf(self.hir, prop);
                    if (op.is_computed) try self.reportStaticFutureFieldReads(op.key, class_name, declared_static_fields, initialized_static_fields);
                    try self.reportStaticAssignmentTargetReads(op.value, class_name, declared_static_fields, initialized_static_fields);
                } else {
                    try self.reportStaticAssignmentTargetReads(prop, class_name, declared_static_fields, initialized_static_fields);
                }
            },
            else => try self.reportStaticFutureFieldReads(node, class_name, declared_static_fields, initialized_static_fields),
        }
    }

    fn staticMemberAccessUsesCurrentClass(self: *Checker, object: NodeId, class_name: ?hir_mod.StringId) bool {
        if (object == hir_mod.none_node_id) return false;
        if (self.nodeIsThisReference(object)) return true;
        if (class_name) |name| {
            if (self.hir.kindOf(object) == .identifier) {
                return hir_mod.identifierOf(self.hir, object).name == name;
            }
        }
        return false;
    }

    fn checkPrivateBaseRedeclarations(
        self: *Checker,
        node: NodeId,
        child_name: hir_mod.StringId,
        parent_name: hir_mod.StringId,
        child_private: *const std.AutoHashMapUnmanaged(hir_mod.StringId, void),
        child_members: *const std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!void {
        const parent_private = self.class_private_members.getPtr(parent_name) orelse return;
        var it = parent_private.keyIterator();
        while (it.next()) |name_ptr| {
            const member_name = name_ptr.*;
            if (!child_members.contains(member_name)) continue;
            if (child_private.contains(member_name)) continue;
            const child_str = self.string_interner.get(child_name);
            const parent_str = self.string_interner.get(parent_name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Class '{s}' incorrectly extends base class '{s}'.",
                .{ child_str, parent_str },
            );
            try self.diagnostics.append(self.gpa, .{
                .node = node,
                .code = TsCodes.class_incorrectly_extends_base,
                .message = msg,
            });
            return;
        }
    }

    fn reportClassExtendsIndexMismatch(self: *Checker, node: NodeId) CheckError!void {
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.property_not_assignable_to_base,
            .message = "Class incorrectly extends base class; index signatures are incompatible.",
        });
    }

    fn heritageAssignable(self: *Checker, source: TypeId, target: TypeId) !bool {
        if (source == target) return true;
        if (self.containsFreeTypeParameter(target) and
            !self.containsFreeTypeParameter(source) and
            !self.sourceMayAssignToFreeTargetDuringHeritage(source))
        {
            return false;
        }
        return self.engine.isAssignableTo(source, target);
    }

    fn heritageMemberAssignable(self: *Checker, source: TypeId, target: TypeId) CheckError!bool {
        if (self.heritageAssignable(source, target) catch false) return true;
        if (try self.zeroArgSignatureReturnType(target)) |ret| {
            if (self.heritageAssignable(source, ret) catch false) return true;
        }
        if (try self.zeroArgSignatureReturnType(source)) |ret| {
            if (self.heritageAssignable(ret, target) catch false) return true;
        }
        return false;
    }

    fn zeroArgSignatureReturnType(self: *Checker, t: TypeId) CheckError!?TypeId {
        if (!self.interner.isSignature(t)) return null;
        if (self.interner.signatureParams(t).len != 0) return null;
        return self.interner.signatureReturn(t) orelse types.Primitive.any;
    }

    fn sourceMayAssignToFreeTargetDuringHeritage(self: *Checker, source: TypeId) bool {
        if (source == types.Primitive.any) return true;
        if (source >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(source);
        if (!flags.is_signature) return false;
        const ret = self.interner.signatureReturn(source) orelse return true;
        return ret == types.Primitive.any;
    }

    fn objectHasNoOverlapWithWeakTarget(self: *Checker, source: TypeId, target: TypeId) bool {
        if (source >= self.interner.pool.typeCount() or target >= self.interner.pool.typeCount()) return false;
        const sf = self.interner.pool.flagsOf(source);
        const tf = self.interner.pool.flagsOf(target);
        if (!sf.is_object_type or !tf.is_object_type) return false;
        const target_members = self.interner.objectMembers(target);
        if (target_members.len == 0) return false;
        for (target_members) |tm| {
            if (!tm.is_optional) return false;
        }
        for (self.interner.objectMembers(source)) |sm| {
            if (self.interner.objectMember(target, sm.name) != null) return false;
        }
        return true;
    }

    fn classExtendsName(self: *Checker, extends_expr: NodeId) ?hir_mod.StringId {
        return switch (self.hir.kindOf(extends_expr)) {
            .identifier => hir_mod.identifierOf(self.hir, extends_expr).name,
            .type_ref => blk: {
                const r = hir_mod.typeRefOf(self.hir, extends_expr);
                if (r.qualifier_len != 0) break :blk null;
                break :blk r.name;
            },
            else => null,
        };
    }

    fn classExtendsInstanceType(self: *Checker, extends_expr: NodeId) CheckError!?TypeId {
        return switch (self.hir.kindOf(extends_expr)) {
            .identifier => blk: {
                const id = hir_mod.identifierOf(self.hir, extends_expr);
                if (self.class_instance_types.get(id.name)) |t| break :blk t;
                if (try self.resolveForwardClassInstanceType(extends_expr, id.name)) |t| break :blk t;
                if (self.lowerBuiltinObjectType(self.string_interner.get(id.name))) |t| break :blk t;
                if (try self.heritageValueType(extends_expr, id.name)) |value_t| {
                    if (try self.constructReturnType(value_t)) |instance_t| break :blk instance_t;
                }
                break :blk null;
            },
            .type_ref => blk: {
                if (try self.reactComponentInstanceType(extends_expr)) |t| break :blk t;
                break :blk try self.lowererLowerWithTypeParams(extends_expr);
            },
            .class_decl, .class_expr => blk: {
                try self.checkClassDecl(extends_expr);
                if (self.class_static_type_by_node.get(extends_expr)) |static_t| {
                    if (try self.constructReturnType(static_t)) |instance_t| break :blk instance_t;
                }
                break :blk self.hir.typeOf(extends_expr);
            },
            else => null,
        };
    }

    fn constructReturnType(self: *Checker, t: TypeId) CheckError!?TypeId {
        var construct_sigs: std.ArrayListUnmanaged(TypeId) = .empty;
        defer construct_sigs.deinit(self.gpa);
        try self.collectConstructSignatures(t, &construct_sigs);
        if (construct_sigs.items.len == 0) return null;
        return self.interner.signatureReturn(construct_sigs.items[0]) orelse types.Primitive.any;
    }

    fn heritageValueType(self: *Checker, at_node: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        if (self.lookupNarrow(name)) |t| return t;
        return try self.typeOfVisibleNameNoDiag(at_node, name);
    }

    fn reactComponentInstanceType(self: *Checker, type_ref_node: NodeId) CheckError!?TypeId {
        const r = hir_mod.typeRefOf(self.hir, type_ref_node);
        const ref_name = self.string_interner.get(r.name);
        if (!std.mem.eql(u8, ref_name, "Component") and
            !std.mem.eql(u8, ref_name, "PureComponent"))
        {
            return null;
        }
        const qualifiers = self.hir.childSlice(r.qualifier_start, r.qualifier_len);
        if (qualifiers.len != 1 or self.hir.kindOf(qualifiers[0]) != .identifier) return null;
        const q = hir_mod.identifierOf(self.hir, qualifiers[0]);
        if (!std.mem.eql(u8, self.string_interner.get(q.name), "React")) return null;
        const args = self.hir.childSlice(r.args_start, r.args_len);
        const props_t: TypeId = if (args.len > 0)
            try self.lowererLowerWithTypeParams(args[0])
        else
            types.Primitive.any;
        const state_t: TypeId = if (args.len > 1)
            try self.lowererLowerWithTypeParams(args[1])
        else
            types.Primitive.any;
        const props_name = self.string_interner.intern("props") catch return error.OutOfMemory;
        const state_name = self.string_interner.intern("state") catch return error.OutOfMemory;
        const members = [_]types.ObjectMember{
            .{
                .name = props_name,
                .type = props_t,
                .is_optional = false,
                .is_readonly = true,
                .is_method = false,
            },
            .{
                .name = state_name,
                .type = state_t,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            },
        };
        return self.interner.internObjectType(&members) catch return error.OutOfMemory;
    }

    fn reactComponentClassType(self: *Checker, type_ref_node: NodeId) CheckError!?TypeId {
        const r = hir_mod.typeRefOf(self.hir, type_ref_node);
        if (!std.mem.eql(u8, self.string_interner.get(r.name), "ComponentClass")) return null;
        const qualifiers = self.hir.childSlice(r.qualifier_start, r.qualifier_len);
        if (qualifiers.len != 1 or self.hir.kindOf(qualifiers[0]) != .identifier) return null;
        const q = hir_mod.identifierOf(self.hir, qualifiers[0]);
        const q_name = self.string_interner.get(q.name);
        if (!std.mem.eql(u8, q_name, "React") and !std.mem.eql(u8, q_name, "__React")) return null;

        const args = self.hir.childSlice(r.args_start, r.args_len);
        const props_t: TypeId = if (args.len > 0)
            try self.lowererLowerWithTypeParams(args[0])
        else
            types.Primitive.any;
        const props_name = self.string_interner.intern("props") catch return error.OutOfMemory;
        const instance_members = [_]types.ObjectMember{.{
            .name = props_name,
            .type = props_t,
            .is_optional = false,
            .is_readonly = true,
            .is_method = false,
        }};
        const instance_t = self.interner.internObjectType(&instance_members) catch return error.OutOfMemory;
        const ctor_params = [_]TypeId{props_t};
        const ctor_sig = self.interner.internSignature(&ctor_params, instance_t, true) catch return error.OutOfMemory;
        const construct_name = self.string_interner.intern("__construct") catch return error.OutOfMemory;
        const class_members = [_]types.ObjectMember{.{
            .name = construct_name,
            .type = ctor_sig,
            .is_optional = false,
            .is_readonly = false,
            .is_method = true,
        }};
        return self.interner.internObjectType(&class_members) catch return error.OutOfMemory;
    }

    fn classExtendsStaticType(self: *Checker, extends_expr: NodeId) CheckError!?TypeId {
        return switch (self.hir.kindOf(extends_expr)) {
            .identifier => blk: {
                const id = hir_mod.identifierOf(self.hir, extends_expr);
                if (self.class_static_types.get(id.name)) |t| break :blk t;
                if (try self.heritageValueType(extends_expr, id.name)) |value_t| {
                    const static_t = self.typeParameterConstraint(value_t) orelse value_t;
                    if (try self.constructReturnType(static_t)) |_| break :blk static_t;
                    if (static_t != value_t) {
                        if (try self.constructReturnType(value_t)) |_| break :blk value_t;
                    }
                }
                break :blk null;
            },
            .type_ref => blk: {
                const r = hir_mod.typeRefOf(self.hir, extends_expr);
                if (r.qualifier_len != 0) break :blk null;
                break :blk self.class_static_types.get(r.name);
            },
            .class_decl, .class_expr => blk: {
                try self.checkClassDecl(extends_expr);
                break :blk self.class_static_type_by_node.get(extends_expr);
            },
            else => null,
        };
    }

    /// Per-statement check for `import … from "spec"`. The binder
    /// already declared the local bindings; this pass enforces the
    /// `resolveJsonModule` rule: when the option is OFF, an import
    /// from a `.json` specifier is unresolved and emits TS2307.
    /// When ON the import resolves and the default binding stays
    /// `any` (v0 — TS would refine to the parsed JSON's shape).
    fn checkImportDecl(self: *Checker, node: NodeId) CheckError!void {
        const imp = hir_mod.importOf(self.hir, node);
        const spec = self.string_interner.get(imp.module);
        if (spec.len == 0) {
            try self.checkImportEqualsEntity(node, imp);
            return;
        }
        if (self.importDeclIsRequireAssignment(node) and self.sourceDirectiveValueMentions("module", "esnext")) {
            try self.report(node, TsCodes.import_assignment_es_module, "Import assignment cannot be used when targeting ECMAScript modules.");
        }
        if (self.importDeclIsRequireAssignment(node) and self.sourceDirectiveValueMentions("rewriteRelativeImportExtensions", "true") and
            std.mem.startsWith(u8, spec, ".") and try self.virtualRelativeImportResolvesToIndexUnderExtensionPath(node, spec))
        {
            try self.report(node, TsCodes.unsafe_rewrite_relative_import, "This relative import path is unsafe to rewrite because it looks like a file name, but actually resolves to an index file.");
        }
        try self.checkImportingTsExtensionSpecifier(node, spec, imp.is_type_only);
        if (std.mem.endsWith(u8, spec, ".json")) {
            if (self.strict_flags.resolve_json_module or
                self.nodeSourceContainsImportAttributes(node) or
                self.sourceContainsImportAttributesForSpecifier(spec) or
                try self.virtualJsonModuleExists(node, spec)) return;
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Cannot find module '{s}' or its corresponding type declarations.",
                .{spec},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = node,
                .code = TsCodes.cannot_find_module,
                .message = msg,
            });
            return;
        }
        if (imp.is_type_only and self.nodeSourceContainsImportAttributes(node)) {
            try self.report(node, TsCodes.type_not_assignable, "Import attributes are not valid on type-only imports.");
        }
        if (std.mem.startsWith(u8, spec, ".")) {
            try self.checkNamedImportSpecifiers(node, imp, spec);
            if (try self.checkVirtualRelativeModuleImport(node, spec)) return;
            if (try self.isKnownAmbientModuleName(node, spec)) return;
            if (self.sourceHasVirtualFilenameSections()) {
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Cannot find module '{s}' or its corresponding type declarations.",
                    .{spec},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = node,
                    .code = TsCodes.cannot_find_module,
                    .message = msg,
                });
            }
            return;
        }
        if (try self.checkVirtualBareModuleImport(node, spec)) {
            try self.checkNamedImportSpecifiers(node, imp, spec);
            return;
        }
        if (try self.virtualClassicBareModuleExists(node, spec)) return;
        if (self.referenceLibProvidesBareModule(spec)) return;
        if (try self.isKnownAmbientModuleName(node, spec)) return;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find module '{s}' or its corresponding type declarations.",
            .{spec},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.cannot_find_module,
            .message = msg,
        });
    }

    fn nodeSourceContainsImportAttributes(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const sp = self.hir.spanOf(node);
        if (sp.start >= sp.end or sp.end > src.len) return false;
        const text = src[sp.start..sp.end];
        return std.mem.indexOf(u8, text, " with") != null or
            std.mem.indexOf(u8, text, " assert") != null;
    }

    fn sourceContainsImportAttributesForSpecifier(self: *Checker, spec: []const u8) bool {
        const src = self.source orelse return false;
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, spec)) |pos| {
            search_start = pos + spec.len;
            const end = std.mem.indexOfScalarPos(u8, src, search_start, ';') orelse @min(src.len, search_start + 160);
            const tail = src[search_start..@min(end, src.len)];
            if (std.mem.indexOf(u8, tail, "with") != null or std.mem.indexOf(u8, tail, "assert") != null) return true;
        }
        return false;
    }

    fn referenceLibProvidesBareModule(self: *Checker, spec: []const u8) bool {
        const src = self.source orelse return false;
        if (std.mem.eql(u8, spec, "react") and std.mem.indexOf(u8, src, "/.lib/react16.d.ts") != null) return true;
        if (std.mem.eql(u8, spec, "prop-types") and std.mem.indexOf(u8, src, "/.lib/react16.d.ts") != null) return true;
        return false;
    }

    fn virtualJsonModuleExists(self: *Checker, node: NodeId, spec: []const u8) CheckError!bool {
        if (!self.sourceHasVirtualFilenameSections() or !std.mem.startsWith(u8, spec, ".")) return false;
        const from = self.virtualSectionFilenameForNode(node) orelse return false;
        const resolved = try self.resolveVirtualRelativePath(from, spec);
        defer self.gpa.free(resolved);
        if (self.virtualSourceHasFilename(resolved)) return true;
        var tail = spec;
        while (std.mem.startsWith(u8, tail, "./")) tail = tail[2..];
        if (std.mem.lastIndexOfScalar(u8, tail, '/')) |slash| tail = tail[slash + 1 ..];
        const src = self.source orelse return false;
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw| {
            const line = std.mem.trim(u8, raw, " \t\r");
            const marker = std.mem.indexOf(u8, line, "@filename:") orelse
                (std.mem.indexOf(u8, line, "@Filename:") orelse continue);
            var path = std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
            while (std.mem.startsWith(u8, path, "/")) path = path[1..];
            if (std.mem.lastIndexOfScalar(u8, path, '/')) |slash| path = path[slash + 1 ..];
            if (std.mem.eql(u8, path, tail)) return true;
        }
        return false;
    }

    const VirtualModuleResolution = enum {
        none,
        declaration,
        implementation,
    };

    fn checkVirtualRelativeModuleImport(self: *Checker, node: NodeId, spec: []const u8) CheckError!bool {
        if (!self.sourceHasVirtualFilenameSections()) return false;
        const resolution = try self.resolveVirtualRelativeModule(node, spec);
        switch (resolution) {
            .none => return false,
            .declaration => return true,
            .implementation => {
                if (self.strict_flags.no_implicit_any) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Could not find a declaration file for module '{s}'.",
                        .{spec},
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = node,
                        .code = TsCodes.untyped_module,
                        .message = msg,
                    });
                }
                return true;
            },
        }
    }

    fn importDeclIsRequireAssignment(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const sp = self.hir.spanOf(node);
        if (sp.start >= sp.end or sp.end > src.len) return false;
        const text = src[sp.start..sp.end];
        return std.mem.indexOf(u8, text, " = require") != null;
    }

    fn checkImportingTsExtensionSpecifier(self: *Checker, node: NodeId, spec: []const u8, is_type_only_context: bool) CheckError!void {
        if (is_type_only_context) return;
        if (!self.sourceDirectiveValueMentions("allowImportingTsExtensions", "false")) return;
        if (!std.mem.startsWith(u8, spec, ".")) return;
        const code = tsExtensionImportDiagnosticCode(spec) orelse return;
        const msg = if (code == TsCodes.declaration_file_import_requires_import_type)
            "A declaration file cannot be imported without 'import type'."
        else
            "An import path can only end with a TypeScript extension when 'allowImportingTsExtensions' is enabled.";
        try self.report(node, code, msg);
    }

    fn tsExtensionImportDiagnosticCode(spec: []const u8) ?u32 {
        if (std.mem.endsWith(u8, spec, ".d.ts") or
            std.mem.endsWith(u8, spec, ".d.mts") or
            std.mem.endsWith(u8, spec, ".d.cts"))
        {
            return TsCodes.declaration_file_import_requires_import_type;
        }
        if (std.mem.endsWith(u8, spec, ".ts") or
            std.mem.endsWith(u8, spec, ".tsx") or
            std.mem.endsWith(u8, spec, ".mts") or
            std.mem.endsWith(u8, spec, ".cts"))
        {
            return TsCodes.import_path_ts_extension;
        }
        return null;
    }

    fn checkRewriteRelativeImportCall(self: *Checker, node: NodeId, callee: NodeId, args: []const NodeId) CheckError!void {
        if (!self.sourceDirectiveValueMentions("rewriteRelativeImportExtensions", "true")) return;
        if (args.len == 0 or self.hir.kindOf(args[0]) != .literal_string) return;
        const is_loader = if (self.isDynamicImportCallee(callee))
            true
        else blk: {
            if (self.hir.kindOf(callee) != .identifier) break :blk false;
            const id = hir_mod.identifierOf(self.hir, callee);
            break :blk std.mem.eql(u8, self.string_interner.get(id.name), "require");
        };
        if (!is_loader) return;
        const lit = hir_mod.literalStringOf(self.hir, args[0]);
        const spec = self.string_interner.get(lit.value);
        if (!std.mem.startsWith(u8, spec, ".")) return;
        if (!(std.mem.endsWith(u8, spec, ".ts") or
            std.mem.endsWith(u8, spec, ".tsx") or
            std.mem.endsWith(u8, spec, ".mts") or
            std.mem.endsWith(u8, spec, ".cts"))) return;
        if ((try self.resolveVirtualRelativeModule(node, spec)) != .none) return;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find module '{s}' or its corresponding type declarations.",
            .{spec},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = args[0],
            .code = TsCodes.cannot_find_module,
            .message = msg,
        });
    }

    fn checkVirtualBareModuleImport(self: *Checker, node: NodeId, spec: []const u8) CheckError!bool {
        if (!self.sourceHasVirtualFilenameSections()) return false;
        const resolution = try self.resolveVirtualBareModule(spec);
        switch (resolution) {
            .none => return false,
            .declaration => return true,
            .implementation => {
                if (self.strict_flags.no_implicit_any) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Could not find a declaration file for module '{s}'.",
                        .{spec},
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = node,
                        .code = TsCodes.untyped_module,
                        .message = msg,
                    });
                }
                return true;
            },
        }
    }

    fn virtualClassicBareModuleExists(self: *Checker, node: NodeId, spec: []const u8) CheckError!bool {
        if (!self.sourceHasVirtualFilenameSections()) return false;
        if (!(self.sourceDirectiveValueMentions("ModuleResolution", "classic") or
            self.sourceDirectiveValueMentions("moduleResolution", "classic"))) return false;
        if (std.mem.indexOfScalar(u8, spec, '/') != null) return false;
        const from = self.virtualSectionFilenameForNode(node) orelse return false;
        var from_path = from;
        while (std.mem.startsWith(u8, from_path, "/")) from_path = from_path[1..];
        const dir = if (std.mem.lastIndexOfScalar(u8, from_path, '/')) |slash| from_path[0..slash] else "";
        const local_base = if (dir.len > 0)
            try std.fmt.allocPrint(self.gpa, "{s}/{s}", .{ dir, spec })
        else
            try self.gpa.dupe(u8, spec);
        defer self.gpa.free(local_base);
        if (self.virtualSourceHasFilenameWithExtOrIndex(local_base, ".d.ts")) return true;
        return self.virtualSourceHasFilenameWithExtOrIndex(spec, ".d.ts");
    }

    fn resolveVirtualRelativeModule(self: *Checker, node: NodeId, spec: []const u8) CheckError!VirtualModuleResolution {
        const from = self.virtualSectionFilenameForNode(node) orelse return .none;
        const resolved = try self.resolveVirtualRelativePath(from, spec);
        defer self.gpa.free(resolved);

        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".d.ts")) return .declaration;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".d.mts")) return .declaration;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".d.cts")) return .declaration;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".ts")) return .declaration;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".tsx")) return .declaration;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".mts")) return .declaration;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".cts")) return .declaration;

        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".js")) return .implementation;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".jsx")) return .implementation;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".mjs")) return .implementation;
        if (self.virtualSourceHasFilenameWithExtOrIndex(resolved, ".cjs")) return .implementation;
        return .none;
    }

    fn virtualRelativeImportResolvesToIndexUnderExtensionPath(self: *Checker, node: NodeId, spec: []const u8) CheckError!bool {
        if (!self.sourceHasVirtualFilenameSections()) return false;
        const dot = std.mem.lastIndexOfScalar(u8, spec, '.') orelse return false;
        const slash = std.mem.lastIndexOfScalar(u8, spec, '/');
        if (slash != null and dot < slash.?) return false;
        const from = self.virtualSectionFilenameForNode(node) orelse return false;
        const resolved = try self.resolveVirtualRelativePath(from, spec);
        defer self.gpa.free(resolved);
        const exts = [_][]const u8{ ".d.ts", ".ts", ".tsx", ".mts", ".cts", ".js", ".jsx", ".mjs", ".cjs" };
        for (exts) |ext| {
            const index = std.fmt.allocPrint(self.gpa, "{s}/index{s}", .{ resolved, ext }) catch return error.OutOfMemory;
            defer self.gpa.free(index);
            if (self.virtualSourceHasFilename(index)) return true;
        }
        return false;
    }

    fn resolveVirtualBareModule(self: *Checker, spec: []const u8) CheckError!VirtualModuleResolution {
        if (std.mem.startsWith(u8, spec, ".")) return .none;
        const slash = packageNameEnd(spec);
        const package_name = spec[0..slash];
        const subpath = if (slash < spec.len) spec[slash + 1 ..] else "";

        if (try self.virtualBareModuleDeclarationFilename(spec)) |path| {
            self.gpa.free(path);
            return .declaration;
        }
        if (self.sourceDirectiveValueMentions("ModuleResolution", "classic") or self.sourceDirectiveValueMentions("moduleResolution", "classic")) {
            if (self.virtualSourceHasFilenameWithExtOrIndex(spec, ".d.ts")) return .declaration;
        }

        if (try self.virtualPackageHasImplementation("node_modules", package_name, subpath)) return .implementation;
        if (subpath.len == 0 and try self.virtualPackageHasAnyImplementation("node_modules", package_name)) return .implementation;
        if (try self.virtualPackageHasImplementation("", package_name, subpath)) return .implementation;
        if (subpath.len == 0 and try self.virtualPackageHasAnyImplementation("", package_name)) return .implementation;
        return .none;
    }

    fn resolveVirtualRelativePath(self: *Checker, from: []const u8, spec: []const u8) CheckError![]u8 {
        var from_path = from;
        while (std.mem.startsWith(u8, from_path, "/")) from_path = from_path[1..];
        const dir = if (std.mem.lastIndexOfScalar(u8, from_path, '/')) |slash| from_path[0..slash] else "";
        const joined = if (dir.len > 0)
            try std.fmt.allocPrint(self.gpa, "{s}/{s}", .{ dir, spec })
        else
            try self.gpa.dupe(u8, spec);
        defer self.gpa.free(joined);
        return try self.normalizeVirtualPath(joined);
    }

    fn normalizeVirtualPath(self: *Checker, path: []const u8) CheckError![]u8 {
        var parts: std.ArrayListUnmanaged([]const u8) = .empty;
        defer parts.deinit(self.gpa);
        var it = std.mem.splitScalar(u8, path, '/');
        while (it.next()) |part| {
            if (part.len == 0 or std.mem.eql(u8, part, ".")) continue;
            if (std.mem.eql(u8, part, "..")) {
                if (parts.items.len > 0) _ = parts.pop();
                continue;
            }
            try parts.append(self.gpa, part);
        }

        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(self.gpa);
        for (parts.items, 0..) |part, i| {
            if (i > 0) try out.append(self.gpa, '/');
            try out.appendSlice(self.gpa, part);
        }
        return try out.toOwnedSlice(self.gpa);
    }

    fn packageNameEnd(spec: []const u8) usize {
        if (std.mem.startsWith(u8, spec, "@")) {
            const first = std.mem.indexOfScalar(u8, spec, '/') orelse return spec.len;
            const rest = spec[first + 1 ..];
            const second_rel = std.mem.indexOfScalar(u8, rest, '/') orelse return spec.len;
            return first + 1 + second_rel;
        }
        return std.mem.indexOfScalar(u8, spec, '/') orelse spec.len;
    }

    fn virtualPackageHasDeclaration(self: *Checker, root: []const u8, package_name: []const u8, subpath: []const u8) CheckError!bool {
        return try self.virtualPackageHasExt(root, package_name, subpath, ".d.ts");
    }

    fn virtualPackageHasImplementation(self: *Checker, root: []const u8, package_name: []const u8, subpath: []const u8) CheckError!bool {
        if (try self.virtualPackageHasExt(root, package_name, subpath, ".ts")) return true;
        if (try self.virtualPackageHasExt(root, package_name, subpath, ".tsx")) return true;
        if (try self.virtualPackageHasExt(root, package_name, subpath, ".js")) return true;
        if (try self.virtualPackageHasExt(root, package_name, subpath, ".jsx")) return true;
        return false;
    }

    fn virtualPackageHasAnyImplementation(self: *Checker, root: []const u8, package_name: []const u8) CheckError!bool {
        const prefix = if (root.len > 0)
            std.fmt.allocPrint(self.gpa, "{s}/{s}/", .{ root, package_name }) catch return error.OutOfMemory
        else
            std.fmt.allocPrint(self.gpa, "{s}/", .{package_name}) catch return error.OutOfMemory;
        defer self.gpa.free(prefix);
        const src = self.source orelse return false;
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw| {
            const line = std.mem.trim(u8, raw, " \t\r");
            const marker = std.mem.indexOf(u8, line, "@filename:") orelse
                (std.mem.indexOf(u8, line, "@Filename:") orelse continue);
            var path = std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
            while (std.mem.startsWith(u8, path, "/")) path = path[1..];
            while (std.mem.startsWith(u8, path, "./")) path = path[2..];
            if (!std.mem.startsWith(u8, path, prefix)) continue;
            const rest = path[prefix.len..];
            if (std.mem.indexOfScalar(u8, rest, '/')) |slash| {
                const tail = rest[slash + 1 ..];
                if (std.mem.indexOfScalar(u8, tail, '/') == null and isVirtualIndexImplementationPath(tail)) return true;
                continue;
            }
            if (isVirtualImplementationPath(rest)) return true;
        }
        return false;
    }

    fn isVirtualIndexImplementationPath(path: []const u8) bool {
        return std.mem.eql(u8, path, "index.js") or
            std.mem.eql(u8, path, "index.jsx") or
            std.mem.eql(u8, path, "index.mjs") or
            std.mem.eql(u8, path, "index.cjs") or
            std.mem.eql(u8, path, "index.ts") or
            std.mem.eql(u8, path, "index.tsx");
    }

    fn isVirtualImplementationPath(path: []const u8) bool {
        return std.mem.endsWith(u8, path, ".js") or
            std.mem.endsWith(u8, path, ".jsx") or
            std.mem.endsWith(u8, path, ".mjs") or
            std.mem.endsWith(u8, path, ".cjs") or
            std.mem.endsWith(u8, path, ".ts") or
            std.mem.endsWith(u8, path, ".tsx");
    }

    fn virtualPackageHasTypesVersionDeclaration(self: *Checker, root: []const u8, package_name: []const u8, subpath: []const u8) CheckError!bool {
        if (try self.virtualPackageDeclarationFilenameAt(root, package_name, "ts3.1", subpath, ".d.ts")) |path| {
            self.gpa.free(path);
            return true;
        }
        return false;
    }

    fn virtualPackageHasExt(self: *Checker, root: []const u8, package_name: []const u8, subpath: []const u8, ext: []const u8) CheckError!bool {
        return try self.virtualPackageHasExtAt(root, package_name, "", subpath, ext);
    }

    fn virtualPackageHasExtAt(self: *Checker, root: []const u8, package_name: []const u8, prefix: []const u8, subpath: []const u8, ext: []const u8) CheckError!bool {
        var candidates: std.ArrayListUnmanaged([]u8) = .empty;
        defer {
            for (candidates.items) |candidate| self.gpa.free(candidate);
            candidates.deinit(self.gpa);
        }

        if (subpath.len == 0) {
            try self.appendVirtualPackagePathCandidate(&candidates, root, package_name, prefix, "index", ext);
        } else {
            try self.appendVirtualPackagePathCandidate(&candidates, root, package_name, prefix, subpath, ext);
            const indexed = try std.fmt.allocPrint(self.gpa, "{s}/index", .{subpath});
            defer self.gpa.free(indexed);
            try self.appendVirtualPackagePathCandidate(&candidates, root, package_name, prefix, indexed, ext);
        }

        for (candidates.items) |candidate| {
            if (self.virtualSourceHasFilename(candidate)) return true;
        }
        return false;
    }

    fn virtualBareModuleDeclarationFilename(self: *Checker, spec: []const u8) CheckError!?[]u8 {
        if (std.mem.startsWith(u8, spec, ".")) return null;
        const slash = packageNameEnd(spec);
        const package_name = spec[0..slash];
        const subpath = if (slash < spec.len) spec[slash + 1 ..] else "";
        const roots = [_][]const u8{ "node_modules", "" };
        const prefixes = [_][]const u8{ "ts3.1", "" };
        for (roots) |root| {
            for (prefixes) |prefix| {
                if (try self.virtualPackageDeclarationFilenameAt(root, package_name, prefix, subpath, ".d.ts")) |path| return path;
            }
        }
        if (try self.virtualAnyNodeModulesPackageDeclarationFilename(package_name, subpath)) |path| return path;
        if (try self.virtualAnyTypesPackageDeclarationFilename(spec)) |path| return path;
        if (subpath.len > 0) {
            for (roots) |root| {
                for (prefixes) |prefix| {
                    const index_path = (try self.virtualPackageDeclarationFilenameAt(root, package_name, prefix, "", ".d.ts")) orelse continue;
                    if (self.virtualDeclarationFileHasAmbientModule(index_path, spec)) return index_path;
                    self.gpa.free(index_path);
                }
            }
        }
        return null;
    }

    fn virtualAnyNodeModulesPackageDeclarationFilename(self: *Checker, package_name: []const u8, subpath: []const u8) CheckError!?[]u8 {
        const src = self.source orelse return null;
        const needle = try std.fmt.allocPrint(self.gpa, "node_modules/{s}/", .{package_name});
        defer self.gpa.free(needle);
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw| {
            const line = std.mem.trim(u8, raw, " \t\r");
            const marker = std.mem.indexOf(u8, line, "@filename:") orelse
                (std.mem.indexOf(u8, line, "@Filename:") orelse continue);
            var path = std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
            while (std.mem.startsWith(u8, path, "/")) path = path[1..];
            const pos = std.mem.indexOf(u8, path, needle) orelse continue;
            const rest = path[pos + needle.len ..];
            if (subpath.len == 0) {
                if (std.mem.eql(u8, rest, "index.d.ts")) return try self.gpa.dupe(u8, path);
                continue;
            }
            const direct = try std.fmt.allocPrint(self.gpa, "{s}.d.ts", .{subpath});
            defer self.gpa.free(direct);
            if (std.mem.eql(u8, rest, direct)) return try self.gpa.dupe(u8, path);
            const indexed = try std.fmt.allocPrint(self.gpa, "{s}/index.d.ts", .{subpath});
            defer self.gpa.free(indexed);
            if (std.mem.eql(u8, rest, indexed)) return try self.gpa.dupe(u8, path);
        }
        return null;
    }

    fn virtualPackageDeclarationFilenameAt(
        self: *Checker,
        root: []const u8,
        package_name: []const u8,
        prefix: []const u8,
        subpath: []const u8,
        ext: []const u8,
    ) CheckError!?[]u8 {
        var candidates: std.ArrayListUnmanaged([]u8) = .empty;
        defer {
            for (candidates.items) |candidate| self.gpa.free(candidate);
            candidates.deinit(self.gpa);
        }

        if (subpath.len == 0) {
            try self.appendVirtualPackagePathCandidate(&candidates, root, package_name, prefix, "index", ext);
        } else {
            try self.appendVirtualPackagePathCandidate(&candidates, root, package_name, prefix, subpath, ext);
            const indexed = try std.fmt.allocPrint(self.gpa, "{s}/index", .{subpath});
            defer self.gpa.free(indexed);
            try self.appendVirtualPackagePathCandidate(&candidates, root, package_name, prefix, indexed, ext);
        }

        for (candidates.items) |candidate| {
            if (self.virtualSourceHasFilename(candidate)) return try self.gpa.dupe(u8, candidate);
        }
        return null;
    }

    fn appendVirtualPackagePathCandidate(
        self: *Checker,
        candidates: *std.ArrayListUnmanaged([]u8),
        root: []const u8,
        package_name: []const u8,
        prefix: []const u8,
        relative: []const u8,
        ext: []const u8,
    ) CheckError!void {
        const path = if (root.len > 0 and prefix.len > 0)
            std.fmt.allocPrint(self.gpa, "{s}/{s}/{s}/{s}{s}", .{ root, package_name, prefix, relative, ext }) catch return error.OutOfMemory
        else if (root.len > 0)
            std.fmt.allocPrint(self.gpa, "{s}/{s}/{s}{s}", .{ root, package_name, relative, ext }) catch return error.OutOfMemory
        else if (prefix.len > 0)
            std.fmt.allocPrint(self.gpa, "{s}/{s}/{s}{s}", .{ package_name, prefix, relative, ext }) catch return error.OutOfMemory
        else
            std.fmt.allocPrint(self.gpa, "{s}/{s}{s}", .{ package_name, relative, ext }) catch return error.OutOfMemory;
        try candidates.append(self.gpa, path);
    }

    fn virtualTypesPackageHasDeclaration(self: *Checker, spec: []const u8) CheckError!bool {
        const path = (try self.virtualAnyTypesPackageDeclarationFilename(spec)) orelse return false;
        self.gpa.free(path);
        return true;
    }

    fn virtualAnyTypesPackageDeclarationFilename(self: *Checker, spec: []const u8) CheckError!?[]u8 {
        if (std.mem.startsWith(u8, spec, ".")) return null;
        const slash = packageNameEnd(spec);
        const package_name = spec[0..slash];
        const subpath = if (slash < spec.len) spec[slash + 1 ..] else "";
        const types_pkg = if (std.mem.startsWith(u8, package_name, "@")) blk: {
            const scoped_slash = std.mem.indexOfScalar(u8, package_name[1..], '/') orelse return null;
            const scope = package_name[1 .. 1 + scoped_slash];
            const name = package_name[1 + scoped_slash + 1 ..];
            break :blk try std.fmt.allocPrint(self.gpa, "@types/{s}__{s}", .{ scope, name });
        } else try std.fmt.allocPrint(self.gpa, "@types/{s}", .{package_name});
        defer self.gpa.free(types_pkg);
        const needle = try std.fmt.allocPrint(self.gpa, "node_modules/{s}/", .{types_pkg});
        defer self.gpa.free(needle);
        const src = self.source orelse return null;
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw| {
            const line = std.mem.trim(u8, raw, " \t\r");
            const marker = std.mem.indexOf(u8, line, "@filename:") orelse
                (std.mem.indexOf(u8, line, "@Filename:") orelse continue);
            var path = std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
            while (std.mem.startsWith(u8, path, "/")) path = path[1..];
            const pos = std.mem.indexOf(u8, path, needle) orelse continue;
            const rest = path[pos + needle.len ..];
            if (!virtualTypesPackageRestMatches(rest, subpath)) continue;
            return try self.gpa.dupe(u8, path);
        }
        return null;
    }

    fn virtualTypesPackageRestMatches(rest: []const u8, subpath: []const u8) bool {
        if (std.mem.eql(u8, rest, "package.json")) return false;
        if (subpath.len == 0) {
            return std.mem.endsWith(u8, rest, ".d.ts") or
                std.mem.endsWith(u8, rest, ".ts") or
                std.mem.endsWith(u8, rest, ".tsx");
        }
        if (std.mem.startsWith(u8, rest, subpath)) {
            const tail = rest[subpath.len..];
            if (std.mem.eql(u8, tail, ".d.ts") or
                std.mem.eql(u8, tail, ".ts") or
                std.mem.eql(u8, tail, ".tsx")) return true;
            if (std.mem.startsWith(u8, tail, "/index") and
                (std.mem.endsWith(u8, tail, ".d.ts") or
                    std.mem.endsWith(u8, tail, ".ts") or
                    std.mem.endsWith(u8, tail, ".tsx"))) return true;
        }
        return false;
    }

    fn virtualSourceHasFilenameWithExtOrIndex(self: *Checker, base: []const u8, ext: []const u8) bool {
        if (std.mem.endsWith(u8, base, ext) and self.virtualSourceHasFilename(base)) return true;
        if (virtualSourceHasExtensionSubstitution(self, base, ext)) return true;
        const direct = std.fmt.allocPrint(self.gpa, "{s}{s}", .{ base, ext }) catch return false;
        defer self.gpa.free(direct);
        if (self.virtualSourceHasFilename(direct)) return true;
        if (std.mem.eql(u8, ext, ".ts") or std.mem.eql(u8, ext, ".d.ts")) {
            if (std.mem.lastIndexOfScalar(u8, base, '.')) |dot| {
                const arbitrary_decl = std.fmt.allocPrint(self.gpa, "{s}.d{s}.ts", .{ base[0..dot], base[dot..] }) catch return false;
                defer self.gpa.free(arbitrary_decl);
                if (self.virtualSourceHasFilename(arbitrary_decl)) return true;
            }
        }
        const index = std.fmt.allocPrint(self.gpa, "{s}/index{s}", .{ base, ext }) catch return false;
        defer self.gpa.free(index);
        return self.virtualSourceHasFilename(index);
    }

    fn virtualSourceHasExtensionSubstitution(self: *Checker, base: []const u8, ext: []const u8) bool {
        const source_exts = [_][]const u8{ ".js", ".jsx", ".mjs", ".cjs" };
        for (source_exts) |source_ext| {
            if (!std.mem.endsWith(u8, base, source_ext)) continue;
            if (std.mem.eql(u8, source_ext, ".mjs") and !std.mem.eql(u8, ext, ".mts") and !std.mem.eql(u8, ext, ".d.mts")) continue;
            if (std.mem.eql(u8, source_ext, ".cjs") and !std.mem.eql(u8, ext, ".cts") and !std.mem.eql(u8, ext, ".d.cts")) continue;
            if (std.mem.eql(u8, source_ext, ".jsx") and !std.mem.eql(u8, ext, ".tsx") and !std.mem.eql(u8, ext, ".d.ts")) continue;
            const stem = base[0 .. base.len - source_ext.len];
            const substituted = std.fmt.allocPrint(self.gpa, "{s}{s}", .{ stem, ext }) catch return false;
            defer self.gpa.free(substituted);
            if (self.virtualSourceHasFilename(substituted)) return true;
        }
        return false;
    }

    fn virtualSourceHasFilename(self: *Checker, wanted: []const u8) bool {
        const src = self.source orelse return false;
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw| {
            const line = std.mem.trim(u8, raw, " \t\r");
            const marker = std.mem.indexOf(u8, line, "@filename:") orelse
                (std.mem.indexOf(u8, line, "@Filename:") orelse continue);
            const path = std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
            if (virtualPathEquals(path, wanted)) return true;
        }
        return false;
    }

    fn virtualPathEquals(path: []const u8, wanted: []const u8) bool {
        var a = path;
        var b = wanted;
        while (std.mem.startsWith(u8, a, "/")) a = a[1..];
        while (std.mem.startsWith(u8, b, "/")) b = b[1..];
        while (std.mem.startsWith(u8, a, "./")) a = a[2..];
        while (std.mem.startsWith(u8, b, "./")) b = b[2..];
        return std.mem.eql(u8, a, b);
    }

    fn checkImportEqualsEntity(self: *Checker, node: NodeId, imp: hir_mod.ImportPayload) CheckError!void {
        if (imp.import_equals == hir_mod.none_node_id) return;
        if (self.hir.kindOf(imp.import_equals) != .type_ref) return;
        const r = hir_mod.typeRefOf(self.hir, imp.import_equals);
        const qualifiers = hir_mod.typeRefQualifier(self.hir, imp.import_equals);
        const root_name = if (qualifiers.len > 0) blk: {
            if (self.hir.kindOf(qualifiers[0]) != .identifier) return;
            break :blk hir_mod.identifierOf(self.hir, qualifiers[0]).name;
        } else r.name;
        if (self.rootHasNonImportDeclarationNamed(root_name)) {
            try self.recordImportEqualsAbstractAlias(imp);
            return;
        }
        if (try self.moduleNamespaceTypeForLocalImport(root_name, node)) |_| return;
        const root_text = self.string_interner.get(root_name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find namespace '{s}'.",
            .{root_text},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.cannot_find_namespace,
            .message = msg,
        });
    }

    fn recordImportEqualsAbstractAlias(self: *Checker, imp: hir_mod.ImportPayload) CheckError!void {
        if (imp.default_binding == hir_mod.none_node_id or self.hir.kindOf(imp.default_binding) != .identifier) return;
        const target = self.importEqualsTargetDecl(imp.import_equals) orelse return;
        if (self.hir.kindOf(target) != .class_decl and self.hir.kindOf(target) != .class_expr) return;
        const c = hir_mod.classOf(self.hir, target);
        if (!c.is_abstract) return;
        const alias = hir_mod.identifierOf(self.hir, imp.default_binding);
        try self.abstract_classes.put(self.gpa, alias.name, {});
    }

    fn importEqualsTargetDecl(self: *Checker, type_ref_node: NodeId) ?NodeId {
        if (type_ref_node == hir_mod.none_node_id or self.hir.kindOf(type_ref_node) != .type_ref) return null;
        const r = hir_mod.typeRefOf(self.hir, type_ref_node);
        const qualifiers = hir_mod.typeRefQualifier(self.hir, type_ref_node);
        if (qualifiers.len == 0) return null;
        var path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer path.deinit(self.gpa);
        for (qualifiers) |q| {
            if (self.hir.kindOf(q) != .identifier) return null;
            path.append(self.gpa, hir_mod.identifierOf(self.hir, q).name) catch return null;
        }
        const root = self.rootBlockFor(type_ref_node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const ns_node = self.findNamespaceByPath(hir_mod.blockStmts(self.hir, root), path.items) orelse return null;
        return self.findNamedValueDeclInNamespace(ns_node, r.name) orelse self.findNamedTypeDeclInNamespace(ns_node, r.name);
    }

    fn checkNamedImportSpecifiers(self: *Checker, node: NodeId, imp: hir_mod.ImportPayload, spec: []const u8) CheckError!void {
        _ = imp;
        const scoped_virtual_relative = std.mem.startsWith(u8, spec, ".") and self.sourceHasVirtualFilenameSections();
        const scoped_virtual_bare = !std.mem.startsWith(u8, spec, ".") and self.sourceHasVirtualFilenameSections();
        for (hir_mod.importNamed(self.hir, node)) |spec_node| {
            if (self.hir.kindOf(spec_node) != .import_specifier) continue;
            const sp = hir_mod.importSpecifierOf(self.hir, spec_node);
            if (sp.is_type_only or std.mem.eql(u8, self.string_interner.get(sp.imported), "default")) continue;
            if (scoped_virtual_relative) {
                if (try self.virtualRelativeModuleHasNamedExport(node, spec, sp.imported)) continue;
                try self.report(spec_node, TsCodes.no_exported_member_suggestion, "Module has no exported member.");
                continue;
            }
            if (scoped_virtual_bare) {
                if (try self.ambientModuleExportsNameForSpec(node, spec, sp.imported)) continue;
                if (try self.virtualBareModuleHasNamedExport(node, spec, sp.imported)) continue;
                try self.report(spec_node, TsCodes.no_exported_member_suggestion, "Module has no exported member.");
                continue;
            }
            if (self.rootHasNonImportDeclarationNamed(sp.imported) or self.rootHasExportedName(sp.imported)) continue;
            if (self.closestNonImportDeclarationName(sp.imported)) |suggestion| {
                const requested = self.string_interner.get(sp.imported);
                const suggested = self.string_interner.get(suggestion);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "\"{s}\" has no exported member named '{s}'. Did you mean '{s}'?",
                    .{ spec, requested, suggested },
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = spec_node,
                    .code = TsCodes.no_exported_member_suggestion,
                    .message = msg,
                });
            }
        }
    }

    fn virtualRelativeModuleHasNamedExport(self: *Checker, node: NodeId, spec: []const u8, name: hir_mod.StringId) CheckError!bool {
        const from = self.virtualSectionFilenameForNode(node) orelse return true;
        const resolved = try self.resolveVirtualRelativePath(from, spec);
        defer self.gpa.free(resolved);
        const root = self.rootBlockFor(node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return true;
        var found_module = false;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            if (!self.virtualSectionMatchesResolvedModule(raw, resolved, spec)) continue;
            found_module = true;
            if (self.hir.kindOf(raw) != .export_decl) continue;
            const ex = hir_mod.exportOf(self.hir, raw);
            if (ex.is_default and std.mem.eql(u8, self.string_interner.get(name), "default")) return true;
            for (hir_mod.exportNamed(self.hir, raw)) |export_spec| {
                if (self.hir.kindOf(export_spec) != .import_specifier) continue;
                const sp = hir_mod.importSpecifierOf(self.hir, export_spec);
                if (self.exportSpecifierExportedName(export_spec, sp) == name) return true;
            }
            const decl = self.unwrapExportDecl(raw);
            const decl_name = self.declarationName(decl) orelse continue;
            if (decl_name == name) return true;
        }
        return !found_module;
    }

    fn virtualBareModuleHasNamedExport(self: *Checker, anchor: NodeId, spec: []const u8, name: hir_mod.StringId) CheckError!bool {
        const decl_file = (try self.virtualBareModuleDeclarationFilename(spec)) orelse return true;
        defer self.gpa.free(decl_file);
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return true;
        var found_module = false;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            const filename = self.virtualSectionFilenameForNode(raw) orelse continue;
            if (!virtualPathEquals(filename, decl_file)) continue;
            found_module = true;
            const local = self.unwrapExportDecl(raw);
            if (self.namespaceDeclMatchesModule(local, spec)) {
                if (self.namespaceExportsName(local, name)) return true;
                continue;
            }
            if (self.hir.kindOf(raw) != .export_decl) continue;
            const decl = self.unwrapExportDecl(raw);
            const decl_name = self.declarationName(decl) orelse continue;
            if (decl_name == name) return true;
        }
        return !found_module;
    }

    fn virtualBareModuleExportType(self: *Checker, anchor: NodeId, spec: []const u8, name: hir_mod.StringId) CheckError!?TypeId {
        const decl_file = (try self.virtualBareModuleDeclarationFilename(spec)) orelse return null;
        defer self.gpa.free(decl_file);
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            const filename = self.virtualSectionFilenameForNode(raw) orelse continue;
            if (!virtualPathEquals(filename, decl_file)) continue;
            const local = self.unwrapExportDecl(raw);
            if (self.namespaceDeclMatchesModule(local, spec)) {
                if (try self.namespaceExportType(local, name)) |t| return t;
                continue;
            }
            if (self.hir.kindOf(raw) != .export_decl) continue;
            const decl = self.unwrapExportDecl(raw);
            const decl_name = self.declarationName(decl) orelse continue;
            if (decl_name != name) continue;
            const dk = self.hir.kindOf(decl);
            if (dk == .var_decl or dk == .let_decl or dk == .const_decl) {
                const v = hir_mod.varDeclOf(self.hir, decl);
                if (v.type_annotation != hir_mod.none_node_id) {
                    const declared_t = try self.lowerValueTypeAnnotation(name, v.type_annotation);
                    self.hir.setType(decl, declared_t);
                    if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, declared_t);
                    return declared_t;
                }
                if (v.init != hir_mod.none_node_id) {
                    var init_t = try self.checkExpression(v.init);
                    if (dk == .const_decl) init_t = try self.constInitializerType(v.init, init_t);
                    self.hir.setType(decl, init_t);
                    if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, init_t);
                    return init_t;
                }
            }
            const t = self.hir.typeOf(decl);
            if (t != types.Primitive.none) return t;
        }
        return null;
    }

    fn virtualImportTypeForLocal(self: *Checker, local_name: hir_mod.StringId, anchor: NodeId) CheckError!?TypeId {
        if (!self.sourceHasVirtualFilenameSections()) return null;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const anchor_section = self.virtualSectionStartForNode(anchor);
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            if (self.virtualSectionStartForNode(stmt) != anchor_section) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            const spec_text = self.string_interner.get(imp.module);
            if (std.mem.startsWith(u8, spec_text, ".")) continue;
            for (hir_mod.importNamed(self.hir, stmt)) |spec_node| {
                if (self.hir.kindOf(spec_node) != .import_specifier) continue;
                const sp = hir_mod.importSpecifierOf(self.hir, spec_node);
                if (sp.local != local_name) continue;
                return try self.virtualBareModuleExportType(stmt, spec_text, sp.imported);
            }
        }
        return null;
    }

    fn virtualDefaultImportTypeForLocal(self: *Checker, local_name: hir_mod.StringId, anchor: NodeId) CheckError!?TypeId {
        if (!self.sourceHasAllowJsDirective() or !self.sourceHasVirtualFilenameSections()) return null;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const anchor_section = self.virtualSectionStartForNode(anchor);
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            if (self.virtualSectionStartForNode(stmt) != anchor_section) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            if (imp.default_binding == hir_mod.none_node_id or self.hir.kindOf(imp.default_binding) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, imp.default_binding);
            if (id.name != local_name) continue;
            const spec_text = self.string_interner.get(imp.module);
            if (std.mem.startsWith(u8, spec_text, ".")) continue;
            if ((try self.resolveVirtualBareModule(spec_text)) != .implementation) continue;
            const default_name = self.string_interner.intern("default") catch return error.OutOfMemory;
            const members = [_]types.ObjectMember{.{
                .name = default_name,
                .type = types.Primitive.any,
                .is_optional = false,
                .is_readonly = true,
                .is_method = false,
            }};
            return self.interner.internObjectType(&members) catch return error.OutOfMemory;
        }
        return null;
    }

    fn memberAccessOnVirtualJsDefaultImport(self: *Checker, object_node: NodeId, member_name: hir_mod.StringId) CheckError!bool {
        if (!self.sourceHasAllowJsDirective() or !self.sourceHasVirtualFilenameSections()) return false;
        if (self.hir.kindOf(object_node) != .identifier) return false;
        if (std.mem.eql(u8, self.string_interner.get(member_name), "default")) return false;
        const local_name = hir_mod.identifierOf(self.hir, object_node).name;
        const root = self.rootBlockFor(object_node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        const anchor_section = self.virtualSectionStartForNode(object_node);
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            if (self.virtualSectionStartForNode(stmt) != anchor_section) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            if (imp.default_binding == hir_mod.none_node_id or self.hir.kindOf(imp.default_binding) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, imp.default_binding).name != local_name) continue;
            const spec_text = self.string_interner.get(imp.module);
            if (std.mem.startsWith(u8, spec_text, ".")) return false;
            return (try self.resolveVirtualBareModule(spec_text)) == .implementation;
        }
        return false;
    }

    fn typeOnlyImportLocal(self: *Checker, local_name: hir_mod.StringId, anchor: NodeId) bool {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        const anchor_section = if (self.sourceHasVirtualFilenameSections()) self.virtualSectionStartForNode(anchor) else 0;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            if (self.sourceHasVirtualFilenameSections() and self.virtualSectionStartForNode(stmt) != anchor_section) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            if (!imp.is_type_only) continue;
            if (imp.default_binding != hir_mod.none_node_id and self.hir.kindOf(imp.default_binding) == .identifier) {
                if (hir_mod.identifierOf(self.hir, imp.default_binding).name == local_name) return true;
            }
            if (imp.namespace_binding != hir_mod.none_node_id and self.hir.kindOf(imp.namespace_binding) == .identifier) {
                if (hir_mod.identifierOf(self.hir, imp.namespace_binding).name == local_name) return true;
            }
            for (hir_mod.importNamed(self.hir, stmt)) |spec_node| {
                if (self.hir.kindOf(spec_node) != .import_specifier) continue;
                const sp = hir_mod.importSpecifierOf(self.hir, spec_node);
                if (sp.local == local_name) return true;
            }
        }
        return false;
    }

    fn importDeclBindsLocal(self: *Checker, import_node: NodeId, local_name: hir_mod.StringId) bool {
        if (import_node == hir_mod.none_node_id or self.hir.kindOf(import_node) != .import_decl) return false;
        const imp = hir_mod.importOf(self.hir, import_node);
        if (imp.default_binding != hir_mod.none_node_id and self.hir.kindOf(imp.default_binding) == .identifier and
            hir_mod.identifierOf(self.hir, imp.default_binding).name == local_name) return true;
        if (imp.namespace_binding != hir_mod.none_node_id and self.hir.kindOf(imp.namespace_binding) == .identifier and
            hir_mod.identifierOf(self.hir, imp.namespace_binding).name == local_name) return true;
        for (hir_mod.importNamed(self.hir, import_node)) |spec_node| {
            if (self.hir.kindOf(spec_node) != .import_specifier) continue;
            if (hir_mod.importSpecifierOf(self.hir, spec_node).local == local_name) return true;
        }
        return false;
    }

    fn virtualNamespaceImportExportsMember(self: *Checker, local_name: hir_mod.StringId, member_name: hir_mod.StringId, anchor: NodeId) CheckError!bool {
        if (!self.sourceHasVirtualFilenameSections()) return false;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        const section = self.virtualSectionStartForNode(anchor);
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            if (self.virtualSectionStartForNode(stmt) != section) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            const spec = self.string_interner.get(imp.module);
            if (!std.mem.startsWith(u8, spec, ".")) continue;
            const binds_namespace =
                (imp.namespace_binding != hir_mod.none_node_id and
                    self.hir.kindOf(imp.namespace_binding) == .identifier and
                    hir_mod.identifierOf(self.hir, imp.namespace_binding).name == local_name) or
                (imp.default_binding != hir_mod.none_node_id and
                    self.hir.kindOf(imp.default_binding) == .identifier and
                    hir_mod.identifierOf(self.hir, imp.default_binding).name == local_name and
                    self.importDeclIsRequireAssignment(stmt));
            if (!binds_namespace) continue;
            return try self.virtualRelativeModuleHasNamedExport(stmt, spec, member_name);
        }
        return false;
    }

    fn virtualDeclarationFileHasAmbientModule(self: *Checker, decl_file: []const u8, spec: []const u8) bool {
        var node: hir_mod.NodeId = 1;
        while (node < self.hir.nodeCount()) : (node += 1) {
            const filename = self.virtualSectionFilenameForNode(node) orelse continue;
            if (!virtualPathEquals(filename, decl_file)) continue;
            if (self.namespaceDeclMatchesModule(node, spec)) return true;
        }
        return false;
    }

    fn namespaceDeclMatchesModule(self: *Checker, node: NodeId, spec: []const u8) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) return false;
        const ns = hir_mod.namespaceOf(self.hir, node);
        if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, ns.name);
        return self.moduleNameMatchesSpecifier(self.string_interner.get(id.name), spec);
    }

    fn namespaceExportsName(self: *Checker, ns_node: NodeId, name: hir_mod.StringId) bool {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |body_stmt| {
            const decl = self.unwrapExportDecl(body_stmt);
            const decl_name = self.declarationName(decl) orelse continue;
            if (decl_name == name) return true;
        }
        return false;
    }

    fn namespaceExportType(self: *Checker, ns_node: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |body_stmt| {
            const decl = self.unwrapExportDecl(body_stmt);
            const decl_name = self.declarationName(decl) orelse continue;
            if (decl_name != name) continue;
            const dk = self.hir.kindOf(decl);
            if (dk == .var_decl or dk == .let_decl or dk == .const_decl) {
                const v = hir_mod.varDeclOf(self.hir, decl);
                if (v.type_annotation != hir_mod.none_node_id) {
                    const declared_t = try self.lowerValueTypeAnnotation(name, v.type_annotation);
                    self.hir.setType(decl, declared_t);
                    if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, declared_t);
                    return declared_t;
                }
                if (v.init != hir_mod.none_node_id) {
                    var init_t = try self.checkExpression(v.init);
                    if (dk == .const_decl) init_t = try self.constInitializerType(v.init, init_t);
                    self.hir.setType(decl, init_t);
                    if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, init_t);
                    return init_t;
                }
            }
            const t = self.hir.typeOf(decl);
            if (t != types.Primitive.none) return t;
        }
        return null;
    }

    fn globalAugmentedValueType(
        self: *Checker,
        name: hir_mod.StringId,
        anchor: NodeId,
    ) CheckError!?TypeId {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            const ns_node = self.unwrapExportDecl(raw);
            if (self.hir.kindOf(ns_node) != .namespace_decl) continue;
            if (self.virtualSectionFilenameForNode(ns_node)) |filename| {
                if (std.mem.indexOf(u8, filename, "node_modules/") != null) continue;
            }
            const ns = hir_mod.namespaceOf(self.hir, ns_node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            const ns_name = hir_mod.identifierOf(self.hir, ns.name).name;
            if (!std.mem.eql(u8, self.string_interner.get(ns_name), "global")) continue;
            if (try self.namespaceExportValueType(ns_node, name)) |t| return t;
        }
        return null;
    }

    fn namespaceExportValueType(self: *Checker, ns_node: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |body_stmt| {
            const decl = self.unwrapExportDecl(body_stmt);
            const decl_name = self.declarationName(decl) orelse continue;
            if (decl_name != name) continue;
            const dk = self.hir.kindOf(decl);
            if (dk == .class_decl or dk == .class_expr) {
                if (self.class_static_types.get(name)) |static_t| return static_t;
            }
            if (dk == .fn_decl or dk == .fn_expr) {
                if (self.overloadedFunctionValueType(name) catch null) |overload_t| return overload_t;
            }
            if (dk == .var_decl or dk == .let_decl or dk == .const_decl) {
                const v = hir_mod.varDeclOf(self.hir, decl);
                if (v.type_annotation != hir_mod.none_node_id) {
                    const declared_t = try self.lowerValueTypeAnnotation(name, v.type_annotation);
                    self.hir.setType(decl, declared_t);
                    if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, declared_t);
                    return declared_t;
                }
                if (v.init != hir_mod.none_node_id) {
                    var init_t = try self.checkExpression(v.init);
                    if (dk == .const_decl) init_t = try self.constInitializerType(v.init, init_t);
                    self.hir.setType(decl, init_t);
                    if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, init_t);
                    return init_t;
                }
                return types.Primitive.any;
            }
        }
        return null;
    }

    fn virtualSectionMatchesResolvedModule(self: *Checker, node: NodeId, resolved: []const u8, spec: []const u8) bool {
        const filename = self.virtualSectionFilenameForNode(node) orelse return false;
        if (virtualRelativeSpecifierPrefersIndex(spec)) {
            const index_exts = [_][]const u8{ ".d.ts", ".ts", ".tsx", ".mts", ".cts", ".js", ".jsx", ".mjs", ".cjs" };
            for (index_exts) |ext| {
                const index = std.fmt.allocPrint(self.gpa, "{s}/index{s}", .{ resolved, ext }) catch return false;
                defer self.gpa.free(index);
                if (virtualPathEquals(filename, index)) return true;
            }
            return false;
        }
        if (virtualPathEquals(filename, resolved)) return true;
        const exts = [_][]const u8{ ".d.ts", ".ts", ".tsx", ".mts", ".cts", ".js", ".jsx", ".mjs", ".cjs" };
        for (exts) |ext| {
            const direct = std.fmt.allocPrint(self.gpa, "{s}{s}", .{ resolved, ext }) catch return false;
            defer self.gpa.free(direct);
            if (virtualPathEquals(filename, direct)) return true;
            const index = std.fmt.allocPrint(self.gpa, "{s}/index{s}", .{ resolved, ext }) catch return false;
            defer self.gpa.free(index);
            if (virtualPathEquals(filename, index)) return true;
        }
        return false;
    }

    fn virtualRelativeSpecifierPrefersIndex(spec: []const u8) bool {
        return std.mem.eql(u8, spec, ".") or
            std.mem.eql(u8, spec, "./") or
            std.mem.eql(u8, spec, "..") or
            std.mem.eql(u8, spec, "../") or
            std.mem.endsWith(u8, spec, "/.") or
            std.mem.endsWith(u8, spec, "/..");
    }

    fn isKnownAmbientModuleName(self: *Checker, anchor: NodeId, spec: []const u8) CheckError!bool {
        const known = [_][]const u8{
            "assert",
            "buffer",
            "child_process",
            "crypto",
            "events",
            "fs",
            "http",
            "https",
            "module",
            "os",
            "path",
            "react",
            "stream",
            "url",
            "util",
            "y",
        };
        for (known) |name| {
            if (std.mem.eql(u8, spec, name)) return true;
            if (std.mem.startsWith(u8, spec, "node:") and std.mem.eql(u8, spec["node:".len..], name)) return true;
        }
        const root = self.rootBlockFor(anchor);
        if (root != hir_mod.none_node_id and self.hir.kindOf(root) == .block_stmt) {
            const spec_id = self.string_interner.intern(spec) catch return error.OutOfMemory;
            if (try self.hasAmbientModuleDecl(hir_mod.blockStmts(self.hir, root), spec_id)) return true;
        }
        return false;
    }

    fn reportMissingImportTypeModule(self: *Checker, node: NodeId) CheckError!bool {
        const spec = self.importTypeModuleSpecifier(node) orelse return false;
        if (try self.importTypeModuleExists(node, spec)) return false;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot find module '{s}' or its corresponding type declarations.",
            .{spec},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.cannot_find_module,
            .message = msg,
        });
        return true;
    }

    fn importTypeModuleExists(self: *Checker, anchor: NodeId, spec: []const u8) CheckError!bool {
        if (std.mem.startsWith(u8, spec, ".")) {
            if (!self.sourceHasVirtualFilenameSections()) return true;
            const from = self.virtualSectionFilenameForNode(anchor) orelse return true;
            const resolved = try self.resolveVirtualRelativePath(from, spec);
            defer self.gpa.free(resolved);
            const root = self.rootBlockFor(anchor);
            if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return true;
            for (hir_mod.blockStmts(self.hir, root)) |raw| {
                if (self.virtualSectionMatchesResolvedModule(raw, resolved, spec)) return true;
            }
            return false;
        }
        if (self.source) |src| {
            if (std.mem.indexOf(u8, src, "@moduleResolution: classic") != null or
                std.mem.indexOf(u8, src, "@moduleResolution: bundler, classic") != null)
            {
                return false;
            }
        }
        return try self.isKnownAmbientModuleName(anchor, spec);
    }

    fn importTypeModuleSpecifier(self: *Checker, node: NodeId) ?[]const u8 {
        const src = self.source orelse return null;
        const sp = self.hir.spanOf(node);
        if (sp.start >= sp.end or sp.end > src.len) return null;
        var text = std.mem.trim(u8, src[sp.start..sp.end], " \t\r\n");
        if (!std.mem.startsWith(u8, text, "import")) return null;
        text = std.mem.trimStart(u8, text["import".len..], " \t\r\n");
        if (text.len == 0 or text[0] != '(') return null;
        text = std.mem.trimStart(u8, text[1..], " \t\r\n");
        if (text.len == 0) return null;
        const quote = text[0];
        if (quote != '"' and quote != '\'') return null;
        var i: usize = 1;
        while (i < text.len) : (i += 1) {
            if (text[i] == '\\') {
                i += 1;
                continue;
            }
            if (text[i] == quote) return text[1..i];
        }
        return null;
    }

    fn hasAmbientModuleDecl(self: *Checker, stmts: []const NodeId, module_name: hir_mod.StringId) CheckError!bool {
        const spec = self.string_interner.get(module_name);
        for (stmts) |stmt| {
            const local = self.unwrapExportDecl(stmt);
            if (local == hir_mod.none_node_id or self.hir.kindOf(local) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, local);
            if (self.hir.kindOf(ns.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, ns.name);
            if (self.moduleNameMatchesSpecifier(self.string_interner.get(id.name), spec)) return true;
        }
        return false;
    }

    fn ambientModuleExportsNameForSpec(self: *Checker, anchor: NodeId, spec: []const u8, exported_name: hir_mod.StringId) CheckError!bool {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            const local = self.unwrapExportDecl(stmt);
            if (local == hir_mod.none_node_id or self.hir.kindOf(local) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, local);
            if (self.hir.kindOf(ns.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, ns.name);
            if (!self.moduleNameMatchesSpecifier(self.string_interner.get(id.name), spec)) continue;
            if (self.namespaceExportsName(local, exported_name)) return true;
        }
        return false;
    }

    fn ambientModuleExportsName(
        self: *Checker,
        stmts: []const NodeId,
        module_name: hir_mod.StringId,
        exported_name: hir_mod.StringId,
    ) CheckError!bool {
        if (module_name == string_interner.empty_string_id) return false;
        const spec = self.string_interner.get(module_name);
        for (stmts) |stmt| {
            const local = self.unwrapExportDecl(stmt);
            if (local == hir_mod.none_node_id or self.hir.kindOf(local) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, local);
            if (self.hir.kindOf(ns.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, ns.name);
            if (!self.moduleNameMatchesSpecifier(self.string_interner.get(id.name), spec)) continue;
            for (hir_mod.namespaceBody(self.hir, local)) |body_stmt| {
                if (self.hir.kindOf(body_stmt) != .export_decl) continue;
                const ex = hir_mod.exportOf(self.hir, body_stmt);
                if (!self.isExportAssignmentDecl(body_stmt)) continue;
                if (ex.decl == hir_mod.none_node_id or self.hir.kindOf(ex.decl) != .identifier) continue;
                if (hir_mod.identifierOf(self.hir, ex.decl).name == exported_name) return true;
            }
        }
        return false;
    }

    fn moduleNameMatchesSpecifier(self: *Checker, pattern: []const u8, spec: []const u8) bool {
        _ = self;
        if (std.mem.eql(u8, pattern, spec)) return true;
        const star = std.mem.indexOfScalar(u8, pattern, '*') orelse return false;
        if (std.mem.indexOfScalarPos(u8, pattern, star + 1, '*') != null) return false;
        const prefix = pattern[0..star];
        const suffix = pattern[star + 1 ..];
        return spec.len >= prefix.len + suffix.len and
            std.mem.startsWith(u8, spec, prefix) and
            std.mem.endsWith(u8, spec, suffix);
    }

    fn rootHasNonImportDeclarationNamed(self: *Checker, name: hir_mod.StringId) bool {
        var i: hir_mod.NodeId = 1;
        while (i < self.hir.nodeCount()) : (i += 1) {
            if (self.nodeHasAncestorKind(i, .import_decl) or self.hir.kindOf(i) == .import_decl) continue;
            if (self.declarationName(i)) |decl_name| {
                if (decl_name == name) return true;
            }
        }
        return false;
    }

    fn rootHasExportedName(self: *Checker, name: hir_mod.StringId) bool {
        var i: hir_mod.NodeId = 1;
        while (i < self.hir.nodeCount()) : (i += 1) {
            if (self.hir.kindOf(i) != .export_decl) continue;
            const ex = hir_mod.exportOf(self.hir, i);
            if (ex.is_namespace and ex.namespace_alias == name) return true;
            for (hir_mod.exportNamed(self.hir, i)) |spec_node| {
                if (self.hir.kindOf(spec_node) != .import_specifier) continue;
                const sp = hir_mod.importSpecifierOf(self.hir, spec_node);
                if (sp.local == name) return true;
            }
        }
        return false;
    }

    fn closestNonImportDeclarationName(self: *Checker, typo_name: hir_mod.StringId) ?hir_mod.StringId {
        const typo = self.string_interner.get(typo_name);
        var best_name: hir_mod.StringId = 0;
        var best_dist: usize = std.math.maxInt(usize);
        var i: hir_mod.NodeId = 1;
        while (i < self.hir.nodeCount()) : (i += 1) {
            if (self.nodeHasAncestorKind(i, .import_decl) or self.hir.kindOf(i) == .import_decl) continue;
            const decl_name = self.declarationName(i) orelse continue;
            const cand = self.string_interner.get(decl_name);
            const dist = levenshtein(typo, cand);
            if (dist < best_dist) {
                best_dist = dist;
                best_name = decl_name;
            }
        }
        if (best_dist <= @max(@as(usize, 2), typo.len / 4)) return best_name;
        return null;
    }

    /// Lower an interface declaration into an interned object type
    /// matching its member list. Each `name: T` becomes a member
    /// typed as the lowering of `T`; each method shorthand `name(p):
    /// R` becomes a member typed as the matching signature. The
    /// resulting TypeId is recorded on the interface name and in
    /// `type_names` so subsequent `b: I` annotations resolve.
    fn checkInterfaceDecl(self: *Checker, node: NodeId) CheckError!void {
        const it = hir_mod.interfaceOf(self.hir, node);
        const members = hir_mod.interfaceMembers(self.hir, node);
        const type_params = self.hir.childSlice(it.type_params_start, it.type_params_len);
        try self.checkTypeParameterDeclList(type_params);
        if (type_params.len > 0) try self.pushNarrowScope();
        defer if (type_params.len > 0) self.popNarrowScope();

        var param_ids: std.ArrayListUnmanaged(TypeId) = .empty;
        defer param_ids.deinit(self.gpa);
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tpp = hir_mod.typeParameterOf(self.hir, tp);
            const constraint: TypeId = if (tpp.constraint != hir_mod.none_node_id)
                try self.lowerer.lower(tpp.constraint)
            else
                types.Primitive.unknown;
            const def: TypeId = if (tpp.default != hir_mod.none_node_id)
                try self.lowerer.lower(tpp.default)
            else
                types.Primitive.none;
            const tp_id = self.interner.internFreshTypeParameterWithFlags(
                tpp.name,
                constraint,
                def,
                types.Variance.fromHirBits(tpp.variance),
                tpp.is_const,
            ) catch return error.OutOfMemory;
            self.hir.setType(tp, tp_id);
            try self.recordNarrow(tpp.name, tp_id);
            try param_ids.append(self.gpa, tp_id);
        }

        var iface_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer iface_members.deinit(self.gpa);
        var iface_member_predicates: std.AutoHashMapUnmanaged(hir_mod.StringId, FnPredicate) = .empty;
        defer iface_member_predicates.deinit(self.gpa);

        var string_idx: TypeId = types.Primitive.none;
        var number_idx: TypeId = types.Primitive.none;
        var symbol_idx: TypeId = types.Primitive.none;
        var has_readonly_index = false;
        var own_index_signatures: IndexSignatureDuplicateState = .{};
        const extends = hir_mod.interfaceExtends(self.hir, node);
        for (members) |m| {
            if (self.hir.kindOf(m) == .index_signature) {
                const ix = hir_mod.indexSignatureOf(self.hir, m);
                if (ix.is_readonly) has_readonly_index = true;
                const value_t = if (ix.value_type != hir_mod.none_node_id)
                    try self.lowererLowerWithTypeParams(ix.value_type)
                else
                    types.Primitive.any;
                const key_t = if (ix.key_type != hir_mod.none_node_id)
                    try self.lowererLowerWithTypeParams(ix.key_type)
                else
                    types.Primitive.string_t;
                try self.checkDuplicateIndexSignature(m, key_t, &own_index_signatures);
                if (key_t == types.Primitive.string_t) string_idx = value_t;
                if (key_t == types.Primitive.number_t) number_idx = value_t;
                if (key_t == types.Primitive.symbol_t) symbol_idx = value_t;
                continue;
            }
            if (self.hir.kindOf(m) != .interface_member) continue;
            const im = hir_mod.interfaceMemberOf(self.hir, m);
            // name == 0 means a computed key — skip until we have
            // late-bound key support.
            if (im.name == 0) continue;
            const member_t: TypeId = blk: {
                if (im.type_node != hir_mod.none_node_id) {
                    break :blk try self.lowererLowerWithTypeParams(im.type_node);
                }
                break :blk types.Primitive.any;
            };
            if (self.signature_predicates.get(member_t)) |pred| {
                try iface_member_predicates.put(self.gpa, im.name, pred);
            }
            if (self.strict_flags.no_implicit_any and im.type_node == hir_mod.none_node_id and !im.is_method) {
                try self.reportMemberImplicitAny(m, im.name);
            }
            var has_base_member = false;
            for (extends) |extends_node| {
                const parent_t = self.lowererLowerWithTypeParams(extends_node) catch continue;
                if (self.baseClassHasMember(parent_t, im.name)) {
                    has_base_member = true;
                    break;
                }
            }
            if (im.is_override and !has_base_member) {
                try self.report(m, TsCodes.override_not_in_base, "This member cannot have an 'override' modifier because it is not declared in the base interface.");
            } else if (!im.is_override and has_base_member and self.strict_flags.no_implicit_override) {
                try self.report(m, TsCodes.missing_override, "This member must have an 'override' modifier because it overrides a member in the base interface.");
            }
            try iface_members.append(self.gpa, .{
                .name = im.name,
                .type = member_t,
                .is_optional = im.is_optional,
                .is_readonly = im.is_readonly,
                .is_method = im.is_method,
            });
        }

        // `interface B extends A { ... }` — merge each parent's
        // members into the child. Child decls win on name conflict.
        if (extends.len > 0) {
            for (extends) |extends_node| {
                if (self.bareTypeNodeIsTypeParam(extends_node, type_params)) {
                    try self.report(extends_node, TsCodes.interface_incorrectly_extends, "An interface can only extend an object type or intersection of object types with statically known members.");
                }
            }
            try self.checkInterfaceExtendsCompatibility(node, extends, iface_members.items, string_idx, number_idx, symbol_idx);
            try self.mergeInterfaceExtends(extends, &iface_members, &string_idx, &number_idx, &symbol_idx);
            for (extends) |extends_node| {
                const parent_t = self.lowererLowerWithTypeParams(extends_node) catch continue;
                if (self.typeHasReadonlyIndexSignature(parent_t)) has_readonly_index = true;
            }
        }
        try self.checkIndexSignatureMemberCompatibility(node, iface_members.items, string_idx, number_idx, symbol_idx);

        const iface_t = self.interner.internObjectTypeWithIndexAndSymbol(iface_members.items, string_idx, number_idx, symbol_idx) catch return error.OutOfMemory;
        if (has_readonly_index) try self.readonly_index_types.put(self.gpa, iface_t, {});
        try self.recordMemberPredicatesForReceiver(iface_t, &iface_member_predicates);
        for (extends) |extends_node| {
            const parent_t = self.lowererLowerWithTypeParams(extends_node) catch continue;
            try self.copyMemberPredicatesFromReceiver(iface_t, parent_t);
        }
        self.hir.setType(node, iface_t);
        if (it.name != hir_mod.none_node_id and self.hir.kindOf(it.name) == .identifier) {
            const id = hir_mod.identifierOf(self.hir, it.name);
            for (iface_members.items) |member| {
                if (self.interfaceMemberHasSelfThisParameter(members, member.name, id.name)) {
                    try self.signature_this_params.put(self.gpa, member.type, iface_t);
                }
            }
            try self.type_names.put(self.gpa, id.name, iface_t);
            if (param_ids.items.len > 0) {
                const owned_params = try self.gpa.dupe(TypeId, param_ids.items);
                if (self.generic_aliases.get(id.name)) |old| {
                    self.gpa.free(old.params);
                }
                try self.generic_aliases.put(self.gpa, id.name, .{
                    .params = owned_params,
                    .body = iface_t,
                    .body_node = hir_mod.none_node_id,
                });
            }
            self.hir.setType(it.name, iface_t);
        }
    }

    fn interfaceMemberHasSelfThisParameter(
        self: *Checker,
        members: []const NodeId,
        member_name: hir_mod.StringId,
        iface_name: hir_mod.StringId,
    ) bool {
        for (members) |m| {
            if (self.hir.kindOf(m) != .interface_member) continue;
            const im = hir_mod.interfaceMemberOf(self.hir, m);
            if (im.name != member_name or im.type_node == hir_mod.none_node_id) continue;
            if (self.hir.kindOf(im.type_node) != .fn_type) continue;
            const ft = hir_mod.fnTypeOf(self.hir, im.type_node);
            const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
            if (params.len == 0 or !self.isThisParameter(params[0])) return false;
            const p = hir_mod.parameterOf(self.hir, params[0]);
            if (p.type_annotation == hir_mod.none_node_id) return false;
            return switch (self.hir.kindOf(p.type_annotation)) {
                .type_ref => blk: {
                    const r = hir_mod.typeRefOf(self.hir, p.type_annotation);
                    if (r.qualifier_len != 0) break :blk false;
                    const raw = self.string_interner.get(r.name);
                    break :blk r.name == iface_name or std.mem.eql(u8, raw, "this");
                },
                .identifier => blk: {
                    const id = hir_mod.identifierOf(self.hir, p.type_annotation);
                    const raw = self.string_interner.get(id.name);
                    break :blk id.name == iface_name or std.mem.eql(u8, raw, "this");
                },
                else => false,
            };
        }
        return false;
    }

    fn reportMemberImplicitAny(self: *Checker, node: NodeId, name: hir_mod.StringId) CheckError!void {
        const member_name = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Member '{s}' implicitly has an 'any' type.",
            .{member_name},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.member_implicitly_any,
            .message = msg,
        });
    }

    fn reportObjectLiteralPropertyImplicitAny(self: *Checker, node: NodeId, name: hir_mod.StringId) CheckError!void {
        const member_name = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Object literal's property '{s}' implicitly has an 'any' type.",
            .{member_name},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.object_literal_property_implicitly_any,
            .message = msg,
        });
    }

    fn checkInterfaceExtendsCompatibility(
        self: *Checker,
        node: NodeId,
        extends: []const NodeId,
        child_members: []const types.ObjectMember,
        child_string_idx: TypeId,
        child_number_idx: TypeId,
        child_symbol_idx: TypeId,
    ) CheckError!void {
        for (extends) |ext_node| {
            try self.checkInterfaceClassPrivateHeritage(node, ext_node, child_members);
            const parent_t = self.lowererLowerWithTypeParams(ext_node) catch continue;
            if (!self.interner.pool.flagsOf(parent_t).is_object_type) continue;
            const parent_string_idx = self.interner.objectStringIndex(parent_t);
            if (parent_string_idx != types.Primitive.none and child_string_idx != types.Primitive.none) {
                const type_ok = try self.heritageAssignableDeep(child_string_idx, parent_string_idx);
                if (!type_ok) {
                    try self.reportInterfaceExtendsIndexMismatch(node);
                    continue;
                }
            }
            const parent_number_idx = self.interner.objectNumberIndex(parent_t);
            if (parent_number_idx != types.Primitive.none and child_number_idx != types.Primitive.none) {
                const type_ok = try self.heritageAssignableDeep(child_number_idx, parent_number_idx);
                if (!type_ok) {
                    try self.reportInterfaceExtendsIndexMismatch(node);
                    continue;
                }
            }
            if (parent_number_idx != types.Primitive.none and child_string_idx != types.Primitive.none) {
                const type_ok = try self.heritageAssignableDeep(child_string_idx, parent_number_idx);
                if (!type_ok) {
                    try self.reportInterfaceExtendsIndexMismatch(node);
                    continue;
                }
            }
            const parent_symbol_idx = self.interner.objectSymbolIndex(parent_t);
            if (parent_symbol_idx != types.Primitive.none and child_symbol_idx != types.Primitive.none) {
                const type_ok = try self.heritageAssignableDeep(child_symbol_idx, parent_symbol_idx);
                if (!type_ok) {
                    try self.reportInterfaceExtendsIndexMismatch(node);
                    continue;
                }
            }
            for (extends) |other_ext_node| {
                if (other_ext_node == ext_node) continue;
                const other_t = self.lowererLowerWithTypeParams(other_ext_node) catch continue;
                if (!self.interner.pool.flagsOf(other_t).is_object_type) continue;
                for (self.interner.objectMembers(parent_t)) |pm| {
                    if (!self.isSymbolNamedMember(pm.name)) continue;
                    for (self.interner.objectMembers(other_t)) |om| {
                        if (om.name != pm.name) continue;
                        const pm_flags = self.interner.pool.flagsOf(pm.type);
                        const om_flags = self.interner.pool.flagsOf(om.type);
                        if (!pm_flags.is_signature or !om_flags.is_signature) continue;
                        const pr = self.interner.signatureReturn(pm.type) orelse types.Primitive.void_t;
                        const or_ = self.interner.signatureReturn(om.type) orelse types.Primitive.void_t;
                        if ((self.heritageAssignable(pr, or_) catch true) or (self.heritageAssignable(or_, pr) catch true)) continue;
                        try self.reportInterfaceExtendsIndexMismatch(node);
                        break;
                    }
                }
            }
            for (self.interner.objectMembers(parent_t)) |pm| {
                for (child_members) |cm| {
                    if (cm.name != pm.name) continue;
                    const cm_flags = self.interner.pool.flagsOf(cm.type);
                    const pm_flags = self.interner.pool.flagsOf(pm.type);
                    if ((cm_flags.is_signature or pm_flags.is_signature) and !self.strict_flags.strict_function_types) {
                        if (!self.isSymbolNamedMember(cm.name)) break;
                        if (cm_flags.is_signature and pm_flags.is_signature) {
                            const cr = self.interner.signatureReturn(cm.type) orelse types.Primitive.void_t;
                            const pr = self.interner.signatureReturn(pm.type) orelse types.Primitive.void_t;
                            if (self.heritageAssignable(cr, pr) catch true) break;
                        } else {
                            break;
                        }
                    }
                    const optional_ok = pm.is_optional or !cm.is_optional;
                    const type_ok = try self.heritageAssignableDeep(cm.type, pm.type);
                    if (optional_ok and type_ok) break;
                    const prop_name = self.string_interner.get(cm.name);
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Interface incorrectly extends base interface; property '{s}' is incompatible.",
                        .{prop_name},
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = node,
                        .code = TsCodes.interface_incorrectly_extends,
                        .message = msg,
                    });
                    break;
                }
            }
        }
    }

    fn checkInterfaceClassPrivateHeritage(
        self: *Checker,
        iface_node: NodeId,
        extends_node: NodeId,
        child_members: []const types.ObjectMember,
    ) CheckError!void {
        const class_name = self.unqualifiedTypeRefName(extends_node) orelse return;
        const root = self.rootBlockFor(iface_node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            const decl = self.unwrapExportDecl(stmt);
            if (decl == hir_mod.none_node_id or self.hir.kindOf(decl) != .class_decl) continue;
            const found_name = self.declarationName(decl) orelse continue;
            if (found_name != class_name) continue;
            for (hir_mod.classMembers(self.hir, decl)) |member| {
                const private_name = try self.privateOrProtectedClassMemberName(member);
                if (private_name == null) continue;
                for (child_members) |child| {
                    if (child.name != private_name.?) continue;
                    try self.report(iface_node, TsCodes.interface_incorrectly_extends, "Interface incorrectly extends class with private or protected member.");
                    return;
                }
            }
            for (child_members) |child| {
                if (self.classSourceHasPrivateOrProtectedMember(decl, child.name)) {
                    try self.report(iface_node, TsCodes.interface_incorrectly_extends, "Interface incorrectly extends class with private or protected member.");
                    return;
                }
            }
        }
    }

    fn privateOrProtectedClassMemberName(self: *Checker, member: NodeId) CheckError!?hir_mod.StringId {
        return switch (self.hir.kindOf(member)) {
            .fn_decl => blk: {
                const f = hir_mod.fnDeclOf(self.hir, member);
                if (!f.flags.is_private and !f.flags.is_protected) break :blk null;
                break :blk try self.classMemberNameFromFunctionName(f.name);
            },
            .object_property => blk: {
                const op = hir_mod.objectPropertyOf(self.hir, member);
                if (op.visibility != .private and op.visibility != .protected) break :blk null;
                break :blk try self.classMemberNameFromPropertyKey(op.key, op.is_computed);
            },
            else => null,
        };
    }

    fn classSourceHasPrivateOrProtectedMember(self: *Checker, class_node: NodeId, name: hir_mod.StringId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(class_node);
        if (span.end > src.len or span.start > span.end) return false;
        const body = src[span.start..span.end];
        const name_text = self.string_interner.get(name);
        var buf: [256]u8 = undefined;
        const private_pat = std.fmt.bufPrint(&buf, "private {s}", .{name_text}) catch return false;
        if (std.mem.indexOf(u8, body, private_pat) != null) return true;
        const protected_pat = std.fmt.bufPrint(&buf, "protected {s}", .{name_text}) catch return false;
        return std.mem.indexOf(u8, body, protected_pat) != null;
    }

    fn heritageAssignableDeep(self: *Checker, source: TypeId, target: TypeId) CheckError!bool {
        if (!(self.heritageAssignable(source, target) catch false)) return false;
        return try self.presentObjectMembersAssignable(source, target);
    }

    fn presentObjectMembersAssignable(self: *Checker, source: TypeId, target: TypeId) CheckError!bool {
        if (source >= self.interner.pool.typeCount() or target >= self.interner.pool.typeCount()) return true;
        const sf = self.interner.pool.flagsOf(source);
        const tf = self.interner.pool.flagsOf(target);
        if (!sf.is_object_type or !tf.is_object_type) return true;
        for (self.interner.objectMembers(target)) |tm| {
            const sm_t = self.interner.objectMember(source, tm.name) orelse {
                if (tm.is_optional) continue;
                return false;
            };
            if (!(self.heritageAssignable(sm_t, tm.type) catch false)) return false;
            if (!try self.presentObjectMembersAssignable(sm_t, tm.type)) return false;
        }
        return true;
    }

    fn reportInterfaceExtendsIndexMismatch(self: *Checker, node: NodeId) CheckError!void {
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.interface_incorrectly_extends,
            .message = "Interface incorrectly extends base interface; index signatures are incompatible.",
        });
    }

    fn checkIndexSignatureMemberCompatibility(
        self: *Checker,
        node: NodeId,
        members: []const types.ObjectMember,
        string_idx: TypeId,
        number_idx: TypeId,
        symbol_idx: TypeId,
    ) CheckError!void {
        if (string_idx != types.Primitive.none) {
            try self.checkObjectInterfaceStringIndexerCompatibility(node, members);
            for (members) |m| {
                if (self.isSymbolNamedMember(m.name)) continue;
                if (m.type == types.Primitive.any or string_idx == types.Primitive.any) continue;
                if (try self.heritageAssignableDeep(m.type, string_idx)) continue;
                const prop_str = self.string_interner.get(m.name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Property '{s}' is not assignable to string index type.",
                    .{prop_str},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = node,
                    .code = TsCodes.property_not_assignable_to_index_type,
                    .message = msg,
                });
            }
        }
        if (number_idx != types.Primitive.none) {
            for (members) |m| {
                if (!self.memberNameIsNumeric(m.name)) continue;
                if (m.type == types.Primitive.any or number_idx == types.Primitive.any) continue;
                if (try self.heritageAssignableDeep(m.type, number_idx)) continue;
                const prop_str = self.string_interner.get(m.name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Property '{s}' is not assignable to number index type.",
                    .{prop_str},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = node,
                    .code = TsCodes.property_not_assignable_to_index_type,
                    .message = msg,
                });
            }
        }
        if (number_idx != types.Primitive.none and string_idx != types.Primitive.none and
            !(try self.heritageAssignableDeep(number_idx, string_idx)))
        {
            try self.report(node, TsCodes.property_not_assignable_to_index_type, "Number index type is not assignable to string index type.");
        }
        if (symbol_idx != types.Primitive.none) {
            for (members) |m| {
                if (m.type == types.Primitive.any or symbol_idx == types.Primitive.any) continue;
                if (!self.isSymbolNamedMember(m.name)) continue;
                if (try self.heritageAssignableDeep(m.type, symbol_idx)) continue;
                const prop_str = self.string_interner.get(m.name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Property '{s}' is not assignable to symbol index type.",
                    .{prop_str},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = node,
                    .code = TsCodes.property_not_assignable_to_index_type,
                    .message = msg,
                });
            }
        }
    }

    fn checkObjectInterfaceStringIndexerCompatibility(
        self: *Checker,
        node: NodeId,
        members: []const types.ObjectMember,
    ) CheckError!void {
        if (self.hir.kindOf(node) != .interface_decl) return;
        const iface_name = self.declarationName(node) orelse return;
        if (!std.mem.eql(u8, self.string_interner.get(iface_name), "Object")) return;

        for (members) |member| {
            if (member.type == types.Primitive.any or member.type == types.Primitive.unknown) continue;
            if (self.objectStringIndexObjectValueCompatible(member.type)) continue;
            try self.reportPropertyNotAssignableToStringIndex(node, member.name);
        }

        const function_t = self.lowerBuiltinObjectType("Function") orelse types.Primitive.any;
        const Probe = struct {
            name: []const u8,
            type: TypeId,
        };
        const object_members = [_]Probe{
            .{ .name = "constructor", .type = function_t },
            .{ .name = "toString", .type = try self.interner.internSignature(&.{}, types.Primitive.string_t, false) },
            .{ .name = "toLocaleString", .type = try self.interner.internSignature(&.{}, types.Primitive.string_t, false) },
            .{ .name = "valueOf", .type = try self.interner.internSignature(&.{}, types.Primitive.object_t, false) },
            .{ .name = "hasOwnProperty", .type = try self.interner.internSignature(&.{types.Primitive.string_t}, types.Primitive.boolean_t, false) },
            .{ .name = "isPrototypeOf", .type = try self.interner.internSignature(&.{types.Primitive.object_t}, types.Primitive.boolean_t, false) },
            .{ .name = "propertyIsEnumerable", .type = try self.interner.internSignature(&.{types.Primitive.string_t}, types.Primitive.boolean_t, false) },
        };
        for (object_members) |entry| {
            if (self.objectStringIndexObjectValueCompatible(entry.type)) continue;
            const name = self.string_interner.intern(entry.name) catch return error.OutOfMemory;
            try self.reportPropertyNotAssignableToStringIndex(node, name);
        }
    }

    fn objectStringIndexObjectValueCompatible(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.any or t == types.Primitive.unknown or t == types.Primitive.object_t) return true;
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_signature) return false;
        if (flags.is_type_parameter) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |member| {
                if (!self.objectStringIndexObjectValueCompatible(member)) return false;
            }
            return true;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.objectStringIndexObjectValueCompatible(member)) return true;
            }
            return false;
        }
        if (!flags.is_object_type) return false;
        for (self.interner.objectMembers(t)) |member| {
            if (!self.objectStringIndexObjectValueCompatible(member.type)) return false;
        }
        return true;
    }

    fn reportPropertyNotAssignableToStringIndex(
        self: *Checker,
        node: NodeId,
        name: hir_mod.StringId,
    ) CheckError!void {
        const prop_str = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Property '{s}' is not assignable to string index type.",
            .{prop_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.property_not_assignable_to_index_type,
            .message = msg,
        });
    }

    fn memberNameIsNumeric(self: *Checker, name: hir_mod.StringId) bool {
        const s = self.string_interner.get(name);
        if (s.len == 0) return false;
        for (s) |ch| {
            if (ch < '0' or ch > '9') return false;
        }
        return true;
    }

    /// Pull in members from every parent interface listed in
    /// `extends`. Child entries already in `child_members` win on
    /// name conflict. Index signatures inherit when the child
    /// hasn't declared its own.
    fn mergeInterfaceExtends(
        self: *Checker,
        extends: []const NodeId,
        child_members: *std.ArrayListUnmanaged(types.ObjectMember),
        string_idx: *TypeId,
        number_idx: *TypeId,
        symbol_idx: *TypeId,
    ) CheckError!void {
        var child_names: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer child_names.deinit(self.gpa);
        for (child_members.items) |m| try child_names.put(self.gpa, m.name, {});

        var inherited: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer inherited.deinit(self.gpa);
        for (extends) |ext_node| {
            // Each entry is a `type_ref`; lower it through the
            // type-name table to get the parent's interned shape.
            const parent_t = self.lowererLowerWithTypeParams(ext_node) catch continue;
            try self.appendInheritedInterfaceMembers(parent_t, &child_names, &inherited);
            self.inheritInterfaceIndexSignatures(parent_t, string_idx, number_idx, symbol_idx);
        }
        if (inherited.items.len > 0) {
            try child_members.insertSlice(self.gpa, 0, inherited.items);
        }
    }

    fn appendInheritedInterfaceMembers(
        self: *Checker,
        parent_t: TypeId,
        child_names: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
        inherited: *std.ArrayListUnmanaged(types.ObjectMember),
    ) CheckError!void {
        if (parent_t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(parent_t);
        if (flags.is_signature and self.signatureIsConstruct(parent_t)) {
            const construct_name = self.string_interner.intern("__construct") catch return error.OutOfMemory;
            if (!child_names.contains(construct_name)) {
                try inherited.append(self.gpa, .{
                    .name = construct_name,
                    .type = parent_t,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                });
                try child_names.put(self.gpa, construct_name, {});
            }
            return;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(parent_t)) |member_t| {
                try self.appendInheritedInterfaceMembers(member_t, child_names, inherited);
            }
            return;
        }
        if (!flags.is_object_type) return;
        for (self.interner.objectMembers(parent_t)) |pm| {
            if (child_names.contains(pm.name)) continue;
            try inherited.append(self.gpa, pm);
            try child_names.put(self.gpa, pm.name, {});
        }
    }

    fn inheritInterfaceIndexSignatures(
        self: *Checker,
        parent_t: TypeId,
        string_idx: *TypeId,
        number_idx: *TypeId,
        symbol_idx: *TypeId,
    ) void {
        if (parent_t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(parent_t);
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(parent_t)) |member_t| {
                self.inheritInterfaceIndexSignatures(member_t, string_idx, number_idx, symbol_idx);
            }
            return;
        }
        if (!flags.is_object_type) return;
        if (string_idx.* == types.Primitive.none) {
            const pi = self.interner.objectStringIndex(parent_t);
            if (pi != types.Primitive.none) string_idx.* = pi;
        }
        if (number_idx.* == types.Primitive.none) {
            const pi = self.interner.objectNumberIndex(parent_t);
            if (pi != types.Primitive.none) number_idx.* = pi;
        }
        if (symbol_idx.* == types.Primitive.none) {
            const pi = self.interner.objectSymbolIndex(parent_t);
            if (pi != types.Primitive.none) symbol_idx.* = pi;
        }
    }

    /// Walk an `enum E { A, B = 5, C }` declaration: assign each
    /// member its concrete numeric value, applying TS auto-increment
    /// rules. The first member with no initializer starts at `0`;
    /// each subsequent un-initialized member takes the previous
    /// numeric value plus one. An explicit numeric initializer
    /// resets the running counter. Once a string initializer
    /// appears, a following un-initialized member raises TS2553
    /// (matching tsc's "Computed values are not permitted in an
    /// enum with string valued members").
    ///
    /// Initializer expressions resolve a small literal subset for
    /// v0:
    ///   - `literal_number` — direct value
    ///   - `unary -<literal_number>` — negated value
    ///   - `literal_string` — string-valued, blocks auto-increment
    /// Anything else clears the running counter, so the next
    /// un-initialized member won't auto-increment. Resolved numeric
    /// values land in `enum_member_values` keyed by `(enum_name,
    /// member_name)` for later access typing and (eventually) `const
    /// enum` inlining.
    fn checkEnumDecl(self: *Checker, node: NodeId) CheckError!void {
        const e = hir_mod.enumOf(self.hir, node);
        const enum_name: hir_mod.StringId = blk: {
            if (self.hir.kindOf(e.name) != .identifier) return;
            break :blk hir_mod.identifierOf(self.hir, e.name).name;
        };
        if (e.is_const) try self.const_enums.put(self.gpa, enum_name, {});
        const members = hir_mod.enumMembers(self.hir, node);

        // Running numeric value for the *next* un-initialized
        // member. `null` means the previous member's value isn't a
        // tracked number (string-valued or unresolvable expression),
        // so an un-initialized successor is an error.
        var next_numeric: ?f64 = 0;
        // Once a string-valued member appears, plain auto-increment
        // is forbidden for any later un-initialized member.
        var saw_string: bool = false;
        var member_literal_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer member_literal_types.deinit(self.gpa);

        for (members) |m| {
            if (self.hir.kindOf(m) != .object_property) continue;
            const prop = hir_mod.objectPropertyOf(self.hir, m);
            if (self.hir.kindOf(prop.key) != .identifier) continue;
            const member_name = hir_mod.identifierOf(self.hir, prop.key).name;
            const key: MemberKey = .{ .obj_name = enum_name, .prop_name = member_name };

            if (prop.value == hir_mod.none_node_id) {
                if (saw_string or next_numeric == null) {
                    if (!self.sourceHasAllowJsDirective()) {
                        try self.report(
                            m,
                            TsCodes.enum_computed_after_string,
                            "Enum member must have initializer.",
                        );
                    }
                    next_numeric = null;
                    continue;
                }
                const v = next_numeric.?;
                try self.enum_member_values.put(self.gpa, key, v);
                try member_literal_types.append(self.gpa, self.interner.internNumberLiteral(v) catch return error.OutOfMemory);
                next_numeric = v + 1;
                continue;
            }

            // Has an initializer — resolve a small constant-expression
            // subset first so unqualified references to earlier enum
            // members (`B = A`, `C = A + 1`) are treated as enum
            // constants rather than unresolved value identifiers.
            const init_kind = self.hir.kindOf(prop.value);
            switch (init_kind) {
                .literal_string => {
                    saw_string = true;
                    const lit = hir_mod.literalStringOf(self.hir, prop.value);
                    try member_literal_types.append(self.gpa, self.interner.internStringLiteral(lit.value) catch return error.OutOfMemory);
                    next_numeric = null;
                },
                else => {
                    if (self.nodeSourceStringLiteralId(prop.value)) |sid| {
                        saw_string = true;
                        try member_literal_types.append(self.gpa, self.interner.internStringLiteral(sid) catch return error.OutOfMemory);
                        next_numeric = null;
                        continue;
                    }
                    if (self.evalEnumConstExpression(enum_name, prop.value)) |v| {
                        try self.enum_member_values.put(self.gpa, key, v);
                        try member_literal_types.append(self.gpa, self.interner.internNumberLiteral(v) catch return error.OutOfMemory);
                        next_numeric = v + 1;
                    } else {
                        if (e.is_const and self.hir.kindOf(prop.value) != .identifier) {
                            try self.report(prop.value, TsCodes.const_enum_initializer_must_be_constant, "const enum member initializers must be constant expressions.");
                        } else if (!e.is_const) {
                            _ = try self.checkExpression(prop.value);
                        }
                        next_numeric = null;
                    }
                },
            }
        }
        const enum_t: TypeId = if (saw_string and member_literal_types.items.len > 0)
            self.interner.internUnion(member_literal_types.items) catch return error.OutOfMemory
        else
            types.Primitive.number_t;
        if (!saw_string and !e.is_const) try self.numeric_enums.put(self.gpa, enum_name, {});
        try self.type_names.put(self.gpa, enum_name, enum_t);
        self.hir.setType(node, enum_t);
        self.hir.setType(e.name, enum_t);
    }

    fn evalEnumConstExpression(self: *Checker, enum_name: hir_mod.StringId, node: NodeId) ?f64 {
        return switch (self.hir.kindOf(node)) {
            .literal_number => hir_mod.literalNumberOf(self.hir, node),
            .identifier => blk: {
                const id = hir_mod.identifierOf(self.hir, node);
                break :blk self.enum_member_values.get(.{ .obj_name = enum_name, .prop_name = id.name });
            },
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, node);
                if (self.hir.kindOf(m.object) != .identifier) break :blk null;
                const obj = hir_mod.identifierOf(self.hir, m.object);
                break :blk self.enum_member_values.get(.{ .obj_name = obj.name, .prop_name = m.name });
            },
            .unary_op => blk: {
                const u = hir_mod.unaryOf(self.hir, node);
                const value = self.evalEnumConstExpression(enum_name, u.operand) orelse break :blk null;
                break :blk switch (u.op) {
                    .plus => value,
                    .neg => -value,
                    .bit_not => bitNotEnumValue(value),
                    else => null,
                };
            },
            .binary_op => blk: {
                const b = hir_mod.binopOf(self.hir, node);
                const lhs = self.evalEnumConstExpression(enum_name, b.lhs) orelse break :blk null;
                const rhs = self.evalEnumConstExpression(enum_name, b.rhs) orelse break :blk null;
                break :blk switch (b.op) {
                    .add => lhs + rhs,
                    .sub => lhs - rhs,
                    .mul => lhs * rhs,
                    .div => lhs / rhs,
                    .mod => @mod(lhs, rhs),
                    .bit_or => bitwiseEnumValue(lhs, rhs, .bit_or),
                    .bit_and => bitwiseEnumValue(lhs, rhs, .bit_and),
                    .bit_xor => bitwiseEnumValue(lhs, rhs, .bit_xor),
                    .shl => shiftEnumValue(lhs, rhs, .shl),
                    .shr => shiftEnumValue(lhs, rhs, .shr),
                    .shr_unsigned => shiftEnumValue(lhs, rhs, .shr_unsigned),
                    else => null,
                };
            },
            else => null,
        };
    }

    const EnumBitOp = enum { bit_or, bit_and, bit_xor };
    const EnumShiftOp = enum { shl, shr, shr_unsigned };

    fn enumIntValue(value: f64) ?i64 {
        if (value != @floor(value)) return null;
        const min: f64 = @floatFromInt(std.math.minInt(i64));
        const max: f64 = @floatFromInt(std.math.maxInt(i64));
        if (value < min or value > max) return null;
        return @intFromFloat(value);
    }

    fn bitNotEnumValue(value: f64) ?f64 {
        const int_value = enumIntValue(value) orelse return null;
        return @floatFromInt(~int_value);
    }

    fn bitwiseEnumValue(lhs: f64, rhs: f64, op: EnumBitOp) ?f64 {
        const lhs_int = enumIntValue(lhs) orelse return null;
        const rhs_int = enumIntValue(rhs) orelse return null;
        const result = switch (op) {
            .bit_or => lhs_int | rhs_int,
            .bit_and => lhs_int & rhs_int,
            .bit_xor => lhs_int ^ rhs_int,
        };
        return @floatFromInt(result);
    }

    fn shiftEnumValue(lhs: f64, rhs: f64, op: EnumShiftOp) ?f64 {
        const lhs_int = enumIntValue(lhs) orelse return null;
        const rhs_int = enumIntValue(rhs) orelse return null;
        if (rhs_int < 0) return null;
        const amount: u6 = @intCast(@as(u64, @intCast(rhs_int)) & 63);
        const result = switch (op) {
            .shl => lhs_int << amount,
            .shr => lhs_int >> amount,
            .shr_unsigned => lhs_int >> amount,
        };
        return @floatFromInt(result);
    }

    /// If `obj_name` resolves to a `const enum` declaration and
    /// `prop_name` is one of its members with a tracked numeric
    /// value, return the literal type for that value. Otherwise
    /// `null`. Used by member-access typing so `E.A` types as the
    /// literal `1` (the same shape `E.A as const` would produce).
    fn constEnumLiteralAccess(
        self: *Checker,
        obj_name: hir_mod.StringId,
        prop_name: hir_mod.StringId,
        anchor: NodeId,
    ) ?TypeId {
        const is_const_enum = if (self.const_enums.contains(obj_name))
            true
        else blk: {
            const module = self.module orelse break :blk false;
            const sym = module.root.lookup(obj_name) orelse break :blk false;
            if (sym.decls.items.len == 0) break :blk false;
            const decl = sym.decls.items[0];
            if (self.hir.kindOf(decl) != .enum_decl) break :blk false;
            break :blk hir_mod.enumOf(self.hir, decl).is_const;
        };
        if (!is_const_enum) return null;
        const key: MemberKey = .{ .obj_name = obj_name, .prop_name = prop_name };
        if (self.enum_member_values.get(key)) |v| {
            return self.interner.internNumberLiteral(v) catch null;
        }
        const decl = self.enumDeclForNameAt(obj_name, anchor) orelse return null;
        for (hir_mod.enumMembers(self.hir, decl)) |member| {
            if (self.hir.kindOf(member) != .object_property) continue;
            const prop = hir_mod.objectPropertyOf(self.hir, member);
            if (prop.key == hir_mod.none_node_id or self.hir.kindOf(prop.key) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, prop.key).name != prop_name) continue;
            if (prop.value != hir_mod.none_node_id and self.hir.kindOf(prop.value) == .literal_string) {
                const lit = hir_mod.literalStringOf(self.hir, prop.value);
                return self.interner.internStringLiteral(lit.value) catch null;
            }
            if (prop.value != hir_mod.none_node_id) {
                if (self.nodeSourceStringLiteralId(prop.value)) |sid| {
                    return self.interner.internStringLiteral(sid) catch null;
                }
            }
            return types.Primitive.number_t;
        }
        return null;
    }

    fn nodeSourceStringLiteralId(self: *Checker, node: NodeId) ?hir_mod.StringId {
        const src = self.source orelse return null;
        const sp = self.hir.spanOf(node);
        if (sp.end > src.len or sp.start >= sp.end) return null;
        const text = std.mem.trim(u8, src[sp.start..sp.end], " \t\r\n");
        if (text.len < 2) return null;
        const quote = text[0];
        if ((quote == '"' or quote == '\'') and text[text.len - 1] == quote) {
            return self.string_interner.intern(text[1 .. text.len - 1]) catch null;
        }
        if (sp.start > 0 and sp.end < src.len) {
            const before = src[sp.start - 1];
            const after = src[sp.end];
            if ((before == '"' or before == '\'') and after == before) {
                return self.string_interner.intern(src[sp.start..sp.end]) catch null;
            }
        }
        return null;
    }

    fn enumMemberStringLiteralAccess(
        self: *Checker,
        obj_name: hir_mod.StringId,
        prop_name: hir_mod.StringId,
        anchor: NodeId,
    ) ?TypeId {
        const decl = self.enumDeclForNameAt(obj_name, anchor) orelse return null;
        for (hir_mod.enumMembers(self.hir, decl)) |member| {
            if (self.hir.kindOf(member) != .object_property) continue;
            const prop = hir_mod.objectPropertyOf(self.hir, member);
            if (prop.key == hir_mod.none_node_id or self.hir.kindOf(prop.key) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, prop.key).name != prop_name) continue;
            if (prop.value != hir_mod.none_node_id and self.hir.kindOf(prop.value) == .literal_string) {
                const lit = hir_mod.literalStringOf(self.hir, prop.value);
                return self.interner.internStringLiteral(lit.value) catch null;
            }
            return null;
        }
        return null;
    }

    fn enumMemberAccessType(
        self: *Checker,
        obj_name: hir_mod.StringId,
        prop_name: hir_mod.StringId,
        anchor: NodeId,
    ) CheckError!?TypeId {
        if (self.const_enums.contains(obj_name)) return null;
        const decl = self.enumDeclForNameAt(obj_name, anchor) orelse return null;
        var found = false;
        for (hir_mod.enumMembers(self.hir, decl)) |member| {
            if (self.hir.kindOf(member) != .object_property) continue;
            const prop = hir_mod.objectPropertyOf(self.hir, member);
            const key_name: ?hir_mod.StringId = switch (self.hir.kindOf(prop.key)) {
                .identifier => hir_mod.identifierOf(self.hir, prop.key).name,
                .literal_string => hir_mod.literalStringOf(self.hir, prop.key).value,
                else => null,
            };
            if (key_name != null and key_name.? == prop_name) {
                found = true;
                break;
            }
        }
        if (!found) return null;
        return try self.enumNominalType(obj_name);
    }

    fn enumNominalType(self: *Checker, enum_name: hir_mod.StringId) CheckError!TypeId {
        const enum_name_str = self.string_interner.get(enum_name);
        const brand = try std.fmt.allocPrint(self.gpa, "__enum:{s}", .{enum_name_str});
        defer self.gpa.free(brand);
        const brand_name = self.string_interner.intern(brand) catch return error.OutOfMemory;
        const brand_obj = self.interner.internObjectType(&.{.{
            .name = brand_name,
            .type = types.Primitive.never,
            .is_optional = false,
            .is_readonly = true,
            .is_method = false,
        }}) catch return error.OutOfMemory;
        return self.interner.internIntersection(&.{ types.Primitive.number_t, brand_obj }) catch return error.OutOfMemory;
    }

    fn enumDeclForName(self: *Checker, name: hir_mod.StringId) ?NodeId {
        return self.enumDeclForNameAt(name, hir_mod.none_node_id);
    }

    fn enumDeclForNameAt(self: *Checker, name: hir_mod.StringId, anchor: NodeId) ?NodeId {
        if (self.module) |module| {
            if (module.root.lookup(name)) |sym| {
                if (sym.decls.items.len > 0) {
                    const decl = sym.decls.items[0];
                    if (self.hir.kindOf(decl) == .enum_decl) return decl;
                }
            }
        }
        if (anchor != hir_mod.none_node_id) {
            const root = self.rootBlockFor(anchor);
            if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
            for (hir_mod.blockStmts(self.hir, root)) |raw| {
                const decl = self.unwrapExportDecl(raw);
                if (self.hir.kindOf(decl) != .enum_decl) continue;
                const e = hir_mod.enumOf(self.hir, decl);
                if (e.name == hir_mod.none_node_id or self.hir.kindOf(e.name) != .identifier) continue;
                if (hir_mod.identifierOf(self.hir, e.name).name == name) return decl;
            }
        }
        return null;
    }

    fn enumHasMember(self: *Checker, enum_name: hir_mod.StringId, member_name: hir_mod.StringId) bool {
        if (self.enum_member_values.get(.{ .obj_name = enum_name, .prop_name = member_name }) != null) return true;
        const decl = self.enumDeclForName(enum_name) orelse return false;
        for (hir_mod.enumMembers(self.hir, decl)) |member| {
            if (self.hir.kindOf(member) != .object_property) continue;
            const prop = hir_mod.objectPropertyOf(self.hir, member);
            const key_name: ?hir_mod.StringId = switch (self.hir.kindOf(prop.key)) {
                .identifier => hir_mod.identifierOf(self.hir, prop.key).name,
                .literal_string => hir_mod.literalStringOf(self.hir, prop.key).value,
                else => null,
            };
            if (key_name != null and key_name.? == member_name) return true;
        }
        return false;
    }

    fn checkEnumMemberAssignment(self: *Checker, target: NodeId) CheckError!void {
        var enum_name: ?hir_mod.StringId = null;
        var member_name: ?hir_mod.StringId = null;
        switch (self.hir.kindOf(target)) {
            .member_access => {
                const m = hir_mod.memberOf(self.hir, target);
                if (self.hir.kindOf(m.object) == .identifier) {
                    enum_name = hir_mod.identifierOf(self.hir, m.object).name;
                    member_name = m.name;
                }
            },
            .element_access => {
                const e = hir_mod.elementOf(self.hir, target);
                if (self.hir.kindOf(e.object) == .identifier and self.hir.kindOf(e.index) == .literal_string) {
                    enum_name = hir_mod.identifierOf(self.hir, e.object).name;
                    member_name = hir_mod.literalStringOf(self.hir, e.index).value;
                }
            },
            else => {},
        }
        const enum_id = enum_name orelse return;
        const member_id = member_name orelse return;
        if (!self.enumHasMember(enum_id, member_id)) return;
        const member_str = self.string_interner.get(member_id);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Cannot assign to '{s}' because it is an enum member.",
            .{member_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = target,
            .code = TsCodes.readonly_property,
            .message = msg,
        });
    }

    /// Classify an enum referenced by `obj_name`. Returns `true`
    /// when the symbol resolves to an enum decl whose members are
    /// all (or partly) numeric — i.e. one with a TS-style reverse
    /// mapping at runtime, so `E[n]` indexes back to a member name.
    /// Returns `false` for string-valued enums (which have no
    /// reverse mapping). Returns `null` when `obj_name` doesn't
    /// resolve to any enum decl. Used by indexed-access typing.
    fn enumIsNumeric(self: *Checker, obj_name: hir_mod.StringId) ?bool {
        const module = self.module orelse return null;
        const sym = module.root.lookup(obj_name) orelse return null;
        if (sym.decls.items.len == 0) return null;
        const decl = sym.decls.items[0];
        if (self.hir.kindOf(decl) != .enum_decl) return null;
        return self.enumDeclIsNumeric(decl, obj_name);
    }

    fn enumDeclIsNumeric(self: *Checker, decl: NodeId, obj_name: hir_mod.StringId) ?bool {
        // Walk members directly: a string-valued initializer flags
        // the enum as string (no reverse mapping). Otherwise, if any
        // member has a tracked numeric value the enum is numeric.
        const members = hir_mod.enumMembers(self.hir, decl);
        var any_numeric: bool = false;
        for (members) |m| {
            if (self.hir.kindOf(m) != .object_property) continue;
            const prop = hir_mod.objectPropertyOf(self.hir, m);
            if (prop.value != hir_mod.none_node_id and
                self.hir.kindOf(prop.value) == .literal_string)
            {
                return false;
            }
            if (prop.value == hir_mod.none_node_id) {
                any_numeric = true;
                continue;
            }
            if (self.hir.kindOf(prop.value) == .literal_number) {
                any_numeric = true;
                continue;
            }
            if (self.hir.kindOf(prop.key) != .identifier) continue;
            const member_name = hir_mod.identifierOf(self.hir, prop.key).name;
            const key: MemberKey = .{ .obj_name = obj_name, .prop_name = member_name };
            if (self.enum_member_values.get(key) != null) any_numeric = true;
        }
        return if (any_numeric) true else null;
    }

    /// Lower a type alias `type Alias<T...> = U` into the
    /// underlying type's TypeId and record it under the alias name.
    /// For non-generic aliases the body lowers directly. For
    /// generic aliases, we intern each type parameter, push it onto
    /// the narrow scope so the body resolves under that binding,
    /// and store `(params, body)` in `generic_aliases` so later
    /// `Alias<X>` references can substitute X for the original
    /// parameter.
    fn checkTypeAliasDecl(self: *Checker, node: NodeId) CheckError!void {
        const ta = hir_mod.typeAliasOf(self.hir, node);
        if (ta.aliased == hir_mod.none_node_id) return;
        const type_params = self.hir.childSlice(ta.type_params_start, ta.type_params_len);
        if (type_params.len == 0) {
            if (ta.name != hir_mod.none_node_id and self.hir.kindOf(ta.name) == .identifier) {
                const id = hir_mod.identifierOf(self.hir, ta.name);
                if (self.typeAliasCircularTypeofVarDecl(ta.aliased, id.name)) |var_decl| {
                    try self.reportSelfReferencedTypeAnnotation(var_decl);
                    try self.report(node, TsCodes.type_alias_circular, "Type alias circularly references itself.");
                    self.hir.setType(node, types.Primitive.any);
                    try self.type_names.put(self.gpa, id.name, types.Primitive.any);
                    self.hir.setType(ta.name, types.Primitive.any);
                    return;
                }
                if (self.typeAliasHasDirectCircularDependency(ta.aliased, id.name, id.name, 0)) {
                    try self.report(node, TsCodes.type_alias_circular, "Type alias circularly references itself.");
                    self.hir.setType(node, types.Primitive.any);
                    try self.type_names.put(self.gpa, id.name, types.Primitive.any);
                    self.hir.setType(ta.name, types.Primitive.any);
                    return;
                }
            }
            const aliased_t = try self.lowererLowerWithTypeParams(ta.aliased);
            self.hir.setType(node, aliased_t);
            if (ta.name != hir_mod.none_node_id and self.hir.kindOf(ta.name) == .identifier) {
                const id = hir_mod.identifierOf(self.hir, ta.name);
                try self.type_names.put(self.gpa, id.name, aliased_t);
                self.hir.setType(ta.name, aliased_t);
            }
            return;
        }

        // Generic alias: intern each type parameter, lower body
        // under their narrow binding, then store the (params, body)
        // for later instantiation.
        try self.checkTypeParameterDeclList(type_params);
        try self.pushNarrowScope();
        defer self.popNarrowScope();
        var param_ids: std.ArrayListUnmanaged(TypeId) = .empty;
        errdefer param_ids.deinit(self.gpa);
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tpp = hir_mod.typeParameterOf(self.hir, tp);
            const constraint: TypeId = if (tpp.constraint != hir_mod.none_node_id)
                try self.lowerer.lower(tpp.constraint)
            else
                types.Primitive.unknown;
            const def: TypeId = if (tpp.default != hir_mod.none_node_id)
                try self.lowerer.lower(tpp.default)
            else
                types.Primitive.none;
            const tp_id = self.interner.internFreshTypeParameterWithFlags(
                tpp.name,
                constraint,
                def,
                types.Variance.fromHirBits(tpp.variance),
                tpp.is_const,
            ) catch return error.OutOfMemory;
            self.hir.setType(tp, tp_id);
            try self.recordNarrow(tpp.name, tp_id);
            try param_ids.append(self.gpa, tp_id);
        }
        const body_t = try self.lowererLowerWithTypeParams(ta.aliased);
        self.hir.setType(node, body_t);
        // Auto-infer variance for any alias type parameter without
        // an explicit `in` / `out` modifier. See `inferVariance`.
        {
            var tp_ix: usize = 0;
            for (type_params) |tp_node| {
                if (self.hir.kindOf(tp_node) != .type_parameter) continue;
                const tpp_h = hir_mod.typeParameterOf(self.hir, tp_node);
                if (tp_ix >= param_ids.items.len) break;
                const tp_id_v = param_ids.items[tp_ix];
                tp_ix += 1;
                if (tpp_h.variance != 0) continue; // explicit `in`/`out`
                const v = self.inferVariance(body_t, tp_id_v);
                try self.inferred_variance.put(self.gpa, tp_id_v, v);
            }
        }
        const owned_params = param_ids.toOwnedSlice(self.gpa) catch return error.OutOfMemory;
        if (ta.name != hir_mod.none_node_id and self.hir.kindOf(ta.name) == .identifier) {
            const id = hir_mod.identifierOf(self.hir, ta.name);
            // Free any params slice from a placeholder entry put down by
            // `preRegisterTypeAlias` before overwriting with the real body.
            if (self.generic_aliases.get(id.name)) |old| {
                self.gpa.free(old.params);
            }
            try self.generic_aliases.put(self.gpa, id.name, .{
                .params = owned_params,
                .body = body_t,
                .body_node = ta.aliased,
            });
            // Also expose the un-instantiated body via `type_names`
            // so a bare `Alias` (no type-args) resolves — TS treats
            // it as `Alias<unknown, …>`.
            try self.type_names.put(self.gpa, id.name, body_t);
            self.hir.setType(ta.name, body_t);
        }
    }

    fn typeAliasCircularTypeofVarDecl(self: *Checker, aliased: NodeId, alias_name: hir_mod.StringId) ?NodeId {
        if (aliased == hir_mod.none_node_id or self.hir.kindOf(aliased) != .typeof_type) return null;
        const tt = hir_mod.typeofTypeOf(self.hir, aliased);
        if (self.hir.kindOf(tt.operand) != .identifier) return null;
        const value_name = hir_mod.identifierOf(self.hir, tt.operand).name;
        const root = self.rootBlockFor(aliased);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            const decl = self.unwrapExportDecl(raw);
            if (decl == hir_mod.none_node_id) continue;
            const k = self.hir.kindOf(decl);
            if (k != .var_decl and k != .let_decl and k != .const_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, decl);
            if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, v.name).name != value_name) continue;
            if (self.typeNodeContainsAliasReference(v.type_annotation, alias_name)) return decl;
        }
        return null;
    }

    fn reportSelfReferencedTypeAnnotation(self: *Checker, var_decl: NodeId) CheckError!void {
        const v = hir_mod.varDeclOf(self.hir, var_decl);
        const name_str = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
            self.string_interner.get(hir_mod.identifierOf(self.hir, v.name).name)
        else
            "value";
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}' is referenced directly or indirectly in its own type annotation.",
            .{name_str},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = var_decl,
            .code = TsCodes.self_referenced_type_annotation,
            .message = msg,
        });
    }

    fn typeNodeContainsAliasReference(self: *Checker, node: NodeId, alias_name: hir_mod.StringId) bool {
        if (node == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(node)) {
            .type_ref => blk: {
                const ref = hir_mod.typeRefOf(self.hir, node);
                if (ref.qualifier_len == 0 and ref.name == alias_name) break :blk true;
                for (hir_mod.typeRefArgs(self.hir, node)) |arg| {
                    if (self.typeNodeContainsAliasReference(arg, alias_name)) break :blk true;
                }
                break :blk false;
            },
            .union_type => blk: {
                for (hir_mod.unionTypeMembers(self.hir, node)) |member| {
                    if (self.typeNodeContainsAliasReference(member, alias_name)) break :blk true;
                }
                break :blk false;
            },
            .intersection_type => blk: {
                for (hir_mod.intersectionTypeMembers(self.hir, node)) |member| {
                    if (self.typeNodeContainsAliasReference(member, alias_name)) break :blk true;
                }
                break :blk false;
            },
            .array_type => self.typeNodeContainsAliasReference(hir_mod.arrayTypeOf(self.hir, node).element, alias_name),
            .tuple_type => blk: {
                for (hir_mod.tupleTypeElements(self.hir, node)) |member| {
                    if (self.typeNodeContainsAliasReference(member, alias_name)) break :blk true;
                }
                break :blk false;
            },
            else => false,
        };
    }

    fn typeAliasHasDirectCircularDependency(
        self: *Checker,
        node: NodeId,
        target_name: hir_mod.StringId,
        current_name: hir_mod.StringId,
        depth: u8,
    ) bool {
        if (node == hir_mod.none_node_id or depth > 32) return false;
        return switch (self.hir.kindOf(node)) {
            .type_ref => blk: {
                const ref = hir_mod.typeRefOf(self.hir, node);
                if (ref.qualifier_len != 0 or ref.args_len != 0) break :blk false;
                if (ref.name == target_name) break :blk true;
                if (ref.name == current_name and depth != 0) break :blk false;
                const decl = self.findTypeAliasDeclInScope(node, ref.name) orelse break :blk false;
                const ta = hir_mod.typeAliasOf(self.hir, decl);
                break :blk self.typeAliasHasDirectCircularDependency(ta.aliased, target_name, ref.name, depth + 1);
            },
            .union_type => blk: {
                for (hir_mod.unionTypeMembers(self.hir, node)) |member| {
                    if (self.typeAliasHasDirectCircularDependency(member, target_name, current_name, depth)) break :blk true;
                }
                break :blk false;
            },
            else => false,
        };
    }

    fn findTypeAliasDeclInScope(self: *Checker, anchor: NodeId, name: hir_mod.StringId) ?NodeId {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const anchor_section = self.virtualSectionStartForNode(anchor);
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            const decl = self.unwrapExportDecl(raw);
            if (decl == hir_mod.none_node_id or self.hir.kindOf(decl) != .type_alias_decl) continue;
            if (self.virtualSectionStartForNode(decl) != anchor_section) continue;
            const ta = hir_mod.typeAliasOf(self.hir, decl);
            if (ta.name == hir_mod.none_node_id or self.hir.kindOf(ta.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, ta.name).name == name) return decl;
        }
        return null;
    }

    fn resolveForwardClassInstanceType(self: *Checker, anchor: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        if (self.class_instance_types.get(name)) |t| return t;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            const decl = self.unwrapExportDecl(raw);
            if (decl == hir_mod.none_node_id) continue;
            const k = self.hir.kindOf(decl);
            if (k != .class_decl and k != .class_expr) continue;
            const c = hir_mod.classOf(self.hir, decl);
            if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, c.name).name != name) continue;
            if (self.nodeHasAncestor(anchor, decl)) return null;
            try self.preRegisterClassInstanceShape(decl);
            return self.class_instance_types.get(name);
        }
        return null;
    }

    fn preRegisterClassInstanceShape(self: *Checker, node: NodeId) CheckError!void {
        if (self.checked_class_decls.contains(node)) return;
        try self.checked_class_decls.put(self.gpa, node, {});
        defer _ = self.checked_class_decls.remove(node);

        const c = hir_mod.classOf(self.hir, node);
        if (c.name == hir_mod.none_node_id or self.hir.kindOf(c.name) != .identifier) return;
        const cid = hir_mod.identifierOf(self.hir, c.name);
        if (self.class_instance_types.contains(cid.name)) return;

        const type_params = self.hir.childSlice(c.type_params_start, c.type_params_len);
        if (type_params.len > 0) try self.pushNarrowScope();
        defer if (type_params.len > 0) self.popNarrowScope();
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const tpp = hir_mod.typeParameterOf(self.hir, tp);
            const constraint: TypeId = if (tpp.constraint != hir_mod.none_node_id)
                (self.lowererLowerWithTypeParams(tpp.constraint) catch types.Primitive.unknown)
            else
                types.Primitive.unknown;
            const tp_id = self.interner.internFreshTypeParameterWithFlags(
                tpp.name,
                constraint,
                types.Primitive.none,
                types.Variance.fromHirBits(tpp.variance),
                tpp.is_const,
            ) catch return error.OutOfMemory;
            self.hir.setType(tp, tp_id);
            try self.recordNarrow(tpp.name, tp_id);
        }

        var instance_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer instance_members.deinit(self.gpa);
        var string_idx: TypeId = types.Primitive.none;
        var number_idx: TypeId = types.Primitive.none;
        var symbol_idx: TypeId = types.Primitive.none;
        var has_readonly_index = false;

        if (c.extends != hir_mod.none_node_id) {
            if (try self.classExtendsInstanceType(c.extends)) |parent_t| {
                if (parent_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(parent_t).is_object_type) {
                    try instance_members.appendSlice(self.gpa, self.interner.objectMembers(parent_t));
                    string_idx = self.interner.objectStringIndex(parent_t);
                    number_idx = self.interner.objectNumberIndex(parent_t);
                    symbol_idx = self.interner.objectSymbolIndex(parent_t);
                    if (self.typeHasReadonlyIndexSignature(parent_t)) has_readonly_index = true;
                }
            }
        }

        for (hir_mod.classMembers(self.hir, node)) |m| {
            switch (self.hir.kindOf(m)) {
                .index_signature => {
                    const ix = hir_mod.indexSignatureOf(self.hir, m);
                    has_readonly_index = true;
                    const value_t = if (ix.value_type != hir_mod.none_node_id)
                        (self.lowererLowerWithTypeParams(ix.value_type) catch types.Primitive.any)
                    else
                        types.Primitive.any;
                    const key_t = if (ix.key_type != hir_mod.none_node_id)
                        (self.lowererLowerWithTypeParams(ix.key_type) catch types.Primitive.string_t)
                    else
                        types.Primitive.string_t;
                    if (key_t == types.Primitive.string_t) string_idx = value_t;
                    if (key_t == types.Primitive.number_t) number_idx = value_t;
                    if (key_t == types.Primitive.symbol_t) symbol_idx = value_t;
                },
                .object_property => {
                    const op = hir_mod.objectPropertyOf(self.hir, m);
                    if (op.is_static) continue;
                    const member_name = (try self.classMemberNameFromPropertyKey(op.key, op.is_computed)) orelse continue;
                    const field_t: TypeId = if (op.type_annotation != hir_mod.none_node_id)
                        (self.lowererLowerWithTypeParams(op.type_annotation) catch types.Primitive.any)
                    else
                        types.Primitive.any;
                    try instance_members.append(self.gpa, .{
                        .name = member_name,
                        .type = field_t,
                        .is_optional = false,
                        .is_readonly = false,
                        .is_method = false,
                    });
                },
                .fn_decl, .fn_expr, .arrow_fn => {
                    const fp = hir_mod.fnDeclOf(self.hir, m);
                    if (fp.flags.is_static or fp.flags.is_constructor) continue;
                    const member_name = (try self.classMemberNameFromFunctionName(fp.name)) orelse continue;
                    const sig = self.interner.internSignature(&.{}, types.Primitive.any, false) catch return error.OutOfMemory;
                    try instance_members.append(self.gpa, .{
                        .name = member_name,
                        .type = sig,
                        .is_optional = false,
                        .is_readonly = false,
                        .is_method = true,
                    });
                },
                else => {},
            }
        }

        const instance_t = self.interner.internObjectTypeWithIndexAndSymbol(
            instance_members.items,
            string_idx,
            number_idx,
            symbol_idx,
        ) catch return error.OutOfMemory;
        if (has_readonly_index) try self.readonly_index_types.put(self.gpa, instance_t, {});
        try self.class_instance_types.put(self.gpa, cid.name, instance_t);
        try self.class_name_by_instance.put(self.gpa, instance_t, cid.name);
        try self.type_names.put(self.gpa, cid.name, instance_t);
        self.hir.setType(node, instance_t);
        self.hir.setType(c.name, instance_t);
    }

    fn lowerValueTypeAnnotation(self: *Checker, name: hir_mod.StringId, type_annotation: NodeId) CheckError!TypeId {
        if (type_annotation == hir_mod.none_node_id) return types.Primitive.none;
        if (self.resolving_value_types.contains(name)) return types.Primitive.any;
        try self.resolving_value_types.put(self.gpa, name, {});
        defer _ = self.resolving_value_types.remove(name);
        return try self.lowererLowerWithTypeParams(type_annotation);
    }

    fn reportInvalidUppercasePrimitiveTypeRef(self: *Checker, type_node: NodeId, name: hir_mod.StringId) CheckError!bool {
        const raw = self.string_interner.get(name);
        if (std.mem.eql(u8, raw, "Null") or std.mem.eql(u8, raw, "Undefined")) {
            try self.reportCannotFindName(type_node, name);
            return true;
        }
        return false;
    }

    fn genericAliasHasMissingRequiredArgs(self: *Checker, info: GenericAliasInfo, supplied: usize) bool {
        if (supplied >= info.params.len) return false;
        for (info.params[supplied..]) |p| {
            if (!self.interner.pool.flagsOf(p).is_type_parameter) return true;
            const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(p)];
            if (tp.default == types.Primitive.none) return true;
        }
        return false;
    }

    fn reportGenericTypeRequiresArgs(self: *Checker, node: NodeId, name: hir_mod.StringId, info: GenericAliasInfo) CheckError!void {
        const raw = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Generic type '{s}' requires {d} type argument(s).",
            .{ raw, info.params.len },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.generic_type_requires_args,
            .message = msg,
        });
    }

    fn activeGenericAliasShouldDefer(self: *Checker, name: hir_mod.StringId, first_arg: TypeId) bool {
        var depth: usize = 0;
        for (self.active_generic_aliases.items) |active| {
            if (active.name != name) continue;
            depth += 1;
            if (active.first_arg == first_arg) return true;
        }
        return depth >= 32;
    }

    fn reportTypeNotGeneric(self: *Checker, node: NodeId, name: hir_mod.StringId) CheckError!void {
        const raw = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Type '{s}' is not generic.",
            .{raw},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .code = TsCodes.type_not_generic,
            .message = msg,
        });
    }

    fn typeRefNameAcceptsTypeArgs(self: *Checker, name: hir_mod.StringId, raw: []const u8) bool {
        if (self.generic_aliases.contains(name)) return true;
        if (std.mem.eql(u8, raw, "Array") or
            std.mem.eql(u8, raw, "ReadonlyArray") or
            std.mem.eql(u8, raw, "Record") or
            std.mem.eql(u8, raw, "ThisType") or
            std.mem.eql(u8, raw, "NoInfer") or
            std.mem.eql(u8, raw, "NonNullable") or
            std.mem.eql(u8, raw, "Uppercase") or
            std.mem.eql(u8, raw, "Lowercase") or
            std.mem.eql(u8, raw, "Capitalize") or
            std.mem.eql(u8, raw, "Uncapitalize") or
            std.mem.eql(u8, raw, "Promise") or
            std.mem.eql(u8, raw, "Awaited") or
            std.mem.eql(u8, raw, "Generator") or
            std.mem.eql(u8, raw, "Map") or
            std.mem.eql(u8, raw, "Set") or
            std.mem.eql(u8, raw, "AsyncGenerator"))
        {
            return true;
        }
        return false;
    }

    fn typeRefNameExists(self: *Checker, name: hir_mod.StringId) bool {
        if (self.type_names.contains(name)) return true;
        if (self.class_instance_types.contains(name)) return true;
        if (self.lookupNarrow(name)) |t| {
            return t != types.Primitive.none and t != types.Primitive.any and t != types.Primitive.unknown;
        }
        return false;
    }

    fn stringLiteralValueFromType(self: *Checker, t: TypeId) ?hir_mod.StringId {
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) return null;
        if (flags.is_literal and flags.is_string) {
            return switch (self.interner.literalOf(t)) {
                .string_lit => |sid| sid,
                else => null,
            };
        }
        if (flags.is_intersection) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.intersection_payloads.items.len) return null;
            for (self.interner.intersectionMembers(t)) |member| {
                if (self.stringLiteralValueFromType(member)) |sid| return sid;
            }
        }
        return null;
    }

    fn applyStringMappingBuiltin(self: *Checker, name: []const u8, inner: TypeId) CheckError!TypeId {
        if (inner < self.interner.pool.typeCount() and self.interner.pool.flagsOf(inner).is_union) {
            var mapped: std.ArrayListUnmanaged(TypeId) = .empty;
            defer mapped.deinit(self.gpa);
            for (self.interner.unionMembers(inner)) |member| {
                try mapped.append(self.gpa, try self.applyStringMappingBuiltin(name, member));
            }
            return self.interner.internUnion(mapped.items) catch return error.OutOfMemory;
        }
        const kind = stringMappingKindFromName(name) orelse return inner;
        if (inner == types.Primitive.any or inner == types.Primitive.unknown) return inner;
        const sid = self.stringLiteralValueFromType(inner) orelse
            return self.interner.internStringMapping(kind, inner) catch return error.OutOfMemory;
        const raw = self.string_interner.get(sid);
        const buf = try self.gpa.alloc(u8, raw.len);
        defer self.gpa.free(buf);
        @memcpy(buf, raw);
        applyStringMappingToBuffer(kind, buf);
        const mapped_sid = self.string_interner.intern(buf) catch return error.OutOfMemory;
        return self.interner.internStringLiteral(mapped_sid) catch return error.OutOfMemory;
    }

    fn stringMappingKindFromName(name: []const u8) ?types.StringMappingKind {
        if (std.mem.eql(u8, name, "Lowercase")) return .lowercase;
        if (std.mem.eql(u8, name, "Uppercase")) return .uppercase;
        if (std.mem.eql(u8, name, "Capitalize")) return .capitalize;
        if (std.mem.eql(u8, name, "Uncapitalize")) return .uncapitalize;
        return null;
    }

    fn applyStringMappingToBuffer(kind: types.StringMappingKind, buf: []u8) void {
        switch (kind) {
            .lowercase => {
                for (buf) |*c| c.* = std.ascii.toLower(c.*);
            },
            .uppercase => {
                for (buf) |*c| c.* = std.ascii.toUpper(c.*);
            },
            .capitalize => {
                if (buf.len > 0) buf[0] = std.ascii.toUpper(buf[0]);
            },
            .uncapitalize => {
                if (buf.len > 0) buf[0] = std.ascii.toLower(buf[0]);
            },
        }
    }

    fn lowerTemplateLiteralTypeWithTypeParams(self: *Checker, type_node: NodeId) CheckError!TypeId {
        const text_parts = hir_mod.templateLiteralTypeTexts(self.hir, type_node);
        const type_parts = hir_mod.templateLiteralTypeTypes(self.hir, type_node);
        if (text_parts.len == 0) return types.Primitive.string_t;

        var buf: std.ArrayListUnmanaged(u8) = .empty;
        defer buf.deinit(self.gpa);
        var text_ids: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer text_ids.deinit(self.gpa);
        var lowered_parts: std.ArrayListUnmanaged(TypeId) = .empty;
        defer lowered_parts.deinit(self.gpa);
        var all_literal_parts = true;
        for (text_parts, 0..) |text_node, i| {
            if (text_node != hir_mod.none_node_id and self.hir.kindOf(text_node) == .literal_string) {
                const lit = hir_mod.literalStringOf(self.hir, text_node);
                try text_ids.append(self.gpa, lit.value);
                try buf.appendSlice(self.gpa, self.string_interner.get(lit.value));
            } else {
                return types.Primitive.string_t;
            }
            if (i < type_parts.len) {
                const sub_t = try self.lowererLowerWithTypeParams(type_parts[i]);
                try lowered_parts.append(self.gpa, sub_t);
                if (self.stringLiteralValueFromType(sub_t)) |sid| {
                    try buf.appendSlice(self.gpa, self.string_interner.get(sid));
                } else {
                    all_literal_parts = false;
                }
            }
        }
        if (all_literal_parts) {
            const sid = self.string_interner.intern(buf.items) catch return error.OutOfMemory;
            return self.interner.internStringLiteral(sid) catch return error.OutOfMemory;
        }
        return self.interner.internTemplateLiteral(text_ids.items, lowered_parts.items) catch return error.OutOfMemory;
    }

    /// Lower a type annotation while consulting the current
    /// narrow scope (for in-scope type parameters) and the
    /// named-type table (for class / interface / type-alias names).
    fn lowererLowerWithTypeParams(self: *Checker, type_node: NodeId) CheckError!TypeId {
        switch (self.hir.kindOf(type_node)) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, type_node);
                const name_str = self.string_interner.get(id.name);
                if (std.mem.eql(u8, name_str, "any")) return types.Primitive.any;
                if (std.mem.eql(u8, name_str, "unknown")) return types.Primitive.unknown;
                if (std.mem.eql(u8, name_str, "never")) return types.Primitive.never;
                if (std.mem.eql(u8, name_str, "void")) return types.Primitive.void_t;
                if (std.mem.eql(u8, name_str, "null")) return types.Primitive.null_t;
                if (std.mem.eql(u8, name_str, "undefined")) return types.Primitive.undefined_t;
                if (std.mem.eql(u8, name_str, "string")) return types.Primitive.string_t;
                if (std.mem.eql(u8, name_str, "number")) return types.Primitive.number_t;
                if (std.mem.eql(u8, name_str, "boolean")) return types.Primitive.boolean_t;
                if (std.mem.eql(u8, name_str, "bigint")) return types.Primitive.bigint_t;
                if (std.mem.eql(u8, name_str, "symbol")) return types.Primitive.symbol_t;
                if (std.mem.eql(u8, name_str, "object")) return types.Primitive.object_t;
                if (std.mem.eql(u8, name_str, "this")) return try self.freshThisTypeParameter(id.name);
                if (self.lookupNarrow(id.name)) |t| return t;
                if (self.numeric_enums.contains(id.name)) return try self.enumNominalType(id.name);
                if (self.enumDeclForNameAt(id.name, type_node)) |decl| {
                    const e = hir_mod.enumOf(self.hir, decl);
                    if (!e.is_const and (self.enumDeclIsNumeric(decl, id.name) orelse false)) return try self.enumNominalType(id.name);
                }
                if (try self.resolveForwardClassInstanceType(type_node, id.name)) |t| return t;
                if (std.mem.eql(u8, name_str, "Object")) {
                    if (self.type_names.get(id.name)) |t| return t;
                }
                if (std.mem.eql(u8, name_str, "String")) {
                    return lib.stringProto(&self.lib_cache, self.interner, self.string_interner) catch types.Primitive.unknown;
                }
                if (self.lowerBuiltinObjectType(name_str)) |t| return t;
                if (self.type_names.get(id.name)) |t| return t;
                if (try self.reportInvalidUppercasePrimitiveTypeRef(type_node, id.name)) return types.Primitive.any;
            },
            .literal_number => {
                const value = self.literalNumberWithSourceSign(type_node);
                return self.interner.internNumberLiteral(value) catch return error.OutOfMemory;
            },
            .this_expr => {
                const this_name = self.string_interner.intern("this") catch return error.OutOfMemory;
                return try self.freshThisTypeParameter(this_name);
            },
            .object_type => {
                // Member types must lower under the same narrow
                // scope as the enclosing annotation so that type
                // parameters bound by an enclosing alias / fn
                // resolve. The raw `lowerObjectType` doesn't see
                // them — re-implement it here.
                const members = hir_mod.objectTypeMembers(self.hir, type_node);
                var built: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
                defer built.deinit(self.gpa);
                var string_idx: TypeId = types.Primitive.none;
                var number_idx: TypeId = types.Primitive.none;
                var has_readonly_index = false;
                var own_index_signatures: IndexSignatureDuplicateState = .{};
                for (members) |m| {
                    if (self.hir.kindOf(m) == .index_signature) {
                        const ix = hir_mod.indexSignatureOf(self.hir, m);
                        if (ix.is_readonly) has_readonly_index = true;
                        const value_t = if (ix.value_type != hir_mod.none_node_id)
                            try self.lowererLowerWithTypeParams(ix.value_type)
                        else
                            types.Primitive.any;
                        const key_t = if (ix.key_type != hir_mod.none_node_id)
                            try self.lowererLowerWithTypeParams(ix.key_type)
                        else
                            types.Primitive.string_t;
                        try self.checkDuplicateIndexSignature(m, key_t, &own_index_signatures);
                        if (key_t == types.Primitive.string_t) string_idx = value_t;
                        if (key_t == types.Primitive.number_t) number_idx = value_t;
                        continue;
                    }
                    if (self.hir.kindOf(m) != .interface_member) continue;
                    const im = hir_mod.interfaceMemberOf(self.hir, m);
                    if (im.name == 0) continue;
                    const t: TypeId = if (im.type_node != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(im.type_node)
                    else
                        types.Primitive.any;
                    try built.append(self.gpa, .{
                        .name = im.name,
                        .type = t,
                        .is_optional = im.is_optional,
                        .is_readonly = im.is_readonly,
                        .is_method = im.is_method,
                    });
                }
                if (self.strict_flags.strict_null_checks and string_idx != types.Primitive.none and number_idx != types.Primitive.none) {
                    if (!(self.heritageAssignable(number_idx, string_idx) catch true)) {
                        try self.report(type_node, TsCodes.number_index_not_assignable_to_string_index, "Number index type is not assignable to string index type.");
                    }
                }
                const obj_t = self.interner.internObjectTypeWithIndex(built.items, string_idx, number_idx) catch return error.OutOfMemory;
                if (has_readonly_index) try self.readonly_index_types.put(self.gpa, obj_t, {});
                return obj_t;
            },
            .union_type => {
                const members = hir_mod.unionTypeMembers(self.hir, type_node);
                var ms: std.ArrayListUnmanaged(TypeId) = .empty;
                defer ms.deinit(self.gpa);
                for (members) |m| try ms.append(self.gpa, try self.lowererLowerWithTypeParams(m));
                return self.interner.internUnion(ms.items) catch return error.OutOfMemory;
            },
            .intersection_type => {
                const members = hir_mod.intersectionTypeMembers(self.hir, type_node);
                var ms: std.ArrayListUnmanaged(TypeId) = .empty;
                defer ms.deinit(self.gpa);
                for (members) |m| try ms.append(self.gpa, try self.lowererLowerWithTypeParams(m));
                return self.interner.internIntersection(ms.items) catch return error.OutOfMemory;
            },
            .unary_op => {
                const u = hir_mod.unaryOf(self.hir, type_node);
                if ((u.op == .neg or u.op == .plus) and self.hir.kindOf(u.operand) == .literal_number) {
                    const value = hir_mod.literalNumberOf(self.hir, u.operand);
                    const signed = if (u.op == .neg and value > 0) -value else value;
                    return self.interner.internNumberLiteral(signed) catch return error.OutOfMemory;
                }
            },
            .tuple_type => return try self.lowerTupleWithTypeParams(type_node),
            .template_literal_type => return try self.lowerTemplateLiteralTypeWithTypeParams(type_node),
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, type_node);
                if (try self.reportMissingImportTypeModule(type_node)) return types.Primitive.any;
                if (r.qualifier_len > 0) {
                    if (try self.qualifiedEnumMemberTypeRef(type_node)) |t| return t;
                    if (try self.resolveQualifiedTypeRef(type_node)) |t| return t;
                    if (try self.reactComponentClassType(type_node)) |t| return t;
                }
                if (r.qualifier_len == 0 and r.args_len == 0) {
                    const name_str = self.string_interner.get(r.name);
                    if (std.mem.eql(u8, name_str, "this")) return try self.freshThisTypeParameter(r.name);
                    if (self.lookupNarrow(r.name)) |t| return t;
                    if (self.numeric_enums.contains(r.name)) return try self.enumNominalType(r.name);
                    if (self.enumDeclForNameAt(r.name, type_node)) |decl| {
                        const e = hir_mod.enumOf(self.hir, decl);
                        if (!e.is_const and (self.enumDeclIsNumeric(decl, r.name) orelse false)) return try self.enumNominalType(r.name);
                    }
                    if (self.generic_aliases.get(r.name)) |info| {
                        if (self.genericAliasHasMissingRequiredArgs(info, 0)) {
                            try self.reportGenericTypeRequiresArgs(type_node, r.name, info);
                            return info.body;
                        } else if (info.params.len > 0) {
                            var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
                            defer subs.deinit(self.gpa);
                            for (info.params) |p| {
                                const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(p)];
                                if (tp.default != types.Primitive.none) try subs.put(self.gpa, p, tp.default);
                            }
                            const instantiated = self.substituteType(info.body, &subs) catch info.body;
                            try self.copyMemberPredicatesFromReceiver(instantiated, info.body);
                            return instantiated;
                        }
                    }
                    if (try self.resolveUnqualifiedNamespaceTypeRef(type_node, r.name)) |t| return t;
                    if (try self.resolveForwardClassInstanceType(type_node, r.name)) |t| return t;
                    if (std.mem.eql(u8, name_str, "Object")) {
                        if (self.type_names.get(r.name)) |t| return t;
                    }
                    if (std.mem.eql(u8, name_str, "String")) {
                        return lib.stringProto(&self.lib_cache, self.interner, self.string_interner) catch types.Primitive.unknown;
                    }
                    if (self.lowerBuiltinObjectType(name_str)) |t| return t;
                    if (self.type_names.get(r.name)) |t| return t;
                    if (try self.reportInvalidUppercasePrimitiveTypeRef(type_node, r.name)) return types.Primitive.any;
                }
                // `Alias<X, Y>` — instantiate the generic alias by
                // substituting each declared parameter with the
                // corresponding lowered argument. Extra args are
                // ignored; missing args fall back to the parameter's
                // own TypeId (so partial application leaves the
                // remaining slot in place).
                if (r.qualifier_len == 0 and r.args_len > 0) {
                    // `ThisType<T>` — TS marker that re-binds contextual
                    // `this` inside object literals to T. The marker is
                    // structurally empty for assignment; contextual-this
                    // handling is layered in the object-literal checker.
                    {
                        const name_str = self.string_interner.get(r.name);
                        if (!self.typeRefNameAcceptsTypeArgs(r.name, name_str) and self.typeRefNameExists(r.name)) {
                            try self.reportTypeNotGeneric(type_node, r.name);
                        }
                        if (std.mem.eql(u8, name_str, "Generator") or std.mem.eql(u8, name_str, "AsyncGenerator")) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            const yield_t = if (args.len >= 1)
                                try self.lowererLowerWithTypeParams(args[0])
                            else
                                types.Primitive.unknown;
                            const return_t = if (args.len >= 2)
                                try self.lowererLowerWithTypeParams(args[1])
                            else
                                types.Primitive.void_t;
                            const next_t = if (args.len >= 3)
                                try self.lowererLowerWithTypeParams(args[2])
                            else
                                types.Primitive.unknown;
                            return try self.synthesizeGeneratorTypeFull(yield_t, return_t, next_t);
                        }
                        if (std.mem.eql(u8, name_str, "Map") and r.args_len == 2) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            return try self.builtinMapInstanceType(
                                try self.lowererLowerWithTypeParams(args[0]),
                                try self.lowererLowerWithTypeParams(args[1]),
                            );
                        }
                        if (std.mem.eql(u8, name_str, "Set") and r.args_len == 1) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            return try self.builtinSetInstanceType(try self.lowererLowerWithTypeParams(args[0]));
                        }
                        if (std.mem.eql(u8, name_str, "Record") and r.args_len == 2) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            const key_t = try self.lowererLowerWithTypeParams(args[0]);
                            const value_t = try self.lowererLowerWithTypeParams(args[1]);
                            if (key_t == types.Primitive.string_t) {
                                return self.interner.internObjectTypeWithIndexAndSymbol(&.{}, value_t, types.Primitive.none, types.Primitive.none) catch return error.OutOfMemory;
                            }
                            if (key_t == types.Primitive.number_t) {
                                return self.interner.internObjectTypeWithIndexAndSymbol(&.{}, types.Primitive.none, value_t, types.Primitive.none) catch return error.OutOfMemory;
                            }
                            if (key_t == types.Primitive.symbol_t) {
                                return self.interner.internObjectTypeWithIndexAndSymbol(&.{}, types.Primitive.none, types.Primitive.none, value_t) catch return error.OutOfMemory;
                            }
                            var literal_keys: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
                            defer literal_keys.deinit(self.gpa);
                            if (self.collectStringLiteralKeys(key_t, &literal_keys) and literal_keys.items.len > 0) {
                                var record_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
                                defer record_members.deinit(self.gpa);
                                for (literal_keys.items) |key_name| {
                                    try record_members.append(self.gpa, .{
                                        .name = key_name,
                                        .type = value_t,
                                        .is_optional = false,
                                        .is_readonly = false,
                                        .is_method = false,
                                    });
                                }
                                return self.interner.internObjectType(record_members.items) catch return error.OutOfMemory;
                            }
                            if (self.enumNameFromNominal(key_t)) |enum_name| {
                                var record_members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
                                defer record_members.deinit(self.gpa);
                                try self.appendNumericEnumRecordMembers(enum_name, value_t, &record_members);
                                if (record_members.items.len > 0) {
                                    return self.interner.internObjectType(record_members.items) catch return error.OutOfMemory;
                                }
                            }
                        }
                    }
                    if (r.args_len == 1) {
                        const name_str = self.string_interner.get(r.name);
                        if (std.mem.eql(u8, name_str, "Array") or std.mem.eql(u8, name_str, "ReadonlyArray")) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            const inner = try self.lowererLowerWithTypeParams(args[0]);
                            return self.interner.internArrayType(self.string_interner, inner) catch error.OutOfMemory;
                        }
                        if (std.mem.eql(u8, name_str, "ThisType")) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            const constraint = try self.lowererLowerWithTypeParams(args[0]);
                            const marker_name = self.string_interner.intern("__home_this_type") catch return error.OutOfMemory;
                            const marker_members = [_]types.ObjectMember{.{
                                .name = marker_name,
                                .type = constraint,
                                .is_optional = true,
                                .is_readonly = true,
                                .is_method = false,
                            }};
                            const marker_t = self.interner.internObjectType(&marker_members) catch return error.OutOfMemory;
                            try self.this_type_markers.put(self.gpa, marker_t, constraint);
                            return marker_t;
                        }
                        // `NoInfer<T>` (TS 5.4) — marks a type-arg
                        // slot as non-inference so callers can't
                        // contribute candidates from this position.
                        // For v0 we treat it transparently: lower to
                        // T directly. Inference still records the
                        // first-seen T from any non-NoInfer slot;
                        // remaining slots reuse the substituted T,
                        // so explicit `<number>` + non-numeric arg
                        // still emits TS2345 as expected.
                        if (std.mem.eql(u8, name_str, "NoInfer")) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            return try self.lowererLowerWithTypeParams(args[0]);
                        }
                        // `NonNullable<T>` is defined in lib.es5 as
                        // `T & {}`. Model the observable utility
                        // behavior directly so generic return
                        // instantiation preserves literal/enum-member
                        // candidates while dropping nullish branches.
                        if (std.mem.eql(u8, name_str, "NonNullable")) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            const inner = try self.lowererLowerWithTypeParams(args[0]);
                            return self.subtractNullUndefined(inner);
                        }
                        if (std.mem.eql(u8, name_str, "Uppercase") or
                            std.mem.eql(u8, name_str, "Lowercase") or
                            std.mem.eql(u8, name_str, "Capitalize") or
                            std.mem.eql(u8, name_str, "Uncapitalize"))
                        {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            const inner = try self.lowererLowerWithTypeParams(args[0]);
                            return try self.applyStringMappingBuiltin(name_str, inner);
                        }
                        // `Promise<T>` — there is no real lib.d.ts
                        // wired up yet, so synthesize a minimal
                        // structural Promise (`{ then: (cb: (v: T) =>
                        // any) => any }`) on the fly. This lets
                        // downstream `Awaited<…>` / `await …` peel it.
                        if (std.mem.eql(u8, name_str, "Promise")) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            const inner = try self.lowererLowerWithTypeParams(args[0]);
                            return try self.buildStructuralPromise(inner);
                        }
                        // `Awaited<T>` (TS 4.5) — recursively unwrap
                        // any structural `Promise<U>` chain. Non-
                        // Promise operands pass through unchanged.
                        if (std.mem.eql(u8, name_str, "Awaited")) {
                            const args = hir_mod.typeRefArgs(self.hir, type_node);
                            const inner = try self.lowererLowerWithTypeParams(args[0]);
                            return self.evalAwaited(inner);
                        }
                    }
                    if (self.generic_aliases.get(r.name)) |info| {
                        if (self.genericAliasHasMissingRequiredArgs(info, r.args_len)) {
                            try self.reportGenericTypeRequiresArgs(type_node, r.name, info);
                        }
                        const args = hir_mod.typeRefArgs(self.hir, type_node);
                        var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
                        defer subs.deinit(self.gpa);
                        const npairs = @min(args.len, info.params.len);
                        var i: usize = 0;
                        while (i < npairs) : (i += 1) {
                            const arg_t = try self.lowererLowerWithTypeParams(args[i]);
                            try subs.put(self.gpa, info.params[i], arg_t);
                        }
                        // Fill remaining type-parameters with their
                        // declaration-site defaults (`<T, U = number>`)
                        // for partial application like `Pair<string>`.
                        if (args.len < info.params.len) {
                            var j: usize = args.len;
                            while (j < info.params.len) : (j += 1) {
                                const p = info.params[j];
                                if (!self.interner.pool.flagsOf(p).is_type_parameter) continue;
                                const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(p)];
                                if (tp.default == types.Primitive.none) continue;
                                try subs.put(self.gpa, p, tp.default);
                            }
                        }
                        const first_arg = if (info.params.len > 0)
                            (subs.get(info.params[0]) orelse info.params[0])
                        else
                            types.Primitive.unknown;
                        if (self.activeGenericAliasShouldDefer(r.name, first_arg)) {
                            return info.body;
                        }
                        try self.active_generic_aliases.append(self.gpa, .{ .name = r.name, .first_arg = first_arg });
                        defer _ = self.active_generic_aliases.pop();

                        // Homomorphic mapped-type alias: when the
                        // alias body is `{ [K in keyof T]: F<K> }`,
                        // the static `body_t` collapsed to `unknown`
                        // because `keyof T` couldn't materialize at
                        // alias-decl time. Re-evaluate the mapped
                        // body now under the outer-parameter
                        // substitution so `Partial<{x: number}>`
                        // returns `{ x?: number }`.
                        if (info.body_node != hir_mod.none_node_id and
                            self.hir.kindOf(info.body_node) == .mapped_type)
                        {
                            try self.pushNarrowScope();
                            defer self.popNarrowScope();
                            // Push T → arg_t into the narrow scope so
                            // type-refs inside the mapped body
                            // resolve through `lookupNarrow`.
                            for (info.params, 0..) |param_t, idx| {
                                if (idx >= args.len) break;
                                const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(param_t)];
                                const arg_t = subs.get(param_t) orelse continue;
                                try self.recordNarrow(tp.name, arg_t);
                            }
                            return self.evalMappedType(info.body_node) catch info.body;
                        }
                        if (info.body_node != hir_mod.none_node_id and
                            (self.hir.kindOf(info.body_node) == .conditional_type or
                                self.hir.kindOf(info.body_node) == .template_literal_type or
                                self.hir.kindOf(info.body_node) == .type_ref or
                                self.hir.kindOf(info.body_node) == .intersection_type or
                                self.hir.kindOf(info.body_node) == .union_type or
                                self.hir.kindOf(info.body_node) == .indexed_access_type or
                                self.hir.kindOf(info.body_node) == .keyof_type))
                        {
                            try self.pushNarrowScope();
                            defer self.popNarrowScope();
                            for (info.params) |param_t| {
                                if (param_t >= self.interner.pool.typeCount()) continue;
                                if (!self.interner.pool.flagsOf(param_t).is_type_parameter) continue;
                                const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(param_t)];
                                const arg_t = subs.get(param_t) orelse continue;
                                try self.recordNarrow(tp.name, arg_t);
                            }
                            return self.lowererLowerWithTypeParams(info.body_node) catch info.body;
                        }
                        const instantiated = self.substituteType(info.body, &subs) catch info.body;
                        try self.copyMemberPredicatesFromReceiver(instantiated, info.body);
                        return instantiated;
                    }
                }
            },
            .typeof_type => {
                // `type T = typeof x` — query the value-namespace for
                // the identifier's TypeId. We reuse the same lookup
                // path identifier expressions go through, so the
                // result honors module-level scoping + nested scopes.
                const tt = hir_mod.typeofTypeOf(self.hir, type_node);
                if (self.hir.kindOf(tt.operand) == .identifier) {
                    const name = hir_mod.identifierOf(self.hir, tt.operand).name;
                    const raw = self.string_interner.get(name);
                    if (std.mem.startsWith(u8, raw, "Symbol.")) {
                        return types.Primitive.symbol_t;
                    }
                    if (self.lookupNarrow(name)) |narrow_t| {
                        if (narrow_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(narrow_t).is_type_parameter) {
                            const msg = try std.fmt.allocPrint(
                                self.diag_arena.allocator(),
                                "'{s}' only refers to a type, but is being used as a value here.",
                                .{raw},
                            );
                            try self.diagnostics.append(self.gpa, .{
                                .node = tt.operand,
                                .code = TsCodes.type_only_used_as_value,
                                .message = msg,
                            });
                            return types.Primitive.any;
                        }
                    }
                    if (std.mem.indexOfScalar(u8, raw, '.')) |_| {
                        if (try self.typeOfDottedValueReference(raw, type_node)) |dotted_t| {
                            return dotted_t;
                        }
                        if (try self.typeOfQualifiedNamespaceValue(raw, type_node)) |qualified_t| {
                            return qualified_t;
                        }
                    }
                    if (self.typeofQueryReferencesOwnDeclaration(type_node, name)) return types.Primitive.any;
                    return self.typeOfIdentifier(tt.operand);
                }
                _ = try self.lowererLowerWithTypeParams(tt.operand);
                return types.Primitive.unknown;
            },
            .keyof_type => {
                // `keyof T` — re-resolve the operand through the
                // type-name aware path, then evaluate eagerly when
                // the result is a known object type.
                const k = hir_mod.keyofTypeOf(self.hir, type_node);
                const operand = try self.lowererLowerWithTypeParams(k.operand);
                var key_names: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
                defer key_names.deinit(self.gpa);
                if (try self.collectKeyofObjectKeys(operand, &key_names)) {
                    if (key_names.items.len == 0) return types.Primitive.never;
                    var lits: std.ArrayListUnmanaged(TypeId) = .empty;
                    defer lits.deinit(self.gpa);
                    for (key_names.items) |name| {
                        const lit = self.interner.internStringLiteral(name) catch continue;
                        try lits.append(self.gpa, lit);
                    }
                    if (lits.items.len == 1) return lits.items[0];
                    return self.interner.internUnion(lits.items) catch return error.OutOfMemory;
                }
                return self.interner.internKeyof(operand) catch return error.OutOfMemory;
            },
            .indexed_access_type => {
                // `T[K]` — resolve both sides through the narrow-aware
                // path. If T is now an object type and K is a known
                // string literal, return the matching member directly.
                // If K is a union of string literals (typically from
                // `keyof T`), distribute the indexed access over each
                // member, yielding the union of value types.
                const ia = hir_mod.indexedAccessTypeOf(self.hir, type_node);
                const obj = try self.lowererLowerWithTypeParams(ia.object);
                const idx = try self.lowererLowerWithTypeParams(ia.index);
                try self.checkInvalidIndexedAccessType(ia.index, obj, idx);
                try self.checkInvalidMappedObjectIndexedAccessType(ia.object, ia.index);
                if (try self.resolveObjectIndexedAccessType(obj, idx)) |resolved| return resolved;
                return self.interner.internIndexedAccess(obj, idx) catch return error.OutOfMemory;
            },
            .conditional_type => {
                // `T extends U ? X : Y` — eagerly evaluate when neither
                // `T` nor `U` contains an unresolved type parameter.
                // Distributive: when `T` resolves to a union, distribute
                // the conditional across each member and union the
                // results.
                //
                // `[T] extends [U]` — the bracketed tuple-of-one form
                // suppresses distribution. We detect both sides being
                // single-element tuples and unwrap them, evaluating
                // non-distributively.
                //
                // `infer R` placeholders in the extends-side need to
                // be visible to the true-branch (`R`). We push a
                // narrow scope around the conditional, lower the
                // ext side first (registering each infer'd name), then
                // lower the branches.
                const c = hir_mod.conditionalTypeOf(self.hir, type_node);
                try self.checkConditionalInferConstraints(c.extends);
                try self.pushNarrowScope();
                defer self.popNarrowScope();

                // Detect `[T] extends [U]` — both sides are
                // single-element tuples. Unwrap and skip distribution.
                if (self.hir.kindOf(c.check) == .tuple_type and self.hir.kindOf(c.extends) == .tuple_type) {
                    const check_elems = hir_mod.tupleTypeElements(self.hir, c.check);
                    const ext_elems = hir_mod.tupleTypeElements(self.hir, c.extends);
                    if (check_elems.len == 1 and ext_elems.len == 1) {
                        const check = try self.lowererLowerWithTypeParams(check_elems[0]);
                        const ext = try self.lowererLowerWithTypeParams(ext_elems[0]);
                        try self.registerInferNames(ext_elems[0], ext);
                        const tt = try self.lowererLowerWithTypeParams(c.true_branch);
                        const ff = try self.lowererLowerWithTypeParams(c.false_branch);
                        // Non-distributing: evaluate as a single check
                        // (skipping the union-distribute branch).
                        return self.evalConditionalNonDistributing(check, ext, tt, ff, self.typeNodeContainsInfer(ext_elems[0]));
                    }
                }

                const check = try self.lowererLowerWithTypeParams(c.check);
                const ext = try self.lowererLowerWithTypeParams(c.extends);
                try self.registerInferNames(c.extends, ext);
                const tt = try self.lowererLowerWithTypeParams(c.true_branch);
                const ff = try self.lowererLowerWithTypeParams(c.false_branch);
                return self.evalConditional(check, ext, tt, ff, self.typeNodeContainsInfer(c.extends));
            },
            .mapped_type => {
                // `{ [K in T]: V }` — when `T` resolves to a known
                // string-literal union, materialize the result as an
                // object type with one property per literal. Each
                // property's type is the value template with `K`
                // substituted for that literal.
                return self.evalMappedType(type_node);
            },
            .array_type => {
                // `T[]` — recurse on the element through the
                // type-param-aware path so a bound parameter `T`
                // resolves to its TypeParameter id (not the base
                // lowerer's `unknown` placeholder for non-primitive
                // names). Without this, generic call-site inference
                // can't see the indexer pointing at `T` and `id<T>(x:
                // T[]): T[]` would lose `T` after lowering.
                const a = hir_mod.arrayTypeOf(self.hir, type_node);
                const element = try self.lowererLowerWithTypeParams(a.element);
                return self.interner.internArrayType(self.string_interner, element) catch error.OutOfMemory;
            },
            .fn_type, .constructor_type => {
                // `(x: T) => U` — same reasoning as array_type: the
                // base lowerer can't see in-scope type parameters,
                // so each param annotation and the return type need
                // to round-trip through `lowererLowerWithTypeParams`.
                const ft = hir_mod.fnTypeOf(self.hir, type_node);
                const ft_type_params = self.hir.childSlice(ft.type_params_start, ft.type_params_len);
                if (ft_type_params.len > 0) try self.pushNarrowScope();
                defer if (ft_type_params.len > 0) self.popNarrowScope();
                for (ft_type_params) |tp| {
                    if (self.hir.kindOf(tp) != .type_parameter) continue;
                    const tpp = hir_mod.typeParameterOf(self.hir, tp);
                    const placeholder = self.interner.internFreshTypeParameterWithFlags(
                        tpp.name,
                        types.Primitive.unknown,
                        types.Primitive.none,
                        types.Variance.fromHirBits(tpp.variance),
                        tpp.is_const,
                    ) catch return error.OutOfMemory;
                    self.hir.setType(tp, placeholder);
                    try self.recordNarrow(tpp.name, placeholder);
                }
                var captured_tp_ids: std.ArrayListUnmanaged(TypeId) = .empty;
                defer captured_tp_ids.deinit(self.gpa);
                for (ft_type_params) |tp| {
                    if (self.hir.kindOf(tp) != .type_parameter) continue;
                    const tpp = hir_mod.typeParameterOf(self.hir, tp);
                    const constraint: TypeId = if (tpp.constraint != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(tpp.constraint)
                    else
                        types.Primitive.unknown;
                    const def: TypeId = if (tpp.default != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(tpp.default)
                    else
                        types.Primitive.none;
                    const tp_id = if (tpp.constraint == hir_mod.none_node_id and tpp.default == hir_mod.none_node_id)
                        (self.lookupNarrow(tpp.name) orelse self.hir.typeOf(tp))
                    else
                        self.interner.internFreshTypeParameterWithFlags(
                            tpp.name,
                            constraint,
                            def,
                            types.Variance.fromHirBits(tpp.variance),
                            tpp.is_const,
                        ) catch return error.OutOfMemory;
                    self.hir.setType(tp, tp_id);
                    try self.recordNarrow(tpp.name, tp_id);
                    try captured_tp_ids.append(self.gpa, tp_id);
                }
                var fn_param_ts: std.ArrayListUnmanaged(TypeId) = .empty;
                defer fn_param_ts.deinit(self.gpa);
                var fn_param_omittable: std.ArrayListUnmanaged(bool) = .empty;
                defer fn_param_omittable.deinit(self.gpa);
                const fn_params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
                var has_rest_param = false;
                var explicit_this_t: TypeId = types.Primitive.none;
                for (fn_params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    const is_this_param = self.isThisParameter(p);
                    if (pp.flags.is_rest and !is_this_param) has_rest_param = true;
                    var t = if (pp.type_annotation != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(pp.type_annotation)
                    else
                        types.Primitive.any;
                    if (pp.flags.is_optional or pp.default_value != hir_mod.none_node_id) {
                        t = self.unionWithUndefined(t) catch t;
                    }
                    if (is_this_param) {
                        explicit_this_t = t;
                        continue;
                    }
                    try fn_param_ts.append(self.gpa, t);
                    try fn_param_omittable.append(self.gpa, pp.flags.is_rest or pp.type_annotation == hir_mod.none_node_id or pp.flags.is_optional or pp.default_value != hir_mod.none_node_id or t == types.Primitive.void_t);
                }
                const is_predicate = ft.return_type != hir_mod.none_node_id and
                    self.hir.kindOf(ft.return_type) == .type_predicate_type;
                const ret_t = if (ft.return_type != hir_mod.none_node_id)
                    (if (is_predicate) types.Primitive.boolean_t else try self.lowererLowerWithTypeParams(ft.return_type))
                else
                    types.Primitive.void_t;
                const is_construct = self.hir.kindOf(type_node) == .constructor_type;
                const sig = self.interner.internSignature(fn_param_ts.items, ret_t, is_construct) catch return error.OutOfMemory;
                try self.recordSignatureMinArgs(sig, fn_param_omittable.items);
                if (explicit_this_t != types.Primitive.none) try self.signature_this_params.put(self.gpa, sig, explicit_this_t);
                if (is_predicate) {
                    const pred = hir_mod.typePredicateOf(self.hir, ft.return_type);
                    const target_t: TypeId = if (pred.target_type != hir_mod.none_node_id)
                        (self.lowererLowerWithTypeParams(pred.target_type) catch types.Primitive.unknown)
                    else
                        types.Primitive.unknown;
                    try self.signature_predicates.put(self.gpa, sig, .{
                        .param_index = pred.param_index,
                        .target_type = target_t,
                        .target_node = pred.target_type,
                        .is_asserts = pred.is_asserts,
                    });
                }
                if (has_rest_param) try self.rest_signatures.put(self.gpa, sig, {});
                if (captured_tp_ids.items.len > 0) {
                    const owned = captured_tp_ids.toOwnedSlice(self.gpa) catch return error.OutOfMemory;
                    errdefer self.gpa.free(owned);
                    if (self.generic_signature_params.fetchRemove(sig)) |old| {
                        self.gpa.free(old.value);
                    }
                    try self.generic_signature_params.put(self.gpa, sig, owned);
                }
                return sig;
            },
            else => {},
        }
        return self.lowerer.lower(type_node);
    }

    fn literalNumberWithSourceSign(self: *Checker, node: NodeId) f64 {
        var value = hir_mod.literalNumberOf(self.hir, node);
        const src = self.source orelse return value;
        const sp = self.hir.spanOf(node);
        if (sp.start == 0 or sp.start > src.len) return value;
        var i: usize = sp.start;
        while (i > 0) {
            const c = src[i - 1];
            if (c == ' ' or c == '\t' or c == '\r' or c == '\n') {
                i -= 1;
                continue;
            }
            if (c == '-' and value > 0) value = -value;
            break;
        }
        return value;
    }

    fn typeofQueryReferencesOwnDeclaration(self: *Checker, type_node: NodeId, name: hir_mod.StringId) bool {
        var cur = type_node;
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .var_decl and k != .let_decl and k != .const_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, cur);
            if (v.type_annotation != type_node) return false;
            if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) return false;
            return hir_mod.identifierOf(self.hir, v.name).name == name;
        }
        return false;
    }

    fn resolveQualifiedTypeRef(self: *Checker, type_node: NodeId) CheckError!?TypeId {
        const r = hir_mod.typeRefOf(self.hir, type_node);
        const qualifiers = hir_mod.typeRefQualifier(self.hir, type_node);
        if (qualifiers.len == 0) return null;
        var path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer path.deinit(self.gpa);
        for (qualifiers) |q| {
            if (self.hir.kindOf(q) != .identifier) return null;
            try path.append(self.gpa, hir_mod.identifierOf(self.hir, q).name);
        }
        if (try self.resolveQualifiedImportNamespaceTypeRef(type_node, path.items, r.name)) |t| return t;
        const root = self.rootBlockFor(type_node);
        const root_stmts = if (root != hir_mod.none_node_id and self.hir.kindOf(root) == .block_stmt)
            hir_mod.blockStmts(self.hir, root)
        else
            return null;
        const ns_node = self.findNamespaceByPath(root_stmts, path.items) orelse return null;
        const decl = self.findNamedTypeDeclInNamespace(ns_node, r.name) orelse return null;
        if (self.qualifiedDeclHasMissingRequiredTypeArgs(decl, r.args_len)) {
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Generic type '{s}' requires type argument(s).",
                .{self.string_interner.get(r.name)},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = type_node,
                .code = TsCodes.generic_type_requires_args,
                .message = msg,
            });
        }
        const t = self.hir.typeOf(decl);
        if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
        return switch (self.hir.kindOf(decl)) {
            .interface_decl => blk: {
                try self.checkInterfaceDecl(decl);
                const lowered = self.hir.typeOf(decl);
                break :blk if (lowered != types.Primitive.none) lowered else null;
            },
            .type_alias_decl => blk: {
                try self.checkTypeAliasDecl(decl);
                const lowered = self.hir.typeOf(decl);
                break :blk if (lowered != types.Primitive.none) lowered else null;
            },
            .class_decl, .class_expr => blk: {
                const c = hir_mod.classOf(self.hir, decl);
                if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier) {
                    const cid = hir_mod.identifierOf(self.hir, c.name);
                    if (self.class_instance_types.get(cid.name)) |ct| break :blk ct;
                }
                break :blk null;
            },
            .enum_decl => self.hir.typeOf(decl),
            else => null,
        };
    }

    fn resolveQualifiedImportNamespaceTypeRef(
        self: *Checker,
        type_node: NodeId,
        qualifiers: []const hir_mod.StringId,
        leaf_name: hir_mod.StringId,
    ) CheckError!?TypeId {
        if (qualifiers.len == 0) return null;
        var full_path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer full_path.deinit(self.gpa);
        if (!try self.appendImportEqualsNamespacePathForLocal(&full_path, qualifiers[0], type_node)) {
            try full_path.append(self.gpa, qualifiers[0]);
        }
        for (qualifiers[1..]) |q| try full_path.append(self.gpa, q);
        if (full_path.items.len == 0) return null;
        const specifier = self.localImportModuleSpecifier(full_path.items[0], type_node) orelse return null;
        return try self.virtualRelativeModuleExportType(type_node, specifier, full_path.items[1..], leaf_name);
    }

    fn appendImportEqualsNamespacePathForLocal(
        self: *Checker,
        out: *std.ArrayListUnmanaged(hir_mod.StringId),
        local_name: hir_mod.StringId,
        anchor: NodeId,
    ) CheckError!bool {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            if (self.string_interner.get(imp.module).len != 0) continue;
            if (imp.default_binding == hir_mod.none_node_id or self.hir.kindOf(imp.default_binding) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, imp.default_binding).name != local_name) continue;
            if (imp.import_equals == hir_mod.none_node_id or self.hir.kindOf(imp.import_equals) != .type_ref) return false;
            const r = hir_mod.typeRefOf(self.hir, imp.import_equals);
            const qs = hir_mod.typeRefQualifier(self.hir, imp.import_equals);
            for (qs) |q| {
                if (self.hir.kindOf(q) != .identifier) return false;
                try out.append(self.gpa, hir_mod.identifierOf(self.hir, q).name);
            }
            try out.append(self.gpa, r.name);
            return true;
        }
        return false;
    }

    fn localImportModuleSpecifier(self: *Checker, local_name: hir_mod.StringId, anchor: NodeId) ?hir_mod.StringId {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            const spec = self.string_interner.get(imp.module);
            if (spec.len == 0) continue;
            const binding = if (imp.namespace_binding != hir_mod.none_node_id)
                imp.namespace_binding
            else if (imp.default_binding != hir_mod.none_node_id and std.mem.startsWith(u8, spec, ".") and self.importDeclIsRequireAssignment(stmt))
                imp.default_binding
            else
                hir_mod.none_node_id;
            if (binding == hir_mod.none_node_id or self.hir.kindOf(binding) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, binding).name == local_name) return imp.module;
        }
        return null;
    }

    fn virtualRelativeModuleExportType(
        self: *Checker,
        anchor: NodeId,
        specifier: hir_mod.StringId,
        namespace_path: []const hir_mod.StringId,
        leaf_name: hir_mod.StringId,
    ) CheckError!?TypeId {
        const src = self.source orelse return null;
        if (!self.sourceHasVirtualFilenameSections()) return null;
        const spec = self.string_interner.get(specifier);
        if (!std.mem.startsWith(u8, spec, ".")) return null;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            if (!self.virtualSectionMatchesSpecifier(src, raw, spec)) continue;
            if (self.hir.kindOf(raw) != .export_decl) continue;
            const decl = self.unwrapExportDecl(raw);
            if (namespace_path.len == 0) {
                const decl_name = self.declarationName(decl) orelse continue;
                if (decl_name != leaf_name) continue;
                return try self.typeOfExportedTypeDecl(decl, leaf_name);
            }
            if (self.hir.kindOf(decl) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, decl);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, ns.name).name != namespace_path[0]) continue;
            return try self.namespaceExportTypeByPath(decl, namespace_path[1..], leaf_name);
        }
        return null;
    }

    fn namespaceExportTypeByPath(
        self: *Checker,
        ns_node: NodeId,
        namespace_path: []const hir_mod.StringId,
        leaf_name: hir_mod.StringId,
    ) CheckError!?TypeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |raw| {
            const decl = self.unwrapExportDecl(raw);
            if (namespace_path.len == 0) {
                const decl_name = self.declarationName(decl) orelse continue;
                if (decl_name != leaf_name) continue;
                return try self.typeOfExportedTypeDecl(decl, leaf_name);
            }
            if (self.hir.kindOf(decl) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, decl);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, ns.name).name != namespace_path[0]) continue;
            return try self.namespaceExportTypeByPath(decl, namespace_path[1..], leaf_name);
        }
        return null;
    }

    fn typeOfExportedTypeDecl(self: *Checker, decl: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        const t = self.hir.typeOf(decl);
        if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
        return switch (self.hir.kindOf(decl)) {
            .interface_decl => blk: {
                try self.checkInterfaceDecl(decl);
                const lowered = self.hir.typeOf(decl);
                break :blk if (lowered != types.Primitive.none) lowered else null;
            },
            .type_alias_decl => blk: {
                try self.checkTypeAliasDecl(decl);
                const lowered = self.hir.typeOf(decl);
                break :blk if (lowered != types.Primitive.none) lowered else null;
            },
            .class_decl, .class_expr => blk: {
                try self.checkClassDecl(decl);
                if (self.class_instance_types.get(name)) |ct| break :blk ct;
                break :blk self.hir.typeOf(decl);
            },
            .enum_decl => blk: {
                try self.checkEnumDecl(decl);
                break :blk self.hir.typeOf(decl);
            },
            else => null,
        };
    }

    fn resolveUnqualifiedNamespaceTypeRef(self: *Checker, type_node: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        var cur = self.hir.parentOf(type_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (self.hir.kindOf(cur) != .namespace_decl) continue;
            const decl = self.findNamedTypeDeclInNamespace(cur, name) orelse continue;
            if (self.nodeHasAncestor(type_node, decl)) return null;
            const t = self.hir.typeOf(decl);
            if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
            return switch (self.hir.kindOf(decl)) {
                .interface_decl => blk: {
                    try self.checkInterfaceDecl(decl);
                    const lowered = self.hir.typeOf(decl);
                    break :blk if (lowered != types.Primitive.none) lowered else null;
                },
                .type_alias_decl => blk: {
                    try self.checkTypeAliasDecl(decl);
                    const lowered = self.hir.typeOf(decl);
                    break :blk if (lowered != types.Primitive.none) lowered else null;
                },
                .class_decl, .class_expr => blk: {
                    const c = hir_mod.classOf(self.hir, decl);
                    if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier) {
                        const cid = hir_mod.identifierOf(self.hir, c.name);
                        if (self.class_instance_types.get(cid.name)) |ct| break :blk ct;
                    }
                    break :blk null;
                },
                .enum_decl => self.hir.typeOf(decl),
                else => null,
            };
        }
        return null;
    }

    fn nodeHasAncestor(self: *Checker, node: NodeId, ancestor: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (cur == ancestor) return true;
        }
        return false;
    }

    fn qualifiedEnumMemberTypeRef(self: *Checker, type_node: NodeId) CheckError!?TypeId {
        const r = hir_mod.typeRefOf(self.hir, type_node);
        const qualifiers = hir_mod.typeRefQualifier(self.hir, type_node);
        if (qualifiers.len != 1 or self.hir.kindOf(qualifiers[0]) != .identifier) return null;
        const enum_name = hir_mod.identifierOf(self.hir, qualifiers[0]).name;
        if (self.constEnumLiteralAccess(enum_name, r.name, type_node)) |lit_t| return lit_t;
        if (self.enumMemberStringLiteralAccess(enum_name, r.name, type_node)) |lit_t| return lit_t;
        if (self.enumHasMember(enum_name, r.name)) return try self.enumNominalType(enum_name);
        return null;
    }

    fn qualifiedDeclHasMissingRequiredTypeArgs(self: *Checker, decl: NodeId, supplied: usize) bool {
        const params = switch (self.hir.kindOf(decl)) {
            .class_decl, .class_expr => blk: {
                const c = hir_mod.classOf(self.hir, decl);
                break :blk self.hir.childSlice(c.type_params_start, c.type_params_len);
            },
            .interface_decl => blk: {
                const i = hir_mod.interfaceOf(self.hir, decl);
                break :blk self.hir.childSlice(i.type_params_start, i.type_params_len);
            },
            .type_alias_decl => blk: {
                const t = hir_mod.typeAliasOf(self.hir, decl);
                break :blk self.hir.childSlice(t.type_params_start, t.type_params_len);
            },
            else => return false,
        };
        if (supplied >= params.len) return false;
        for (params[supplied..]) |param| {
            if (self.hir.kindOf(param) != .type_parameter) return true;
            const tp = hir_mod.typeParameterOf(self.hir, param);
            if (tp.default == hir_mod.none_node_id) return true;
        }
        return false;
    }

    fn rootBlockFor(self: *Checker, node: NodeId) NodeId {
        var cur = node;
        var parent = self.hir.parentOf(cur);
        while (parent != hir_mod.none_node_id) : (parent = self.hir.parentOf(cur)) {
            cur = parent;
        }
        return cur;
    }

    fn findNamespaceByPath(
        self: *Checker,
        stmts: []const NodeId,
        path: []const hir_mod.StringId,
    ) ?NodeId {
        if (path.len == 0) return null;
        for (stmts) |raw| {
            const node = self.unwrapExportDecl(raw);
            if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            const ns_name = self.string_interner.get(hir_mod.identifierOf(self.hir, ns.name).name);
            const consumed = self.namespaceNameConsumesPath(ns_name, path) orelse continue;
            if (consumed == path.len) return node;
            if (self.findNamespaceByPath(hir_mod.namespaceBody(self.hir, node), path[consumed..])) |nested| {
                return nested;
            }
        }
        return null;
    }

    fn namespaceNameConsumesPath(
        self: *Checker,
        ns_name: []const u8,
        path: []const hir_mod.StringId,
    ) ?usize {
        var consumed: usize = 0;
        var it = std.mem.splitScalar(u8, ns_name, '.');
        while (it.next()) |segment| {
            if (consumed >= path.len) return null;
            if (!std.mem.eql(u8, segment, self.string_interner.get(path[consumed]))) return null;
            consumed += 1;
        }
        return consumed;
    }

    fn findNamedTypeDeclInNamespace(
        self: *Checker,
        ns_node: NodeId,
        name: hir_mod.StringId,
    ) ?NodeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |raw| {
            const node = self.unwrapExportDecl(raw);
            switch (self.hir.kindOf(node)) {
                .interface_decl,
                .type_alias_decl,
                .class_decl,
                .class_expr,
                .enum_decl,
                => {
                    const decl_name = self.declarationName(node) orelse continue;
                    if (decl_name == name) return node;
                },
                else => {},
            }
        }
        return null;
    }

    fn findNamedValueDeclInNamespace(
        self: *Checker,
        ns_node: NodeId,
        name: hir_mod.StringId,
    ) ?NodeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |raw| {
            const node = self.unwrapExportDecl(raw);
            switch (self.hir.kindOf(node)) {
                .var_decl,
                .let_decl,
                .const_decl,
                .fn_decl,
                .fn_expr,
                .class_decl,
                .class_expr,
                .enum_decl,
                => {
                    const decl_name = self.declarationName(node) orelse continue;
                    if (decl_name == name) return node;
                },
                else => {},
            }
        }
        return null;
    }

    fn typeOfQualifiedNamespaceValue(
        self: *Checker,
        raw: []const u8,
        anchor: NodeId,
    ) CheckError!?TypeId {
        var parts = std.mem.splitScalar(u8, raw, '.');
        var ids: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer ids.deinit(self.gpa);
        while (parts.next()) |part| {
            if (part.len == 0) return null;
            try ids.append(self.gpa, self.string_interner.intern(part) catch return error.OutOfMemory);
        }
        if (ids.items.len < 2) return null;
        const value_name = ids.items[ids.items.len - 1];
        const root = self.rootBlockFor(anchor);
        const root_stmts = if (root != hir_mod.none_node_id and self.hir.kindOf(root) == .block_stmt)
            hir_mod.blockStmts(self.hir, root)
        else
            return null;
        const ns_node = self.findNamespaceByPath(root_stmts, ids.items[0 .. ids.items.len - 1]) orelse return null;
        const decl = self.findNamedValueDeclInNamespace(ns_node, value_name) orelse return null;
        var t = self.hir.typeOf(decl);
        if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
        switch (self.hir.kindOf(decl)) {
            .var_decl, .let_decl, .const_decl => try self.checkNamespaceValueDecl(decl),
            .fn_decl, .fn_expr, .arrow_fn => try self.checkFnSignatureOnlyNoBody(decl),
            .class_decl, .class_expr, .enum_decl => try self.checkStatement(decl),
            else => {},
        }
        t = self.hir.typeOf(decl);
        if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
        return types.Primitive.any;
    }

    fn lowerTupleWithTypeParams(self: *Checker, type_node: NodeId) CheckError!TypeId {
        const elems = hir_mod.tupleTypeElements(self.hir, type_node);

        var fixed_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer fixed_types.deinit(self.gpa);
        var rest_elem_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer rest_elem_types.deinit(self.gpa);
        var saw_unknown_rest = false;

        for (elems) |e| {
            if (self.hir.kindOf(e) == .rest_type) {
                const rt = hir_mod.restTypeOf(self.hir, e);
                const opk = self.hir.kindOf(rt.operand);
                if (opk == .tuple_type) {
                    const inner_elems = hir_mod.tupleTypeElements(self.hir, rt.operand);
                    var inner_has_rest = false;
                    for (inner_elems) |ie| {
                        if (self.hir.kindOf(ie) == .rest_type) {
                            inner_has_rest = true;
                            break;
                        }
                    }
                    if (!inner_has_rest) {
                        for (inner_elems) |ie| {
                            var t = try self.lowererLowerWithTypeParams(ie);
                            if (self.tupleElementHasOptionalMarker(ie)) {
                                t = self.unionWithUndefined(t) catch t;
                            }
                            try fixed_types.append(self.gpa, t);
                        }
                        continue;
                    }
                }
                if (opk == .array_type) {
                    const at = hir_mod.arrayTypeOf(self.hir, rt.operand);
                    const elt = try self.lowererLowerWithTypeParams(at.element);
                    try rest_elem_types.append(self.gpa, elt);
                    saw_unknown_rest = true;
                    continue;
                }
                const elt = try self.lowererLowerWithTypeParams(rt.operand);
                try rest_elem_types.append(self.gpa, elt);
                saw_unknown_rest = true;
                continue;
            }
            var t = try self.lowererLowerWithTypeParams(e);
            if (self.tupleElementHasOptionalMarker(e)) {
                t = self.unionWithUndefined(t) catch t;
            }
            try fixed_types.append(self.gpa, t);
        }

        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);

        const fixed_prefix_len: usize = if (saw_unknown_rest) blk: {
            var n: usize = 0;
            for (elems) |e| {
                if (self.hir.kindOf(e) == .rest_type) {
                    const rt = hir_mod.restTypeOf(self.hir, e);
                    const opk = self.hir.kindOf(rt.operand);
                    if (opk == .tuple_type) {
                        const inner_elems = hir_mod.tupleTypeElements(self.hir, rt.operand);
                        var inner_has_rest = false;
                        for (inner_elems) |ie| {
                            if (self.hir.kindOf(ie) == .rest_type) {
                                inner_has_rest = true;
                                break;
                            }
                        }
                        if (!inner_has_rest) {
                            n += inner_elems.len;
                            continue;
                        }
                    }
                    break;
                }
                n += 1;
            }
            break :blk n;
        } else fixed_types.items.len;

        var i: usize = 0;
        while (i < fixed_prefix_len) : (i += 1) {
            const t = fixed_types.items[i];
            var nbuf: [12]u8 = undefined;
            const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{i}) catch continue;
            const name = self.string_interner.intern(name_str) catch continue;
            try members.append(self.gpa, .{
                .name = name,
                .type = t,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            });
        }

        const length_id = self.string_interner.intern("length") catch return error.OutOfMemory;
        const length_t: TypeId = if (saw_unknown_rest)
            types.Primitive.number_t
        else
            self.interner.internNumberLiteral(@floatFromInt(fixed_types.items.len)) catch types.Primitive.number_t;
        try members.append(self.gpa, .{
            .name = length_id,
            .type = length_t,
            .is_optional = false,
            .is_readonly = true,
            .is_method = false,
        });

        var idx_union: std.ArrayListUnmanaged(TypeId) = .empty;
        defer idx_union.deinit(self.gpa);
        for (fixed_types.items) |t| try idx_union.append(self.gpa, t);
        for (rest_elem_types.items) |t| try idx_union.append(self.gpa, t);
        const elem_union: TypeId = if (idx_union.items.len == 0)
            types.Primitive.never
        else if (idx_union.items.len == 1)
            idx_union.items[0]
        else
            self.interner.internUnion(idx_union.items) catch types.Primitive.any;
        return self.interner.internObjectTypeWithIndex(members.items, types.Primitive.none, elem_union) catch error.OutOfMemory;
    }

    fn tupleElementHasOptionalMarker(self: *Checker, elem: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(elem);
        var i = span.end;
        while (i < src.len) : (i += 1) {
            switch (src[i]) {
                ' ', '\t', '\r', '\n' => continue,
                '?' => return true,
                else => return false,
            }
        }
        return false;
    }

    /// Evaluate `check extends ext ? tt : ff`. If either side carries a
    /// free type parameter (or a downstream conditional/keyof that
    /// hasn't reduced), defer by interning the conditional. If `check`
    /// is a union and itself a naked type parameter substitution,
    /// distribute. Otherwise pick the branch by structural assignability.
    /// Side note on `infer X` placeholders: when `ext` carries one,
    /// we attempt structural matching against `check` to bind the
    /// `infer` variable; the substitution is then applied to `tt`
    /// before returning. Today only the function-return case is
    /// supported (`T extends (...) => infer R ? R : never`).
    fn evalConditional(
        self: *Checker,
        check: TypeId,
        ext: TypeId,
        tt: TypeId,
        ff: TypeId,
        allow_infer_match: bool,
    ) CheckError!TypeId {
        // Distribute over a union check.
        if (self.interner.pool.flagsOf(check).is_union) {
            const members = self.interner.unionMembers(check);
            var built: std.ArrayListUnmanaged(TypeId) = .empty;
            defer built.deinit(self.gpa);
            for (members) |m| {
                const member_tt = if (tt == check) m else tt;
                const member_ff = if (ff == check) m else ff;
                const r = try self.evalConditional(m, ext, member_tt, member_ff, allow_infer_match);
                if (r == types.Primitive.never) continue;
                try built.append(self.gpa, r);
            }
            if (built.items.len == 0) return types.Primitive.never;
            if (built.items.len == 1) return built.items[0];
            return self.interner.internUnion(built.items) catch return error.OutOfMemory;
        }
        // `infer X` matching: when `ext` is a signature with infer'd
        // type-parameter placeholders and `check` is also a signature,
        // bind each infer'd placeholder structurally and substitute
        // into `tt` before returning.
        if (allow_infer_match) {
            var infer_subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
            defer infer_subs.deinit(self.gpa);
            const matched = self.matchInfer(check, ext, &infer_subs) catch false;
            if (matched and infer_subs.count() > 0) {
                return self.substituteType(tt, &infer_subs);
            }
        }
        // Defer if the check or extends type carries a free type parameter.
        if (self.containsFreeTypeParameter(check) or self.containsFreeTypeParameter(ext)) {
            return self.interner.internConditional(check, ext, tt, ff) catch return error.OutOfMemory;
        }
        const ok = if (self.stringLiteralValueFromType(check)) |sid|
            try self.stringLiteralAssignableToType(sid, ext)
        else
            self.engine.isAssignableTo(check, ext) catch false;
        return if (ok) tt else ff;
    }

    /// Like `evalConditional` but skips union distribution — used for
    /// the bracketed `[T] extends [U]` form where TS suppresses the
    /// distributive behavior.
    fn evalConditionalNonDistributing(
        self: *Checker,
        check: TypeId,
        ext: TypeId,
        tt: TypeId,
        ff: TypeId,
        allow_infer_match: bool,
    ) CheckError!TypeId {
        if (allow_infer_match) {
            var infer_subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
            defer infer_subs.deinit(self.gpa);
            const matched = self.matchInfer(check, ext, &infer_subs) catch false;
            if (matched and infer_subs.count() > 0) {
                return self.substituteType(tt, &infer_subs);
            }
        }
        if (self.containsFreeTypeParameter(check) or self.containsFreeTypeParameter(ext)) {
            return self.interner.internConditional(check, ext, tt, ff) catch return error.OutOfMemory;
        }
        const ok = if (self.stringLiteralValueFromType(check)) |sid|
            try self.stringLiteralAssignableToType(sid, ext)
        else
            self.engine.isAssignableTo(check, ext) catch false;
        return if (ok) tt else ff;
    }

    /// Walk the HIR ext-side of a conditional looking for `infer X`
    /// nodes; for each, register the name → TypeParameter mapping
    /// in the current narrow scope so subsequent `X` references in
    /// the conditional's true-branch resolve.
    fn registerInferNames(self: *Checker, ext_node: NodeId, ext_t: TypeId) !void {
        _ = ext_t;
        try self.walkAndRegisterInfer(ext_node);
    }

    const InferConstraintInfo = struct {
        node: NodeId,
        constraint: NodeId,
        first_reported: bool = false,
    };

    fn checkConditionalInferConstraints(self: *Checker, ext_node: NodeId) CheckError!void {
        var inferred: std.AutoHashMapUnmanaged(hir_mod.StringId, InferConstraintInfo) = .empty;
        defer inferred.deinit(self.gpa);
        try self.collectInferConstraintInfo(ext_node, &inferred);
        try self.reportInvalidInferConstraintRefs(ext_node, &inferred);
    }

    fn collectInferConstraintInfo(
        self: *Checker,
        node: NodeId,
        inferred: *std.AutoHashMapUnmanaged(hir_mod.StringId, InferConstraintInfo),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .infer_type => {
                const ip = hir_mod.inferTypeOf(self.hir, node);
                if (inferred.getPtr(ip.name)) |prior| {
                    if (!self.inferConstraintsEqual(prior.constraint, ip.constraint)) {
                        if (!prior.first_reported) {
                            try self.report(prior.node, TsCodes.infer_constraints_not_identical, "All declarations of this type parameter must have identical constraints.");
                            prior.first_reported = true;
                        }
                        try self.report(node, TsCodes.infer_constraints_not_identical, "All declarations of this type parameter must have identical constraints.");
                    }
                } else {
                    try inferred.put(self.gpa, ip.name, .{ .node = node, .constraint = ip.constraint });
                }
                if (ip.constraint != hir_mod.none_node_id) {
                    try self.collectInferConstraintInfo(ip.constraint, inferred);
                }
            },
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            try self.collectInferConstraintInfo(im.type_node, inferred);
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            try self.collectInferConstraintInfo(ix.key_type, inferred);
                            try self.collectInferConstraintInfo(ix.value_type, inferred);
                        },
                        else => {},
                    }
                }
            },
            .fn_type, .constructor_type => {
                const ft = hir_mod.fnTypeOf(self.hir, node);
                const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    try self.collectInferConstraintInfo(pp.type_annotation, inferred);
                }
                try self.collectInferConstraintInfo(ft.return_type, inferred);
            },
            .union_type => for (hir_mod.unionTypeMembers(self.hir, node)) |m| try self.collectInferConstraintInfo(m, inferred),
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| try self.collectInferConstraintInfo(m, inferred),
            .array_type => try self.collectInferConstraintInfo(hir_mod.arrayTypeOf(self.hir, node).element, inferred),
            .tuple_type => for (hir_mod.tupleTypeElements(self.hir, node)) |e| try self.collectInferConstraintInfo(e, inferred),
            .rest_type => try self.collectInferConstraintInfo(hir_mod.restTypeOf(self.hir, node).operand, inferred),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                try self.collectInferConstraintInfo(ia.object, inferred);
                try self.collectInferConstraintInfo(ia.index, inferred);
            },
            .keyof_type => try self.collectInferConstraintInfo(hir_mod.keyofTypeOf(self.hir, node).operand, inferred),
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                try self.collectInferConstraintInfo(c.check, inferred);
                try self.collectInferConstraintInfo(c.extends, inferred);
                try self.collectInferConstraintInfo(c.true_branch, inferred);
                try self.collectInferConstraintInfo(c.false_branch, inferred);
            },
            else => {},
        }
    }

    fn inferConstraintsEqual(self: *Checker, a: NodeId, b: NodeId) bool {
        if (a == hir_mod.none_node_id or b == hir_mod.none_node_id) return true;
        return self.nodeSourceTextEqual(a, b);
    }

    fn reportInvalidInferConstraintRefs(
        self: *Checker,
        node: NodeId,
        inferred: *const std.AutoHashMapUnmanaged(hir_mod.StringId, InferConstraintInfo),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .infer_type => {
                const ip = hir_mod.inferTypeOf(self.hir, node);
                if (ip.constraint != hir_mod.none_node_id) {
                    try self.reportInvalidInferConstraintRefsInConstraint(ip.constraint, inferred);
                }
            },
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            try self.reportInvalidInferConstraintRefs(im.type_node, inferred);
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            try self.reportInvalidInferConstraintRefs(ix.key_type, inferred);
                            try self.reportInvalidInferConstraintRefs(ix.value_type, inferred);
                        },
                        else => {},
                    }
                }
            },
            .fn_type, .constructor_type => {
                const ft = hir_mod.fnTypeOf(self.hir, node);
                const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    try self.reportInvalidInferConstraintRefs(pp.type_annotation, inferred);
                }
                try self.reportInvalidInferConstraintRefs(ft.return_type, inferred);
            },
            .union_type => for (hir_mod.unionTypeMembers(self.hir, node)) |m| try self.reportInvalidInferConstraintRefs(m, inferred),
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| try self.reportInvalidInferConstraintRefs(m, inferred),
            .array_type => try self.reportInvalidInferConstraintRefs(hir_mod.arrayTypeOf(self.hir, node).element, inferred),
            .tuple_type => for (hir_mod.tupleTypeElements(self.hir, node)) |e| try self.reportInvalidInferConstraintRefs(e, inferred),
            .rest_type => try self.reportInvalidInferConstraintRefs(hir_mod.restTypeOf(self.hir, node).operand, inferred),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                try self.reportInvalidInferConstraintRefs(ia.object, inferred);
                try self.reportInvalidInferConstraintRefs(ia.index, inferred);
            },
            .keyof_type => try self.reportInvalidInferConstraintRefs(hir_mod.keyofTypeOf(self.hir, node).operand, inferred),
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                try self.reportInvalidInferConstraintRefs(c.check, inferred);
                try self.reportInvalidInferConstraintRefs(c.extends, inferred);
                try self.reportInvalidInferConstraintRefs(c.true_branch, inferred);
                try self.reportInvalidInferConstraintRefs(c.false_branch, inferred);
            },
            else => {},
        }
    }

    fn reportInvalidInferConstraintRefsInConstraint(
        self: *Checker,
        node: NodeId,
        inferred: *const std.AutoHashMapUnmanaged(hir_mod.StringId, InferConstraintInfo),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, node);
                if (r.qualifier_len == 0) {
                    if (inferred.contains(r.name) or !self.inferConstraintTypeRefResolvable(r.name)) {
                        try self.reportCannotFindName(node, r.name);
                    }
                }
                for (hir_mod.typeRefArgs(self.hir, node)) |arg| {
                    try self.reportInvalidInferConstraintRefsInConstraint(arg, inferred);
                }
            },
            .union_type => for (hir_mod.unionTypeMembers(self.hir, node)) |m| try self.reportInvalidInferConstraintRefsInConstraint(m, inferred),
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| try self.reportInvalidInferConstraintRefsInConstraint(m, inferred),
            .array_type => try self.reportInvalidInferConstraintRefsInConstraint(hir_mod.arrayTypeOf(self.hir, node).element, inferred),
            .tuple_type => for (hir_mod.tupleTypeElements(self.hir, node)) |e| try self.reportInvalidInferConstraintRefsInConstraint(e, inferred),
            .rest_type => try self.reportInvalidInferConstraintRefsInConstraint(hir_mod.restTypeOf(self.hir, node).operand, inferred),
            .keyof_type => try self.reportInvalidInferConstraintRefsInConstraint(hir_mod.keyofTypeOf(self.hir, node).operand, inferred),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                try self.reportInvalidInferConstraintRefsInConstraint(ia.object, inferred);
                try self.reportInvalidInferConstraintRefsInConstraint(ia.index, inferred);
            },
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                try self.reportInvalidInferConstraintRefsInConstraint(c.check, inferred);
                try self.reportInvalidInferConstraintRefsInConstraint(c.extends, inferred);
                try self.reportInvalidInferConstraintRefsInConstraint(c.true_branch, inferred);
                try self.reportInvalidInferConstraintRefsInConstraint(c.false_branch, inferred);
            },
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            try self.reportInvalidInferConstraintRefsInConstraint(im.type_node, inferred);
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            try self.reportInvalidInferConstraintRefsInConstraint(ix.key_type, inferred);
                            try self.reportInvalidInferConstraintRefsInConstraint(ix.value_type, inferred);
                        },
                        else => {},
                    }
                }
            },
            else => {},
        }
    }

    fn inferConstraintTypeRefResolvable(self: *Checker, name: hir_mod.StringId) bool {
        const raw = self.string_interner.get(name);
        if (std.mem.eql(u8, raw, "any") or
            std.mem.eql(u8, raw, "unknown") or
            std.mem.eql(u8, raw, "never") or
            std.mem.eql(u8, raw, "void") or
            std.mem.eql(u8, raw, "null") or
            std.mem.eql(u8, raw, "undefined") or
            std.mem.eql(u8, raw, "string") or
            std.mem.eql(u8, raw, "number") or
            std.mem.eql(u8, raw, "boolean") or
            std.mem.eql(u8, raw, "bigint") or
            std.mem.eql(u8, raw, "symbol") or
            std.mem.eql(u8, raw, "object"))
        {
            return true;
        }
        if (self.generic_aliases.contains(name)) return true;
        return self.typeRefNameExists(name);
    }

    fn typeNodeContainsInfer(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .infer_type => return true,
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            if (self.typeNodeContainsInfer(im.type_node)) return true;
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            if (self.typeNodeContainsInfer(ix.key_type) or self.typeNodeContainsInfer(ix.value_type)) return true;
                        },
                        else => {},
                    }
                }
                return false;
            },
            .fn_type, .constructor_type => {
                const ft = hir_mod.fnTypeOf(self.hir, node);
                const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (self.typeNodeContainsInfer(pp.type_annotation)) return true;
                }
                return self.typeNodeContainsInfer(ft.return_type);
            },
            .union_type => {
                for (hir_mod.unionTypeMembers(self.hir, node)) |m| if (self.typeNodeContainsInfer(m)) return true;
                return false;
            },
            .intersection_type => {
                for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| if (self.typeNodeContainsInfer(m)) return true;
                return false;
            },
            .array_type => return self.typeNodeContainsInfer(hir_mod.arrayTypeOf(self.hir, node).element),
            .tuple_type => {
                for (hir_mod.tupleTypeElements(self.hir, node)) |e| if (self.typeNodeContainsInfer(e)) return true;
                return false;
            },
            .rest_type => return self.typeNodeContainsInfer(hir_mod.restTypeOf(self.hir, node).operand),
            .keyof_type => return self.typeNodeContainsInfer(hir_mod.keyofTypeOf(self.hir, node).operand),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                return self.typeNodeContainsInfer(ia.object) or self.typeNodeContainsInfer(ia.index);
            },
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                return self.typeNodeContainsInfer(c.check) or
                    self.typeNodeContainsInfer(c.extends) or
                    self.typeNodeContainsInfer(c.true_branch) or
                    self.typeNodeContainsInfer(c.false_branch);
            },
            else => return false,
        }
    }

    fn walkAndRegisterInfer(self: *Checker, node: NodeId) !void {
        if (node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(node);
        if (k == .infer_type) {
            const ip = hir_mod.inferTypeOf(self.hir, node);
            const constraint: TypeId = if (ip.constraint != hir_mod.none_node_id)
                try self.lowerer.lower(ip.constraint)
            else
                types.Primitive.unknown;
            const tp_id = self.interner.internTypeParameter(ip.name, constraint, types.Primitive.none) catch return;
            try self.recordNarrow(ip.name, tp_id);
            return;
        }
        if (k == .fn_type or k == .constructor_type) {
            const ft = hir_mod.fnTypeOf(self.hir, node);
            const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
            for (params) |p| {
                if (self.hir.kindOf(p) == .parameter) {
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.type_annotation != hir_mod.none_node_id) {
                        try self.walkAndRegisterInfer(pp.type_annotation);
                    }
                }
            }
            if (ft.return_type != hir_mod.none_node_id) {
                try self.walkAndRegisterInfer(ft.return_type);
            }
            return;
        }
        if (k == .union_type) {
            for (hir_mod.unionTypeMembers(self.hir, node)) |m| try self.walkAndRegisterInfer(m);
            return;
        }
        if (k == .intersection_type) {
            for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| try self.walkAndRegisterInfer(m);
            return;
        }
        if (k == .array_type) {
            const a = hir_mod.arrayTypeOf(self.hir, node);
            try self.walkAndRegisterInfer(a.element);
            return;
        }
        if (k == .tuple_type) {
            for (hir_mod.tupleTypeElements(self.hir, node)) |e| try self.walkAndRegisterInfer(e);
            return;
        }
        if (k == .indexed_access_type) {
            const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
            try self.walkAndRegisterInfer(ia.object);
            try self.walkAndRegisterInfer(ia.index);
            return;
        }
        if (k == .rest_type) {
            try self.walkAndRegisterInfer(hir_mod.restTypeOf(self.hir, node).operand);
            return;
        }
        if (k == .keyof_type) {
            try self.walkAndRegisterInfer(hir_mod.keyofTypeOf(self.hir, node).operand);
            return;
        }
        if (k == .conditional_type) {
            const c = hir_mod.conditionalTypeOf(self.hir, node);
            try self.walkAndRegisterInfer(c.check);
            try self.walkAndRegisterInfer(c.extends);
            try self.walkAndRegisterInfer(c.true_branch);
            try self.walkAndRegisterInfer(c.false_branch);
            return;
        }
        if (k == .object_type) {
            for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                switch (self.hir.kindOf(member)) {
                    .interface_member => {
                        const im = hir_mod.interfaceMemberOf(self.hir, member);
                        try self.walkAndRegisterInfer(im.type_node);
                    },
                    .index_signature => {
                        const ix = hir_mod.indexSignatureOf(self.hir, member);
                        try self.walkAndRegisterInfer(ix.key_type);
                        try self.walkAndRegisterInfer(ix.value_type);
                    },
                    else => {},
                }
            }
            return;
        }
        // Other type-node kinds either don't carry infer placeholders
        // in normal usage, or are deferred to a Phase 6 follow-up.
    }

    /// Structural match between `check` and `ext`, treating any
    /// TypeParameter in `ext` as an infer'd placeholder. On match,
    /// records `infer_param -> check_subterm` in `subs`. Returns
    /// false if the structural shapes don't align.
    fn matchInfer(
        self: *Checker,
        check: TypeId,
        ext: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) !bool {
        if (self.interner.pool.flagsOf(ext).is_type_parameter) {
            const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(ext)];
            if (tp.constraint != types.Primitive.none and
                tp.constraint != types.Primitive.unknown and
                !(self.engine.isAssignableTo(check, tp.constraint) catch false))
            {
                return false;
            }
            try subs.put(self.gpa, ext, check);
            return true;
        }
        const ef = self.interner.pool.flagsOf(ext);
        const cf = self.interner.pool.flagsOf(check);
        if (ef.is_signature and cf.is_signature) {
            // For the common ReturnType pattern `(...args: any[]) =>
            // infer R`, the ext side may have a different parameter
            // count than the check side. We don't enforce parameter
            // matching here — only the return-type unification. This
            // is the high-frequency `infer R` use case (ReturnType,
            // Awaited, Parameters, etc.); structural param matching
            // is a Phase 6 follow-up.
            const er = self.interner.signatureReturn(ext) orelse return true;
            const cr = self.interner.signatureReturn(check) orelse return true;
            return self.matchInfer(cr, er, subs);
        }
        // Default: identity.
        return check == ext;
    }

    fn containsFreeTypeParameter(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| if (self.containsFreeTypeParameter(m)) return true;
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |m| if (self.containsFreeTypeParameter(m)) return true;
            return false;
        }
        if (flags.is_object_type) {
            const members = self.interner.objectMembers(t);
            for (members) |m| if (self.containsFreeTypeParameter(m.type)) return true;
            const string_idx = self.interner.objectStringIndex(t);
            if (string_idx != types.Primitive.none and self.containsFreeTypeParameter(string_idx)) return true;
            const number_idx = self.interner.objectNumberIndex(t);
            if (number_idx != types.Primitive.none and self.containsFreeTypeParameter(number_idx)) return true;
            return false;
        }
        if (flags.is_signature) {
            const params = self.interner.signatureParams(t);
            for (params) |p| if (self.containsFreeTypeParameter(p)) return true;
            if (self.interner.signatureReturn(t)) |r| if (self.containsFreeTypeParameter(r)) return true;
            return false;
        }
        if (flags.is_keyof) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.keyof_payloads.items.len) return false;
            const k = self.interner.pool.keyof_payloads.items[payload_idx];
            return self.containsFreeTypeParameter(k.operand);
        }
        if (flags.is_indexed_access) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.indexed_access_payloads.items.len) return false;
            const ia = self.interner.pool.indexed_access_payloads.items[payload_idx];
            return self.containsFreeTypeParameter(ia.object) or self.containsFreeTypeParameter(ia.index);
        }
        if (flags.is_conditional) {
            const c = self.interner.conditionalPayload(t);
            return self.containsFreeTypeParameter(c.check_type) or
                self.containsFreeTypeParameter(c.extends_type) or
                self.containsFreeTypeParameter(c.true_branch) or
                self.containsFreeTypeParameter(c.false_branch);
        }
        if (flags.is_mapped) {
            const m = self.interner.mappedPayload(t);
            return self.containsFreeTypeParameter(m.constraint) or self.containsFreeTypeParameter(m.template);
        }
        if (flags.is_template_literal) {
            for (self.interner.templateLiteralTypes(t)) |part| {
                if (self.containsFreeTypeParameter(part)) return true;
            }
            return false;
        }
        if (flags.is_string_mapping) {
            return self.containsFreeTypeParameter(self.interner.stringMappingPayload(t).inner);
        }
        return false;
    }

    fn firstFreeTypeParameter(self: *Checker, t: TypeId) ?TypeId {
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter) return t;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| {
                if (self.firstFreeTypeParameter(m)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |m| {
                if (self.firstFreeTypeParameter(m)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_object_type) {
            for (self.interner.objectMembers(t)) |m| {
                if (self.firstFreeTypeParameter(m.type)) |tp| return tp;
            }
            const string_idx = self.interner.objectStringIndex(t);
            if (string_idx != types.Primitive.none) {
                if (self.firstFreeTypeParameter(string_idx)) |tp| return tp;
            }
            const number_idx = self.interner.objectNumberIndex(t);
            if (number_idx != types.Primitive.none) {
                if (self.firstFreeTypeParameter(number_idx)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_signature) {
            for (self.interner.signatureParams(t)) |p| {
                if (self.firstFreeTypeParameter(p)) |tp| return tp;
            }
            if (self.interner.signatureReturn(t)) |r| {
                if (self.firstFreeTypeParameter(r)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_mapped) {
            const m = self.interner.mappedPayload(t);
            if (self.firstFreeTypeParameter(m.constraint)) |tp| return tp;
            return self.firstFreeTypeParameter(m.template);
        }
        if (flags.is_template_literal) {
            for (self.interner.templateLiteralTypes(t)) |part| {
                if (self.firstFreeTypeParameter(part)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_string_mapping) {
            return self.firstFreeTypeParameter(self.interner.stringMappingPayload(t).inner);
        }
        return null;
    }

    fn lowerBuiltinObjectType(self: *Checker, name: []const u8) ?TypeId {
        if (std.mem.eql(u8, name, "Date")) {
            const sig_void_number = self.interner.internSignature(&[_]TypeId{}, types.Primitive.number_t, false) catch
                return types.Primitive.unknown;
            const sig_void_string = self.interner.internSignature(&[_]TypeId{}, types.Primitive.string_t, false) catch
                return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("getDate") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getDay") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getFullYear") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getHours") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getMilliseconds") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getMinutes") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getMonth") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getSeconds") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getTime") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("toISOString") catch return types.Primitive.unknown,
                    .type = sig_void_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("toString") catch return types.Primitive.unknown,
                    .type = sig_void_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "Number")) {
            const sig_to_fixed = self.interner.internSignature(&[_]TypeId{types.Primitive.number_t}, types.Primitive.string_t, false) catch
                return types.Primitive.unknown;
            const sig_value_of = self.interner.internSignature(&[_]TypeId{}, types.Primitive.number_t, false) catch
                return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("toFixed") catch return types.Primitive.unknown,
                    .type = sig_to_fixed,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("valueOf") catch return types.Primitive.unknown,
                    .type = sig_value_of,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "Function")) {
            const any_array = self.interner.internArrayType(self.string_interner, types.Primitive.any) catch
                return types.Primitive.unknown;
            const sig_call = self.interner.internSignature(&[_]TypeId{any_array}, types.Primitive.any, false) catch
                return types.Primitive.unknown;
            const sig_call_method = self.interner.internSignature(&[_]TypeId{ types.Primitive.any, any_array }, types.Primitive.any, false) catch
                return types.Primitive.unknown;
            self.rest_signatures.put(self.gpa, sig_call, {}) catch return types.Primitive.unknown;
            self.rest_signatures.put(self.gpa, sig_call_method, {}) catch return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("__call") catch return types.Primitive.unknown,
                    .type = sig_call,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("call") catch return types.Primitive.unknown,
                    .type = sig_call_method,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "Node")) {
            const node_t = self.interner.internObjectType(&.{}) catch return types.Primitive.unknown;
            const sig_remove_child = self.interner.internSignature(&[_]TypeId{node_t}, node_t, false) catch
                return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("parentNode") catch return types.Primitive.unknown,
                    .type = node_t,
                    .is_optional = true,
                    .is_readonly = false,
                    .is_method = false,
                },
                .{
                    .name = self.string_interner.intern("removeChild") catch return types.Primitive.unknown,
                    .type = sig_remove_child,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        const builtins = [_][]const u8{
            "Object",
            "RegExp",
            "Error",
            "TypeError",
            "RangeError",
            "SyntaxError",
            "Function",
            "PromiseLike",
            "Iterator",
            "AsyncIterator",
            "Iterable",
            "ArrayBuffer",
            "Uint8Array",
            "Uint8ClampedArray",
            "Int8Array",
            "Uint16Array",
            "Int16Array",
            "Uint32Array",
            "Int32Array",
            "Float16Array",
            "Float32Array",
            "Float64Array",
            "BigUint64Array",
            "BigInt64Array",
        };
        for (builtins) |b| {
            if (!std.mem.eql(u8, name, b)) continue;
            return self.interner.internObjectType(&.{}) catch types.Primitive.unknown;
        }
        return null;
    }

    fn evalMappedType(self: *Checker, node: NodeId) CheckError!TypeId {
        const m = hir_mod.mappedTypeOf(self.hir, node);
        if (m.constraint == hir_mod.none_node_id or m.value == hir_mod.none_node_id) {
            // Fall back to plain lower.
            return self.lowerer.lower(node);
        }
        const constraint_t = try self.lowererLowerWithTypeParams(m.constraint);
        // The type-parameter NodeId — its `name` is the StringId we
        // bind for the value template.
        if (m.type_param == hir_mod.none_node_id or self.hir.kindOf(m.type_param) != .type_parameter) {
            return self.lowerer.lower(node);
        }
        const tp = hir_mod.typeParameterOf(self.hir, m.type_param);
        const tp_id = self.interner.internTypeParameter(tp.name, types.Primitive.unknown, types.Primitive.none) catch
            return error.OutOfMemory;
        try self.pushNarrowScope();
        defer self.popNarrowScope();
        try self.recordNarrow(tp.name, tp_id);

        // Materialize when the constraint is a string-literal union or
        // a single string-literal type.
        var literal_keys: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer literal_keys.deinit(self.gpa);
        const can_materialize = self.collectStringLiteralKeys(constraint_t, &literal_keys);
        if (!can_materialize or literal_keys.items.len == 0) {
            if (self.typeNodeIndexedAccessHasMissingKeys(m.constraint)) {
                try self.reportOnce(m.constraint, TsCodes.type_not_assignable, "Type is not assignable to mapped type key constraint.");
            }
            if (self.hir.kindOf(m.constraint) == .keyof_type) {
                const k = hir_mod.keyofTypeOf(self.hir, m.constraint);
                const operand = self.lowererLowerWithTypeParams(k.operand) catch types.Primitive.unknown;
                const operand_flags = if (operand < self.interner.pool.typeCount())
                    self.interner.pool.flagsOf(operand)
                else
                    std.mem.zeroes(types.TypeFlags);
                if (operand != types.Primitive.unknown and
                    operand != types.Primitive.any and
                    !operand_flags.is_type_parameter and
                    !operand_flags.is_indexed_access and
                    !operand_flags.is_keyof)
                {
                    return operand;
                }
                if (operand_flags.is_type_parameter and self.mappedTypeHasIdentityTemplate(m)) {
                    const payload = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(operand)];
                    if (payload.constraint != types.Primitive.none and
                        payload.constraint != types.Primitive.unknown and
                        payload.constraint != types.Primitive.any and
                        payload.constraint < self.interner.pool.typeCount() and
                        self.interner.pool.flagsOf(payload.constraint).is_object_type and
                        self.interner.objectNumberIndex(payload.constraint) != types.Primitive.none)
                    {
                        return operand;
                    }
                }
            } else {
                return self.lowerer.lower(node);
            }
            return self.lowerer.lower(node);
        }

        var built: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer built.deinit(self.gpa);
        // Modifier values: 0 = unspecified (inherit from source),
        // 1 = add, 2 = remove. The homomorphic case
        // (`{ [K in keyof T]: ... }`) inherits the source object's
        // is_optional / is_readonly when the modifier is unspecified.
        const homomorphic_source: ?TypeId = blk: {
            if (self.hir.kindOf(m.constraint) != .keyof_type) break :blk null;
            const k = hir_mod.keyofTypeOf(self.hir, m.constraint);
            const operand = self.lowererLowerWithTypeParams(k.operand) catch break :blk null;
            if (self.interner.pool.flagsOf(operand).is_object_type) break :blk operand;
            break :blk null;
        };
        for (literal_keys.items) |key_name| {
            const key_lit = self.interner.internStringLiteral(key_name) catch continue;
            // Lower the property value with the mapped key bound to
            // the current literal. This is more faithful than lowering
            // once and substituting afterward because recursive alias
            // arguments like `DeepReadonly<T[P]>` need `T[P]` to be
            // resolved before the nested alias instantiates.
            const value_t = blk_value: {
                try self.pushNarrowScope();
                defer self.popNarrowScope();
                try self.recordNarrow(tp.name, key_lit);
                break :blk_value try self.lowererLowerWithTypeParams(m.value);
            };

            // Resolve the per-key effective name. With an `as`
            // clause (TS 4.1+ key remapping), re-lower the remap
            // with `K` bound to the current key's string literal
            // so template-literal / conditional / `Exclude<K, …>`
            // shapes evaluate eagerly. If the remap reduces to
            // `never` the key is dropped; otherwise the result
            // must be a string-like literal and replaces `key_name`.
            var effective_name: hir_mod.StringId = key_name;
            if (m.remap != hir_mod.none_node_id) {
                try self.pushNarrowScope();
                try self.recordNarrow(tp.name, key_lit);
                const remap_t = self.lowererLowerWithTypeParams(m.remap) catch types.Primitive.never;
                self.popNarrowScope();
                if (remap_t == types.Primitive.never) continue;
                const rf = self.interner.pool.flagsOf(remap_t);
                // Unwrap an intersection containing a string literal
                // (e.g. `K & string` after substitution).
                const named: TypeId = blk2: {
                    if (rf.is_intersection) {
                        const ms = self.interner.intersectionMembers(remap_t);
                        for (ms) |mt| {
                            const mf = self.interner.pool.flagsOf(mt);
                            if (mf.is_literal and mf.is_string) break :blk2 mt;
                        }
                    }
                    break :blk2 remap_t;
                };
                const nf = self.interner.pool.flagsOf(named);
                if (!(nf.is_literal and nf.is_string)) continue;
                const lit = self.interner.literalOf(named);
                switch (lit) {
                    .string_lit => |sid| effective_name = sid,
                    else => continue,
                }
            }
            // Inherit source flags when homomorphic + modifier
            // unspecified; apply +/- modifiers otherwise.
            var src_optional = false;
            var src_readonly = false;
            if (homomorphic_source) |src_t| {
                if (self.interner.objectMemberInfo(src_t, key_name)) |info| {
                    src_optional = info.is_optional;
                    src_readonly = info.is_readonly;
                }
            }
            const is_optional = switch (m.optional) {
                1 => true, // +?
                2 => false, // -?
                else => src_optional, // inherit (or false when no source)
            };
            const is_readonly = switch (m.readonly) {
                1 => true,
                2 => false,
                else => src_readonly,
            };
            try built.append(self.gpa, .{
                .name = effective_name,
                .type = value_t,
                .is_optional = is_optional,
                .is_readonly = is_readonly,
                .is_method = false,
            });
        }
        return self.interner.internObjectType(built.items) catch return error.OutOfMemory;
    }

    fn collectKeyofObjectKeys(
        self: *Checker,
        t: TypeId,
        out: *std.ArrayListUnmanaged(hir_mod.StringId),
    ) CheckError!bool {
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                _ = try self.collectKeyofObjectKeys(member, out);
            }
            return true;
        }
        if (!flags.is_object_type) return false;
        for (self.interner.objectMembers(t)) |member| {
            var seen = false;
            for (out.items) |existing| {
                if (existing == member.name) {
                    seen = true;
                    break;
                }
            }
            if (!seen) try out.append(self.gpa, member.name);
        }
        return true;
    }

    fn mappedTypeHasIdentityTemplate(self: *Checker, m: hir_mod.MappedTypePayload) bool {
        if (m.constraint == hir_mod.none_node_id or m.value == hir_mod.none_node_id or m.type_param == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(m.constraint) != .keyof_type or self.hir.kindOf(m.value) != .indexed_access_type) return false;
        const k = hir_mod.keyofTypeOf(self.hir, m.constraint);
        const ia = hir_mod.indexedAccessTypeOf(self.hir, m.value);
        const operand_name = self.bareTypeNodeName(k.operand) orelse return false;
        const object_name = self.bareTypeNodeName(ia.object) orelse return false;
        if (operand_name != object_name) return false;
        const tp = hir_mod.typeParameterOf(self.hir, m.type_param);
        const index_name = self.bareTypeNodeName(ia.index) orelse return false;
        return index_name == tp.name;
    }

    fn bareTypeNodeName(self: *Checker, node: NodeId) ?hir_mod.StringId {
        if (node == hir_mod.none_node_id) return null;
        return switch (self.hir.kindOf(node)) {
            .identifier => hir_mod.identifierOf(self.hir, node).name,
            .type_parameter => hir_mod.typeParameterOf(self.hir, node).name,
            .type_ref => blk: {
                const r = hir_mod.typeRefOf(self.hir, node);
                if (r.qualifier_len != 0 or r.args_len != 0) break :blk null;
                break :blk r.name;
            },
            else => null,
        };
    }

    /// Walk a type and accumulate the StringIds of every string-literal
    /// member. Returns false if any member isn't a string literal —
    /// in that case the mapped type can't be materialized eagerly.
    fn collectStringLiteralKeys(
        self: *Checker,
        t: TypeId,
        out: *std.ArrayListUnmanaged(hir_mod.StringId),
    ) bool {
        const flags = self.interner.pool.flagsOf(t);
        // Check `is_union` *first* because the union's propagated flag
        // set OR-folds in `is_string`/`is_literal` from each member,
        // which would otherwise misroute through the literal branch.
        if (flags.is_union) {
            const members = self.interner.unionMembers(t);
            for (members) |mt| if (!self.collectStringLiteralKeys(mt, out)) return false;
            return true;
        }
        if (flags.is_literal and flags.is_string) {
            const lit = self.interner.literalOf(t);
            switch (lit) {
                .string_lit => |sid| {
                    out.append(self.gpa, sid) catch return false;
                    return true;
                },
                else => return false,
            }
        }
        return false;
    }

    /// True iff `target` is shaped like a lowered tuple type — an
    /// object with at least a `length` member plus a numeric "0"
    /// positional member (variadic tuples have only a leading "0"
    /// when there's a middle/trailing rest, so we don't require
    /// a full sequence).
    fn isTupleShapedTarget(self: *Checker, target: TypeId) bool {
        const flags = self.interner.pool.flagsOf(target);
        if (!flags.is_object_type) return false;
        const length_id = self.string_interner.intern("length") catch return false;
        const length_t = self.interner.objectMember(target, length_id) orelse return false;
        const length_flags = self.interner.pool.flagsOf(length_t);
        if (length_flags.is_literal and length_flags.is_number) return true;
        const zero_id = self.string_interner.intern("0") catch return false;
        return self.interner.objectMember(target, zero_id) != null;
    }

    /// Positional check of an `array_literal` init against a
    /// tuple-shaped target. For each element index `i`, look up
    /// the target's member named `"i"`; if missing, fall back to
    /// the target's number-key indexer (rest slot). Returns true
    /// when every element assigns.
    fn checkArrayLiteralAgainstTuple(self: *Checker, init_node: NodeId, target: TypeId) !bool {
        const elements = hir_mod.arrayLiteralElements(self.hir, init_node);
        if (self.fixedTupleLength(target)) |len| {
            if (elements.len > len) return false;
        }
        const num_idx = self.interner.objectNumberIndex(target);
        for (elements, 0..) |el, i| {
            if (el == hir_mod.none_node_id) continue;
            const el_t = try self.checkExpression(el);
            // Look up the matching positional member.
            var nbuf: [12]u8 = undefined;
            const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{i}) catch return false;
            const name = self.string_interner.intern(name_str) catch return error.OutOfMemory;
            const tgt_t: TypeId = if (self.interner.objectMember(target, name)) |t|
                t
            else if (num_idx != types.Primitive.none)
                num_idx
            else
                return false;
            if (try self.literalExpressionAssignableToTarget(el, tgt_t)) continue;
            const ok = self.engine.isAssignableTo(el_t, tgt_t) catch return error.OutOfMemory;
            if (!ok) return false;
        }
        return true;
    }

    fn checkArrayDestructuringAssignment(self: *Checker, target_node: NodeId, source_t: TypeId, source_node: NodeId, source_offset: usize) CheckError!void {
        if (source_node != hir_mod.none_node_id and
            self.hir.kindOf(source_node) == .object_literal and
            !self.objectLiteralHasSymbolIteratorMethod(source_node))
        {
            try self.report(target_node, TsCodes.yield_star_not_iterable, "Type must have a '[Symbol.iterator]()' method that returns an iterator.");
            return;
        }
        if (source_t != types.Primitive.any and source_t != types.Primitive.unknown and
            !self.isIterableLikeType(source_t) and !self.objectLiteralHasSymbolIteratorMethod(source_node))
        {
            try self.report(target_node, TsCodes.yield_star_not_iterable, "Type must have a '[Symbol.iterator]()' method that returns an iterator.");
            return;
        }
        const fallback_elem_t = try self.iterableElementType(source_t);
        for (hir_mod.arrayLiteralElements(self.hir, target_node), 0..) |el, i| {
            if (el == hir_mod.none_node_id) continue;
            const k = self.hir.kindOf(el);
            const elem_t = self.tupleElementType(source_t, source_offset + i);
            const source_elem_t = if (try self.arrayLiteralSourceElementType(source_node, source_offset + i)) |literal_elem_t|
                literal_elem_t
            else if (elem_t != types.Primitive.none)
                elem_t
            else
                fallback_elem_t;
            if (k == .spread) {
                const sp = hir_mod.spreadOf(self.hir, el);
                if (self.hir.kindOf(sp.expression) == .assignment) {
                    try self.report(sp.expression, TsCodes.rest_element_cannot_have_initializer, "A rest element cannot have an initializer.");
                    continue;
                }
                const rest_source_t = try self.arrayRestSourceType(source_node, source_offset + i, source_elem_t);
                if (self.hir.kindOf(sp.expression) == .array_literal) {
                    try self.checkArrayDestructuringAssignment(sp.expression, source_t, source_node, source_offset + i);
                } else if (self.hir.kindOf(sp.expression) == .object_literal) {
                    try self.checkObjectDestructuringAssignment(sp.expression, rest_source_t, hir_mod.none_node_id);
                } else {
                    try self.checkDestructuringAssignmentTarget(sp.expression, rest_source_t);
                }
                continue;
            }
            if (k == .assignment) {
                const a = hir_mod.assignmentOf(self.hir, el);
                const default_t = try self.checkExpression(a.value);
                const effective_t = try self.destructuringSourceWithDefault(source_elem_t, default_t);
                try self.checkDestructuringAssignmentTarget(a.target, effective_t);
                continue;
            }
            if (k == .identifier) {
                const target_t = self.typeOfIdentifier(el);
                if (target_t == types.Primitive.none or
                    target_t == types.Primitive.any or
                    target_t == types.Primitive.unknown)
                {
                    continue;
                }
                const ok = self.engine.isAssignableTo(source_elem_t, target_t) catch return error.OutOfMemory;
                if (!ok) {
                    try self.report(el, TsCodes.type_not_assignable, "Type is not assignable to target type.");
                } else {
                    const id = hir_mod.identifierOf(self.hir, el);
                    try self.recordNarrow(id.name, source_elem_t);
                }
                continue;
            }
            if (k == .array_literal) {
                try self.checkArrayDestructuringAssignment(el, source_elem_t, hir_mod.none_node_id, 0);
            } else if (k == .object_literal) {
                try self.checkObjectDestructuringAssignment(el, source_elem_t, hir_mod.none_node_id);
            }
        }
    }

    fn arrayRestSourceType(self: *Checker, source_node: NodeId, start_index: usize, fallback_elem_t: TypeId) CheckError!TypeId {
        if (source_node != hir_mod.none_node_id and self.hir.kindOf(source_node) == .array_literal) {
            const elements = hir_mod.arrayLiteralElements(self.hir, source_node);
            var elems: std.ArrayListUnmanaged(TypeId) = .empty;
            defer elems.deinit(self.gpa);
            if (start_index < elements.len) {
                var i = start_index;
                while (i < elements.len) : (i += 1) {
                    if (elements[i] == hir_mod.none_node_id) continue;
                    try elems.append(self.gpa, try self.checkExpression(elements[i]));
                }
            }
            const elem_t = if (elems.items.len == 0)
                types.Primitive.never
            else if (elems.items.len == 1)
                elems.items[0]
            else
                self.interner.internUnion(elems.items) catch return error.OutOfMemory;
            return self.interner.internArrayType(self.string_interner, elem_t) catch return error.OutOfMemory;
        }
        return self.interner.internArrayType(self.string_interner, fallback_elem_t) catch return error.OutOfMemory;
    }

    fn arrayLiteralSourceElementType(self: *Checker, source_node: NodeId, index: usize) CheckError!?TypeId {
        if (source_node == hir_mod.none_node_id or self.hir.kindOf(source_node) != .array_literal) return null;
        const elements = hir_mod.arrayLiteralElements(self.hir, source_node);
        if (index >= elements.len or elements[index] == hir_mod.none_node_id) return types.Primitive.never;
        return try self.checkExpression(elements[index]);
    }

    fn checkObjectDestructuringAssignment(self: *Checker, target_node: NodeId, source_t: TypeId, source_node: NodeId) CheckError!void {
        if (source_t == types.Primitive.any or source_t == types.Primitive.unknown) return;
        if (source_node != hir_mod.none_node_id and self.hir.kindOf(source_node) == .object_literal) {
            const expected_t = try self.objectBindingPatternExpectedType(target_node, true);
            try self.checkExcessProperties(source_node, expected_t);
        }
        var has_dynamic_computed_key = false;
        for (hir_mod.objectLiteralProps(self.hir, target_node)) |prop_node| {
            if (self.hir.kindOf(prop_node) != .object_property) {
                if (has_dynamic_computed_key) {
                    const rest_t = self.interner.internObjectType(&.{}) catch return error.OutOfMemory;
                    try self.checkDestructuringAssignmentTarget(prop_node, rest_t);
                }
                continue;
            }
            const op = hir_mod.objectPropertyOf(self.hir, prop_node);
            if (op.value == hir_mod.none_node_id) continue;
            if (op.is_computed) {
                const key_t = try self.checkExpression(op.key);
                if (try self.reportMissingIndexForComputedBindingKey(op.key, source_t, key_t)) {
                    has_dynamic_computed_key = true;
                }
            }
            const maybe_prop_t = try self.objectPropertyTypeForDestructuring(source_t, op.key, op.is_computed);
            if (maybe_prop_t == null and self.hir.kindOf(op.value) != .assignment) {
                const prop_name = if (op.is_computed)
                    try self.propertyNameFromComputedKeyNode(op.key)
                else
                    self.propertyNameFromKeyNode(op.key);
                if (prop_name) |name| {
                    const name_str = self.string_interner.get(name);
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Property '{s}' does not exist on type.",
                        .{name_str},
                    );
                    try self.diagnostics.append(self.gpa, .{
                        .node = op.key,
                        .code = TsCodes.property_does_not_exist,
                        .message = msg,
                    });
                }
            }
            const prop_t = maybe_prop_t orelse types.Primitive.any;
            if (self.hir.kindOf(op.value) == .assignment) {
                const a = hir_mod.assignmentOf(self.hir, op.value);
                const default_t = try self.checkExpression(a.value);
                const effective_t = try self.destructuringSourceWithDefault(prop_t, default_t);
                try self.checkDestructuringAssignmentTarget(a.target, effective_t);
            } else {
                try self.checkDestructuringAssignmentTarget(op.value, prop_t);
            }
        }
    }

    fn checkDestructuringAssignmentTarget(self: *Checker, target_node: NodeId, source_t: TypeId) CheckError!void {
        switch (self.hir.kindOf(target_node)) {
            .identifier, .member_access, .element_access => {
                const target_t = if (self.hir.kindOf(target_node) == .identifier)
                    self.typeOfIdentifierDeclared(target_node)
                else
                    try self.checkExpression(target_node);
                if (target_t == types.Primitive.none or target_t == types.Primitive.any or target_t == types.Primitive.unknown) return;
                if (target_t == types.Primitive.undefined_t and
                    self.hir.kindOf(target_node) == .identifier and
                    self.identifierIsUntypedUninitializedVar(target_node))
                {
                    return;
                }
                const source_idx = if (source_t < self.interner.pool.typeCount()) self.interner.objectNumberIndex(source_t) else types.Primitive.none;
                const target_idx = if (target_t < self.interner.pool.typeCount()) self.interner.objectNumberIndex(target_t) else types.Primitive.none;
                if (source_idx != types.Primitive.none and target_idx != types.Primitive.none and
                    !(self.engine.isAssignableTo(source_idx, target_idx) catch true))
                {
                    try self.report(target_node, TsCodes.type_not_assignable, "Type is not assignable to target type.");
                    return;
                }
                if (!(self.engine.isAssignableTo(source_t, target_t) catch true)) {
                    try self.report(target_node, TsCodes.type_not_assignable, "Type is not assignable to target type.");
                } else if (self.hir.kindOf(target_node) == .identifier and
                    source_t != types.Primitive.none and
                    source_t != types.Primitive.any and
                    source_t != types.Primitive.unknown)
                {
                    const id = hir_mod.identifierOf(self.hir, target_node);
                    try self.recordNarrow(id.name, source_t);
                }
            },
            .array_literal => try self.checkArrayDestructuringAssignment(target_node, source_t, hir_mod.none_node_id, 0),
            .object_literal => try self.checkObjectDestructuringAssignment(target_node, source_t, hir_mod.none_node_id),
            else => {},
        }
    }

    fn objectBindingPatternExpectedType(self: *Checker, pattern_node: NodeId, include_empty: bool) CheckError!TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        const elems: []const NodeId = switch (self.hir.kindOf(pattern_node)) {
            .object_pattern => hir_mod.patternElements(self.hir, pattern_node),
            .object_literal => hir_mod.objectLiteralProps(self.hir, pattern_node),
            else => &.{},
        };
        for (elems) |elem| {
            if (self.hir.kindOf(elem) == .parameter) {
                const p = hir_mod.parameterOf(self.hir, elem);
                if (p.flags.is_rest or p.name == hir_mod.none_node_id) continue;
                const key_name = (try self.objectBindingElementKeyName(elem, p.name)) orelse continue;
                const target_node = if (p.default_value != hir_mod.none_node_id and self.hir.kindOf(p.default_value) == .assignment)
                    hir_mod.assignmentOf(self.hir, p.default_value).target
                else
                    p.name;
                const member_t = try self.destructuringTargetExpectedType(target_node);
                try members.append(self.gpa, .{ .name = key_name, .type = member_t, .is_optional = false, .is_readonly = false, .is_method = false });
            } else if (self.hir.kindOf(elem) == .object_property) {
                const op = hir_mod.objectPropertyOf(self.hir, elem);
                if (op.value == hir_mod.none_node_id) continue;
                const key_name = if (op.is_computed)
                    try self.propertyNameFromComputedKeyNode(op.key)
                else
                    self.propertyNameFromKeyNode(op.key);
                const name = key_name orelse continue;
                const target_node = if (self.hir.kindOf(op.value) == .assignment)
                    hir_mod.assignmentOf(self.hir, op.value).target
                else
                    op.value;
                const member_t = try self.destructuringTargetExpectedType(target_node);
                try members.append(self.gpa, .{ .name = name, .type = member_t, .is_optional = false, .is_readonly = false, .is_method = false });
            }
        }
        if (members.items.len == 0 and !include_empty) return types.Primitive.none;
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn destructuringTargetExpectedType(self: *Checker, target_node: NodeId) CheckError!TypeId {
        if (target_node == hir_mod.none_node_id) return types.Primitive.any;
        return switch (self.hir.kindOf(target_node)) {
            .identifier, .member_access, .element_access => blk: {
                const t = if (self.hir.kindOf(target_node) == .identifier)
                    self.typeOfIdentifierDeclared(target_node)
                else
                    try self.checkExpression(target_node);
                break :blk if (t == types.Primitive.none or t == types.Primitive.undefined_t) types.Primitive.any else t;
            },
            .object_literal, .object_pattern => try self.objectBindingPatternExpectedType(target_node, true),
            .array_pattern => try self.arrayBindingPatternParameterType(target_node),
            .array_literal => self.interner.internArrayType(self.string_interner, types.Primitive.any) catch return error.OutOfMemory,
            else => types.Primitive.any,
        };
    }

    fn identifierIsUntypedUninitializedVar(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, node);
        const use_start = self.hir.spanOf(node).start;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const stmts: ?[]const NodeId = switch (self.hir.kindOf(cur)) {
                .block_stmt => hir_mod.blockStmts(self.hir, cur),
                .namespace_decl => hir_mod.namespaceBody(self.hir, cur),
                else => null,
            };
            if (stmts) |items| {
                for (items) |stmt| {
                    if (self.hir.spanOf(stmt).start >= use_start) break;
                    const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
                    if (decl == hir_mod.none_node_id) continue;
                    const dk = self.hir.kindOf(decl);
                    if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
                    const v = hir_mod.varDeclOf(self.hir, decl);
                    if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
                    if (hir_mod.identifierOf(self.hir, v.name).name != id.name) continue;
                    return v.type_annotation == hir_mod.none_node_id and v.init == hir_mod.none_node_id;
                }
                continue;
            }
        }
        return false;
    }

    fn destructuringSourceWithDefault(self: *Checker, source_t: TypeId, default_t: TypeId) !TypeId {
        if (source_t == types.Primitive.any or source_t == types.Primitive.unknown) return source_t;
        if (default_t == types.Primitive.any or default_t == types.Primitive.unknown) return default_t;
        const without_undefined = self.subtractType(source_t, types.Primitive.undefined_t) catch source_t;
        if (without_undefined == types.Primitive.never or without_undefined == types.Primitive.none) return default_t;
        if (default_t == types.Primitive.never or default_t == types.Primitive.none) return without_undefined;
        if (without_undefined == default_t) return without_undefined;
        return self.interner.internUnion(&.{ without_undefined, default_t }) catch return error.OutOfMemory;
    }

    fn objectPropertyTypeForDestructuring(self: *Checker, source_t: TypeId, key_node: NodeId, is_computed: bool) CheckError!?TypeId {
        const key_name = if (is_computed)
            try self.propertyNameFromComputedKeyNode(key_node)
        else
            self.propertyNameFromKeyNode(key_node);
        const name = key_name orelse return null;
        return self.objectPropertyTypeByName(source_t, name);
    }

    fn objectPropertyTypeByName(self: *Checker, source_t: TypeId, key_name: hir_mod.StringId) ?TypeId {
        if (source_t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(source_t);
        if (flags.is_union) {
            var vals: std.ArrayListUnmanaged(TypeId) = .empty;
            defer vals.deinit(self.gpa);
            for (self.interner.unionMembers(source_t)) |member| {
                if (self.objectPropertyTypeByName(member, key_name)) |t| {
                    vals.append(self.gpa, t) catch return null;
                }
            }
            if (vals.items.len == 0) return null;
            if (vals.items.len == 1) return vals.items[0];
            return self.interner.internUnion(vals.items) catch null;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(source_t)) |member| {
                if (self.objectPropertyTypeByName(member, key_name)) |t| return t;
            }
            return null;
        }
        if (!flags.is_object_type) return null;
        if (self.interner.objectMember(source_t, key_name)) |t| return t;
        const string_idx = self.interner.objectStringIndex(source_t);
        if (string_idx != types.Primitive.none) return string_idx;
        if (self.isNumericStringId(key_name)) {
            const number_idx = self.interner.objectNumberIndex(source_t);
            if (number_idx != types.Primitive.none) return number_idx;
        }
        return null;
    }

    fn propertyNameFromKeyNode(self: *Checker, key_node: NodeId) ?hir_mod.StringId {
        return switch (self.hir.kindOf(key_node)) {
            .identifier => hir_mod.identifierOf(self.hir, key_node).name,
            .literal_string => hir_mod.literalStringOf(self.hir, key_node).value,
            .literal_number => blk: {
                const span = self.hir.spanOf(key_node);
                const src = self.source orelse break :blk null;
                if (span.end > src.len or span.start >= span.end) break :blk null;
                break :blk self.string_interner.intern(src[span.start..span.end]) catch null;
            },
            else => null,
        };
    }

    fn propertyNameFromComputedKeyNode(self: *Checker, key_node: NodeId) CheckError!?hir_mod.StringId {
        const key_t = try self.checkExpression(key_node);
        if (try self.propertyNameFromLiteralType(key_t)) |name| return name;
        return self.propertyNameFromKeyNode(key_node);
    }

    fn propertyNameFromLiteralType(self: *Checker, t: TypeId) CheckError!?hir_mod.StringId {
        if (t == types.Primitive.true_lit) return self.string_interner.intern("true") catch return error.OutOfMemory;
        if (t == types.Primitive.false_lit) return self.string_interner.intern("false") catch return error.OutOfMemory;
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_literal) return null;
        switch (self.interner.literalOf(t)) {
            .string_lit => |sid| return sid,
            .number_lit => |bits| {
                const v: f64 = @bitCast(bits);
                var buf: [64]u8 = undefined;
                const text = if (v == @floor(v) and v >= -9007199254740991 and v <= 9007199254740991)
                    std.fmt.bufPrint(&buf, "{d}", .{@as(i64, @intFromFloat(v))}) catch return null
                else
                    std.fmt.bufPrint(&buf, "{d}", .{v}) catch return null;
                return self.string_interner.intern(text) catch return error.OutOfMemory;
            },
            else => return null,
        }
    }

    fn fixedTupleLength(self: *Checker, target: TypeId) ?u64 {
        if (target >= self.interner.pool.typeCount()) return null;
        if (!self.interner.pool.flagsOf(target).is_object_type) return null;
        const length_id = self.string_interner.intern("length") catch return null;
        const length_t = self.interner.objectMember(target, length_id) orelse return null;
        const flags = self.interner.pool.flagsOf(length_t);
        if (!flags.is_literal or !flags.is_number) return null;
        return switch (self.interner.literalOf(length_t)) {
            .number_lit => |bits| blk: {
                const v: f64 = @bitCast(bits);
                if (v < 0 or v != @floor(v)) break :blk null;
                break :blk @as(u64, @intFromFloat(v));
            },
            else => null,
        };
    }

    fn tupleElementType(self: *Checker, target: TypeId, index: usize) TypeId {
        if (target >= self.interner.pool.typeCount()) return types.Primitive.none;
        if (!self.interner.pool.flagsOf(target).is_object_type) return types.Primitive.none;
        var nbuf: [12]u8 = undefined;
        const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{index}) catch return types.Primitive.none;
        const name = self.string_interner.intern(name_str) catch return types.Primitive.none;
        if (self.interner.objectMember(target, name)) |t| return t;
        return self.interner.objectNumberIndex(target);
    }

    fn tupleFixedPrefixCount(self: *Checker, target: TypeId) usize {
        if (target >= self.interner.pool.typeCount()) return 0;
        if (!self.interner.pool.flagsOf(target).is_object_type) return 0;
        var count: usize = 0;
        while (true) : (count += 1) {
            var nbuf: [12]u8 = undefined;
            const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{count}) catch return count;
            const name = self.string_interner.intern(name_str) catch return count;
            if (self.interner.objectMember(target, name) == null) return count;
        }
    }

    fn reportTupleIndexOutOfBounds(self: *Checker, index_node: NodeId, index: u64, length: u64) CheckError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Tuple type of length '{d}' has no element at index '{d}'.",
            .{ length, index },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = index_node,
            .code = TsCodes.tuple_index_out_of_bounds,
            .message = msg,
        });
    }

    fn checkVarDecl(self: *Checker, node: NodeId) CheckError!void {
        const v = hir_mod.varDeclOf(self.hir, node);

        // Lower type annotation first (so we can check init against it).
        var declared_type: TypeId = types.Primitive.none;
        if (v.type_annotation != hir_mod.none_node_id) {
            declared_type = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
                try self.lowerValueTypeAnnotation(hir_mod.identifierOf(self.hir, v.name).name, v.type_annotation)
            else
                try self.lowererLowerWithTypeParams(v.type_annotation);
            self.hir.setType(node, declared_type);
        } else if (try self.jsDocTypeForVarDecl(node)) |jsdoc_t| {
            declared_type = jsdoc_t;
            self.hir.setType(node, declared_type);
        }

        // Type the initializer.
        var init_type: TypeId = if (v.is_ambient) types.Primitive.any else types.Primitive.undefined_t;
        if (v.init != hir_mod.none_node_id) {
            init_type = try self.checkExpression(v.init);
            if (declared_type == types.Primitive.none and
                init_type == types.Primitive.undefined_t and
                self.virtualSectionIsJsLike(node))
            {
                init_type = types.Primitive.any;
            }
            if (declared_type == types.Primitive.none and self.hir.kindOf(node) == .const_decl) {
                init_type = try self.constInitializerType(v.init, init_type);
            }
            if (declared_type == types.Primitive.none and
                self.sourceHasCheckJsDirective() and
                self.virtualSectionIsJsLike(node) and
                self.hir.kindOf(v.init) == .object_literal and
                v.name != hir_mod.none_node_id and
                self.hir.kindOf(v.name) == .identifier)
            {
                const id = hir_mod.identifierOf(self.hir, v.name);
                if (self.class_static_types.get(id.name)) |class_t| {
                    const ok = (self.objectLiteralAssignableToTarget(v.init, init_type, class_t) catch false) or
                        (self.engine.isAssignableTo(init_type, class_t) catch true);
                    if (!ok) {
                        try self.report(node, TsCodes.type_missing_properties, "Type is missing the following properties from target type.");
                    }
                }
            }
        }
        if (v.name != hir_mod.none_node_id and
            v.init == hir_mod.none_node_id and
            !v.is_ambient)
        {
            const nk = self.hir.kindOf(v.name);
            if (nk == .object_pattern or nk == .array_pattern) {
                try self.report(v.name, TsCodes.destructuring_decl_must_have_initializer, "A destructuring declaration must have an initializer.");
            }
        }
        if (v.name != hir_mod.none_node_id and
            self.hir.kindOf(v.name) == .array_pattern and
            v.init != hir_mod.none_node_id and
            ((self.hir.kindOf(v.init) == .object_literal and !self.objectLiteralHasSymbolIteratorMethod(v.init)) or
                !self.isIterableLikeType(init_type)) and
            !self.objectLiteralHasSymbolIteratorMethod(v.init))
        {
            try self.report(v.init, TsCodes.yield_star_not_iterable, "Type must have a '[Symbol.iterator]()' method that returns an iterator.");
        }
        if (self.strict_flags.strict_null_checks and v.name != hir_mod.none_node_id and v.init != hir_mod.none_node_id) {
            const nk = self.hir.kindOf(v.name);
            if (nk == .array_pattern and (self.typeIncludesNull(init_type) or self.typeIncludesUndefined(init_type))) {
                try self.report(v.init, TsCodes.yield_star_not_iterable, "Type must have a '[Symbol.iterator]()' method that returns an iterator.");
            } else if (nk == .object_pattern and (init_type == types.Primitive.void_t or self.typeIncludesUndefined(init_type))) {
                try self.report(v.init, TsCodes.object_possibly_undefined, "Object is possibly 'undefined'.");
            }
        }

        // If both are present, check assignability.
        const final_type: TypeId = if (declared_type != types.Primitive.none) declared_type else init_type;
        if (declared_type != types.Primitive.none and v.init != hir_mod.none_node_id) {
            // Special-case array-literal → tuple positional check.
            // The init's structural Array<T>-shape loses positional
            // info, so plain assignability would reject `[1, "a"]`
            // against `[number, string]`. Instead, when init is a
            // literal `[…]` and the target is a tuple-shaped object
            // type (positional "0", "1", … members), check each
            // element against the matching positional slot, then
            // fall back to the target's number-key indexer for any
            // extras (variadic tuple rest).
            const ok = blk: {
                if (v.type_annotation != hir_mod.none_node_id and
                    self.hir.kindOf(v.init) == .array_literal and
                    self.isTupleShapedTarget(declared_type))
                {
                    break :blk try self.checkArrayLiteralAgainstTuple(v.init, declared_type);
                }
                if (self.hir.kindOf(v.init) == .object_literal and
                    declared_type < self.interner.pool.typeCount() and
                    self.interner.pool.flagsOf(declared_type).is_union and
                    (self.objectLiteralAssignableToTarget(v.init, init_type, declared_type) catch false))
                {
                    break :blk true;
                }
                if (self.hir.kindOf(v.init) == .object_literal and
                    self.objectTargetHasLiteralMember(declared_type) and
                    (self.objectLiteralAssignableToTarget(v.init, init_type, declared_type) catch false))
                {
                    break :blk true;
                }
                if ((self.hir.kindOf(v.init) == .arrow_fn or self.hir.kindOf(v.init) == .fn_expr) and
                    try self.functionExpressionAssignableToTarget(v.init, declared_type))
                {
                    break :blk true;
                }
                if (try self.logicalExpressionAssignableToTarget(v.init, declared_type)) break :blk true;
                if (try self.awaitedExpressionAssignableToTarget(v.init, init_type, declared_type)) break :blk true;
                if (try self.literalExpressionAssignableToTarget(v.init, declared_type)) break :blk true;
                if (try self.templateExpressionAssignableToType(v.init, declared_type)) break :blk true;
                if (self.dynamicImportDefinitelyMismatchesTypeofNamespace(v.init, v.type_annotation)) break :blk false;
                break :blk self.engine.isAssignableTo(init_type, declared_type) catch return error.OutOfMemory;
            };
            if (!ok) {
                if (!self.callExpressionHasAnyArgument(v.init)) {
                    try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to declared type.");
                }
            } else {
                try self.checkRemappedMappedIndexedDecl(node, declared_type, v.init);
                try self.checkGenericValueMappedTargetDecl(node, v.type_annotation, init_type, v.init);
            }
            // TS2353: fresh-object-literal excess-property check.
            // Only fires when the init is a literal `{ … }` and the
            // declared type is a known object — otherwise extra
            // properties may legitimately come from elsewhere.
            try self.checkExcessProperties(v.init, declared_type);
            try self.checkArrayLiteralContextualElements(v.init, declared_type);
            // TS2375: `exactOptionalPropertyTypes` rejects literal
            // `undefined` flowing into an optional-but-not-undefined
            // property.
            try self.checkExactOptionalProperties(v.init, declared_type);
        } else if (declared_type == types.Primitive.none) {
            self.hir.setType(node, init_type);
        }
        // Propagate the declaration's type to the name identifier
        // so hover-on-identifier returns the right type.
        if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, final_type);
        if (v.name != hir_mod.none_node_id and
            v.init != hir_mod.none_node_id and
            self.hir.kindOf(v.name) == .identifier)
        {
            const id = hir_mod.identifierOf(self.hir, v.name);
            const flow_t = try self.flowTypeForAssignmentValue(v.init, init_type);
            const flow_ok = (try self.literalExpressionAssignableToTarget(v.init, final_type)) or
                (self.engine.isAssignableTo(flow_t, final_type) catch true);
            if (flow_t != types.Primitive.none and
                flow_t != types.Primitive.any and
                flow_t != types.Primitive.unknown and
                final_type != types.Primitive.any and
                final_type != types.Primitive.unknown and
                (try self.shouldRecordDeclaredVariableFlowNarrow(declared_type, flow_t, final_type)) and
                flow_ok)
            {
                try self.recordNarrow(id.name, flow_t);
            }
        }
        if (v.name != hir_mod.none_node_id) {
            const nk = self.hir.kindOf(v.name);
            if (nk == .object_pattern or nk == .array_pattern) {
                try self.checkPatternComputedBindingKeys(v.name);
                try self.checkBindingPatternDefaultReferences(v.name, .variable);
            }
            if (nk == .object_pattern and v.init != hir_mod.none_node_id) {
                try self.checkObjectBindingPatternAgainstType(v.name, final_type);
                if (self.hir.kindOf(v.init) == .object_literal) {
                    const expected_t = try self.objectBindingPatternExpectedType(v.name, false);
                    if (expected_t != types.Primitive.none) try self.checkExcessProperties(v.init, expected_t);
                }
            } else if (nk == .array_pattern and v.init != hir_mod.none_node_id) {
                try self.checkArrayBindingPatternAgainstType(v.name, final_type);
                try self.reportImplicitAnyNullishArrayBinding(v.name, v.init);
            }
        }
        try self.checkRepeatedVarDeclaration(node, final_type);

        // Aliased conditional narrowing: `let cond = obj.kind === "x"`.
        // Record `cond -> guard_expr_node` so a subsequent `if (cond)`
        // applies the original guard. Only fires for `const`/`let`-style
        // bindings whose init is a recognizably-narrowing expression.
        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier and
            v.init != hir_mod.none_node_id and isNarrowingGuard(self.hir, v.init))
        {
            const id = hir_mod.identifierOf(self.hir, v.name);
            try self.cond_aliases.put(self.gpa, id.name, v.init);
        }

        // TS7005: variable declared without an annotation and
        // without an initializer falls through to `any`.
        if (self.strict_flags.no_implicit_any and
            v.type_annotation == hir_mod.none_node_id and
            v.init == hir_mod.none_node_id)
        {
            const var_name: []const u8 = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
                self.string_interner.get(hir_mod.identifierOf(self.hir, v.name).name)
            else
                "<anonymous>";
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Variable '{s}' implicitly has an 'any' type.",
                .{var_name},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = node,
                .code = TsCodes.variable_implicitly_any,
                .message = msg,
            });
        }
    }

    fn shouldRecordDeclaredVariableFlowNarrow(
        self: *Checker,
        declared_type: TypeId,
        flow_t: TypeId,
        final_type: TypeId,
    ) CheckError!bool {
        if (declared_type == types.Primitive.none) return true;
        if (flow_t == final_type or (self.engine.isIdenticalTo(flow_t, final_type) catch false)) return true;
        if (flow_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(flow_t).is_literal) return false;
        return self.engine.isAssignableTo(flow_t, final_type) catch false;
    }

    fn virtualSectionIsJsLike(self: *Checker, node: NodeId) bool {
        const filename = self.virtualSectionFilenameForNode(node) orelse return false;
        return std.mem.endsWith(u8, filename, ".js") or
            std.mem.endsWith(u8, filename, ".jsx") or
            std.mem.endsWith(u8, filename, ".mjs") or
            std.mem.endsWith(u8, filename, ".cjs");
    }

    fn expressionNodeAssignableToTarget(self: *Checker, value_node: NodeId, value_t: TypeId, target_t: TypeId) CheckError!bool {
        if (try self.literalExpressionAssignableToTarget(value_node, target_t)) return true;
        if (try self.templateExpressionAssignableToType(value_node, target_t)) return true;
        if (self.hir.kindOf(value_node) == .object_literal and
            (self.objectLiteralAssignableToTarget(value_node, value_t, target_t) catch false))
        {
            return true;
        }
        return self.engine.isAssignableTo(value_t, target_t) catch return error.OutOfMemory;
    }

    fn awaitedExpressionAssignableToTarget(self: *Checker, value_node: NodeId, value_t: TypeId, target_t: TypeId) CheckError!bool {
        if (value_node == hir_mod.none_node_id or self.hir.kindOf(value_node) != .await_expr) return false;
        const a = hir_mod.awaitExprOf(self.hir, value_node);
        if (a.expr == hir_mod.none_node_id) return false;
        const operand_t = if (self.hir.typeOf(a.expr) != types.Primitive.none)
            self.hir.typeOf(a.expr)
        else
            try self.checkExpression(a.expr);
        if (self.promiseConstructorResolvedArgumentFromExpr(a.expr)) |resolved| {
            const resolved_t = if (self.hir.typeOf(resolved) != types.Primitive.none)
                self.hir.typeOf(resolved)
            else
                try self.checkExpression(resolved);
            if (try self.expressionNodeAssignableToTarget(resolved, resolved_t, target_t)) return true;
        }
        const awaited_t = self.unwrapPromise(operand_t);
        if (awaited_t != value_t and try self.expressionNodeAssignableToTarget(a.expr, awaited_t, target_t)) return true;
        return try self.expressionNodeAssignableToTarget(a.expr, value_t, target_t);
    }

    fn logicalExpressionAssignableToTarget(self: *Checker, value_node: NodeId, target_t: TypeId) CheckError!bool {
        if (value_node == hir_mod.none_node_id or self.hir.kindOf(value_node) != .logical_op) return false;
        const l = hir_mod.logicalOf(self.hir, value_node);
        if (l.op != .@"and" and l.op != .@"or") return false;
        const rhs_t = if (self.hir.typeOf(l.rhs) != types.Primitive.none)
            self.hir.typeOf(l.rhs)
        else
            try self.checkExpression(l.rhs);
        if (try self.expressionNodeAssignableToTarget(l.rhs, rhs_t, target_t)) return true;
        if ((self.hir.kindOf(l.rhs) == .arrow_fn or self.hir.kindOf(l.rhs) == .fn_expr) and
            try self.functionExpressionAssignableToTarget(l.rhs, target_t))
        {
            return true;
        }
        return false;
    }

    fn constInitializerType(self: *Checker, init_node: NodeId, fallback: TypeId) CheckError!TypeId {
        return switch (self.hir.kindOf(init_node)) {
            .literal_string, .literal_number, .literal_bool, .literal_bigint => self.literalizeForAsConst(init_node, fallback) catch return error.OutOfMemory,
            .as_expr, .type_assertion => blk: {
                const a = hir_mod.asExpressionOf(self.hir, init_node);
                if (a.type_node != hir_mod.none_node_id and self.isAsConstMarker(a.type_node)) {
                    break :blk self.literalizeForAsConst(a.expr, fallback) catch return error.OutOfMemory;
                }
                break :blk fallback;
            },
            .conditional => blk: {
                const c = hir_mod.conditionalOf(self.hir, init_node);
                const then_fallback = self.hir.typeOf(c.then_branch);
                const else_fallback = self.hir.typeOf(c.else_branch);
                const then_t = try self.constInitializerType(
                    c.then_branch,
                    if (then_fallback != types.Primitive.none) then_fallback else fallback,
                );
                const else_t = try self.constInitializerType(
                    c.else_branch,
                    if (else_fallback != types.Primitive.none) else_fallback else fallback,
                );
                if (then_t == else_t) break :blk then_t;
                break :blk self.interner.internUnion(&.{ then_t, else_t }) catch return error.OutOfMemory;
            },
            else => fallback,
        };
    }

    fn jsDocTypeForVarDecl(self: *Checker, node: NodeId) CheckError!?TypeId {
        if (!self.sourceHasCheckJsDirective()) return null;
        return try self.jsDocTypeForLeadingNode(node);
    }

    fn dynamicImportDefinitelyMismatchesTypeofNamespace(self: *Checker, init_node: NodeId, type_annotation: NodeId) bool {
        if (init_node == hir_mod.none_node_id or type_annotation == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(init_node) != .call_expr) return false;
        const c = hir_mod.callOf(self.hir, init_node);
        if (!self.isDynamicImportCallee(c.callee)) return false;
        const args = hir_mod.callArgs(self.hir, init_node);
        if (args.len == 0 or self.hir.kindOf(args[0]) != .literal_string) return false;
        const src = self.source orelse return false;
        const anno_span = self.hir.spanOf(type_annotation);
        if (anno_span.start >= anno_span.end or anno_span.end > src.len) return false;
        const anno_text = src[anno_span.start..anno_span.end];
        const typeof_pos = std.mem.indexOf(u8, anno_text, "typeof") orelse return false;
        var rest = std.mem.trim(u8, anno_text[typeof_pos + "typeof".len ..], " \t\r\n<>(),");
        var name_len: usize = 0;
        while (name_len < rest.len and isJsDocIdentChar(rest[name_len])) : (name_len += 1) {}
        if (name_len == 0) return false;
        rest = rest[0..name_len];
        const namespace_id = self.string_interner.intern(rest) catch return false;
        const expected_spec = self.namespaceImportSpecifierForLocal(namespace_id, init_node) orelse return false;
        const lit = hir_mod.literalStringOf(self.hir, args[0]);
        const actual_spec = self.string_interner.get(lit.value);
        return !moduleSpecifiersEquivalent(expected_spec, actual_spec);
    }

    fn namespaceImportSpecifierForLocal(self: *Checker, local_name: hir_mod.StringId, anchor: NodeId) ?[]const u8 {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const anchor_section = if (self.sourceHasVirtualFilenameSections()) self.virtualSectionStartForNode(anchor) else 0;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            if (self.sourceHasVirtualFilenameSections() and self.virtualSectionStartForNode(stmt) != anchor_section) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            if (imp.namespace_binding == hir_mod.none_node_id or self.hir.kindOf(imp.namespace_binding) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, imp.namespace_binding).name != local_name) continue;
            return self.string_interner.get(imp.module);
        }
        return null;
    }

    fn moduleSpecifiersEquivalent(a_raw: []const u8, b_raw: []const u8) bool {
        var a = a_raw;
        var b = b_raw;
        while (std.mem.startsWith(u8, a, "./")) a = a[2..];
        while (std.mem.startsWith(u8, b, "./")) b = b[2..];
        return std.mem.eql(u8, a, b);
    }

    fn jsDocTypeForLeadingNode(self: *Checker, node: NodeId) CheckError!?TypeId {
        const src = self.source orelse return null;
        if (!self.sourceHasCheckJsDirective()) return null;
        const span = self.hir.spanOf(node);
        const body = self.leadingJsDocBody(src, span.start) orelse return null;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return null;
        defer self.gpa.free(tags);

        for (tags) |tag| {
            if (tag.kind != .type_tag) continue;
            if (try self.jsDocTypeTextToType(src, tag.type_text)) |t| return t;
        }
        return null;
    }

    fn jsDocTypeTextToType(self: *Checker, src: []const u8, type_text: []const u8) CheckError!?TypeId {
        const trimmed = std.mem.trim(u8, type_text, " \t\r\n");
        if (trimmed.len == 0) return null;
        if (std.mem.indexOfScalar(u8, trimmed, '|')) |_| {
            var parts = std.mem.splitScalar(u8, trimmed, '|');
            var items: std.ArrayListUnmanaged(TypeId) = .empty;
            defer items.deinit(self.gpa);
            while (parts.next()) |part| {
                if (try self.jsDocTypeTextToType(src, part)) |member_t| {
                    try items.append(self.gpa, member_t);
                }
            }
            if (items.items.len == 0) return null;
            if (items.items.len == 1) return items.items[0];
            return self.interner.internUnion(items.items) catch return error.OutOfMemory;
        }
        if (try self.jsDocFunctionType(trimmed)) |sig| return sig;
        if (try self.jsDocPrimitiveType(trimmed)) |prim| return prim;
        if (try self.jsDocObjectSkeletonFromTypeText(trimmed)) |obj| return obj;
        const base = jsDocTypeBaseName(trimmed);
        if (base.len == 0) return null;
        if (try self.jsDocCallbackSignature(src, base)) |sig| return sig;
        if (try self.jsDocTypedefObjectSkeleton(src, base)) |t| return t;
        return null;
    }

    fn jsDocPrimitiveType(self: *Checker, type_text: []const u8) CheckError!?TypeId {
        _ = self;
        var t = std.mem.trim(u8, type_text, " \t\r\n");
        while (t.len >= 2 and t[0] == '(' and t[t.len - 1] == ')') {
            t = std.mem.trim(u8, t[1 .. t.len - 1], " \t\r\n");
        }
        if (std.mem.eql(u8, t, "string")) return types.Primitive.string_t;
        if (std.mem.eql(u8, t, "number")) return types.Primitive.number_t;
        if (std.mem.eql(u8, t, "boolean")) return types.Primitive.boolean_t;
        if (std.mem.eql(u8, t, "undefined")) return types.Primitive.undefined_t;
        if (std.mem.eql(u8, t, "null")) return types.Primitive.null_t;
        if (std.mem.eql(u8, t, "void")) return types.Primitive.void_t;
        if (std.mem.eql(u8, t, "any") or std.mem.eql(u8, t, "*")) return types.Primitive.any;
        if (std.mem.eql(u8, t, "Object") or std.mem.eql(u8, t, "object")) return types.Primitive.object_t;
        return null;
    }

    fn jsDocFunctionType(self: *Checker, type_text: []const u8) CheckError!?TypeId {
        const prefix = "function(";
        if (!std.mem.startsWith(u8, type_text, prefix)) return null;
        const close = jsDocMatchingParen(type_text, "function".len) orelse return null;
        var params: std.ArrayListUnmanaged(TypeId) = .empty;
        defer params.deinit(self.gpa);
        const params_text = type_text[prefix.len..close];
        var param_start: usize = 0;
        var depth: i32 = 0;
        var idx: usize = 0;
        while (idx <= params_text.len) : (idx += 1) {
            const at_end = idx == params_text.len;
            if (!at_end) {
                if (params_text[idx] == '(') depth += 1;
                if (params_text[idx] == ')') depth -= 1;
                if (params_text[idx] != ',' or depth != 0) continue;
            }
            const param = std.mem.trim(u8, params_text[param_start..idx], " \t\r\n");
            param_start = idx + 1;
            if (param.len == 0) continue;
            const param_t = (try self.jsDocFunctionType(param)) orelse
                (try self.jsDocPrimitiveType(param)) orelse
                types.Primitive.any;
            try params.append(self.gpa, param_t);
        }
        var ret_t: TypeId = types.Primitive.any;
        const rest = std.mem.trim(u8, type_text[close + 1 ..], " \t\r\n");
        if (std.mem.startsWith(u8, rest, ":")) {
            const ret_text = std.mem.trim(u8, rest[1..], " \t\r\n");
            ret_t = (try self.jsDocFunctionType(ret_text)) orelse
                (try self.jsDocPrimitiveType(ret_text)) orelse
                types.Primitive.any;
        }
        return self.interner.internSignature(params.items, ret_t, false) catch return error.OutOfMemory;
    }

    fn jsDocMatchingParen(text: []const u8, open_idx: usize) ?usize {
        if (open_idx >= text.len or text[open_idx] != '(') return null;
        var depth: i32 = 1;
        var i: usize = open_idx + 1;
        while (i < text.len) : (i += 1) {
            if (text[i] == '(') depth += 1;
            if (text[i] == ')') {
                depth -= 1;
                if (depth == 0) return i;
            }
        }
        return null;
    }

    fn jsDocCallbackSignature(self: *Checker, src: []const u8, wanted_name: []const u8) CheckError!?TypeId {
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "/**")) |start| {
            const body_start = start + 3;
            const end = std.mem.indexOfPos(u8, src, body_start, "*/") orelse return null;
            defer search_start = end + 2;
            const body = src[body_start..end];
            if (!jsDocBlockHasNamedTag(body, "@callback", wanted_name)) continue;
            const tags = ts_parser.jsdoc.parse(self.gpa, body) catch continue;
            defer self.gpa.free(tags);
            var params: std.ArrayListUnmanaged(TypeId) = .empty;
            defer params.deinit(self.gpa);
            var ret_t: TypeId = types.Primitive.any;
            for (tags) |tag| {
                if (tag.kind == .param_tag) {
                    const param_t = (try self.jsDocTypeTextToType(src, tag.type_text)) orelse types.Primitive.any;
                    try params.append(self.gpa, param_t);
                } else if (tag.kind == .returns_tag) {
                    ret_t = (try self.jsDocTypeTextToType(src, tag.type_text)) orelse types.Primitive.any;
                }
            }
            return self.interner.internSignature(params.items, ret_t, false) catch return error.OutOfMemory;
        }
        return null;
    }

    fn leadingJsDocBody(self: *Checker, src: []const u8, decl_start: u32) ?[]const u8 {
        _ = self;
        const limit = @min(@as(usize, decl_start), src.len);
        const before = src[0..limit];
        const end = std.mem.lastIndexOf(u8, before, "*/") orelse return null;
        const between = std.mem.trim(u8, before[end + 2 ..], " \t\r\n");
        if (between.len != 0) return null;
        const start = std.mem.lastIndexOf(u8, before[0..end], "/**") orelse return null;
        return before[start + 3 .. end];
    }

    fn jsDocTypeBaseName(type_text: []const u8) []const u8 {
        const trimmed = std.mem.trim(u8, type_text, " \t\r\n");
        var i: usize = 0;
        while (i < trimmed.len and isJsDocIdentChar(trimmed[i])) : (i += 1) {}
        return trimmed[0..i];
    }

    fn jsDocTypedefObjectSkeleton(
        self: *Checker,
        src: []const u8,
        wanted_name: []const u8,
    ) CheckError!?TypeId {
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "/**")) |start| {
            const body_start = start + 3;
            const end = std.mem.indexOfPos(u8, src, body_start, "*/") orelse return null;
            defer search_start = end + 2;
            const body = src[body_start..end];
            if (jsDocTypedefTypeText(body, wanted_name)) |type_text| {
                if (try self.jsDocObjectSkeletonFromTypeText(type_text)) |t| return t;
            }
            const tags = ts_parser.jsdoc.parse(self.gpa, body) catch continue;
            defer self.gpa.free(tags);
            for (tags) |tag| {
                if (tag.kind != .typedef_tag) continue;
                if (!std.mem.eql(u8, tag.name, wanted_name)) continue;
                if (try self.jsDocObjectSkeletonFromTypeText(tag.type_text)) |t| return t;
            }
        }
        return null;
    }

    fn jsDocTypedefTypeText(body: []const u8, wanted_name: []const u8) ?[]const u8 {
        const tag_pos = std.mem.indexOf(u8, body, "@typedef") orelse return null;
        const rest = body[tag_pos + "@typedef".len ..];
        const brace_pos = std.mem.indexOfScalar(u8, rest, '{') orelse return null;
        const type_len = jsDocBalancedBraceLen(rest[brace_pos..]);
        if (type_len == 0) return null;
        const trailing = std.mem.trim(u8, rest[brace_pos + type_len ..], " \t\r\n*");
        var name_end: usize = 0;
        while (name_end < trailing.len and isJsDocIdentChar(trailing[name_end])) : (name_end += 1) {}
        if (!std.mem.eql(u8, trailing[0..name_end], wanted_name)) return null;
        return rest[brace_pos + 1 .. brace_pos + type_len - 1];
    }

    fn jsDocBlockHasNamedTag(body: []const u8, tag: []const u8, wanted_name: []const u8) bool {
        var line_start: usize = 0;
        var i: usize = 0;
        while (i <= body.len) : (i += 1) {
            const at_end = i == body.len;
            if (!at_end and body[i] != '\n') continue;
            var line = std.mem.trim(u8, body[line_start..i], " \t\r");
            line_start = i + 1;
            if (line.len > 0 and line[0] == '*') line = std.mem.trim(u8, line[1..], " \t\r");
            if (!std.mem.startsWith(u8, line, tag)) continue;
            var rest = std.mem.trim(u8, line[tag.len..], " \t\r");
            if (rest.len > 0 and rest[0] == '{') {
                const type_len = jsDocBalancedBraceLen(rest);
                if (type_len == 0) continue;
                rest = std.mem.trim(u8, rest[type_len..], " \t\r");
            }
            var name_end: usize = 0;
            while (name_end < rest.len and isJsDocIdentChar(rest[name_end])) : (name_end += 1) {}
            if (name_end == wanted_name.len and std.mem.eql(u8, rest[0..name_end], wanted_name)) return true;
        }
        return false;
    }

    fn jsDocBalancedBraceLen(s: []const u8) usize {
        if (s.len == 0 or s[0] != '{') return 0;
        var depth: i32 = 1;
        var i: usize = 1;
        while (i < s.len) : (i += 1) {
            if (s[i] == '{') depth += 1;
            if (s[i] == '}') {
                depth -= 1;
                if (depth == 0) return i + 1;
            }
        }
        return 0;
    }

    fn jsDocObjectSkeletonFromTypeText(self: *Checker, type_text: []const u8) CheckError!?TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);

        if (self.jsDocStringIndexerFromTypeText(type_text)) |value_t| {
            return self.interner.internObjectTypeWithIndex(&.{}, value_t, types.Primitive.none) catch return error.OutOfMemory;
        }

        var lines = std.mem.splitScalar(u8, type_text, '\n');
        while (lines.next()) |raw_line| {
            var line = std.mem.trim(u8, raw_line, " \t\r");
            if (line.len > 0 and line[0] == '*') {
                line = std.mem.trim(u8, line[1..], " \t\r");
            }
            if (line.len == 0 or line[0] == '[' or line[0] == '}') continue;
            if (!isJsDocIdentStart(line[0])) continue;
            var name_end: usize = 1;
            while (name_end < line.len and isJsDocIdentChar(line[name_end])) : (name_end += 1) {}
            const after_name = std.mem.trim(u8, line[name_end..], " \t");
            if (after_name.len == 0) continue;
            if (std.mem.startsWith(u8, after_name, "?:")) continue;
            if (after_name[0] != ':') continue;
            const name = self.string_interner.intern(line[0..name_end]) catch return error.OutOfMemory;
            try members.append(self.gpa, .{
                .name = name,
                .type = types.Primitive.unknown,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            });
        }

        if (members.items.len == 0) return null;
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn jsDocStringIndexerFromTypeText(self: *Checker, type_text: []const u8) ?TypeId {
        _ = self;
        const compact = struct {
            fn containsNeedle(haystack: []const u8, needle: []const u8) bool {
                return std.mem.indexOf(u8, haystack, needle) != null;
            }
        }.containsNeedle;
        if (compact(type_text, "Object.<string,string>") or
            compact(type_text, "Object.<string, string>") or
            compact(type_text, "Object<string,string>") or
            compact(type_text, "Object<string, string>") or
            compact(type_text, "Record<string,string>") or
            compact(type_text, "Record<string, string>"))
        {
            return types.Primitive.string_t;
        }
        if (compact(type_text, "Object.<string,number>") or
            compact(type_text, "Object.<string, number>") or
            compact(type_text, "Object<string,number>") or
            compact(type_text, "Object<string, number>") or
            compact(type_text, "Record<string,number>") or
            compact(type_text, "Record<string, number>"))
        {
            return types.Primitive.number_t;
        }
        return null;
    }

    fn isJsDocIdentStart(c: u8) bool {
        return (c >= 'a' and c <= 'z') or (c >= 'A' and c <= 'Z') or c == '_' or c == '$';
    }

    fn isJsDocIdentChar(c: u8) bool {
        return isJsDocIdentStart(c) or (c >= '0' and c <= '9');
    }

    fn checkRepeatedVarDeclaration(self: *Checker, node: NodeId, final_type: TypeId) CheckError!void {
        if (self.hir.kindOf(node) != .var_decl) return;
        const v = hir_mod.varDeclOf(self.hir, node);
        if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) return;
        if (final_type == types.Primitive.none) return;
        const id = hir_mod.identifierOf(self.hir, v.name);
        const scope = self.hir.parentOf(node);
        if (scope == hir_mod.none_node_id) return;
        const key: VarDeclKey = .{
            .scope = scope,
            .name = id.name,
            .virtual_section_start = self.virtualSectionStartForNode(node),
        };
        const has_annotation = v.type_annotation != hir_mod.none_node_id;
        if (self.var_decl_types.get(key)) |prior| {
            const prior_explicit = self.var_decl_explicit.get(key) orelse false;
            if (final_type == types.Primitive.any and (!has_annotation or self.varDeclAnnotationIsQualifiedName(v.type_annotation))) return;
            if (prior == types.Primitive.any and !prior_explicit and has_annotation) return;
            if (!has_annotation and !prior_explicit and !self.typeIsEnumNominal(prior)) return;
            const compatible = blk: {
                if (self.isThisTypeParameter(prior) or self.isThisTypeParameter(final_type)) break :blk false;
                if (self.typeContainsUnknown(final_type)) break :blk true;
                if ((prior == types.Primitive.any or final_type == types.Primitive.any) and prior != final_type) break :blk false;
                if (self.engine.isIdenticalTo(prior, final_type) catch true) break :blk true;
                if (self.exactlyOneTypeIsUnion(prior, final_type)) break :blk false;
                break :blk (self.engine.isAssignableTo(prior, final_type) catch true) and
                    (self.engine.isAssignableTo(final_type, prior) catch true);
            };
            if (!compatible) {
                const name = self.string_interner.get(id.name);
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Subsequent variable declarations must have the same type. Variable '{s}' has a conflicting type.",
                    .{name},
                );
                try self.diagnostics.append(self.gpa, .{
                    .node = v.name,
                    .code = TsCodes.subsequent_var_type_mismatch,
                    .message = msg,
                });
            }
            return;
        }
        if (!has_annotation and
            final_type != types.Primitive.unknown and
            final_type != types.Primitive.any and
            !self.isThisTypeParameter(final_type) and
            !self.typeIsEnumNominal(final_type)) return;
        try self.var_decl_types.put(self.gpa, key, final_type);
        try self.var_decl_explicit.put(self.gpa, key, has_annotation);
    }

    fn varDeclAnnotationIsQualifiedName(self: *Checker, type_annotation: NodeId) bool {
        if (type_annotation == hir_mod.none_node_id or self.hir.kindOf(type_annotation) != .type_ref) return false;
        return hir_mod.typeRefOf(self.hir, type_annotation).qualifier_len != 0;
    }

    fn checkRepeatedObjectRestVarBinding(
        self: *Checker,
        pattern_node: NodeId,
        name_node: NodeId,
        name: hir_mod.StringId,
        final_type: TypeId,
    ) CheckError!void {
        const decl = self.hir.parentOf(pattern_node);
        if (decl == hir_mod.none_node_id or self.hir.kindOf(decl) != .var_decl) return;
        const scope = self.hir.parentOf(decl);
        if (scope == hir_mod.none_node_id) return;
        const prior = self.previousVarDeclTypeInScope(scope, decl, name) orelse return;
        if (self.repeatedVarTypesCompatible(prior, final_type)) return;
        const name_text = self.string_interner.get(name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Subsequent variable declarations must have the same type. Variable '{s}' has a conflicting type.",
            .{name_text},
        );
        try self.diagnostics.append(self.gpa, .{
            .node = name_node,
            .code = TsCodes.subsequent_var_type_mismatch,
            .message = msg,
        });
    }

    fn previousVarDeclTypeInScope(self: *Checker, scope: NodeId, before_decl: NodeId, name: hir_mod.StringId) ?TypeId {
        const stmts: []const NodeId = switch (self.hir.kindOf(scope)) {
            .block_stmt => hir_mod.blockStmts(self.hir, scope),
            .namespace_decl => hir_mod.namespaceBody(self.hir, scope),
            else => return null,
        };
        for (stmts) |stmt| {
            if (stmt == before_decl) return null;
            const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
            if (decl == hir_mod.none_node_id) continue;
            const dk = self.hir.kindOf(decl);
            if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, decl);
            if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, v.name);
            if (id.name != name) continue;
            const t = self.hir.typeOf(decl);
            if (t != types.Primitive.none) return t;
        }
        return null;
    }

    fn repeatedVarTypesCompatible(self: *Checker, prior: TypeId, final_type: TypeId) bool {
        if (self.isThisTypeParameter(prior) or self.isThisTypeParameter(final_type)) return false;
        if (self.typeContainsUnknown(final_type)) return true;
        if ((prior == types.Primitive.any or final_type == types.Primitive.any) and prior != final_type) return false;
        if (self.engine.isIdenticalTo(prior, final_type) catch true) return true;
        if (self.exactlyOneTypeIsUnion(prior, final_type)) return false;
        return (self.engine.isAssignableTo(prior, final_type) catch true) and
            (self.engine.isAssignableTo(final_type, prior) catch true);
    }

    fn exactlyOneTypeIsUnion(self: *Checker, a: TypeId, b: TypeId) bool {
        return self.typeIsUnion(a) != self.typeIsUnion(b);
    }

    fn typeIsUnion(self: *Checker, t: TypeId) bool {
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return false;
        return self.interner.pool.flagsOf(t).is_union;
    }

    fn typeIsEnumNominal(self: *Checker, t: TypeId) bool {
        return self.enumNameFromNominal(t) != null;
    }

    fn enumNameFromNominal(self: *Checker, t: TypeId) ?hir_mod.StringId {
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_intersection) return null;
        if (flags.is_union) return null;
        const payload_idx = self.interner.pool.payloadOf(t);
        if (payload_idx >= self.interner.pool.intersection_payloads.items.len) return null;
        var saw_number = false;
        var enum_name: ?hir_mod.StringId = null;
        for (self.interner.intersectionMembers(t)) |member| {
            if (member == types.Primitive.number_t) {
                saw_number = true;
                continue;
            }
            if (member >= self.interner.pool.typeCount()) continue;
            if (!self.interner.pool.flagsOf(member).is_object_type) continue;
            for (self.interner.objectMembers(member)) |om| {
                const name = self.string_interner.getOptional(om.name) orelse continue;
                if (std.mem.startsWith(u8, name, "__enum:")) {
                    enum_name = self.string_interner.intern(name["__enum:".len..]) catch return null;
                    break;
                }
            }
        }
        return if (saw_number) enum_name else null;
    }

    fn appendNumericEnumRecordMembers(
        self: *Checker,
        enum_name: hir_mod.StringId,
        value_t: TypeId,
        out: *std.ArrayListUnmanaged(types.ObjectMember),
    ) CheckError!void {
        var it = self.enum_member_values.iterator();
        while (it.next()) |entry| {
            if (entry.key_ptr.obj_name != enum_name) continue;
            const value = entry.value_ptr.*;
            const key_text = if (value == @floor(value))
                try std.fmt.allocPrint(self.gpa, "{d}", .{@as(i64, @intFromFloat(value))})
            else
                try std.fmt.allocPrint(self.gpa, "{d}", .{value});
            defer self.gpa.free(key_text);
            const key_name = self.string_interner.intern(key_text) catch return error.OutOfMemory;
            try out.append(self.gpa, .{
                .name = key_name,
                .type = value_t,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            });
        }
    }

    fn isThisTypeParameter(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_type_parameter) return false;
        const payload_idx = self.interner.pool.payloadOf(t);
        if (payload_idx >= self.interner.pool.type_parameter_payloads.items.len) return false;
        const tp = self.interner.pool.type_parameter_payloads.items[payload_idx];
        const name = tp.name;
        return std.mem.eql(u8, self.string_interner.get(name), "this");
    }

    fn freshThisTypeParameter(self: *Checker, name: hir_mod.StringId) CheckError!TypeId {
        return self.interner.internFreshTypeParameterWithFlags(
            name,
            types.Primitive.unknown,
            types.Primitive.none,
            .bivariant,
            false,
        ) catch return error.OutOfMemory;
    }

    fn typeContainsUnknown(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.unknown) return true;
        if (t < types.Primitive.first_dynamic) return false;
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| if (self.typeContainsUnknown(m)) return true;
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |m| if (self.typeContainsUnknown(m)) return true;
            return false;
        }
        if (flags.is_object_type) {
            for (self.interner.objectMembers(t)) |m| if (self.typeContainsUnknown(m.type)) return true;
            const string_idx = self.interner.objectStringIndex(t);
            if (string_idx != types.Primitive.none and self.typeContainsUnknown(string_idx)) return true;
            const number_idx = self.interner.objectNumberIndex(t);
            if (number_idx != types.Primitive.none and self.typeContainsUnknown(number_idx)) return true;
            return false;
        }
        if (flags.is_signature) {
            for (self.interner.signatureParams(t)) |p| if (self.typeContainsUnknown(p)) return true;
            if (self.interner.signatureReturn(t)) |r| if (self.typeContainsUnknown(r)) return true;
            return false;
        }
        if (flags.is_tuple) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.tuple_payloads.items.len) return false;
            const payload = self.interner.pool.tuple_payloads.items[payload_idx];
            const elems = self.interner.pool.tuple_element_pool.items[payload.elements_start .. payload.elements_start + payload.elements_len];
            for (elems) |elem| if (self.typeContainsUnknown(elem.type)) return true;
            return false;
        }
        return false;
    }

    fn isThisParameter(self: *Checker, param_node: NodeId) bool {
        if (self.hir.kindOf(param_node) != .parameter) return false;
        const p = hir_mod.parameterOf(self.hir, param_node);
        if (p.name == hir_mod.none_node_id or self.hir.kindOf(p.name) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, p.name);
        return std.mem.eql(u8, self.string_interner.get(id.name), "this");
    }

    fn broadObjectPrototypeMember(self: *Checker, name: hir_mod.StringId) CheckError!?TypeId {
        const text = self.string_interner.get(name);
        if (std.mem.eql(u8, text, "toString")) {
            return self.interner.internSignature(&.{}, types.Primitive.string_t, false) catch return error.OutOfMemory;
        }
        if (std.mem.eql(u8, text, "valueOf")) {
            return self.interner.internSignature(&.{}, types.Primitive.object_t, false) catch return error.OutOfMemory;
        }
        if (std.mem.eql(u8, text, "hasOwnProperty") or
            std.mem.eql(u8, text, "propertyIsEnumerable"))
        {
            return self.interner.internSignature(&.{types.Primitive.string_t}, types.Primitive.boolean_t, false) catch return error.OutOfMemory;
        }
        return null;
    }

    fn declaredInterfaceMember(self: *Checker, interface_name: []const u8, member_name: hir_mod.StringId) CheckError!?TypeId {
        const id = self.string_interner.intern(interface_name) catch return error.OutOfMemory;
        const iface_t = self.type_names.get(id) orelse return null;
        return self.lookupObjectMember(iface_t, member_name);
    }

    fn primitivePrototypeMember(self: *Checker, receiver_t: TypeId, member_name: hir_mod.StringId) CheckError!?TypeId {
        if (self.typeHasStringPrimitivePart(receiver_t)) {
            if (try self.declaredInterfaceMember("String", member_name)) |t| return t;
            if (lib.stringProto(&self.lib_cache, self.interner, self.string_interner)) |proto| {
                if (self.interner.objectMember(proto, member_name)) |t| return t;
            } else |_| {}
            if (try self.broadObjectPrototypeMember(member_name)) |t| return t;
            return null;
        }
        if (self.typeHasNumericPrimitivePart(receiver_t)) {
            if (try self.declaredInterfaceMember("Number", member_name)) |t| return t;
            if (lib.numberProto(&self.lib_cache, self.interner, self.string_interner)) |proto| {
                if (self.interner.objectMember(proto, member_name)) |t| return t;
            } else |_| {}
            if (try self.broadObjectPrototypeMember(member_name)) |t| return t;
            return null;
        }
        return null;
    }

    fn lookupObjectMember(self: *Checker, obj_t: TypeId, name: hir_mod.StringId) CheckError!?TypeId {
        const flags = self.interner.pool.flagsOf(obj_t);
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(obj_t) orelse return null;
            if (constraint == obj_t) return null;
            return try self.lookupObjectMember(constraint, name);
        }
        if (flags.is_union) {
            const members = self.interner.unionMembers(obj_t);
            var resolved: std.ArrayListUnmanaged(TypeId) = .empty;
            defer resolved.deinit(self.gpa);
            for (members) |member_t| {
                if (self.interner.objectMember(member_t, name)) |t| {
                    try resolved.append(self.gpa, t);
                } else {
                    return null;
                }
            }
            if (resolved.items.len == 0) return null;
            return self.interner.internUnion(resolved.items) catch return error.OutOfMemory;
        }
        if (flags.is_intersection) {
            const members = self.interner.intersectionMembers(obj_t);
            var resolved: std.ArrayListUnmanaged(TypeId) = .empty;
            defer resolved.deinit(self.gpa);
            for (members) |member_t| {
                if (try self.lookupObjectMember(member_t, name)) |t| {
                    try resolved.append(self.gpa, t);
                }
            }
            if (resolved.items.len == 0) return null;
            if (resolved.items.len == 1) return resolved.items[0];
            return self.interner.internIntersection(resolved.items) catch return error.OutOfMemory;
        }
        return self.interner.objectMember(obj_t, name);
    }

    fn objectHasCallOrConstructSignature(self: *Checker, obj_t: TypeId) bool {
        if (obj_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(obj_t);
        if (flags.is_signature) return true;
        if (!flags.is_object_type) return false;
        const call_id = self.string_interner.intern("__call") catch return false;
        const construct_id = self.string_interner.intern("__construct") catch return false;
        for (self.interner.objectMembers(obj_t)) |member| {
            if (member.name != call_id and member.name != construct_id) continue;
            if (self.interner.isSignature(member.type)) return true;
        }
        return false;
    }

    fn functionInterfaceMemberForCallableObject(self: *Checker, obj_t: TypeId, name: hir_mod.StringId) CheckError!?TypeId {
        if (!self.objectHasCallOrConstructSignature(obj_t)) return null;
        const function_name = self.string_interner.intern("Function") catch return error.OutOfMemory;
        const function_t = self.type_names.get(function_name) orelse return null;
        if (try self.lookupObjectMember(function_t, name)) |member_t| return member_t;
        const string_idx = self.interner.objectStringIndex(function_t);
        return if (string_idx != types.Primitive.none) string_idx else null;
    }

    fn functionInterfaceStringIndexForCallableObject(self: *Checker, obj_t: TypeId) CheckError!?TypeId {
        if (!self.objectHasCallOrConstructSignature(obj_t)) return null;
        const function_name = self.string_interner.intern("Function") catch return error.OutOfMemory;
        const function_t = self.type_names.get(function_name) orelse return null;
        const string_idx = self.interner.objectStringIndex(function_t);
        return if (string_idx != types.Primitive.none) string_idx else null;
    }

    fn typeOfDottedValueReference(self: *Checker, raw: []const u8, at_node: NodeId) CheckError!?TypeId {
        var parts = std.mem.splitScalar(u8, raw, '.');
        const root_raw = parts.next() orelse return null;
        if (root_raw.len == 0) return null;
        const root_name = self.string_interner.intern(root_raw) catch return error.OutOfMemory;
        var current = self.lookupNarrow(root_name) orelse (try self.typeOfVisibleNameNoDiag(at_node, root_name)) orelse {
            if (std.mem.eql(u8, root_raw, "this")) return types.Primitive.any;
            return null;
        };
        var root_for_narrow: ?hir_mod.StringId = root_name;
        while (parts.next()) |part| {
            if (part.len == 0) return null;
            const prop_name = self.string_interner.intern(part) catch return error.OutOfMemory;
            if (root_for_narrow) |obj_name| {
                if (std.mem.eql(u8, part, "prototype")) {
                    if (self.class_instance_types.get(obj_name)) |instance_t| {
                        current = instance_t;
                        root_for_narrow = null;
                        continue;
                    }
                }
            }
            if (root_for_narrow) |obj_name| {
                const key: MemberKey = .{ .obj_name = obj_name, .prop_name = prop_name };
                if (self.lookupMemberNarrow(key)) |nt| {
                    current = nt;
                    root_for_narrow = null;
                    continue;
                }
            }
            current = (try self.lookupObjectMember(current, prop_name)) orelse return null;
            root_for_narrow = null;
        }
        return current;
    }

    fn typeOfVisibleNameNoDiag(self: *Checker, at_node: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        if (self.lookupNarrow(name)) |t| return t;
        var cur: hir_mod.NodeId = self.hir.parentOf(at_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                for (hir_mod.fnParams(self.hir, cur)) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.name == hir_mod.none_node_id or self.hir.kindOf(pp.name) != .identifier) continue;
                    const pid = hir_mod.identifierOf(self.hir, pp.name);
                    if (pid.name == name and self.hir.typeOf(p) != types.Primitive.none) return self.hir.typeOf(p);
                }
            }
            if (k == .block_stmt or k == .namespace_decl) {
                const stmts = if (k == .block_stmt)
                    hir_mod.blockStmts(self.hir, cur)
                else
                    hir_mod.namespaceBody(self.hir, cur);
                for (stmts) |s| {
                    const sk = self.hir.kindOf(s);
                    if (sk == .var_decl or sk == .let_decl or sk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, s);
                        if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
                        const vid = hir_mod.identifierOf(self.hir, v.name);
                        if (vid.name != name) continue;
                        const existing = self.hir.typeOf(s);
                        if (existing != types.Primitive.none) return existing;
                        if (v.type_annotation != hir_mod.none_node_id) {
                            const declared_t = self.lowerValueTypeAnnotation(vid.name, v.type_annotation) catch types.Primitive.any;
                            self.hir.setType(s, declared_t);
                            self.hir.setType(v.name, declared_t);
                            return declared_t;
                        }
                    } else if (sk == .fn_decl or sk == .fn_expr) {
                        const fp = hir_mod.fnDeclOf(self.hir, s);
                        if (fp.name == hir_mod.none_node_id or self.hir.kindOf(fp.name) != .identifier) continue;
                        const fid = hir_mod.identifierOf(self.hir, fp.name);
                        if (fid.name == name and self.hir.typeOf(s) != types.Primitive.none) return self.hir.typeOf(s);
                    } else if (sk == .class_decl or sk == .class_expr) {
                        const cp = hir_mod.classOf(self.hir, s);
                        if (cp.name == hir_mod.none_node_id or self.hir.kindOf(cp.name) != .identifier) continue;
                        const cid = hir_mod.identifierOf(self.hir, cp.name);
                        if (cid.name == name) {
                            if (self.class_static_types.get(name)) |static_t| return static_t;
                            if (self.hir.typeOf(s) != types.Primitive.none) return self.hir.typeOf(s);
                        }
                    } else if (sk == .import_decl) {
                        if (self.importDeclBindsLocal(s, name)) {
                            if (self.moduleNamespaceTypeForLocalImport(name, at_node) catch null) |ns_t| return ns_t;
                            return types.Primitive.any;
                        }
                    }
                }
            }
        }
        if (self.module) |module| {
            if (module.root.lookup(name)) |sym| {
                if (sym.decls.items.len > 0) {
                    const decl = sym.decls.items[0];
                    if (self.hir.typeOf(decl) != types.Primitive.none) return self.hir.typeOf(decl);
                }
            }
        }
        return null;
    }

    fn predicateTargetIsBroadObject(self: *Checker, target: TypeId) bool {
        _ = self;
        return target == types.Primitive.object_t;
    }

    fn predicateTargetIsFunctionObject(self: *Checker, target: TypeId) bool {
        const function_t = self.lowerBuiltinObjectType("Function") orelse return false;
        return target == function_t;
    }

    fn typeMatchesPredicateTarget(self: *Checker, member: TypeId, target: TypeId) bool {
        if (member == target) return true;
        if (target < self.interner.pool.typeCount() and self.interner.pool.flagsOf(target).is_union) {
            for (self.interner.unionMembers(target)) |target_member| {
                if (self.typeMatchesPredicateTarget(member, target_member)) return true;
            }
            return false;
        }
        if (self.predicateTargetIsBroadObject(target) and self.typeIsObjectLikePredicateMember(member)) return true;
        if (self.predicateTargetIsFunctionObject(target) and self.objectHasCallOrConstructSignature(member)) return true;
        if (self.typeParameterConstraintAssignableTo(member, target)) return true;
        return self.engine.isAssignableTo(member, target) catch false;
    }

    fn typeIsObjectLikePredicateMember(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return false;
        const flags = self.interner.pool.flagsOf(t);
        return flags.is_object or
            flags.is_object_type or
            flags.is_signature or
            flags.is_tuple or
            flags.is_intersection;
    }

    fn objectOrNullType(self: *Checker) TypeId {
        return self.interner.internUnion(&.{ types.Primitive.object_t, types.Primitive.null_t }) catch types.Primitive.object_t;
    }

    fn narrowTypeByPredicate(self: *Checker, current: TypeId, target: TypeId) CheckError!TypeId {
        if (current == target or self.typeIsAnyLike(current)) return target;
        if (self.typeIsAnyLike(target)) return current;
        const current_flags = self.interner.pool.flagsOf(current);
        if (current_flags.is_union) {
            var kept: std.ArrayListUnmanaged(TypeId) = .empty;
            defer kept.deinit(self.gpa);
            for (self.interner.unionMembers(current)) |member| {
                const member_flags = self.interner.pool.flagsOf(member);
                if ((member_flags.is_null and !self.typeIncludesNull(target)) or
                    (member_flags.is_undefined and !self.typeIncludesUndefined(target)))
                {
                    continue;
                }
                const member_to_target = self.typeMatchesPredicateTarget(member, target);
                const target_to_member = target == member or (self.engine.isAssignableTo(target, member) catch false);
                if (member_to_target) {
                    try kept.append(self.gpa, member);
                } else if (target_to_member) {
                    if (self.predicateTargetIsFunctionObject(target) and !self.objectHasCallOrConstructSignature(member)) continue;
                    try kept.append(self.gpa, target);
                }
            }
            if (kept.items.len == 0) {
                return self.interner.internIntersection(&.{ current, target }) catch return error.OutOfMemory;
            }
            if (kept.items.len == 1) return kept.items[0];
            return self.interner.internUnion(kept.items) catch return error.OutOfMemory;
        }
        const current_to_target = self.engine.isAssignableTo(current, target) catch false;
        const target_to_current = self.engine.isAssignableTo(target, current) catch false;
        if (current_to_target and !target_to_current) return current;
        if (target_to_current) return target;
        return self.interner.internIntersection(&.{ current, target }) catch return error.OutOfMemory;
    }

    fn subtractTypeByPredicate(self: *Checker, current: TypeId, target: TypeId) CheckError!TypeId {
        if (current == target) return types.Primitive.never;
        const current_flags = self.interner.pool.flagsOf(current);
        if (current_flags.is_union) {
            var kept: std.ArrayListUnmanaged(TypeId) = .empty;
            defer kept.deinit(self.gpa);
            for (self.interner.unionMembers(current)) |member| {
                const remove = self.typeMatchesPredicateTarget(member, target);
                if (!remove) try kept.append(self.gpa, member);
            }
            if (kept.items.len == 0) return types.Primitive.never;
            if (kept.items.len == 1) return kept.items[0];
            return self.interner.internUnion(kept.items) catch return error.OutOfMemory;
        }
        return current;
    }

    fn propertyAllowsDelete(self: *Checker, obj_t: TypeId, name: hir_mod.StringId) bool {
        if (self.typeIsAnyLike(obj_t)) return true;
        const non_null_obj = self.subtractNullUndefined(obj_t) catch obj_t;
        const flags = self.interner.pool.flagsOf(non_null_obj);
        if (flags.is_union) {
            for (self.interner.unionMembers(non_null_obj)) |member_t| {
                if (!self.propertyAllowsDelete(member_t, name)) return false;
            }
            return true;
        }
        if (!flags.is_object_type) return true;
        const info = self.interner.objectMemberInfo(non_null_obj, name) orelse return true;
        return info.is_optional or self.typeIncludesUndefined(info.type);
    }

    fn deleteOperandAllowed(self: *Checker, operand: NodeId) bool {
        return switch (self.hir.kindOf(operand)) {
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, operand);
                const obj_t = self.hir.typeOf(m.object);
                if (obj_t == types.Primitive.none) break :blk true;
                break :blk self.propertyAllowsDelete(obj_t, m.name);
            },
            .element_access => blk: {
                const e = hir_mod.elementOf(self.hir, operand);
                if (self.hir.kindOf(e.index) != .literal_string) break :blk true;
                const obj_t = self.hir.typeOf(e.object);
                if (obj_t == types.Primitive.none) break :blk true;
                const key = hir_mod.literalStringOf(self.hir, e.index).value;
                break :blk self.propertyAllowsDelete(obj_t, key);
            },
            else => true,
        };
    }

    fn arrayElementType(self: *Checker, obj_t: TypeId) CheckError!TypeId {
        const flags = self.interner.pool.flagsOf(obj_t);
        if (flags.is_union) {
            const members = self.interner.unionMembers(obj_t);
            var elems: std.ArrayListUnmanaged(TypeId) = .empty;
            defer elems.deinit(self.gpa);
            for (members) |member_t| {
                const elem_t = self.interner.objectNumberIndex(member_t);
                if (elem_t == types.Primitive.none) return types.Primitive.none;
                try elems.append(self.gpa, elem_t);
            }
            if (elems.items.len == 0) return types.Primitive.none;
            return self.interner.internUnion(elems.items) catch return error.OutOfMemory;
        }
        return self.interner.objectNumberIndex(obj_t);
    }

    fn signaturePrototypeMember(self: *Checker, sig: TypeId, name: hir_mod.StringId) CheckError!?TypeId {
        if (!self.interner.isSignature(sig)) return null;
        const name_str = self.string_interner.get(name);
        if (!std.mem.eql(u8, name_str, "call") and
            !std.mem.eql(u8, name_str, "bind") and
            !std.mem.eql(u8, name_str, "apply"))
        {
            return null;
        }

        const params = self.interner.signatureParams(sig);
        const ret = self.interner.signatureReturn(sig) orelse types.Primitive.any;

        if (std.mem.eql(u8, name_str, "call")) {
            var call_params: std.ArrayListUnmanaged(TypeId) = .empty;
            defer call_params.deinit(self.gpa);
            try call_params.append(self.gpa, types.Primitive.any);
            try call_params.appendSlice(self.gpa, params);
            return try self.interner.internSignature(call_params.items, ret, false);
        }

        if (std.mem.eql(u8, name_str, "bind")) {
            var bind_params: std.ArrayListUnmanaged(TypeId) = .empty;
            defer bind_params.deinit(self.gpa);
            try bind_params.append(self.gpa, types.Primitive.any);
            try bind_params.appendSlice(self.gpa, params);
            const bind_sig = try self.interner.internSignature(bind_params.items, types.Primitive.any, false);
            var omittable: std.ArrayListUnmanaged(bool) = .empty;
            defer omittable.deinit(self.gpa);
            try omittable.append(self.gpa, false);
            var i: usize = 0;
            while (i < params.len) : (i += 1) try omittable.append(self.gpa, true);
            try self.recordSignatureMinArgs(bind_sig, omittable.items);
            return bind_sig;
        }

        var apply_params: [2]TypeId = undefined;
        apply_params[0] = types.Primitive.any;
        const rest_tuple = if (params.len == 0)
            self.interner.internArrayType(self.string_interner, types.Primitive.any) catch types.Primitive.any
        else blk: {
            const members = try self.gpa.alloc(TypeId, params.len);
            defer self.gpa.free(members);
            @memcpy(members, params);
            const union_t = self.interner.internUnion(members) catch types.Primitive.any;
            break :blk self.interner.internArrayType(self.string_interner, union_t) catch types.Primitive.any;
        };
        apply_params[1] = rest_tuple;
        return try self.interner.internSignature(&apply_params, ret, false);
    }

    fn lookupDeclaredArrayMember(self: *Checker, elem_t: TypeId, name: hir_mod.StringId) CheckError!?TypeId {
        const array_names = [_][]const u8{ "Array", "ReadonlyArray" };
        for (array_names) |array_name| {
            const array_id = self.string_interner.intern(array_name) catch return error.OutOfMemory;
            const info = self.generic_aliases.get(array_id) orelse continue;
            var inst_t = info.body;
            if (info.params.len > 0) {
                var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
                defer subs.deinit(self.gpa);
                try subs.put(self.gpa, info.params[0], elem_t);
                var i: usize = 1;
                while (i < info.params.len) : (i += 1) {
                    const p = info.params[i];
                    if (!self.interner.pool.flagsOf(p).is_type_parameter) continue;
                    const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(p)];
                    if (tp.default != types.Primitive.none) try subs.put(self.gpa, p, tp.default);
                }
                inst_t = try self.substituteType(info.body, &subs);
            }
            if (self.interner.objectMember(inst_t, name)) |member_t| return member_t;
        }
        return null;
    }

    fn constructorPrototypeAccess(self: *Checker, obj_name: hir_mod.StringId, prop_name: hir_mod.StringId) CheckError!?TypeId {
        if (!std.mem.eql(u8, self.string_interner.get(prop_name), "prototype")) return null;
        var has_runtime_prototype = self.class_instance_types.contains(obj_name);
        if (!has_runtime_prototype) {
            if (self.module) |module| {
                if (module.root.lookup(obj_name)) |sym| {
                    has_runtime_prototype = sym.flags.is_function or sym.flags.is_class;
                }
            }
        }
        if (!has_runtime_prototype) return null;
        return self.interner.internObjectTypeWithIndex(&.{}, types.Primitive.any, types.Primitive.none) catch return error.OutOfMemory;
    }

    /// Type an expression. Returns its TypeId and also records it
    /// in the HIR's types column.
    pub fn checkExpression(self: *Checker, node: NodeId) CheckError!TypeId {
        const t: TypeId = switch (self.hir.kindOf(node)) {
            .literal_string => types.Primitive.string_t,
            .template_literal => try self.checkTemplateLiteralExpression(node),
            .literal_number => types.Primitive.number_t,
            .literal_bigint => types.Primitive.bigint_t,
            .literal_bool => types.Primitive.boolean_t,
            .literal_null => types.Primitive.null_t,
            .literal_undefined => types.Primitive.undefined_t,
            .literal_regex => types.Primitive.object_t,
            .identifier => self.typeOfIdentifier(node),
            .this_expr => try self.checkThisExpression(node),
            .spread => blk: {
                const sp = hir_mod.spreadOf(self.hir, node);
                break :blk try self.checkExpression(sp.expression);
            },
            .binary_op => try self.checkBinop(node),
            .unary_op => try self.checkUnary(node),
            .logical_op => try self.checkLogical(node),
            .conditional => try self.checkConditional(node),
            .assignment => blk: {
                const a = hir_mod.assignmentOf(self.hir, node);
                const target_kind = self.hir.kindOf(a.target);
                const target_t = if (target_kind == .identifier)
                    self.typeOfIdentifierDeclared(a.target)
                else if (target_kind == .array_literal or target_kind == .object_literal)
                    types.Primitive.none
                else
                    try self.checkExpression(a.target);
                // Reassignment clears any prior conditional alias for
                // the variable: `let cond = isString(x); cond = false;
                // if (cond) ...` — the second branch shouldn't
                // narrow `x` because `cond` is no longer the original
                // guard expression.
                if (self.hir.kindOf(a.target) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, a.target);
                    _ = self.cond_aliases.remove(id.name);
                    try self.removeCondAliasesReferencing(id.name);
                    if (std.mem.eql(u8, self.string_interner.get(id.name), "undefined")) {
                        try self.report(a.target, TsCodes.cannot_assign_undefined, "Cannot assign to 'undefined' because it is not a variable.");
                    }
                    // TS2588: `const x = 1; x = 2;` — assigning to
                    // a const-bound identifier is a hard error.
                    if (self.identifierResolvesToConst(a.target)) {
                        const name_str = self.string_interner.get(id.name);
                        const msg = try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Cannot assign to '{s}' because it is a constant.",
                            .{name_str},
                        );
                        try self.diagnostics.append(self.gpa, .{
                            .node = node,
                            .code = TsCodes.cannot_assign_const,
                            .message = msg,
                        });
                    }
                }
                if (target_kind == .literal_undefined) {
                    try self.report(a.target, TsCodes.cannot_assign_undefined, "Cannot assign to 'undefined' because it is not a variable.");
                }
                if (self.expressionIsOptionalChain(a.target)) {
                    try self.report(a.target, TsCodes.optional_chain_assignment_target, "The left-hand side of an assignment expression may not be an optional property access.");
                }
                try self.checkEnumMemberAssignment(a.target);
                // TS2540: assigning to a property declared `readonly`.
                // Object/interface readonly fields are immutable;
                // class-field readonly is approximated by the
                // constructor exception inside the helper.
                if (self.hir.kindOf(a.target) == .member_access) {
                    try self.checkReadonlyAssignment(a.target);
                }
                if (self.hir.kindOf(a.target) == .element_access) {
                    try self.checkReadonlyIndexAssignment(a.target);
                }
                const value_t = try self.checkExpression(a.value);
                const assignment_check_value_t = if (self.hir.kindOf(a.value) == .identifier) blk_assign_value: {
                    const value_id = hir_mod.identifierOf(self.hir, a.value);
                    if (self.lookupNarrow(value_id.name) != null) break :blk_assign_value value_t;
                    break :blk_assign_value self.typeOfIdentifierDeclared(a.value);
                } else value_t;
                const target_is_destructuring = a.op == null and
                    (self.hir.kindOf(a.target) == .array_literal or self.hir.kindOf(a.target) == .object_literal);
                const target_is_untyped_uninitialized_var =
                    self.hir.kindOf(a.target) == .identifier and
                    target_t == types.Primitive.undefined_t and
                    self.identifierIsUntypedUninitializedVar(a.target);
                var assignment_result_t = value_t;
                if (a.op == null) {
                    assignment_result_t = try self.flowTypeForAssignmentValue(a.value, value_t);
                    const has_active_target_narrow = if (self.hir.kindOf(a.target) == .identifier)
                        self.lookupNarrow(hir_mod.identifierOf(self.hir, a.target).name) != null
                    else
                        false;
                    if ((!self.nodeIsInsideFunctionLike(node) or has_active_target_narrow) and
                        !self.nodeIsInsideLoop(node) and
                        self.hir.kindOf(a.target) == .identifier and
                        assignment_result_t != types.Primitive.none and
                        assignment_result_t != types.Primitive.any and
                        assignment_result_t != types.Primitive.unknown and
                        target_t != types.Primitive.any and
                        target_t != types.Primitive.unknown and
                        ((try self.literalExpressionAssignableToTarget(a.value, target_t)) or
                            (self.engine.isAssignableTo(assignment_result_t, target_t) catch true)))
                    {
                        const target_id = hir_mod.identifierOf(self.hir, a.target);
                        try self.recordNarrow(target_id.name, assignment_result_t);
                    }
                }
                if (a.op) |op| {
                    switch (op) {
                        .add => {
                            try self.checkCompoundAdditionAssignment(node, a.target, a.value, target_t, value_t);
                        },
                        .sub, .mul, .div, .mod, .pow, .bit_and, .bit_or, .bit_xor, .shl, .shr, .shr_unsigned => {
                            if (!self.isArithmeticOperandAllowed(target_t)) {
                                try self.reportArithmeticOperand(a.target, TsCodes.arithmetic_left_operand_type, "The left-hand side of an arithmetic operation must be of type 'any', 'number', 'bigint' or an enum type.");
                            }
                            if (!self.isArithmeticOperandAllowed(value_t)) {
                                try self.reportArithmeticOperand(a.value, TsCodes.arithmetic_right_operand_type, "The right-hand side of an arithmetic operation must be of type 'any', 'number', 'bigint' or an enum type.");
                            }
                        },
                        else => {},
                    }
                }
                if (a.op == null and self.hir.kindOf(a.target) == .array_literal) {
                    try self.checkArrayDestructuringAssignment(a.target, value_t, a.value, 0);
                }
                if (a.op == null and self.hir.kindOf(a.target) == .object_literal) {
                    try self.checkObjectDestructuringAssignment(a.target, value_t, a.value);
                }
                if (a.op == null and
                    self.hir.kindOf(a.value) == .array_literal and
                    target_t != types.Primitive.none and
                    target_t != types.Primitive.any and
                    target_t != types.Primitive.unknown and
                    self.isTupleShapedTarget(target_t) and
                    !(try self.checkArrayLiteralAgainstTuple(a.value, target_t)))
                {
                    try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to target type.");
                }
                if (!target_is_destructuring and !target_is_untyped_uninitialized_var and a.op == null and self.classPrivateStructuralMismatch(target_t, value_t)) {
                    try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to declared type.");
                }
                if (!target_is_destructuring and !target_is_untyped_uninitialized_var and a.op == null and
                    target_t != types.Primitive.none and
                    target_t != types.Primitive.any and
                    target_t != types.Primitive.unknown)
                {
                    // Upstream `typeParameterAssignability.ts`: two
                    // declared type parameters `T` and `U` are mutually
                    // unassignable unless one transitively constrains
                    // the other. The relation engine stays permissive
                    // on type-parameter targets to support inference,
                    // so the assignment-expression checker pins this
                    // case directly.
                    if (self.unrelatedTypeParameterAssignment(assignment_check_value_t, target_t)) {
                        try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to target type.");
                    } else {
                        const ok = (try self.literalExpressionAssignableToTarget(a.value, target_t)) or
                            (self.hir.kindOf(a.value) == .array_literal and
                                self.isTupleShapedTarget(target_t) and
                                (try self.checkArrayLiteralAgainstTuple(a.value, target_t))) or
                            (try self.loweredLogicalAssignmentAssignableToTarget(a.target, a.value, target_t)) or
                            (try self.logicalExpressionAssignableToTarget(a.value, target_t)) or
                            (try self.templateExpressionAssignableToType(a.value, target_t)) or
                            (self.hir.kindOf(a.value) == .object_literal and
                                (self.objectLiteralAssignableToTarget(a.value, value_t, target_t) catch false)) or
                            (self.hir.kindOf(a.value) == .identifier and
                                self.lookupNarrow(hir_mod.identifierOf(self.hir, a.value).name) != null and
                                self.interner.isSignature(target_t) and
                                self.objectHasCallOrConstructSignature(value_t)) or
                            self.genericSignatureAssignmentAssignable(assignment_check_value_t, target_t) or
                            (self.engine.isAssignableTo(assignment_check_value_t, target_t) catch true);
                        if (!ok) {
                            try self.report(node, TsCodes.type_not_assignable, "Type is not assignable to target type.");
                        }
                    }
                }
                if (a.op == null) try self.checkGenericIndexedAssignment(node, a.target, a.value);
                break :blk assignment_result_t;
            },
            .new_expr => blk: {
                const c = hir_mod.callOf(self.hir, node);
                const callee_t = try self.checkExpression(c.callee);
                const args = hir_mod.callArgs(self.hir, node);
                var arg_types: std.ArrayListUnmanaged(TypeId) = .empty;
                defer arg_types.deinit(self.gpa);
                for (args) |arg| {
                    const t = try self.checkExpression(arg);
                    try arg_types.append(self.gpa, t);
                }
                if (self.hir.kindOf(c.callee) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, c.callee);
                    if (std.mem.eql(u8, self.string_interner.get(id.name), "Symbol")) {
                        try self.report(node, TsCodes.new_expression_not_void, "Only a void function can be called with the 'new' keyword.");
                    }
                    if (self.abstract_classes.contains(id.name)) {
                        try self.report(
                            node,
                            TsCodes.abstract_class_instantiation,
                            "Cannot create an instance of an abstract class.",
                        );
                    }
                }
                if (try self.checkNewConstructSignatures(node, c.callee, callee_t, args, arg_types.items)) |ret| {
                    break :blk ret;
                }
                const type_arg_nodes = hir_mod.callTypeArgs(self.hir, node);
                const callee_is_builtin = self.hir.kindOf(c.callee) == .identifier and
                    self.isBuiltinName(hir_mod.identifierOf(self.hir, c.callee).name);
                if (type_arg_nodes.len > 0 and !callee_is_builtin and (callee_t == types.Primitive.any or callee_t == types.Primitive.unknown)) {
