                        var ctor_subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
                        defer ctor_subs.deinit(self.gpa);
                        try self.inferCallSubstitutions(ctor_sig, args, arg_types.items, &ctor_subs);
