    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.declared_but_not_read) continue;
        const msg = d.message;
        if (std.mem.indexOf(u8, msg, "'y'") != null) has_y = true;
        if (std.mem.indexOf(u8, msg, "'x'") != null) only_y = false;
    }
    try T.expect(has_y);
    try T.expect(only_y);
}

